// RAG Knowledge Base Entries for Luna Chat
// Organized by category for efficient retrieval

export const ragEntries = [
  // === Postpartum Depression: Paternal PPD (IDs 1520–1531) ===
  { id: 1520, category: 'postpartum', keywords: ['father postpartum depression symptoms'], question: "Can fathers get postpartum depression?", response: "Yes. About 1 in 10 fathers experience depression during the perinatal period. Symptoms include irritability, withdrawal, fatigue, and mood changes. It's often underrecognized but treatable." },
  { id: 1521, category: 'postpartum', keywords: ['paternal postpartum depression prevalence'], question: "How common is postpartum depression in fathers?", response: "Studies show 8–10% of fathers experience depression during pregnancy or the first year postpartum. Rates are higher (24–50%) when the mother also has postpartum depression." },
  { id: 1522, category: 'postpartum', keywords: ['father postpartum depression risk factors'], question: "What increases a father's risk of postpartum depression?", response: "Key risk factors include: partner with depression, history of depression, relationship stress, financial stress, sleep deprivation, and lack of social support. Younger age and unplanned pregnancy also increase risk." },
  { id: 1523, category: 'postpartum', keywords: ['how paternal depression affects bonding'], question: "How does a father's depression affect bonding with the baby?", response: "Depression can make it harder to engage in sensitive, responsive parenting. Affected fathers may interact less, read fewer books, and sing fewer songs to their infants. Early treatment improves bonding outcomes." },
  { id: 1524, category: 'postpartum', keywords: ['screening fathers for postpartum depression'], question: "Should fathers be screened for postpartum depression?", response: "Yes. The Edinburgh Postnatal Depression Scale (EPDS) can be used with fathers. Screening is recommended during pregnancy and postpartum, especially if the mother has depression or there are relationship stressors." },
  { id: 1525, category: 'postpartum', keywords: ['treatment for fathers with postpartum depression'], question: "How is paternal postpartum depression treated?", response: "Treatment includes psychotherapy (CBT or IPT), support groups, lifestyle changes (sleep, exercise), and sometimes medication. Involving the partner in treatment can improve outcomes for both parents." },
  { id: 1526, category: 'postpartum', keywords: ['impact of father depression on child development'], question: "How does a father's depression affect child development?", response: "Untreated paternal depression is linked to increased behavioral problems, emotional difficulties, and cognitive delays in children. Early identification and treatment protect child outcomes." },
  { id: 1527, category: 'postpartum', keywords: ['when do fathers get postpartum depression'], question: "When does postpartum depression typically start in fathers?", response: "Paternal depression peaks between 3–6 months postpartum, but can start during pregnancy or anytime in the first year. Ongoing monitoring is important throughout the perinatal period." },
  { id: 1528, category: 'postpartum', keywords: ['signs of father postpartum depression'], question: "What are the signs of postpartum depression in fathers?", response: "Common signs include: increased irritability or anger, withdrawal from family, loss of interest in activities, fatigue, changes in appetite or sleep, and increased risk-taking behavior or substance use." },
  { id: 1529, category: 'postpartum', keywords: ['supporting partner with postpartum depression as a father'], question: "How can fathers support a partner with postpartum depression?", response: "Fathers can help by: sharing nighttime feedings, encouraging professional help, attending appointments, providing emotional support, managing household tasks, and being patient and understanding." },
  { id: 1530, category: 'postpartum', keywords: ['father postpartum depression and relationship'], question: "How does paternal postpartum depression affect the relationship?", response: "It can increase conflict, reduce intimacy, and create communication challenges. Couples therapy or involving the partner in individual treatment can help repair and strengthen the relationship." },
  { id: 1531, category: 'postpartum', keywords: ['father postpartum depression resources'], question: "Where can fathers get help for postpartum depression?", response: "Resources include: primary care providers, mental health professionals, Postpartum Support International (PSI), online support groups, and father-specific programs. Many therapists specialize in perinatal mental health." },

  // === Postpartum Depression: Prevention (IDs 1532–1543) ===
  { id: 1532, category: 'postpartum', keywords: ['who should prevent postpartum depression'], question: "Who should get preventive treatment for postpartum depression?", response: "Prevention is recommended for those with: a history of postpartum or major depression, depression during pregnancy, bipolar disorder, or significant psychosocial stressors. Early intervention reduces recurrence risk." },
  { id: 1533, category: 'postpartum', keywords: ['antidepressants to prevent postpartum depression'], question: "Can antidepressants prevent postpartum depression?", response: "For those with a history of severe postpartum depression, starting antidepressants immediately after delivery can significantly reduce recurrence risk. This should be discussed during pregnancy with a psychiatrist." },
  { id: 1534, category: 'postpartum', keywords: ['psychotherapy to prevent postpartum depression'], question: "Can therapy prevent postpartum depression?", response: "Yes. Starting CBT or IPT during pregnancy significantly reduces the risk of developing postpartum depression, especially for those with a history of depression or current mild symptoms." },
  { id: 1535, category: 'postpartum', keywords: ['mindfulness to prevent postpartum depression'], question: "Does mindfulness help prevent postpartum depression?", response: "Mindfulness-based interventions during pregnancy show promise in reducing postpartum depression risk. They help with stress management, emotional regulation, and present-moment awareness." },
  { id: 1536, category: 'postpartum', keywords: ['psychosocial support to prevent postpartum depression'], question: "What role does support play in preventing postpartum depression?", response: "Strong social support is protective. This includes partner support, family help, peer groups, and professional support. Practical help with baby care and household tasks reduces stress and isolation." },
  { id: 1537, category: 'postpartum', keywords: ['omega-3 for preventing postpartum depression'], question: "Do omega-3 supplements prevent postpartum depression?", response: "Evidence is mixed. Some studies suggest omega-3s may help, but they are not considered a standalone preventive treatment. They can be part of a comprehensive approach including therapy and support." },
  { id: 1538, category: 'postpartum', keywords: ['exercise for preventing postpartum depression'], question: "Can exercise prevent postpartum depression?", response: "Regular physical activity during and after pregnancy is associated with lower depression risk. Even moderate exercise like walking can improve mood and reduce stress, though it's not a replacement for treatment in high-risk individuals." },
  { id: 1539, category: 'postpartum', keywords: ['planning ahead to prevent postpartum depression'], question: "How can I plan ahead to prevent postpartum depression?", response: "Create a postpartum plan that includes: arranging support, planning for sleep, identifying warning signs, scheduling follow-up appointments, and discussing medication decisions with your provider before delivery." },
  { id: 1540, category: 'postpartum', keywords: ['what does not prevent postpartum depression'], question: "Do supplements or exercise prevent postpartum depression?", response: "Current evidence does not show that omega-3 supplements, selenium, or exercise alone reliably prevent postpartum depression. They may support overall health but are not considered effective standalone prevention strategies." },
  { id: 1541, category: 'postpartum', keywords: ['early intervention for postpartum depression prevention'], question: "How early should prevention start for postpartum depression?", response: "Prevention should begin during pregnancy, ideally in the second trimester. Early identification of risk factors and starting therapy or medication before delivery provides the best protection." },
  { id: 1542, category: 'postpartum', keywords: ['partner support for preventing postpartum depression'], question: "How can partners help prevent postpartum depression?", response: "Partners can help by: attending prenatal appointments, learning about postpartum depression, planning for practical support, being emotionally available, and encouraging professional help if warning signs appear." },
  { id: 1543, category: 'postpartum', keywords: ['high-risk prevention postpartum depression'], question: "What's recommended for someone at very high risk of postpartum depression?", response: "For very high-risk individuals (severe prior PPD, bipolar disorder), a combination approach is best: prophylactic antidepressants starting at delivery, ongoing therapy, close monitoring, and strong support systems." },

  // === Postpartum Depression: Adverse Consequences (IDs 1544–1558) ===
  { id: 1544, category: 'postpartum', keywords: ['postpartum depression and maternal infant bonding'], question: "How does postpartum depression affect bonding with the baby?", response: "Postpartum depression can interfere with maternal-infant bonding. Mothers may have difficulty feeling connected, responding to cues, or enjoying time with their baby. This is treatable, and bonding can improve with treatment." },
  { id: 1545, category: 'postpartum', keywords: ['postpartum depression and breastfeeding'], question: "Does postpartum depression affect breastfeeding?", response: "It is associated with lower rates of starting breastfeeding and shorter duration. Many depressed mothers still want to breastfeed and can succeed with the right support and treatment." },
  { id: 1546, category: 'postpartum', keywords: ['postpartum depression and partner relationship'], question: "How does postpartum depression affect relationships?", response: "It can strain partner relationships through increased conflict, reduced intimacy, and communication difficulties. Partner involvement in treatment can improve both the relationship and maternal outcomes." },
  { id: 1547, category: 'postpartum', keywords: ['postpartum depression and suicide risk'], question: "Can postpartum depression lead to suicide?", response: "Yes. Suicide is a leading cause of maternal mortality. Severe depression, especially with thoughts of self-harm, requires immediate professional help. Call 988 or go to the ER if you have these thoughts." },
  { id: 1548, category: 'postpartum', keywords: ['postpartum depression and child cognitive development'], question: "How does postpartum depression affect child cognitive development?", response: "Untreated postpartum depression is associated with delays in cognitive development, including lower scores on developmental assessments. Early treatment protects against these effects." },
  { id: 1549, category: 'postpartum', keywords: ['postpartum depression and child behavioral problems'], question: "Does postpartum depression cause behavioral problems in children?", response: "Children of mothers with untreated postpartum depression have higher rates of behavioral problems, including hyperactivity and conduct issues. Treatment reduces this risk." },
  { id: 1550, category: 'postpartum', keywords: ['postpartum depression and child emotional development'], question: "How does postpartum depression affect a child's emotional development?", response: "It can increase the risk of emotional difficulties in children, including anxiety, depression, and difficulty regulating emotions. Secure attachment and early intervention protect against these outcomes." },
  { id: 1551, category: 'postpartum', keywords: ['postpartum depression and infant sleep'], question: "Does postpartum depression affect infant sleep?", response: "Maternal depression is associated with more infant sleep problems. This can create a cycle where poor sleep worsens maternal mood. Addressing both maternal depression and infant sleep can help break this cycle." },
  { id: 1552, category: 'postpartum', keywords: ['postpartum depression and language development'], question: "Can postpartum depression affect language development?", response: "Some studies show delays in language development in children of mothers with untreated postpartum depression. Early treatment and responsive interaction support healthy language development." },
  { id: 1553, category: 'postpartum', keywords: ['postpartum depression and attachment security'], question: "How does postpartum depression affect attachment?", response: "Untreated depression increases the risk of insecure attachment. However, treatment improves maternal sensitivity and attachment outcomes. It's never too late to seek help." },
  { id: 1554, category: 'postpartum', keywords: ['long-term effects of postpartum depression on children'], question: "What are the long-term effects of postpartum depression on children?", response: "Untreated postpartum depression is associated with increased risk of mental health issues, academic difficulties, and social problems in childhood and adolescence. Early treatment significantly reduces these risks." },
  { id: 1555, category: 'postpartum', keywords: ['postpartum depression and parenting quality'], question: "Does postpartum depression affect parenting quality?", response: "Depression can reduce sensitive, responsive parenting. Mothers may be less engaged or more intrusive. Treatment improves parenting quality and parent-child interactions." },
  { id: 1556, category: 'postpartum', keywords: ['postpartum depression and family functioning'], question: "How does postpartum depression affect the whole family?", response: "It impacts the entire family system, including partner mental health, sibling relationships, and overall family functioning. Family-based treatment approaches can address these broader impacts." },
  { id: 1557, category: 'postpartum', keywords: ['postpartum depression and economic impact'], question: "What is the economic impact of postpartum depression?", response: "Postpartum depression has significant economic costs through healthcare utilization, lost productivity, and impacts on child development. Investment in prevention and treatment provides substantial societal benefits." },
  { id: 1558, category: 'postpartum', keywords: ['postpartum depression and breastfeeding'], question: "Does postpartum depression affect breastfeeding?", response: "It is associated with lower rates of starting breastfeeding and shorter duration. Many depressed mothers still want to breastfeed and can succeed with the right support and treatment." },

  // === Postpartum Contraception (IDs 1559–1581) ===
  { id: 1559, category: 'postpartum', keywords: ['when does ovulation return after birth'], question: "When can I get pregnant again after giving birth?", response: "Ovulation can return as early as 25 days after delivery in non-breastfeeding people, though it's more commonly around 45–94 days. You can get pregnant before your first period returns, which is why starting contraception on time is important." },
  { id: 1560, category: 'postpartum', keywords: ['why start contraception soon after birth'], question: "Why is it important to start contraception soon after giving birth?", response: "Many people resume sex before their 6-week checkup, and ovulation can return early. Starting effective contraception before you leave the hospital or at your early postpartum visit helps prevent unintended pregnancy and supports healthy birth spacing." },
  { id: 1561, category: 'postpartum', keywords: ['how soon after birth can I have sex'], question: "When is it safe to have sex again after giving birth?", response: "Most providers recommend waiting until bleeding stops and any tears or incisions have healed — usually around 4–6 weeks. Go at your own pace and use lubrication if you're breastfeeding. Talk to your provider about contraception before resuming sex." },
  { id: 1562, category: 'postpartum', keywords: ['how to choose postpartum contraception'], question: "How should I choose which birth control to use after having a baby?", response: "Think about whether you want more children and when, what's most important to you (effectiveness, convenience, no hormones, etc.), your medical history, and whether you're breastfeeding. A shared decision-making conversation with your provider helps match the best method to your life." },
  { id: 1563, category: 'postpartum', keywords: ['reproductive life plan after birth'], question: "What is a reproductive life plan and why does it matter after having a baby?", response: "It's a conversation about whether and when you want more children. Discussing this during pregnancy or right after birth helps you choose contraception that fits your goals and supports healthy spacing between pregnancies (ideally at least 18–24 months)." },
  { id: 1564, category: 'postpartum', keywords: ['tubal ligation after birth'], question: "Can I get my tubes tied right after giving birth?", response: "Yes. Permanent contraception (tubal ligation or salpingectomy) can be done right after a vaginal or cesarean birth. It's highly effective. If you're sure you don't want more children, discuss this option during pregnancy so it can be arranged." },
  { id: 1565, category: 'postpartum', keywords: ['vasectomy after partner gives birth'], question: "Can my partner get a vasectomy after I have the baby?", response: "Yes. Vasectomy is a simple, highly effective permanent option for male partners. It can be done anytime and has very low risk. It's a good choice if you're certain you don't want more children together." },
  { id: 1566, category: 'postpartum', keywords: ['IUD right after birth'], question: "Can I get an IUD placed right after giving birth?", response: "Yes. An IUD (copper or hormonal) can be placed immediately after delivery of the placenta. This is called postplacental placement. It's safe and convenient, though there is a higher chance of the IUD coming out (expulsion) compared with placement at 6 weeks." },
  { id: 1567, category: 'postpartum', keywords: ['IUD expulsion after birth'], question: "What are the chances my IUD will fall out if I get it right after birth?", response: "Expulsion risk is higher with immediate placement (roughly 10–15% in the first year) compared with placement at 6+ weeks. It's still lower than the risk of unintended pregnancy if you don't have reliable contraception. Many people still successfully use an IUD placed right after birth." },
  { id: 1568, category: 'postpartum', keywords: ['when to check IUD strings after birth'], question: "When should I have my IUD checked after getting it right after birth?", response: "Many providers recommend an ultrasound or string check around 4–6 weeks postpartum to confirm position, especially after immediate placement. Let your provider know if you can't feel the strings or have pain or bleeding." },
  { id: 1569, category: 'postpartum', keywords: ['IUD perforation after birth'], question: "Is there a higher risk of IUD perforation if placed after giving birth?", response: "The overall risk of perforation is low. Some studies show a slightly higher risk with placement between 4–8 weeks postpartum compared with later placement, but it remains uncommon. Breastfeeding may slightly increase risk, but the absolute numbers are still very small." },
  { id: 1570, category: 'postpartum', keywords: ['birth control implant after birth'], question: "Can I get the birth control implant right after having my baby?", response: "Yes. The etonogestrel implant (Nexplanon) can be placed anytime after delivery, including before you go home. It's highly effective, long-acting, and doesn't affect breastfeeding." },
  { id: 1571, category: 'postpartum', keywords: ['Depo shot after birth'], question: "Can I get the Depo-Provera shot right after giving birth?", response: "Yes. The progestin injection can be given immediately after delivery. It provides 3 months of contraception and can be a good bridge until your postpartum visit. Discuss any concerns about mood changes with your provider." },
  { id: 1572, category: 'postpartum', keywords: ['progestin only pill after birth'], question: "Can I start the mini-pill right after giving birth?", response: "Yes. Progestin-only pills can be started immediately after delivery. They are safe while breastfeeding. Remember to take them at the same time every day for best effectiveness." },
  { id: 1573, category: 'postpartum', keywords: ['when can I start combined birth control after birth'], question: "When can I start the regular birth control pill, patch, or ring after giving birth?", response: "You should wait at least 3 weeks (21 days) after delivery to start any estrogen-containing method because of increased blood clot risk. If you have additional risk factors, your provider may recommend waiting 6 weeks." },
  { id: 1574, category: 'postpartum', keywords: ['does hormonal birth control affect breastfeeding'], question: "Will hormonal birth control affect my milk supply?", response: "Most progestin-only methods (implant, IUD, mini-pill, shot) have little to no effect on milk supply for most people. Estrogen-containing methods may have more impact and are usually delayed until breastfeeding is well established. Discuss your priorities with your provider." },
  { id: 1575, category: 'postpartum', keywords: ['best birth control while breastfeeding'], question: "What's the best birth control if I'm breastfeeding?", response: "Progestin-only methods (implant, hormonal IUD, mini-pill, shot) and non-hormonal options (copper IUD, condoms) are excellent choices. They don't significantly affect milk supply for most people and are safe while breastfeeding." },
  { id: 1576, category: 'postpartum', keywords: ['blood clot risk and birth control after birth'], question: "Why can't I start estrogen birth control right after having a baby?", response: "Your risk of blood clots is naturally higher in the weeks after delivery. Adding estrogen further increases that risk, so it's safest to wait at least 3 weeks (longer if you have other risk factors) before starting any estrogen-containing method." },
  { id: "Yes. Both the copper IUD and levonorgestrel pill are safe options postpartum. Ulipristal (ella) is also an option, but you should pump and discard breast milk for 24 hours after taking it if you're breastfeeding." },
  { id: 1578, category: 'postpartum', keywords: ['birth control for teens after birth'], question: "What birth control options are best for young parents after having a baby?", response: "Long-acting reversible contraception (IUD or implant) placed right after birth is highly effective and helps prevent repeat pregnancy. All methods are available — the best choice depends on the individual's preferences and life situation." },
  { id: 1579, category: 'postpartum', keywords: ['birth control with history of depression'], question: "Can I use hormonal birth control if I have a history of depression or postpartum depression?", response: "Yes. Hormonal contraception is generally considered safe for people with depression. There is no clear evidence that most methods worsen mood, though individual responses vary. Discuss any concerns with your provider." },
  { id: 1580, category: 'postpartum', keywords: ['what if I am unsure about birth control after birth'], question: "What if I'm not sure what birth control I want after having my baby?", response: "That's okay. You can start with a highly effective method like an implant or IUD (which can be removed later) while you decide. You can also use condoms or abstinence in the short term. Talk with your provider at your postpartum visits — you don't have to decide everything at once." },
  { id: 1581, category: 'postpartum', keywords: ['birth spacing after having a baby'], question: "How long should I wait before getting pregnant again?", response: "Most experts recommend waiting at least 18–24 months after a birth before trying to conceive again. This gives your body time to recover and is associated with better outcomes for both mother and baby." },

  // === Treatment of Mild–Moderate Postpartum Depression (IDs 1582–1599) ===
  { id: 1582, category: 'postpartum', keywords: ['mild vs moderate vs severe postpartum depression'], question: "How do I know if my postpartum depression is mild, moderate, or severe?", response: "Mild to moderate depression usually involves 5–6 symptoms and you can still function day-to-day, though it's hard. Severe depression involves more symptoms, significant impairment, and often thoughts of self-harm. Your provider can help assess severity using tools like the Edinburgh scale or PHQ-9." },
  { id: 1583, category: 'postpartum', keywords: ['postpartum blues vs postpartum depression'], question: "What's the difference between baby blues and postpartum depression?", response: "Baby blues are mild mood swings, tearfulness, and irritability that usually start a few days after birth and go away within two weeks. Postpartum depression is more intense, lasts longer than two weeks, and interferes with functioning or bonding. If symptoms persist or worsen, get evaluated." },
  { id: 1584, category: 'postpartum', keywords: ['psychotherapy for postpartum depression'], question: "Is therapy effective for postpartum depression?", response: "Yes. Psychotherapy, especially Cognitive Behavioral Therapy (CBT) and Interpersonal Psychotherapy (IPT), is an effective first-line treatment for mild to moderate postpartum depression. Many women prefer therapy, especially while breastfeeding." },
  { id: 1585, category: 'postpartum', keywords: ['CBT for postpartum depression'], question: "What is CBT and how does it help with postpartum depression?", response: "Cognitive Behavioral Therapy (CBT) helps you identify and change unhelpful thought patterns and behaviors that fuel depression. It is one of the most well-studied and effective therapies for postpartum depression and can be done individually or in groups." },
  { id: 1586, category: 'postpartum', keywords: ['interpersonal therapy for postpartum depression'], question: "What is interpersonal therapy (IPT) for postpartum depression?", response: "Interpersonal Psychotherapy (IPT) focuses on relationship changes, role transitions (like becoming a parent), and interpersonal issues that contribute to depression. It is highly effective for postpartum depression and helps improve both mood and relationships." },
  { id: 1587, category: 'postpartum', keywords: ['antidepressants for mild moderate postpartum depression'], question: "Do I need medication for mild to moderate postpartum depression?", response: "Medication is not always required. Many women do well with therapy alone. Antidepressants are a reasonable option if therapy isn't enough, isn't available, or if you've responded well to them in the past. Most are considered compatible with breastfeeding when monitored." },
  { id: 1588, category: 'postpartum', keywords: ['zuranolone for postpartum depression'], question: "What is zuranolone and is it used for postpartum depression?", response: "Zuranolone is a newer oral medication specifically approved for postpartum depression. It is taken for a short course (usually 14 days). It may be an option for some women, but discuss risks, benefits, and breastfeeding compatibility with your provider." },
  { id: 1589, category: 'postpartum', keywords: ['behavioral activation for postpartum depression'], question: "What is behavioral activation and how can it help?", response: "Behavioral activation is a therapy that helps you gradually re-engage in rewarding activities and break the cycle of withdrawal and low mood. It can be very effective for postpartum depression, either on its own or as part of CBT." },
  { id: 1590, category: 'postpartum', keywords: ['exercise for postpartum depression'], question: "Can exercise help with postpartum depression?", response: "Yes. Regular exercise (walking, yoga, strength training) can reduce depressive symptoms in postpartum women. Even modest activity helps. It works best when combined with other treatments like therapy or social support." },
  { id: 1591, category: 'postpartum', keywords: ['peer support for postpartum depression'], question: "Does talking to other moms help with postpartum depression?", response: "Yes. Peer support and mother-to-mother groups can reduce feelings of isolation and improve symptoms. Connecting with others who understand what you're going through is often very helpful alongside professional treatment." },
  { id: 1592, category: 'postpartum', keywords: ['parenting support and postpartum depression'], question: "Can learning parenting skills help my mood?", response: "Yes. Programs that teach practical parenting skills (especially around infant sleep, crying, and soothing) can reduce stress and improve mood in mothers with postpartum depression by increasing confidence and sense of control." },
  { id: 1593, category: 'postpartum', keywords: ['monitoring postpartum depression treatment'], question: "How will my provider know if treatment is working?", response: "Your provider will use tools like the Edinburgh Postnatal Depression Scale or PHQ-9 to track your symptoms over time. You should notice gradual improvement. Regular check-ins help adjust the plan if needed." },
  { id: 1594, category: 'postpartum', keywords: ['what if therapy is not helping enough'], question: "What if therapy isn't helping my postpartum depression enough?", response: "If you're only getting partial improvement, your provider may increase session frequency, add more sessions, switch therapy type, or add medication. Don't give up — many women need a combination or adjustment of treatments to feel better." },
  { id: 1595, category: 'postpartum', keywords: ['what if nothing is helping postpartum depression'], question: "What if my postpartum depression isn't getting better with treatment?", response: "If symptoms persist despite therapy and/or medication, your provider may refer you to a perinatal psychiatrist, consider additional options, or evaluate for other contributing factors. More intensive support or different treatments can still help." },
  { id: 1596, category: 'postpartum', keywords: ['how long to stay on treatment after postpartum depression'], question: "How long should I stay on treatment after postpartum depression improves?", response: "Many women continue treatment for 6–24 months after feeling better to reduce the risk of recurrence. Your provider will work with you to decide the right duration based on your history and risk factors." },
  { id: 1597, category: 'postpartum', keywords: ['planning for future pregnancies after postpartum depression'], question: "What should I do if I want another baby after having postpartum depression?", response: "Talk with your provider before trying to conceive again. Many women restart or continue preventive treatment (therapy and/or medication) during pregnancy and after birth. Planning ahead significantly reduces the chance of recurrence." },
  { id: 1598, category: 'postpartum', keywords: ['therapy while breastfeeding postpartum depression'], question: "Can I do therapy while breastfeeding?", response: "Yes. Therapy (CBT, IPT, etc.) has no impact on breastfeeding and is often the preferred first treatment for breastfeeding mothers with mild to moderate postpartum depression." },
  { id: 1599, category: 'postpartum', keywords: ['medication safety while breastfeeding postpartum depression'], question: "Is it safe to take antidepressants while breastfeeding?", response: "Most antidepressants are considered compatible with breastfeeding. The amount that passes into breast milk is usually low, and benefits of treating depression generally outweigh risks. Your provider and pediatrician can help choose the safest option and monitor your baby." },

  // === NEW UpToDate Treatment of Postpartum Psychosis RAG Entries (IDs 1611–1628) ===
  // Emergency Nature & Safety
  { id: 1611, category: 'postpartum', keywords: ['postpartum psychosis emergency'], question: "Is postpartum psychosis a medical emergency?", response: "Yes. Postpartum psychosis is a psychiatric emergency. It usually starts suddenly within the first few weeks after birth and can involve confusion, hallucinations, delusions, and disorganized thinking. Immediate evaluation and treatment are needed to protect the mother and baby." },
  { id: 1612, category: 'postpartum', keywords: ['hospitalization for postpartum psychosis'], question: "Do I need to go to the hospital if I have postpartum psychosis?", response: "In most cases, yes. Hospitalization is usually recommended so the mother can be kept safe and treated quickly. The baby should not be left alone with someone experiencing postpartum psychosis until symptoms are under control." },
  { id: 1613, category: 'postpartum', keywords: ['mother baby separation postpartum psychosis'], question: "Will I be separated from my baby if I have postpartum psychosis?", response: "Temporarily, yes — for safety. While separation is difficult, it is often necessary until the mother is stable. Many hospitals try to support supervised visits when it is safe. The goal is always to reunite mother and baby as soon as it is safe to do so." },

  // Initial Medication Approach
  { id: 1614, category: 'postpartum', keywords: ['lithium and antipsychotic for postpartum psychosis'], question: "What is the usual medication treatment for postpartum psychosis?", response: "The preferred initial treatment is usually a combination of lithium and a second-generation antipsychotic. This approach is used because many people with postpartum psychosis later receive a diagnosis of bipolar disorder." },
  { id: 1615, category: 'postpartum', keywords: ['why lithium for postpartum psychosis'], question: "Why is lithium used in postpartum psychosis?", response: "Lithium is often added because postpartum psychosis is strongly linked to bipolar disorder. Studies show that adding lithium significantly improves outcomes and helps maintain stability after the acute episode." },
  { id: 1616, category: 'postpartum', keywords: ['second generation antipsychotic postpartum psychosis'], question: "Which antipsychotic is best for postpartum psychosis?", response: "Second-generation antipsychotics (such as olanzapine, quetiapine, or lurasidone) are generally preferred because they tend to have fewer movement-related side effects. The specific choice depends on the person's symptoms, other health conditions, and whether they are breastfeeding." },

  // Special Situations
  { id: 1617, category: 'postpartum', keywords: ['postpartum psychosis with depression'], question: "What if postpartum psychosis comes with strong depressive symptoms?", response: "If there are clear depressive symptoms (such as anhedonia or thoughts of self-harm), an SSRI antidepressant may be added after starting lithium and an antipsychotic. However, if there is emotional lability or irritability, antidepressants are usually avoided because they can worsen symptoms or trigger mania." },
  { id: 1618, category: 'postpartum', keywords: ['lithium monotherapy postpartum psychosis'], question: "Can lithium be used alone for postpartum psychosis?", response: "Sometimes, but only in mild cases with very little disorganization. Most people need both lithium and an antipsychotic. Lithium monotherapy is used infrequently and requires close monitoring." },
  { id: 1619, category: 'postpartum', keywords: ['antipsychotic alone postpartum psychosis'], question: "What if someone can't take lithium?", response: "If lithium is not an option (for example, due to kidney problems), treatment starts with a second-generation antipsychotic alone. If that is not enough, another medication such as valproate may be considered, though it is usually avoided long-term due to risks in future pregnancies." },

  // Insomnia & Agitation
  { id: 1620, category: 'postpartum', keywords: ['benzodiazepines for insomnia in postpartum psychosis'], question: "What helps with severe insomnia or agitation in postpartum psychosis?", response: "A short-acting benzodiazepine (such as lorazepam) is often added to help restore sleep and reduce agitation. Good sleep is very important in recovery from postpartum psychosis." },

  // Next Steps & Inadequate Response
  { id: 1621, category: 'postpartum', keywords: ['what if treatment is not working for postpartum psychosis'], question: "What if someone isn't getting better with lithium and an antipsychotic?", response: "The team may switch to a different antipsychotic and strongly consider electroconvulsive therapy (ECT). ECT can work more quickly than medications and is especially useful when there is high risk of harm to self or baby." },
  { id: 1622, category: 'postpartum', keywords: ['ECT for postpartum psychosis'], question: "Is ECT used for postpartum psychosis?", response: "Yes. Electroconvulsive therapy (ECT) is an effective and relatively fast treatment for postpartum psychosis when medications are not enough or when rapid improvement is needed for safety. It is generally considered safe in the postpartum period." },

  // Continuation & Maintenance
  { id: 1623, category: 'postpartum', keywords: ['how long to stay on medication after postpartum psychosis'], question: "How long do I need to stay on medication after postpartum psychosis?", response: "After a good response, the antipsychotic is usually continued for at least 3–6 months and lithium for at least 9–12 months. Some people need longer treatment, especially if they have an underlying bipolar diagnosis or high risk of recurrence." },
  { id: 1624, category: 'postpartum', keywords: ['psychotherapy after postpartum psychosis'], question: "Is therapy helpful after postpartum psychosis?", response: "Yes. Once acute symptoms are under control, psychotherapy (focused on education, support, and medication adherence) is recommended as an important part of recovery and relapse prevention." },

  // Breastfeeding
  { id: 1625, category: 'postpartum', keywords: ['breastfeeding with postpartum psychosis'], question: "Can I breastfeed if I have postpartum psychosis?", response: "It depends on safety and stability. Many women can breastfeed while taking antipsychotics or lithium, but some with more severe symptoms may need to pause until they are more stable. The decision should be made with the care team, weighing risks and benefits." },
  { id: 1626, category: 'postpartum', keywords: ['medication safety while breastfeeding postpartum psychosis'], question: "Are antipsychotics and lithium safe while breastfeeding?", response: "Most antipsychotics and many antidepressants pass into breast milk in low amounts with minimal short-term effects on the baby. Lithium has more uncertainty. Decisions are made case-by-case with close monitoring of the infant. Never stop medication without medical advice." },

  // General Support & Planning
  { id: 1627, category: 'postpartum', keywords: ['planning future pregnancies after postpartum psychosis'], question: "What if I want another baby after having postpartum psychosis?", response: "This requires careful planning with a perinatal psychiatrist. Many women stay on mood stabilizers (especially lithium) during and after pregnancy to prevent recurrence. Early and proactive care greatly improves outcomes." },
  { id: 1628, category: 'postpartum', keywords: ['support for family after postpartum psychosis'], question: "How can family support someone with postpartum psychosis?", response: "Family support is essential. Help with practical tasks, encourage medication adherence, watch for warning signs of relapse, and support the mother emotionally without judgment. Professional guidance for the whole family is often beneficial." },

  // === NEW UpToDate Headache in Pregnancy & Postpartum RAG Entries (IDs 1646–1660) ===
  // Red Flags & When to Seek Care
  { id: 1646, category: 'pregnancy', keywords: ['headache in pregnancy when to worry'], question: "When should I worry about a headache during pregnancy?", response: "Any new or severe headache after 20 weeks needs prompt evaluation to rule out preeclampsia. Also seek care for sudden severe headache, vision changes, confusion, neck stiffness, seizures, or headache with high blood pressure. These can signal serious problems." },
  { id: 1647, category: 'pregnancy', keywords: ['preeclampsia headache symptoms'], question: "What does a preeclampsia headache feel like?", response: "It is often constant, throbbing, and felt all over the head. It may come with vision changes, upper belly pain, swelling, or high blood pressure. Any headache after 20 weeks should be checked, especially with these other symptoms." },
  { id: 1648, category: 'postpartum', keywords: ['postpartum headache red flags'], question: "When is a headache after birth concerning?", response: "Seek care for severe or worsening headache, vision changes, confusion, seizures, high blood pressure, or headache with neck stiffness. These can signal preeclampsia, blood clots, or other serious issues. Post-dural puncture headache (from epidural/spinal) is also common and treatable." },

  // Migraine in Pregnancy
  { id: 1649, category: 'pregnancy', keywords: ['migraine during pregnancy what to expect'], question: "What usually happens to migraines during pregnancy?", response: "Many women (60–70%) notice improvement, especially in the second and third trimesters. Some stay the same, and a small number worsen. Migraines often return in the first week or month after delivery, especially if you're not breastfeeding." },
  { id: 1650, category: 'pregnancy', keywords: ['safe migraine treatment in pregnancy'], question: "What can I safely take for migraine while pregnant?", response: "Acetaminophen is the safest first choice. If it's not enough, your provider may add metoclopramide or consider a short course of certain other medications depending on how far along you are. Triptans can be used in some cases when benefits outweigh risks. Always check with your provider before taking anything." },
  { id: 1651, category: 'pregnancy', keywords: ['triptans in pregnancy'], question: "Are triptans safe during pregnancy?", response: "Sumatriptan has the most safety data and is often considered acceptable when other treatments fail. Other triptans may also be used. Your provider will weigh the benefits and risks based on your specific situation and gestational age." },
  { id: 1652, category: 'pregnancy', keywords: ['preventive migraine treatment pregnancy'], question: "What can I take daily to prevent migraines while pregnant?", response: "Beta blockers (like propranolol) and some calcium channel blockers are commonly used. Certain antidepressants or nutraceuticals (magnesium, riboflavin) may also be options. Preventive treatment is usually reserved for frequent or disabling migraines. Discuss options with your provider." },

  // Tension-Type Headache
  { id: 1653, category: 'pregnancy', keywords: ['tension headache in pregnancy'], question: "How are tension headaches treated during pregnancy?", response: "Acetaminophen is the first-line treatment. Non-medication approaches like rest, heat/ice, massage, hydration, and stress reduction are also very helpful. Tension headaches often stay stable or improve slightly during pregnancy." },

  // Cluster Headache
  { id: 1654, category: 'pregnancy', keywords: ['cluster headache pregnancy'], question: "What helps with cluster headaches during pregnancy?", response: "100% oxygen is often the safest and most effective abortive treatment. Sumatriptan can be considered if oxygen isn't enough. Preventive options include verapamil or short courses of steroids after the first trimester. Ergotamine should be avoided." },

  // Postpartum Headache
  { id: 1655, category: 'postpartum', keywords: ['post dural puncture headache'], question: "What is a post-dural puncture headache and how is it treated?", response: "It's a headache that worsens when sitting or standing and improves when lying flat. It can occur after an epidural or spinal. Treatment often includes hydration, caffeine, and sometimes a blood patch. It's very treatable and breastfeeding is not a contraindication." },
  { id: 1656, category: 'postpartum', keywords: ['headache while breastfeeding what is safe'], question: "What headache medications are safe while breastfeeding?", response: "Acetaminophen and ibuprofen are generally safe. Some triptans are acceptable with timing adjustments. Avoid ergotamine and limit opioids. Always check with your provider or a lactation consultant before taking medication." },

  // General Safety Principles
  { id: 1657, category: 'pregnancy', keywords: ['headache medication safety by trimester'], question: "Which headache medications are safest in each trimester?", response: "Acetaminophen is safest throughout pregnancy. NSAIDs are generally avoided after 20 weeks. Triptans and certain other medications may be used when benefits outweigh risks. Your provider will choose based on gestational age, severity, and your overall health." },
  { id: 1658, category: 'pregnancy', keywords: ['non medication ways to treat headache in pregnancy'], question: "What can I do for headache without medication during pregnancy?", response: "Rest in a dark, quiet room, apply cold or warm compresses, stay hydrated, eat regular meals, maintain consistent sleep, reduce stress, and try gentle massage or relaxation techniques. These approaches are safe and often helpful." },

  // Medication Overuse
  { id: 1659, category: 'pregnancy', keywords: ['medication overuse headache pregnancy'], question: "Can taking pain medicine too often cause more headaches in pregnancy?", response: "Yes. Frequent use of pain relievers (even acetaminophen) can lead to medication overuse headaches. If you're using headache medication more than a couple of times per week, talk to your provider about preventive strategies and safer long-term options." },

  // When to Get Help
  { id: 1660, category: 'pregnancy', keywords: ['when to go to hospital for headache pregnant'], question: "When should I go to the hospital for a headache while pregnant or postpartum?", response: "Go if the headache is sudden and severe, comes with vision changes, confusion, seizures, high blood pressure, neck stiffness, or if it's the worst headache of your life. These symptoms need urgent evaluation to rule out serious causes." },

  // === NEW UpToDate Perinatal OCD RAG Entries (IDs 1661–1674) ===
  // Common Intrusive Thoughts vs OCD
  { id: 1661, category: 'postpartum', keywords: ['intrusive thoughts about harming baby normal'], question: "Is it normal to have scary thoughts about harming my baby?", response: "Yes — fleeting, unwanted thoughts of accidental harm to the baby are extremely common in new mothers, even those without any mental health history. These thoughts do not mean you will act on them. However, if the thoughts are frequent, very distressing, and lead to compulsive behaviors, it may be perinatal OCD." },
  { id: 1662, category: 'postpartum', keywords: ['postpartum OCD vs normal intrusive thoughts'], question: "How is postpartum OCD different from normal scary thoughts about the baby?", response: "In normal intrusive thoughts, the ideas are occasional and quickly dismissed. In perinatal OCD, the thoughts are frequent, cause intense anxiety or guilt, and lead to repetitive behaviors (like excessive checking, avoiding the baby, or mental rituals) that interfere with daily life and bonding." },

  // Symptoms in Pregnancy vs Postpartum
  { id: 1663, category: 'pregnancy', keywords: ['OCD symptoms during pregnancy'], question: "What does OCD look like during pregnancy?", response: "Common obsessions include fears of fetal harm, contamination, or miscarriage. Compulsions often involve excessive checking on the baby's well-being, repeated cleaning, or ritualized behaviors to 'protect' the pregnancy." },
  { id: 1664, category: 'postpartum', keywords: ['postpartum OCD harm thoughts'], question: "What kind of thoughts occur in postpartum OCD?", response: "Many women experience vivid, unwanted thoughts or images of accidentally or intentionally harming their baby (e.g., dropping the baby, drowning, or suffocating). These thoughts are extremely distressing and ego-dystonic (feel foreign and unwanted). They do not predict actual harm." },

  // Differentiation from Postpartum Psychosis
  { id: 1665, category: 'postpartum', keywords: ['postpartum OCD vs postpartum psychosis'], question: "How is postpartum OCD different from postpartum psychosis?", response: "In OCD, the thoughts are unwanted, resisted, and cause great distress (ego-dystonic). The mother usually has good insight and would never act on them. In postpartum psychosis, thoughts may feel real or justified (ego-syntonic), insight is often poor, and there is higher risk of acting on delusions. This distinction is critical for safety." },

  // Screening & Assessment
  { id: 1666, category: 'postpartum', keywords: ['screening for perinatal OCD'], question: "How is perinatal OCD screened for?", response: "There is no universal standard, but brief questions about intrusive thoughts (especially harm-related) can be helpful. The Perinatal Obsessive-Compulsive Scale (POCS) is a validated tool specifically designed for pregnancy and postpartum. Any positive screen should lead to a full clinical assessment." },
  { id: 1667, category: 'postpartum', keywords: ['assessing risk in perinatal OCD'], question: "How do clinicians assess safety when someone has thoughts of harming their baby?", response: "Clinicians evaluate frequency, intensity, insight, and whether the person is acting on or avoiding the thoughts. They also assess for comorbid depression or psychosis. Most women with OCD have good insight and are at low risk of acting on harm thoughts, but a full evaluation is essential." },

  // Treatment
  { id: 1668, category: 'postpartum', keywords: ['treatment of perinatal OCD'], question: "How is OCD treated during pregnancy and after birth?", response: "Cognitive Behavioral Therapy with Exposure and Response Prevention (ERP) is the first-line treatment. When symptoms are severe, comorbid depression is present, or therapy access is limited, SSRIs are added. Treatment decisions balance the risks of medication against the risks of untreated OCD." },
  { id: 1669, category: 'postpartum', keywords: ['CBT for postpartum OCD'], question: "Is therapy effective for postpartum OCD?", response: "Yes. CBT with Exposure and Response Prevention is highly effective. It helps women understand that intrusive thoughts are common and not dangerous, and reduces compulsive behaviors. Therapy is often preferred during pregnancy and breastfeeding when possible." },
  { id: 1670, category: 'postpartum', keywords: ['SSRIs for perinatal OCD'], question: "Are antidepressants safe for OCD during pregnancy or breastfeeding?", response: "SSRIs are generally considered compatible with pregnancy and breastfeeding when clinically indicated. Sertraline is often preferred due to lower passage into breast milk. The decision involves weighing benefits of treating OCD against potential risks, ideally with shared decision-making." },

  // Impact on Mother-Infant Relationship
  { id: 1671, category: 'postpartum', keywords: ['postpartum OCD and bonding with baby'], question: "Can postpartum OCD affect bonding with my baby?", response: "Yes. Avoidance of the baby, excessive checking, or mental rituals can interfere with bonding and responsive parenting. Early treatment helps protect the mother-infant relationship. Dyadic therapy or infant massage can be helpful adjuncts in some cases." },
  { id: 1672, category: 'postpartum', keywords: ['does postpartum OCD mean I will hurt my baby'], question: "If I have OCD thoughts about harming my baby, does that mean I'm dangerous?", response: "No. In OCD, these thoughts are unwanted and cause intense distress. They do not predict harmful behavior. Women with OCD almost always have good insight and would never intentionally harm their child. Postpartum psychosis is different and carries higher risk." },

  // Prognosis & Support
  { id: 1673, category: 'postpartum', keywords: ['prognosis of perinatal OCD'], question: "What is the outlook for someone with perinatal OCD?", response: "With proper treatment (especially CBT ± medication), most women improve significantly. Untreated OCD can affect bonding and increase risk of postpartum depression. Early recognition and treatment lead to better outcomes for both mother and baby." },
  { id: 1674, category: 'postpartum', keywords: ['support for partners of women with perinatal OCD'], question: "How can partners support someone with perinatal OCD?", response: "Partners can help by learning about OCD, avoiding participating in rituals, encouraging professional treatment, and providing emotional support without judgment. Involvement in therapy sessions can also be very helpful." },

  // === NEW UpToDate Chronic Hypertension in Pregnancy RAG Entries (IDs 1696–1710) ===
  // Definitions & Diagnosis
  { id: 1696, category: 'pregnancy', keywords: ['what is chronic hypertension in pregnancy'], question: "What is chronic hypertension in pregnancy?", response: "Chronic hypertension means you had high blood pressure before pregnancy or it was first found before 20 weeks. It is different from gestational hypertension or preeclampsia, which start later in pregnancy." },
  { id: 1697, category: 'pregnancy', keywords: ['blood pressure numbers for hypertension in pregnancy'], question: "What blood pressure numbers mean hypertension in pregnancy?", response: "Hypertension is systolic ≥140 or diastolic ≥90. Severe hypertension is systolic ≥160 or diastolic ≥110. These numbers should be confirmed on at least two readings before starting treatment, unless they are in the severe range." },

  // Risks
  { id: 1698, category: 'pregnancy', keywords: ['risks of chronic hypertension in pregnancy'], question: "What are the risks of having chronic hypertension during pregnancy?", response: "It increases the chance of preeclampsia, placental abruption, preterm birth, cesarean birth, fetal growth restriction, and other complications. The risks are higher if blood pressure is poorly controlled or if preeclampsia develops on top of chronic hypertension." },
  { id: 1699, category: 'pregnancy', keywords: ['superimposed preeclampsia'], question: "What is superimposed preeclampsia?", response: "This is when preeclampsia develops in someone who already has chronic hypertension. It can be harder to diagnose because some signs (like protein in urine or rising blood pressure) may already be present. Close monitoring is essential." },

  // Preconception & Early Pregnancy
  { id: 1700, category: 'pregnancy', keywords: ['preconception care for chronic hypertension'], question: "What should I do before getting pregnant if I have high blood pressure?", response: "Optimize blood pressure control, review your medications (some are not safe in pregnancy), check for secondary causes of hypertension, and discuss risks with your provider. Folic acid and a healthy lifestyle are also important." },
  { id: 1701, category: 'pregnancy', keywords: ['low dose aspirin for chronic hypertension'], question: "Should I take low-dose aspirin if I have chronic hypertension?", response: "Yes. Low-dose aspirin (usually 81 mg daily) is recommended starting after 12 weeks to help reduce the risk of preeclampsia in people with chronic hypertension." },

  // Monitoring During Pregnancy
  { id: 1702, category: 'pregnancy', keywords: ['monitoring chronic hypertension in pregnancy'], question: "How is chronic hypertension monitored during pregnancy?", response: "You will have more frequent prenatal visits, regular blood pressure checks (often at home), urine and blood tests, and ultrasounds to monitor fetal growth. Your provider will watch closely for signs of preeclampsia or worsening hypertension." },
  { id: 1703, category: 'pregnancy', keywords: ['fetal monitoring with chronic hypertension'], question: "How is the baby monitored if I have chronic hypertension?", response: "Serial growth ultrasounds are usually started around 28–32 weeks. Fetal well-being tests (nonstress tests or biophysical profiles) are often started at 32 weeks or earlier if there are concerns about growth or blood pressure control." },

  // Blood Pressure Treatment
  { id: 1704, category: 'pregnancy', keywords: ['when to treat high blood pressure in pregnancy'], question: "When should high blood pressure be treated during pregnancy?", response: "Severe hypertension (≥160/110) should be treated quickly. For non-severe hypertension, treatment is usually started or continued if blood pressure is consistently ≥140/90, especially if you were already on medication or have end-organ effects." },
  { id: 1705, category: 'pregnancy', keywords: ['safe blood pressure medications in pregnancy'], question: "Which blood pressure medications are safe in pregnancy?", response: "Labetalol and extended-release nifedipine are commonly used and generally considered safe. Methyldopa is an older option. ACE inhibitors, ARBs, and some other drugs are not safe and should be stopped before or early in pregnancy." },
  { id: 1706, category: 'pregnancy', keywords: ['target blood pressure in pregnancy with hypertension'], question: "What is the goal blood pressure during pregnancy if I have hypertension?", response: "Most experts aim to keep blood pressure in the 120–139/80–89 range after starting treatment. The exact target is individualized based on your situation and any end-organ effects." },

  // Delivery
  { id: 1707, category: 'pregnancy', keywords: ['when to deliver with chronic hypertension'], question: "When is delivery recommended if I have chronic hypertension?", response: "For well-controlled hypertension without complications, delivery is often planned between 37 and 39+6 weeks. Earlier delivery may be needed if preeclampsia develops or there are concerns about the baby's growth or your health." },

  // Postpartum
  { id: 1708, category: 'postpartum', keywords: ['blood pressure after birth with chronic hypertension'], question: "What happens to blood pressure after delivery if I have chronic hypertension?", response: "Blood pressure often drops right after birth then can rise again a few days later. Close monitoring (in person or at home) is important in the first weeks postpartum. Your pre-pregnancy medications can often be restarted, with attention to breastfeeding safety." },
  { id: 1709, category: 'postpartum', keywords: ['postpartum follow up for chronic hypertension'], question: "What follow-up do I need after birth if I have high blood pressure?", response: "You should have a blood pressure check within 3–10 days after delivery. Continue monitoring at home and follow up with your primary care provider or cardiologist for long-term management of hypertension." },

  // General Support
  { id: 1710, category: 'pregnancy', keywords: ['planning pregnancy with chronic hypertension'], question: "Can I have a healthy pregnancy with chronic hypertension?", response: "Yes, many people do. Good blood pressure control before and during pregnancy, close monitoring, low-dose aspirin, and a strong care team significantly improve outcomes for both you and your baby." },

  // === NEW UpToDate Treatment of Hypertension in Pregnancy & Postpartum RAG Entries (IDs 1731–1743) ===
  // Blood Pressure Measurement
  { id: 1731, category: 'pregnancy', keywords: ['how to measure blood pressure accurately in pregnancy'], question: "How should blood pressure be measured during pregnancy?", response: "Use the correct cuff size, have the patient rest for 5 minutes with feet on the floor and arm supported at heart level. Avoid caffeine or smoking for 30–60 minutes before. Confirm high readings with repeat measurements. Home monitoring is very helpful between visits." },

  // When to Treat
  { id: 1732, category: 'pregnancy', keywords: ['when to treat high blood pressure in pregnancy'], question: "When should high blood pressure be treated during pregnancy?", response: "Severe hypertension (≥160/110) should be treated promptly (within 30–60 minutes). For milder chronic hypertension, treatment is usually started at ≥140/90. Decisions for new gestational hypertension or preeclampsia depend on how high the pressure is and how far along you are." },
  { id: 1733, category: 'pregnancy', keywords: ['target blood pressure in pregnancy'], question: "What is the goal blood pressure during pregnancy if I have hypertension?", response: "Most experts aim to keep blood pressure below 140/90 after starting treatment. Very low pressures (below 120/80) are generally avoided because they can reduce blood flow to the baby." },

  // Acute Treatment of Severe Hypertension
  { id: 1734, category: 'pregnancy', keywords: ['treatment of severe hypertension in pregnancy'], question: "How is severe high blood pressure treated during pregnancy?", response: "Intravenous labetalol or hydralazine are commonly used first-line options. Oral immediate-release nifedipine can be used if IV access is not available. The goal is to lower pressure gradually and safely while monitoring the baby." },
  { id: 1735, category: 'pregnancy', keywords: ['labetalol vs hydralazine in pregnancy'], question: "Which is better for severe high blood pressure in pregnancy — labetalol or hydralazine?", response: "Both are effective and considered safe. Labetalol is often preferred because it is easier to titrate and has a good safety profile. The choice depends on your heart rate, other medical conditions, and provider preference." },

  // Maintenance Therapy
  { id: 1736, category: 'pregnancy', keywords: ['safe blood pressure medications in pregnancy'], question: "Which blood pressure medications are commonly used during pregnancy?", response: "Labetalol and extended-release nifedipine are first-line choices for most people. Methyldopa is an older but still acceptable option. ACE inhibitors, ARBs, and some other drugs are not safe and should be avoided." },
  { id: 1737, category: 'pregnancy', keywords: ['nifedipine in pregnancy'], question: "Is nifedipine safe during pregnancy?", response: "Yes, extended-release or intermediate-acting nifedipine is commonly used and considered safe. Immediate-release nifedipine is sometimes used for very high blood pressure when quick effect is needed, but extended-release is generally preferred for ongoing control." },

  // Postpartum Hypertension
  { id: 1738, category: 'postpartum', keywords: ['postpartum high blood pressure'], question: "Why does blood pressure often go up after giving birth?", response: "Blood pressure commonly rises in the first few days to a week after delivery as fluid shifts and pregnancy-related changes reverse. Close monitoring (in person or at home) is very important during this time." },
  { id: 1739, category: 'postpartum', keywords: ['managing high blood pressure after birth'], question: "How is high blood pressure managed after delivery?", response: "Medications similar to those used in pregnancy (labetalol, nifedipine) are often continued or started. Brief use of furosemide can help if there is significant fluid retention. Blood pressure should be checked frequently in the first 1–2 weeks after going home." },

  // Breastfeeding
  { id: 1740, category: 'postpartum', keywords: ['blood pressure medication while breastfeeding'], question: "Which blood pressure medications are safe while breastfeeding?", response: "Labetalol, nifedipine, and several other common medications are generally considered compatible with breastfeeding. Always confirm with your provider or pediatrician, especially if your baby is premature or has other health issues." },

  // Drugs to Avoid
  { id: 1741, category: 'pregnancy', keywords: ['blood pressure medications to avoid in pregnancy'], question: "Which blood pressure medications should be avoided during pregnancy?", response: "ACE inhibitors, ARBs, and direct renin inhibitors are generally avoided because they can harm the baby's kidneys and development. Atenolol is also often avoided due to concerns about fetal growth. Always review your medications with your provider if you are planning pregnancy or become pregnant." },

  // Long-Term Follow-Up
  { id: 1742, category: 'postpartum', keywords: ['long term follow up after pregnancy hypertension'], question: "Do I need long-term follow-up after having high blood pressure in pregnancy?", response: "Yes. People who had hypertension, preeclampsia, or gestational hypertension in pregnancy have a higher lifetime risk of cardiovascular disease and chronic hypertension. Annual blood pressure checks and attention to other risk factors (weight, cholesterol, diabetes, lifestyle) are important." },

  // General Support
  { id: 1743, category: 'pregnancy', keywords: ['living with high blood pressure in pregnancy'], question: "What can I do to help manage high blood pressure during pregnancy?", response: "Take medications as prescribed, attend all prenatal visits, monitor blood pressure at home if recommended, eat a balanced diet, stay active as advised, get adequate rest, and report symptoms like headache, vision changes, or swelling promptly. A strong partnership with your care team makes a big difference." },

  // === NEW UpToDate Dysmenorrhea RAG Entries (IDs 1744–1755) ===
  { id: 1744, category: 'menstrual', keywords: ['what is dysmenorrhea'], question: "What is dysmenorrhea?", response: "Dysmenorrhea is the medical term for painful periods. It causes crampy pain in the lower abdomen, and sometimes in the back or thighs. It usually starts just before or as your period begins and improves over 1–3 days." },
  { id: 1745, category: 'menstrual', keywords: ['what causes period cramps'], question: "What causes period cramps?", response: "During your period, the lining of the uterus makes chemicals called prostaglandins. These cause the uterus to contract, which can lead to pain, reduced blood flow, and lower oxygen levels in the uterus. Higher prostaglandin levels are linked to more intense cramps." },
  { id: 1746, category: 'menstrual', keywords: ['normal period pain vs bad cramps'], question: "How much period pain is normal?", response: "Mild to moderate cramping that improves with NSAIDs or a heating pad is common. Pain that is severe, lasts more than 2–3 days, keeps you from school or work, or doesn't improve with usual treatments may need further evaluation." },
  { id: 1747, category: 'menstrual', keywords: ['other symptoms with period pain'], question: "Can period cramps come with other symptoms?", response: "Yes. Many people also experience nausea, diarrhea, fatigue, headache, dizziness, or a flu-like feeling along with cramps. These are often related to prostaglandins and usually improve as the period progresses." },

  // Treatment
  { id: 1748, category: 'menstrual', keywords: ['best treatment for period cramps'], question: "What is the best treatment for period cramps?", response: "Nonsteroidal anti-inflammatory drugs (NSAIDs) like ibuprofen or naproxen are usually the most effective first treatment. Starting them as soon as bleeding or cramps begin and taking them on a regular schedule for 2–3 days works best for most people." },
  { id: 1749, category: 'menstrual', keywords: ['hormonal birth control for cramps'], question: "Can birth control help with period pain?", response: "Yes. Hormonal birth control (pills, patch, ring, hormonal IUD, or implant) often significantly reduces or eliminates period cramps by thinning the uterine lining and lowering prostaglandin levels. Many people notice improvement within a few months." },
  { id: 1750, category: 'menstrual', keywords: ['continuous birth control for period pain'], question: "What is continuous dosing of birth control?", response: "Continuous dosing means taking hormonal birth control without the usual placebo (hormone-free) days so you have fewer or no periods. This can greatly reduce or stop period pain for many people. Spotting or light bleeding is common at first but usually decreases over time." },
  { id: 1751, category: 'menstrual', keywords: ['heat for period cramps'], question: "Does heat help with period cramps?", response: "Yes. Applying heat to your lower abdomen with a heating pad, hot water bottle, or self-heating patch can be as effective as taking an NSAID for many people. You can use heat as often as needed." },
  { id: 1752, category: 'menstrual', keywords: ['exercise for period pain'], question: "Does exercise help with period cramps?", response: "Regular physical activity, even gentle forms like walking or yoga, can reduce period pain and improve mood for many people. It's a helpful addition to other treatments." },

  // When Treatment Isn't Enough
  { id: 1753, category: 'menstrual', keywords: ['what if period pain does not improve with NSAIDs or birth control'], question: "What if my period pain doesn't get better with usual treatments?", response: "If NSAIDs and hormonal birth control don't provide enough relief after 2–3 months, talk to your provider. They may recommend further evaluation (such as an ultrasound or laparoscopy) to look for conditions like endometriosis, or other medication options." },
  { id: 1754, category: 'menstrual', keywords: ['when to see a doctor for period pain'], question: "When should I see a doctor about period pain?", response: "See a provider if your pain is severe, keeps you from daily activities, doesn't improve with NSAIDs or birth control, started after age 25, or is getting worse over time. These can be signs of an underlying condition that needs evaluation." },

  // General Support
  { id: 1755, category: 'menstrual', keywords: ['primary vs secondary dysmenorrhea'], question: "What is the difference between primary and secondary dysmenorrhea?", response: "Primary dysmenorrhea is painful periods without an identifiable underlying cause (most common). Secondary dysmenorrhea is caused by another condition, such as endometriosis, fibroids, or adenomyosis. Your provider can help determine which type you have." },

  // === NEW UpToDate Normal Menstrual Cycle RAG Entries (IDs 1766–1779) ===
  // General Overview
  { id: 1766, category: 'menstrual', keywords: ['what is a normal menstrual cycle'], question: "What is considered a normal menstrual cycle?", response: "A normal cycle usually occurs every 24 to 38 days, lasts up to 8 days of bleeding, and has fairly consistent timing from month to month. The amount of bleeding should not significantly interfere with your daily life. There is natural variation, especially in teens and people approaching menopause." },
  { id: 1767, category: 'menstrual', keywords: ['how long is a normal period'], question: "How long should a period last?", response: "Normal menstrual bleeding typically lasts up to 8 days. Most people bleed for 4 to 6 days. Bleeding that lasts longer than 8 days or is very heavy may need evaluation." },
  { id: 1768, category: 'menstrual', keywords: ['what hormones control the menstrual cycle'], question: "Which hormones control the menstrual cycle?", response: "The main hormones are FSH and LH (from the pituitary), and estradiol and progesterone (from the ovaries). These hormones rise and fall in a coordinated pattern to control follicle growth, ovulation, and the uterine lining." },

  // Phases
  { id: 1769, category: 'menstrual', keywords: ['follicular phase of menstrual cycle'], question: "What happens during the follicular phase?", response: "This phase starts on day 1 of your period and ends at ovulation. FSH stimulates several follicles to grow in the ovary. One becomes dominant and produces rising levels of estrogen, which thickens the uterine lining in preparation for a possible pregnancy." },
  { id: 1770, category: 'menstrual', keywords: ['when does ovulation happen'], question: "When does ovulation usually occur?", response: "Ovulation typically happens around day 14 in a 28-day cycle, but it can vary. It is triggered by a surge in LH (luteinizing hormone). The mature egg is released from the ovary and can be fertilized for about 12–24 hours." },
  { id: 1771, category: 'menstrual', keywords: ['luteal phase of menstrual cycle'], question: "What happens during the luteal phase?", response: "After ovulation, the empty follicle becomes the corpus luteum and produces progesterone. This hormone prepares the uterine lining for possible implantation. If pregnancy doesn't occur, progesterone and estrogen levels drop, triggering your period about 14 days later." },

  // Hormonal Changes
  { id: 1772, category: 'menstrual', keywords: ['estrogen and progesterone during cycle'], question: "How do estrogen and progesterone change during the menstrual cycle?", response: "Estrogen rises during the follicular phase and peaks just before ovulation. After ovulation, progesterone becomes dominant in the luteal phase. Both hormones drop at the end of the cycle if pregnancy doesn't occur, which starts your period." },
  { id: 1773, category: 'menstrual', keywords: ['what is the LH surge'], question: "What is the LH surge?", response: "The LH surge is a sharp rise in luteinizing hormone that triggers ovulation. It usually happens about 24–36 hours before the egg is released. This is the key event that shifts the cycle from the follicular to the luteal phase." },

  // Practical Questions
  { id: 1774, category: 'menstrual', keywords: ['why do cycles vary in length'], question: "Why does my cycle length change from month to month?", response: "Cycle length can vary due to stress, illness, weight changes, sleep, or hormonal fluctuations. Variation of up to 7–9 days is usually normal, especially in younger people or those nearing perimenopause. Very irregular cycles may need evaluation." },
  { id: 1775, category: 'menstrual', keywords: ['how do I know if I ovulated'], question: "How can I tell if I ovulated?", response: "Signs of ovulation can include a slight rise in basal body temperature, changes in cervical mucus (becoming clear and stretchy), mittelschmerz (one-sided pain), or a positive ovulation predictor kit (detects the LH surge). Ultrasound is the most accurate method but is not usually needed." },
  { id: 1776, category: 'menstrual', keywords: ['what is a normal amount of period bleeding'], question: "How much bleeding is considered normal during a period?", response: "Normal bleeding is whatever doesn't significantly disrupt your life. For research purposes, it's defined as less than 80 mL of blood loss per cycle. Soaking through a pad or tampon every hour, passing large clots, or bleeding that lasts more than 8 days is considered heavy and should be evaluated." },

  // Ultrasound & Physiology
  { id: 1777, category: 'menstrual', keywords: ['what does the uterus look like on ultrasound during cycle'], question: "How does the uterus change on ultrasound during the menstrual cycle?", response: "During the follicular phase the lining is thin. It thickens and develops a 'triple stripe' pattern as estrogen rises. After ovulation, the lining becomes brighter and more uniform due to progesterone. These changes can be seen on transvaginal ultrasound." },
  { id: 1778, category: 'menstrual', keywords: ['what is the corpus luteum'], question: "What is the corpus luteum?", response: "After ovulation, the empty follicle transforms into the corpus luteum ('yellow body'). It produces progesterone to support a potential pregnancy. If pregnancy doesn't occur, it shrinks and hormone levels drop, leading to your period." },

  // When to Seek Care
  { id: 1779, category: 'menstrual', keywords: ['when is menstrual bleeding abnormal'], question: "When should I be concerned about my menstrual bleeding?", response: "See a provider if your periods are very irregular, extremely heavy, last longer than 8 days, occur more often than every 24 days or less often than every 38 days, or if you have severe pain, bleeding between periods, or bleeding after sex. These can signal an underlying issue." },

  // === NEW UpToDate Abnormal Uterine Bleeding in Adolescents RAG Entries (IDs 1780–1791) ===
  // General Overview
  { id: 1780, category: 'menstrual', keywords: ['normal period length in teens'], question: "What is a normal menstrual cycle for a teenager?", response: "In the first few years after starting periods, cycles are often longer and more irregular than in adults. Most teens have cycles every 21 to 45 days with bleeding lasting 2 to 7 days. It can take 1–4 years for cycles to become more regular and predictable." },
  { id: 1781, category: 'menstrual', keywords: ['what is abnormal uterine bleeding in teens'], question: "What counts as abnormal uterine bleeding in adolescents?", response: "Abnormal bleeding includes periods that are too frequent (less than every 21 days), too infrequent (more than every 45 days), very heavy, last longer than 7–8 days, or occur at unpredictable times. It also includes bleeding between periods or missing periods for long stretches after they've started." },
  { id: 1782, category: 'menstrual', keywords: ['why are periods irregular in the first years after menarche'], question: "Why are periods often irregular when I first start getting them?", response: "In the first 1–2 years after menarche, many cycles are anovulatory because the brain-ovary connection (HPO axis) is still maturing. Without regular ovulation and progesterone, the uterine lining can build up unevenly and shed unpredictably, leading to irregular or heavy bleeding." },

  // Triage & Initial Steps
  { id: 1783, category: 'menstrual', keywords: ['when to go to ER for heavy period bleeding'], question: "When should a teen with heavy bleeding go to the emergency room?", response: "Go to the ER if you feel dizzy, faint, very weak, have chest pain, or soak through a pad or tampon every hour for several hours. These can be signs of significant blood loss. Also seek care urgently if you think you might be pregnant and are bleeding." },
  { id: 1784, category: 'menstrual', keywords: ['pregnancy test for abnormal bleeding'], question: "Why do I need a pregnancy test if I have abnormal bleeding?", response: "Pregnancy (including miscarriage or ectopic pregnancy) is a common and potentially serious cause of bleeding in teens. A urine pregnancy test is quick, important, and should be done even if you haven't had sex or think it's impossible." },

  // Bleeding Patterns & Evaluation
  { id: 1785, category: 'menstrual', keywords: ['heavy periods and bleeding disorders in teens'], question: "When should heavy periods make me think of a bleeding disorder?", response: "Consider a bleeding disorder (like von Willebrand disease) if heavy bleeding started with your very first period, you've needed a blood transfusion, you have anemia that doesn't improve, or you also have easy bruising, frequent nosebleeds, or bleeding gums. Tell your provider — specific blood tests can check for this." },
  { id: 1786, category: 'menstrual', keywords: ['when to check for PCOS with irregular periods'], question: "When should irregular periods be checked for PCOS?", response: "If you have irregular periods plus signs like excess hair growth, severe acne, or weight gain, your provider may check hormone levels (testosterone, 17-hydroxyprogesterone) and possibly do an ultrasound. PCOS is a common cause of irregular bleeding in teens." },
  { id: 1787, category: 'menstrual', keywords: ['thyroid and abnormal periods'], question: "Can thyroid problems cause abnormal bleeding?", response: "Yes. Both an overactive and underactive thyroid can cause irregular or heavy periods. A simple blood test for TSH is often part of the workup for abnormal uterine bleeding." },

  // Practical Guidance
  { id: 1788, category: 'menstrual', keywords: ['what tests are done for abnormal bleeding in teens'], question: "What tests might I need for abnormal uterine bleeding?", response: "Common tests include a pregnancy test, complete blood count (for anemia), TSH (thyroid), and sometimes prolactin, hormone levels, or tests for bleeding disorders. An ultrasound may be done to look at the uterus and ovaries. Not everyone needs every test — it depends on your symptoms and pattern." },
  { id: 1789, category: 'menstrual', keywords: ['confidentiality when talking about periods and sex'], question: "Can I talk to my doctor alone about my periods or sex?", response: "Yes. Most providers will offer time alone with you during visits, especially when discussing periods, sexual activity, contraception, or any concerns. This is confidential (with a few safety exceptions) and helps you get the best care." },
  { id: 1790, category: 'menstrual', keywords: ['when irregular periods need more evaluation'], question: "When do irregular periods need more than just watching and waiting?", response: "If irregular bleeding continues beyond 2 years after menarche, is very heavy, causes anemia, or comes with other symptoms (severe pain, acne, excess hair, fatigue), further evaluation is needed. Don't just assume it will 'sort itself out' if it's affecting your life." },

  // Supportive
  { id: 1791, category: 'menstrual', keywords: ['reassurance about irregular periods in teens'], question: "Is it normal to have irregular periods as a teenager?", response: "Yes, it's very common in the first few years. Many teens have longer or unpredictable cycles while their hormones mature. However, if the bleeding is very heavy, painful, or worrying you, it's still worth talking to a provider so you can get support and rule out other causes." },

  // === NEW UpToDate Ovulation Detection & Cycle Assessment RAG Entries (IDs 1792–1804) ===
  // Ovulation Detection Methods
  { id: 1792, category: 'menstrual', keywords: ['how to tell if I ovulated'], question: "How can I tell if I'm ovulating?", response: "You can track ovulation with several methods: charting your cycle length, checking basal body temperature daily, using ovulation predictor kits that detect the LH surge, or having a blood test for progesterone about a week before your period. Ultrasound is the most accurate but usually done in a clinic." },
  { id: 1793, category: 'menstrual', keywords: ['basal body temperature for ovulation'], question: "How does basal body temperature show ovulation?", response: "After ovulation, progesterone causes a small but noticeable rise in your resting body temperature (about 0.5°F). Tracking your temperature every morning before getting out of bed can confirm that ovulation has occurred, though it won't predict it in advance." },
  { id: 1794, category: 'menstrual', keywords: ['progesterone test for ovulation'], question: "What does a progesterone blood test tell me about ovulation?", response: "A mid-luteal progesterone level (usually drawn 7 days before your expected period or around day 21 in a 28-day cycle) above 6 ng/mL strongly suggests you ovulated. Levels between 6–25 ng/mL are typical in a normal cycle." },
  { id: 1795, category: 'menstrual', keywords: ['ovulation predictor kits LH surge'], question: "How do ovulation predictor kits work?", response: "These urine tests detect the luteinizing hormone (LH) surge that happens about 24–36 hours before ovulation. Start testing a few days before you expect ovulation. A positive result means you're likely to ovulate soon — this is one of the best ways to time intercourse if you're trying to conceive." },
  { id: 1796, category: 'menstrual', keywords: ['when is the fertile window'], question: "When is the fertile window in my cycle?", response: "The fertile window is roughly the 5–6 days leading up to and including ovulation. The highest chance of conception is usually 1–2 days before ovulation. Tracking ovulation helps you identify this window more accurately than calendar methods alone." },
  { id: 1797, category: 'menstrual', keywords: ['cervical mucus changes ovulation'], question: "How does cervical mucus change around ovulation?", response: "As estrogen rises before ovulation, cervical mucus becomes clearer, stretchier, and more slippery (like raw egg whites). This fertile mucus helps sperm travel. After ovulation, it usually becomes thicker and stickier again under the influence of progesterone." },

  // Ultrasound & Advanced
  { id: 1798, category: 'menstrual', keywords: ['ultrasound to check ovulation'], question: "Can ultrasound show if I ovulated?", response: "Yes. Serial ultrasounds can track follicle growth and confirm ovulation by seeing the dominant follicle collapse and transform into a corpus luteum. It's very accurate but usually done in a fertility clinic setting rather than for routine tracking." },

  // Ovarian Reserve
  { id: 1799, category: 'menstrual', keywords: ['ovarian reserve testing'], question: "What is ovarian reserve testing?", response: "Ovarian reserve testing estimates how many eggs you have left. Common tests include early-cycle FSH + estradiol, anti-Müllerian hormone (AMH), and antral follicle count on ultrasound. These are especially useful if you're over 35 or having trouble conceiving." },
  { id: 1800, category: 'menstrual', keywords: ['FSH test for ovarian reserve'], question: "What does an FSH blood test show?", response: "FSH measured on day 2–4 of your cycle can give information about ovarian reserve. Higher levels may suggest fewer eggs remaining. It's often paired with estradiol for better interpretation." },

  // Practical Use Cases
  { id: 1801, category: 'menstrual', keywords: ['why track ovulation with irregular periods'], question: "Should I track ovulation if my periods are irregular?", response: "Yes. Irregular cycles often mean irregular or absent ovulation. Tracking can help identify whether you're ovulating, when it's happening, and whether anovulation might be contributing to heavy bleeding, long cycles, or difficulty getting pregnant." },
  { id: 1802, category: 'menstrual', keywords: ['best way to track ovulation at home'], question: "What's the easiest and most reliable way to track ovulation at home?", response: "Many people start with ovulation predictor kits (LH strips) combined with cycle charting and cervical mucus observation. Adding basal body temperature gives confirmation after ovulation. Newer apps and wearable sensors can combine multiple signals for better predictions." },
  { id: 1803, category: 'menstrual', keywords: ['does stress affect ovulation'], question: "Can stress stop me from ovulating?", response: "Yes. Significant physical or emotional stress, large weight changes, intense exercise, or illness can disrupt the hormonal signals needed for ovulation, leading to delayed or missed periods. Tracking can help you see these patterns." },

  // When to Seek Help
  { id: 1804, category: 'menstrual', keywords: ['when to see doctor about ovulation'], question: "When should I see a doctor about ovulation or irregular cycles?", response: "Consider seeing a provider if your cycles are very irregular, you're not ovulating, you've been trying to conceive without success, or you have other symptoms like heavy bleeding, severe pain, or signs of hormonal imbalance. Simple tests can often clarify what's happening." },

  // === NEW UpToDate Abnormal Uterine Bleeding Evaluation RAG Entries (IDs 1811–1825) ===
  // Definitions
  { id: 1811, category: 'menstrual', keywords: ['what is abnormal uterine bleeding'], question: "What is considered abnormal uterine bleeding?", response: "Abnormal uterine bleeding includes periods that are too frequent (less than every 24 days), too infrequent (more than every 38 days), irregular in timing, last longer than 8 days, or are heavier than what interferes with your daily life. Bleeding between periods or very light periods can also be abnormal." },
  { id: 1812, category: 'menstrual', keywords: ['heavy menstrual bleeding definition'], question: "What counts as heavy menstrual bleeding?", response: "Heavy menstrual bleeding is when the amount of bleeding interferes with your physical, emotional, social, or material quality of life. This is a patient-centered definition. Passing large clots, soaking through protection hourly, or bleeding that lasts more than 8 days are common signs." },
  { id: 1813, category: 'menstrual', keywords: ['intermenstrual bleeding'], question: "What is intermenstrual bleeding?", response: "Intermenstrual bleeding is bleeding or spotting that occurs between regular menstrual periods. It can be light spotting or heavier flow. Common causes include polyps, hormonal contraception, infection, or (less commonly) more serious conditions." },

  // Initial Evaluation
  { id: 1814, category: 'menstrual', keywords: ['first steps for abnormal bleeding'], question: "What are the first steps when I have abnormal bleeding?", response: "Your provider will ask about your bleeding pattern, medical history, medications, and sexual history. They will do a pregnancy test, physical exam, and often blood work. A pelvic ultrasound is frequently needed to look for structural causes like fibroids or polyps." },
  { id: 1815, category: 'menstrual', keywords: ['pregnancy test for bleeding'], question: "Why do I need a pregnancy test if I have abnormal bleeding?", response: "Pregnancy (including early miscarriage or ectopic pregnancy) is a common cause of bleeding. A pregnancy test is quick, important, and should be done even if you think pregnancy is impossible or you're using contraception." },

  // By Bleeding Pattern
  { id: 1816, category: 'menstrual', keywords: ['evaluation of heavy periods'], question: "What tests are done for heavy menstrual bleeding?", response: "Common tests include a complete blood count (for anemia), ferritin (iron stores), thyroid function (TSH), and often a pelvic ultrasound. If you have risk factors, endometrial sampling may be recommended. Testing for bleeding disorders is considered in certain cases, especially if heavy bleeding started at menarche." },
  { id: 1817, category: 'menstrual', keywords: ['evaluation of irregular bleeding'], question: "What causes irregular bleeding and how is it evaluated?", response: "Irregular bleeding is often due to ovulatory dysfunction (hormonal imbalance). Evaluation may include thyroid and prolactin levels, androgens if there are signs of PCOS, and endometrial sampling if the irregular bleeding has lasted 6 months or more, especially with risk factors like obesity." },
  { id: 1818, category: 'menstrual', keywords: ['bleeding between periods causes'], question: "What causes bleeding between periods?", response: "Common causes include hormonal contraception, endometrial or cervical polyps, cervicitis or endometritis, cesarean scar defects, or (less commonly) more serious conditions. An exam and ultrasound are usually the first steps." },

  // Endometrial Sampling
  { id: 1819, category: 'menstrual', keywords: ['when to do endometrial biopsy'], question: "When is an endometrial biopsy needed for abnormal bleeding?", response: "Endometrial sampling is recommended for bleeding that is persistent, heavy, or irregular in people over 45, or in younger people with risk factors like obesity, chronic irregular cycles, failed medical treatment, or tamoxifen use. It helps rule out endometrial hyperplasia or cancer." },
  { id: 1820, category: 'menstrual', keywords: ['endometrial cancer risk with bleeding'], question: "When should I worry about endometrial cancer with abnormal bleeding?", response: "Risk increases with age (especially over 45), obesity, long-term unopposed estrogen exposure, tamoxifen use, or Lynch/Cowden syndrome. Persistent or new bleeding in these situations should be evaluated promptly with endometrial sampling." },

  // Imaging
  { id: 1821, category: 'menstrual', keywords: ['ultrasound for abnormal bleeding'], question: "Why is ultrasound used for abnormal bleeding?", response: "Pelvic ultrasound is the first-line imaging test. It can detect fibroids, adenomyosis, polyps, ovarian issues, and other structural causes. Saline infusion sonography or hysteroscopy may be added if intracavitary lesions are suspected." },
  { id: 1822, category: 'menstrual', keywords: ['saline sonohysterography vs hysteroscopy'], question: "What is the difference between saline sonohysterography and hysteroscopy?", response: "Both evaluate the inside of the uterus. Saline sonohysterography uses ultrasound with fluid in the uterus and is good for seeing the depth of fibroids. Hysteroscopy uses a small camera for direct visualization and can allow immediate biopsy or removal of polyps." },

  // Special Situations
  { id: 1823, category: 'menstrual', keywords: ['bleeding disorders and heavy periods'], question: "When should a bleeding disorder be considered with heavy periods?", response: "Consider a bleeding disorder (such as von Willebrand disease) if heavy bleeding started with your first period, you have anemia that doesn't respond well to treatment, you needed transfusion, or you have easy bruising, nosebleeds, or bleeding gums. Specific blood tests can evaluate this." },
  { id: 1824, category: 'menstrual', keywords: ['contraception causing bleeding'], question: "Can my birth control cause abnormal bleeding?", response: "Yes. Many hormonal contraceptives (pills, patch, ring, implant, hormonal IUD) can cause unscheduled bleeding or spotting, especially in the first few months. The copper IUD often increases bleeding. This is usually not dangerous but should be discussed with your provider." },

  // Supportive
  { id: 1825, category: 'menstrual', keywords: ['when to see a doctor for bleeding'], question: "When should I see a doctor for abnormal bleeding?", response: "See a provider for bleeding that is very heavy, lasts longer than 8 days, occurs between periods, is irregular, or is new for you — especially if you're over 45, have risk factors for endometrial issues, feel dizzy/weak, or have severe pain. Early evaluation helps identify treatable causes." },

  // === NEW UpToDate Menstrual Suppression RAG Entries (IDs 1826–1837) ===
  { id: 1826, category: 'menstrual', keywords: ['is it safe to stop periods with birth control'], question: "Is it safe to use birth control to stop or reduce periods?", response: "Yes. Monthly bleeding is not medically necessary. Using hormonal contraception to reduce or eliminate periods is safe for most people and has the same risks as regular cyclic use. Many people prefer fewer or no periods for medical or lifestyle reasons." },
  { id: 1827, category: 'menstrual', keywords: ['who benefits from menstrual suppression'], question: "Who might benefit from stopping or reducing periods?", response: "People with heavy or painful periods, endometriosis, adenomyosis, fibroids, bleeding disorders, severe anemia, menstrual migraines, PMDD, or those who find periods inconvenient (athletes, travel, school, disability, or gender dysphoria). It can also help with hygiene challenges or medical treatments." },
  { id: 1828, category: 'contraception', keywords: ['best methods for stopping periods'], question: "Which birth control methods are best for stopping periods completely?", response: "The most effective options for achieving amenorrhea include the levonorgestrel 52 mg IUD, depot medroxyprogesterone acetate (DMPA) shots, and continuous or extended-use combined estrogen-progestin pills or rings. The LNG 52 mg IUD and DMPA often lead to no periods over time, though it can take months." },
  { id: 1829, category: 'contraception', keywords: ['continuous vs extended birth control pills'], question: "What is the difference between continuous and extended birth control pill use?", response: "Extended use means taking active pills for 3–6 months or more before taking a short break for a withdrawal bleed. Continuous use means taking active pills every day with no breaks. Both reduce or eliminate scheduled periods; unscheduled spotting is common at first but usually improves." },
  { id: 1830, category: 'contraception', keywords: ['DMPA shot for stopping periods'], question: "How well does the Depo-Provera shot stop periods?", response: "About 50–75% of people using DMPA for one year develop amenorrhea, and this increases with longer use. It is one of the most effective methods for stopping periods but can cause irregular bleeding at first. It is given as an injection every 3 months." },
  { id: 1831, category: 'contraception', keywords: ['LNG IUD for heavy periods or amenorrhea'], question: "How well does the hormonal IUD stop or reduce periods?", response: "The levonorgestrel 52 mg IUD significantly reduces bleeding and leads to amenorrhea in about 20% of users by 1 year and 30–50% by 2 years. It is an excellent option for heavy periods or when you want long-acting contraception with reduced or no periods." },
  { id: 1832, category: 'contraception', keywords: ['norethindrone acetate for menstrual suppression'], question: "Can norethindrone acetate be used to stop periods?", response: "Yes. Continuous oral norethindrone acetate (often 5 mg daily) can reduce heavy bleeding and often leads to amenorrhea. It is a progestin-only option useful when estrogen is not wanted or contraindicated. It is not approved as a contraceptive at these doses, so backup contraception is needed if pregnancy prevention is required." },
  { id: 1833, category: 'contraception', keywords: ['managing breakthrough bleeding on continuous birth control'], question: "What should I do about spotting or bleeding on continuous birth control?", response: "Unscheduled bleeding is common in the first few months. One helpful approach is to take a short 3-day hormone-free break (if you've been on active hormones for at least 21 days), then resume. Over time, breakthrough bleeding usually becomes less frequent and stops." },
  { id: 1834, category: 'contraception', keywords: ['menstrual suppression for bleeding disorders'], question: "Can menstrual suppression help with bleeding disorders?", response: "Yes. Methods like the LNG 52 mg IUD, DMPA, or continuous progestins can significantly reduce or stop menstrual bleeding in people with von Willebrand disease, thrombocytopenia, or other bleeding disorders. This can help prevent anemia and improve quality of life." },
  { id: 1835, category: 'contraception', keywords: ['menstrual suppression for transgender or gender diverse people'], question: "Is menstrual suppression helpful for gender dysphoria?", response: "Yes. Many transgender and gender-diverse people assigned female at birth choose menstrual suppression to reduce gender dysphoria related to periods. Common options include combined pills, norethindrone, DMPA, or the LNG IUD. Testosterone may also reduce or stop periods but does not provide contraception." },
  { id: 1836, category: 'contraception', keywords: ['which method is best for amenorrhea'], question: "Which method is most likely to stop periods completely?", response: "DMPA shots and the LNG 52 mg IUD tend to have the highest rates of amenorrhea over time. Continuous combined pills or rings are also very effective. The best choice depends on your preferences for route, speed of effect, need for contraception, and side effect tolerance." },
  { id: 1837, category: 'contraception', keywords: ['does stopping periods affect future fertility'], question: "Does using birth control to stop periods affect future fertility?", response: "No. After stopping most hormonal methods, fertility returns to normal. There may be a short delay with some methods (especially DMPA), but long-term fertility is not reduced. Menstrual suppression itself does not cause infertility." },

  // === NEW UpToDate Uterine Cancer RAG Entries (IDs 1846–1855) ===
  { id: 1846, category: 'cancer', keywords: ['what is uterine cancer'], question: "What is uterine cancer?", response: "Uterine cancer happens when cells in the uterus (womb) grow out of control. Most uterine cancers start in the thin inner lining of the uterus (the endometrium), so it is often called endometrial cancer. It is much more common after menopause but can occur at any age." },
  { id: 1847, category: 'cancer', keywords: ['symptoms of uterine cancer'], question: "What are the symptoms of uterine cancer?", response: "The most common symptom is abnormal vaginal bleeding. This includes bleeding between periods, very heavy periods, or any vaginal bleeding after menopause. Other possible symptoms include pelvic pain or a persistent cough if the cancer has spread. These symptoms can also be caused by non-cancer conditions, so it's important to get checked." },
  { id: 1848, category: 'cancer', keywords: ['postmenopausal bleeding uterine cancer'], question: "Is bleeding after menopause a sign of uterine cancer?", response: "Any vaginal bleeding after menopause should be evaluated promptly. While not all postmenopausal bleeding is cancer, it is the most common symptom of uterine (endometrial) cancer. Your provider will usually recommend an ultrasound and/or an endometrial biopsy to investigate." },
  { id: 1849, category: 'cancer', keywords: ['how is uterine cancer diagnosed'], question: "How is uterine cancer diagnosed?", response: "Diagnosis usually starts with a pelvic ultrasound and an endometrial biopsy (a small sample of the uterine lining is taken and examined under a microscope). Sometimes a hysteroscopy or D&C is needed. Imaging like CT or MRI may be used later to check for spread." },
  { id: 1850, category: 'cancer', keywords: ['uterine cancer treatment'], question: "How is uterine cancer treated?", response: "The main treatment is surgery to remove the uterus, ovaries, and fallopian tubes (hysterectomy with salpingo-oophorectomy). Depending on the stage and type, some people also need radiation, chemotherapy, or hormone therapy (progestins). Treatment is personalized based on how far the cancer has spread and your overall health." },
  { id: 1851, category: 'cancer', keywords: ['fertility after uterine cancer'], question: "Can I still have children after uterine cancer treatment?", response: "Many treatments for uterine cancer (especially surgery) affect fertility. If you have not gone through menopause and want to preserve fertility, talk to your doctor before treatment. In select early cases, hormone therapy (progestins) may be used first to delay surgery, but this is not suitable for everyone." },
  { id: 1852, category: 'cancer', keywords: ['uterine cancer staging'], question: "What does staging mean for uterine cancer?", response: "Staging tells doctors how far the cancer has spread (within the uterus, to nearby tissues, or to distant organs). It is one of the most important factors in deciding treatment and prognosis. Your surgical findings and pathology results determine the final stage." },
  { id: 1853, category: 'cancer', keywords: ['follow up after uterine cancer'], question: "What happens after uterine cancer treatment?", response: "You will have regular follow-up visits to check for recurrence. These include exams, discussions about symptoms, and sometimes blood tests or imaging. Report any new bleeding, pelvic pain, or persistent cough to your doctor right away." },
  { id: 1854, category: 'cancer', keywords: ['questions to ask about uterine cancer treatment'], question: "What questions should I ask my doctor about uterine cancer treatment?", response: "Good questions include: What stage is my cancer? What are the benefits and risks of the recommended treatment? Are there fertility-sparing options? What happens if I choose not to have a certain treatment? How will treatment affect my quality of life and long-term health?" },
  { id: 1855, category: 'cancer', keywords: ['is uterine cancer curable'], question: "Is uterine cancer curable?", response: "Many uterine cancers, especially when found early, are highly treatable and often curable with surgery. Outcomes are best when the cancer is confined to the uterus. Your specific prognosis depends on the type, stage, grade, and your overall health." },

  // === NEW UpToDate FSH Test RAG Entries (IDs 1861–1870) ===
  { id: 1861, category: 'testing', keywords: ['what is an FSH test'], question: "What is an FSH test?", response: "An FSH test measures the level of follicle-stimulating hormone in your blood. FSH is made by the pituitary gland and plays a key role in puberty, the menstrual cycle, and fertility. In females, it helps stimulate follicle (egg) development in the ovaries." },
  { id: 1862, category: 'testing', keywords: ['why get an FSH test'], question: "Why would I need an FSH blood test?", response: "Doctors order an FSH test to investigate irregular or missed periods, early or delayed puberty, infertility, or to prepare for IVF. It can also help evaluate other hormone-related symptoms. In males, it helps assess sperm production." },
  { id: 1863, category: 'testing', keywords: ['FSH test for irregular periods'], question: "Can an FSH test help explain irregular periods?", response: "Yes. FSH levels can give clues about whether your ovaries are functioning normally. High levels may suggest diminished ovarian reserve or menopause transition, while low levels can point to issues with the pituitary or hypothalamus." },
  { id: 1864, category: 'testing', keywords: ['FSH test timing menstrual cycle'], question: "When should an FSH test be done during my cycle?", response: "If you still have periods, the test is usually done early in your cycle (typically day 2–4). If you're not having periods, it can be done on any day. Your doctor will tell you the best timing for your situation." },
  { id: 1865, category: 'testing', keywords: ['FSH test for fertility'], question: "How does an FSH test relate to fertility?", response: "FSH helps assess ovarian function. Higher-than-expected levels (especially on day 2–4) can indicate reduced ovarian reserve, which may affect fertility. It is one of several tests used when evaluating difficulty getting pregnant or before IVF." },
  { id: 1866, category: 'testing', keywords: ['what do high FSH levels mean'], question: "What does a high FSH level mean?", response: "High FSH can suggest that the ovaries are not responding well to signals from the brain (diminished ovarian reserve). In younger people it may indicate primary ovarian insufficiency. Your doctor will interpret the result in the context of your age, symptoms, and other tests." },
  { id: 1867, category: 'testing', keywords: ['what do low FSH levels mean'], question: "What does a low FSH level mean?", response: "Low FSH may indicate a problem with the pituitary gland or hypothalamus, or it can occur in certain conditions like hypothalamic amenorrhea (often related to stress, weight loss, or over-exercise). Further testing is usually needed." },
  { id: 1868, category: 'testing', keywords: ['FSH test blood draw'], question: "What happens during an FSH blood test?", response: "A small amount of blood is drawn from a vein in your arm. It only takes a few minutes. You may feel a quick pinch. Wear a short-sleeve shirt if possible, and let the person know if you have a preferred arm, latex allergy, or take blood thinners." },
  { id: 1869, category: 'testing', keywords: ['FSH test results'], question: "How long do FSH test results take and what do they mean?", response: "Results are usually available within a few days. Your doctor or nurse will explain what your levels mean in the context of your symptoms and other tests. Abnormal results often lead to additional evaluation rather than a final diagnosis on their own." },
  { id: 1870, category: 'testing', keywords: ['FSH test and IVF'], question: "Why is FSH tested before IVF?", response: "FSH (along with other tests like AMH and antral follicle count) helps assess ovarian reserve and predict how well your ovaries may respond to stimulation medications during IVF. It guides treatment planning and dosing." },

  // === NEW UpToDate Estrogen Blood Test RAG Entries (IDs 1873–1881) ===
  { id: 1873, category: 'testing', keywords: ['what is an estrogen blood test'], question: "What is an estrogen blood test?", response: "An estrogen blood test measures the level of estrogen in your blood. Estrogen is a key hormone made mostly by the ovaries. It plays important roles in puberty, menstrual cycles, fertility, pregnancy, and also supports bone and heart health. There are different types of estrogen, and normal levels vary by age, cycle phase, and menopausal status." },
  { id: 1874, category: 'testing', keywords: ['why get an estrogen test'], question: "Why would my doctor order an estrogen blood test?", response: "Doctors commonly order it to evaluate symptoms of menopause in people under 45, investigate irregular periods or infertility, monitor hormone levels during fertility treatments (like ovulation induction or IVF), or assess early or delayed puberty in children." },
  { id: 1875, category: 'testing', keywords: ['estrogen test for menopause'], question: "Can an estrogen test diagnose menopause?", response: "It can help. If you're under 45 and having symptoms like hot flashes, night sweats, or changes in your periods, low estrogen levels (along with high FSH) can support a diagnosis of early menopause or primary ovarian insufficiency. However, diagnosis usually requires considering symptoms + multiple hormone tests over time." },
  { id: 1876, category: 'testing', keywords: ['estrogen test and fertility'], question: "How does an estrogen test relate to fertility?", response: "Estrogen levels help assess ovarian function and egg quality. In fertility evaluations or during IVF, doctors track estrogen to see how follicles are growing in response to medications. Abnormal levels can point to issues with ovulation or ovarian reserve." },
  { id: 1877, category: 'testing', keywords: ['estrogen test with FSH'], question: "Why is estrogen often tested with FSH?", response: "FSH and estrogen work together. High FSH with low estrogen often indicates that the ovaries are not responding well (diminished ovarian reserve or menopause transition). Testing both gives a clearer picture than either test alone." },
  { id: 1878, category: 'testing', keywords: ['estrogen levels during menstrual cycle'], question: "How do estrogen levels change during the menstrual cycle?", response: "Estrogen rises during the follicular phase, peaks just before ovulation, drops briefly, then rises again in the luteal phase before falling if pregnancy doesn't occur. This is why timing of the test matters — your doctor will usually specify when in your cycle to test." },
  { id: 1879, category: 'testing', keywords: ['estrogen test in teens or children'], question: "Why would a child or teen need an estrogen blood test?", response: "It can help evaluate early puberty (before expected age) or delayed puberty. Estrogen levels that are higher or lower than expected for age can signal hormonal imbalances that need further investigation." },
  { id: 1880, category: 'testing', keywords: ['what do estrogen test results mean'], question: "What do high or low estrogen levels mean?", response: "Low estrogen can be seen in menopause, primary ovarian insufficiency, hypothalamic amenorrhea, or certain medical conditions. High estrogen can occur with ovarian cysts, tumors, obesity, or during fertility treatments. Your doctor will interpret results alongside your symptoms, age, cycle timing, and other tests." },
  { id: 1881, category: 'testing', keywords: ['preparing for estrogen blood test'], question: "Do I need to prepare for an estrogen blood test?", response: "Usually no special preparation is needed beyond timing (if you still have periods, it's often done early in your cycle). Wear a short-sleeve shirt for easy access to your arm. Tell the person drawing blood if you take blood thinners, have a bleeding disorder, latex allergy, or a preferred arm." },

  // === NEW UpToDate Cervical Cancer RAG Entries (IDs 1885–1895) ===
  { id: 1885, category: 'cancer', keywords: ['what is cervical cancer'], question: "What is cervical cancer?", response: "Cervical cancer occurs when normal cells in the cervix (the lower part of the uterus that connects to the vagina) change and grow out of control. Almost all cases are caused by persistent infection with high-risk types of human papillomavirus (HPV), a common virus spread through skin-to-skin contact and sexual activity." },
  { id: 1886, category: 'cancer', keywords: ['symptoms of cervical cancer'], question: "What are the symptoms of cervical cancer?", response: "Early cervical cancer often has no symptoms. When symptoms appear, they can include bleeding between periods, bleeding after sex, or any vaginal bleeding after menopause. These symptoms can also be caused by non-cancer conditions, so it's important to get them checked." },
  { id: 1887, category: 'cancer', keywords: ['cervical cancer screening Pap HPV test'], question: "How is cervical cancer screened for?", response: "Screening uses a Pap test (which looks at cervical cells under a microscope) and/or an HPV test (which checks for the virus). These are done during a pelvic exam with a speculum. Screening can find precancerous changes or early cancer when it is highly treatable." },
  { id: 1888, category: 'cancer', keywords: ['what is colposcopy and biopsy'], question: "What happens if my Pap or HPV test is abnormal?", response: "Your doctor may recommend a colposcopy — using a magnifying instrument to closely examine the cervix — often with a biopsy (taking small tissue samples). This helps determine if there are precancerous changes or cancer and guides next steps." },
  { id: 1889, category: 'cancer', keywords: ['HPV vaccine cervical cancer prevention'], question: "Can the HPV vaccine prevent cervical cancer?", response: "Yes. The HPV vaccine prevents infection with the high-risk HPV types that cause most cervical cancers. It works best when given before sexual activity begins, but it can still offer protection even if you've already been exposed to some types." },
  { id: 1890, category: 'cancer', keywords: ['cervical cancer treatment options'], question: "How is cervical cancer treated?", response: "Treatment depends on the stage, your age, overall health, and whether you want to preserve fertility. Options include surgery (such as radical hysterectomy), radiation therapy, and chemotherapy (often given together with radiation). Some early cases may be treated with surgery that preserves the uterus." },
  { id: 1891, category: 'cancer', keywords: ['fertility after cervical cancer treatment'], question: "Can I still get pregnant after cervical cancer treatment?", response: "It depends on the treatment. Some surgeries that remove only part of the cervix may allow future pregnancy. However, a full hysterectomy, certain radiation treatments, or chemotherapy can make pregnancy impossible. Talk with your doctor about fertility preservation options before starting treatment." },
  { id: 1892, category: 'cancer', keywords: ['cervical cancer staging'], question: "What does staging mean for cervical cancer?", response: "Staging describes how far the cancer has spread — whether it's confined to the cervix, has spread to nearby tissues, or to distant organs. Staging guides treatment decisions and helps predict outlook. It is determined by exam, imaging (MRI/CT), and surgical findings." },
  { id: 1893, category: 'cancer', keywords: ['follow up after cervical cancer'], question: "What happens after cervical cancer treatment?", response: "You will have regular follow-up visits including pelvic exams and Pap/HPV testing to watch for recurrence. Your care team will also support your overall health, including emotional well-being, sexual health, and lifestyle factors like quitting smoking." },
  { id: 1894, category: 'cancer', keywords: ['questions to ask about cervical cancer treatment'], question: "What questions should I ask about cervical cancer treatment?", response: "Important questions include: What stage is my cancer? What are the benefits and risks of each treatment option? Will this affect my ability to have children? What are the side effects? Are there clinical trials I should consider? What happens if I choose not to have a recommended treatment?" },
  { id: 1895, category: 'cancer', keywords: ['precancerous cervical cells'], question: "What if I have precancerous cells on my cervix?", response: "Precancerous changes (also called cervical dysplasia or CIN) are not cancer but can progress if untreated. Your doctor may recommend monitoring, removing the abnormal cells (via procedures like LEEP or cone biopsy), or other management based on the severity and your situation." },

  // === NEW UpToDate Perimenopause RAG Entries (IDs 1901–1910) ===
  { id: 1901, category: 'perimenopause', keywords: ['what is perimenopause'], question: "What is perimenopause?", response: "Perimenopause is the transition time leading up to menopause, when periods eventually stop. It usually starts about 4 years before your last period (average age around 47). During this time, hormone levels — especially estrogen — fluctuate significantly, causing irregular periods and other symptoms." },
  { id: 1902, category: 'perimenopause', keywords: ['perimenopause symptoms'], question: "What are common symptoms of perimenopause?", response: "The main symptoms include changes in menstrual cycle length and flow (periods may come closer together, farther apart, or be heavier/lighter). Other common symptoms are hot flashes, night sweats, mood changes (including depression or anxiety), and sleep difficulties. Vaginal dryness often appears later." },
  { id: 1903, category: 'perimenopause', keywords: ['hot flashes in perimenopause'], question: "Are hot flashes common in perimenopause?", response: "Yes. Hot flashes and night sweats are very common during perimenopause due to estrogen fluctuations. They can feel like a sudden wave of heat, often starting in the chest and face. Night sweats can disrupt sleep. Hormone therapy is the most effective treatment for these symptoms." },
  { id: 1904, category: 'perimenopause', keywords: ['irregular periods perimenopause'], question: "Why do periods become irregular in perimenopause?", response: "As you approach menopause, ovulation becomes less predictable and estrogen levels swing up and down. This causes periods to come at irregular intervals, vary in length, or change in heaviness. This is a normal part of the transition." },
  { id: 1905, category: 'perimenopause', keywords: ['do I need hormone tests for perimenopause'], question: "Do I need blood tests to diagnose perimenopause?", response: "Usually not if you are over 45 and having typical symptoms. A single hormone test is not very helpful because levels fluctuate so much. Testing is more useful if you are under 45, have very heavy bleeding, or if your doctor needs to rule out other conditions like thyroid disease or pregnancy." },
  { id: 1906, category: 'perimenopause', keywords: ['hormone therapy for perimenopause'], question: "Can hormone therapy help with perimenopause symptoms?", response: "Yes. Estrogen (usually combined with progesterone if you still have a uterus) is the most effective treatment for hot flashes and night sweats. It can also help with sleep and mood in many people. It is generally considered safe for most healthy people under 60 who are within 10 years of menopause onset." },
  { id: 1907, category: 'perimenopause', keywords: ['who should not take hormone therapy'], question: "Who should avoid hormone therapy for menopause symptoms?", response: "Hormone therapy is usually not recommended if you have a history of breast cancer, heart attack, stroke, or blood clots. Your doctor will review your personal and family medical history to help decide if it's safe for you." },
  { id: 1908, category: 'perimenopause', keywords: ['other treatments for perimenopause symptoms'], question: "What other treatments can help with perimenopause symptoms?", response: "Depending on your symptoms, options include certain antidepressants for hot flashes and mood, vaginal estrogen for dryness or painful sex, and lifestyle approaches (exercise, good sleep habits, stress management). Talk to your doctor about what might work best for you." },
  { id: 1909, category: 'perimenopause', keywords: ['natural remedies for perimenopause'], question: "Do natural remedies or supplements help with perimenopause?", response: "Most herbal supplements and 'natural hormone balancing' products are not well studied and may not work. Some can interact with medications or be unsafe (especially if you have a history of breast cancer). It's best to discuss any supplements with your doctor before trying them." },
  { id: 1910, category: 'perimenopause', keywords: ['when to see a doctor about perimenopause'], question: "When should I see a doctor about perimenopause symptoms?", response: "See your doctor if your periods become very heavy, last a long time, or if you have bleeding between periods or after sex. Also seek care for bothersome hot flashes, mood changes, sleep problems, or if you're under 45 and having symptoms. Good treatment options are available." },

  // === NEW UpToDate Cervical Conization RAG Entries (IDs 1916–1926) ===
  { id: 1916, category: 'procedure', keywords: ['what is cervical conization'], question: "What is cervical conization?", response: "Cervical conization (also called a cone biopsy or cold knife conization) is a procedure to remove a cone-shaped piece of tissue from the cervix that contains abnormal cells. It is done to prevent these cells from turning into cervical cancer and to allow the tissue to be examined in the lab for a more accurate diagnosis." },
  { id: 1917, category: 'procedure', keywords: ['why is cervical conization done'], question: "Why would I need a cervical conization?", response: "Your doctor may recommend it if a Pap test, HPV test, or cervical biopsy showed abnormal or precancerous cells. Removing the abnormal area can prevent progression to cancer and gives more information about how severe the changes are." },
  { id: 1918, category: 'procedure', keywords: ['preparing for cervical conization'], question: "How do I prepare for cervical conization?", response: "You may need to fast before the procedure. Tell your doctor about all medications, supplements, allergies (especially iodine), bleeding disorders, and whether you could be pregnant. The procedure can usually be done at any point in your cycle unless you are bleeding heavily that day." },
  { id: 1919, category: 'procedure', keywords: ['what happens during cervical conization'], question: "What happens during a cervical conization procedure?", response: "You will receive anesthesia (regional or general). The doctor uses a speculum and often a colposcope to see the cervix clearly. They remove a cone-shaped piece of tissue from the abnormal area, send it to the lab, and close the site with dissolvable stitches. The procedure usually takes less than an hour." },
  { id: 1920, category: 'procedure', keywords: ['anesthesia for cervical conization'], question: "What kind of anesthesia is used for cervical conization?", response: "You may have regional anesthesia (which numbs the lower body) with sedation, or general anesthesia (you are fully asleep). Your doctor will discuss the best option for you based on your health and preferences." },
  { id: 1921, category: 'procedure', keywords: ['recovery after cervical conization'], question: "What is recovery like after cervical conization?", response: "Most people go home the same day. You may feel groggy from anesthesia and have some pelvic pain or cramping. You will be given pain medication and instructions about activity, bleeding, and when to call the doctor. Full recovery usually takes a few weeks." },
  { id: 1922, category: 'procedure', keywords: ['risks of cervical conization'], question: "What are the risks of cervical conization?", response: "Possible risks include bleeding, infection, and injury to the cervix or nearby structures. A more significant long-term risk is that it can increase the chance of pregnancy complications in the future, such as preterm birth or miscarriage, especially if a large amount of tissue is removed." },
  { id: 1923, category: 'procedure', keywords: ['cervical conization and future pregnancy'], question: "Does cervical conization affect future pregnancies?", response: "Yes, it can. Removing part of the cervix can weaken it, increasing the risk of preterm birth, second-trimester pregnancy loss, or cervical insufficiency in future pregnancies. Your doctor will discuss this risk with you, especially if you plan to have children." },
  { id: 1924, category: 'procedure', keywords: ['bleeding after cervical conization'], question: "How much bleeding is normal after cervical conization?", response: "Some bleeding and discharge (which may be dark or contain tissue) is normal for several days to a couple of weeks. You should contact your doctor if bleeding is very heavy (soaking a pad every hour), has a foul odor, or is accompanied by fever or severe pain." },
  { id: 1925, category: 'procedure', keywords: ['cold knife vs laser conization'], question: "What is the difference between cold knife and laser conization?", response: "Cold knife conization uses a scalpel to remove the tissue. Laser conization uses a laser instead. Both achieve similar results, but cold knife is more commonly used because it provides a better tissue sample for pathology. Your doctor will choose the best method for your situation." },
  { id: 1926, category: 'procedure', keywords: ['when to call doctor after conization'], question: "When should I call my doctor after cervical conization?", response: "Call if you have heavy bleeding, signs of infection (fever, chills, foul-smelling discharge), severe pain not relieved by medication, or any concerns about your recovery. Also call if you think you might be pregnant in the future so your doctor can monitor your cervix closely." },

  // === NEW UpToDate LEEP RAG Entries (IDs 1927–1936) ===
  { id: 1927, category: 'procedure', keywords: ['what is a LEEP procedure'], question: "What is a LEEP procedure?", response: "LEEP stands for Loop Electrosurgical Excision Procedure. It is a quick outpatient surgery that uses a thin wire loop with an electrical current to remove abnormal or precancerous cells from the cervix. It is also sometimes called LLETZ (large loop excision of the transformation zone)." },
  { id: 1928, category: 'procedure', keywords: ['why is LEEP done'], question: "Why would I need a LEEP?", response: "Your doctor may recommend a LEEP if a Pap test, HPV test, or cervical biopsy showed abnormal or precancerous cells. Removing these cells helps prevent them from progressing to cervical cancer and allows the tissue to be examined more thoroughly in the lab." },
  { id: 1929, category: 'procedure', keywords: ['preparing for LEEP'], question: "How do I prepare for a LEEP?", response: "You can usually have a LEEP at any time in your cycle unless you are bleeding heavily. Tell your doctor about all medications, supplements, allergies (especially to iodine), bleeding disorders, and whether you could be pregnant. You may need to avoid eating or drinking for a short time before the procedure." },
  { id: 1930, category: 'procedure', keywords: ['what happens during LEEP'], question: "What happens during a LEEP procedure?", response: "You will lie on an exam table with your feet in stirrups. The doctor inserts a speculum and uses a colposcope to see the cervix clearly. After numbing the cervix with a local anesthetic, they use a thin wire loop with electricity to remove the abnormal area. The tissue is sent to the lab. The procedure usually takes about 20 minutes." },
  { id: 1931, category: 'procedure', keywords: ['does LEEP hurt'], question: "Does a LEEP procedure hurt?", response: "You will receive a local anesthetic injection into the cervix, so you should not feel sharp pain. Many people feel pressure, cramping, or a sensation similar to a strong period cramp. The electrical loop makes a vacuum-like sound, which is normal." },
  { id: 1932, category: 'procedure', keywords: ['recovery after LEEP'], question: "What is recovery like after a LEEP?", response: "Most people go home the same day. You may have cramping, light bleeding, or dark discharge for several days to a couple of weeks. You will be given instructions about activity restrictions, avoiding tampons and sex for a period of time, and when to call your doctor." },
  { id: 1933, category: 'procedure', keywords: ['LEEP risks future pregnancy'], question: "Does LEEP affect future pregnancies?", response: "Yes, it can. Removing part of the cervix can increase the risk of preterm birth, second-trimester miscarriage, or cervical insufficiency in future pregnancies. The risk is generally higher if a larger area of tissue is removed. Discuss this with your doctor if you plan to have children." },
  { id: 1934, category: 'procedure', keywords: ['LEEP vs conization'], question: "What is the difference between LEEP and cervical conization?", response: "Both procedures remove abnormal cervical tissue. LEEP uses an electrically heated wire loop and is usually quicker with less bleeding. Cold knife conization uses a scalpel and may remove a larger or deeper piece of tissue. Your doctor will recommend the best option based on your situation and the extent of abnormal cells." },
  { id: 1935, category: 'procedure', keywords: ['when to call doctor after LEEP'], question: "When should I call my doctor after a LEEP?", response: "Call if you have heavy bleeding (soaking a pad every hour), severe pain, fever, chills, foul-smelling discharge, or any concerns. Also contact your doctor if you become pregnant in the future so they can monitor your cervix closely during pregnancy." },
  { id: 1936, category: 'procedure', keywords: ['LEEP aftercare instructions'], question: "What should I avoid after a LEEP?", response: "You will typically be advised to avoid tampons, douching, and sexual intercourse for several weeks while the cervix heals. Your doctor will give you specific instructions based on your procedure. Follow them closely to reduce the risk of infection or bleeding." },

  // === NEW UpToDate Colposcopy RAG Entries (IDs 1941–1950) ===
  { id: 1941, category: 'procedure', keywords: ['what is a colposcopy'], question: "What is a colposcopy?", response: "A colposcopy is a procedure that allows your doctor to closely examine your cervix, vagina, or vulva using a special magnifying instrument called a colposcope. It is often done after an abnormal Pap test or HPV test to get a better look at any concerning areas." },
  { id: 1942, category: 'procedure', keywords: ['why is colposcopy done'], question: "Why would I need a colposcopy?", response: "Doctors recommend colposcopy if you had an abnormal Pap test, positive HPV test, or if they saw something concerning during a pelvic exam. It helps them identify abnormal cells more clearly and decide whether a biopsy is needed." },
  { id: 1943, category: 'procedure', keywords: ['preparing for colposcopy'], question: "How do I prepare for a colposcopy?", response: "You can have a colposcopy at any time in your cycle unless you are bleeding heavily. Tell your doctor about all medications, supplements, allergies (especially to iodine), bleeding disorders, and whether you could be pregnant. You usually don't need to fast." },
  { id: 1944, category: 'procedure', keywords: ['what happens during colposcopy'], question: "What happens during a colposcopy?", response: "You will lie on an exam table with your feet in stirrups. The doctor inserts a speculum and uses a colposcope (which doesn't touch you) to magnify the cervix. They apply a vinegar-like solution (acetic acid) to highlight abnormal areas. The exam usually takes 5–10 minutes." },
  { id: 1945, category: 'procedure', keywords: ['colposcopy with biopsy'], question: "Does colposcopy include a biopsy?", response: "Not always. If the doctor sees abnormal areas, they may take small tissue samples (biopsies) from the cervix. You might feel brief cramping or discomfort during the biopsy. The samples are sent to a lab for analysis." },
  { id: 1946, category: 'procedure', keywords: ['does colposcopy hurt'], question: "Does a colposcopy hurt?", response: "The procedure itself is usually not painful, though you may feel pressure from the speculum. If a biopsy is taken, you might experience brief cramping or pinching. Many people describe it as uncomfortable but tolerable." },
  { id: 1947, category: 'procedure', keywords: ['recovery after colposcopy'], question: "What is recovery like after a colposcopy?", response: "You can usually return to normal activities right away. If you had a biopsy, you may have light bleeding or dark discharge for a few days. Avoid sex, tampons, and douching for at least 48 hours (or as instructed) to allow healing." },
  { id: 1948, category: 'procedure', keywords: ['colposcopy during pregnancy'], question: "Can I have a colposcopy if I'm pregnant?", response: "Yes, colposcopy is safe during pregnancy. However, your doctor may avoid taking biopsies unless absolutely necessary, as they can increase the risk of bleeding. They will discuss the safest approach for your situation." },
  { id: 1949, category: 'procedure', keywords: ['when to call doctor after colposcopy'], question: "When should I call my doctor after a colposcopy?", response: "Call if you have heavy bleeding, bleeding that lasts more than 7 days, foul-smelling discharge, severe pelvic pain, fever (100.4°F / 38°C or higher), or any other concerning symptoms." },
  { id: 1950, category: 'procedure', keywords: ['colposcopy risks'], question: "What are the risks of colposcopy?", response: "Colposcopy is generally very safe. The main risks are bleeding and infection, especially if a biopsy was performed. Serious complications are rare. Your doctor will review your specific risks with you." },

  // === NEW UpToDate Breast Pain RAG Entries (IDs 1956–1965) ===
  { id: 1956, category: 'breast', keywords: ['types of breast pain'], question: "What are the different types of breast pain?", response: "There are three main types: Cyclical breast pain is related to your menstrual cycle and hormone changes. Noncyclical breast pain is not tied to your cycle and can have many causes. Extramammary pain feels like it's in the breast but actually comes from nearby structures like chest muscles or ribs." },
  { id: 1957, category: 'breast', keywords: ['cyclical breast pain causes'], question: "What causes cyclical breast pain?", response: "Cyclical breast pain is very common and is caused by normal hormone fluctuations during the menstrual cycle. Breasts often feel sore or tender in the week or two before your period. It usually improves after your period starts. Hormone changes during perimenopause or from birth control can also contribute." },
  { id: 1958, category: 'breast', keywords: ['noncyclical breast pain causes'], question: "What can cause noncyclical breast pain?", response: "Noncyclical breast pain is not related to your period. Common causes include breast cysts, large breasts causing ligament strain, mastitis, pregnancy, medications, or (rarely) other breast conditions. It can affect one or both breasts and may be constant or come and go." },
  { id: 1959, category: 'breast', keywords: ['extramammary breast pain'], question: "What is extramammary breast pain?", response: "Extramammary pain feels like it's coming from the breast but actually originates elsewhere — most commonly from strained chest wall muscles, ribs, or nerves. It often worsens with movement, deep breathing, or pressure on the chest." },
  { id: 1960, category: 'breast', keywords: ['is breast pain a sign of cancer'], question: "Is breast pain usually a sign of breast cancer?", response: "No. Breast pain is very common and is rarely a sign of breast cancer, especially when it's cyclical. However, any new, persistent, or changing breast pain should be evaluated by a doctor to rule out other causes." },
  { id: 1961, category: 'breast', keywords: ['when to get imaging for breast pain'], question: "When do I need a mammogram or ultrasound for breast pain?", response: "Your doctor will examine your breasts first. Imaging (mammogram and/or ultrasound) is often recommended if the pain is new, persistent, one-sided, or if there are other concerning findings on exam (such as a lump or skin changes). Normal imaging is very reassuring." },
  { id: 1962, category: 'breast', keywords: ['treatment for breast pain'], question: "How is breast pain treated?", response: "Most breast pain improves with simple measures. Helpful options include wearing a well-fitted, supportive bra (including at night if needed), taking over-the-counter pain relievers like ibuprofen or acetaminophen, using warm or cool compresses, and gentle massage. If pain is related to hormones, adjusting medications may help." },
  { id: 1963, category: 'breast', keywords: ['supportive bra for breast pain'], question: "Can a bra help with breast pain?", response: "Yes. A well-fitted, supportive bra (with or without underwire, depending on breast size) often reduces pain by minimizing movement and strain on breast tissue and ligaments. Some people find wearing a soft supportive bra at night helpful too." },
  { id: 1964, category: 'breast', keywords: ['when to see doctor for breast pain'], question: "When should I see a doctor about breast pain?", response: "See your doctor if breast pain is new or worsening, lasts more than a few weeks, is one-sided and persistent, or is accompanied by a lump, nipple discharge, skin changes, or signs of infection (fever, redness, warmth). Any breast symptom that concerns you deserves evaluation." },
  { id: 1965, category: 'breast', keywords: ['breast pain and menopause'], question: "Can perimenopause or menopause cause breast pain?", response: "Yes. Hormone fluctuations during perimenopause can cause breast tenderness or pain. Some people also experience breast pain when starting or changing hormone therapy for menopause symptoms. Adjusting the dose or type of hormone therapy sometimes helps." },

  // === NEW UpToDate Iron Deficiency RAG Entries (IDs 1971–1981) ===
  { id: 1971, category: 'nutrition', keywords: ['what is iron deficiency'], question: "What is iron deficiency?", response: "Iron deficiency means your body doesn't have enough iron stores. Iron is essential for making hemoglobin, the protein in red blood cells that carries oxygen. When iron is low, you can develop iron deficiency anemia, which means your blood can't carry oxygen as well as it should." },
  { id: 1972, category: 'nutrition', keywords: ['causes of iron deficiency in women'], question: "What are common causes of iron deficiency in women?", response: "The most common cause in women is blood loss from heavy menstrual periods. Pregnancy also increases iron needs. Other causes include poor absorption (from celiac disease, stomach surgery, or certain medications), not eating enough iron-rich foods, or slow bleeding from the digestive tract." },
  { id: 1973, category: 'nutrition', keywords: ['symptoms of iron deficiency'], question: "What are symptoms of iron deficiency?", response: "Common symptoms include fatigue, weakness (especially with activity), irritability, headaches, hair loss, and restless legs syndrome. Some people develop unusual cravings (pica), such as wanting to eat ice, clay, or starch. Severe anemia can cause chest pain or shortness of breath." },
  { id: 1974, category: 'nutrition', keywords: ['ferritin test iron deficiency'], question: "What blood test checks for iron deficiency?", response: "The best test is ferritin, which measures your body's iron stores. Doctors also check hemoglobin (as part of a CBC) to see if you have anemia, and sometimes transferrin saturation (TSAT). A low ferritin level is the earliest and most reliable sign of iron deficiency." },
  { id: 1975, category: 'nutrition', keywords: ['heavy periods and iron deficiency'], question: "Can heavy periods cause iron deficiency?", response: "Yes. Heavy or prolonged menstrual bleeding is one of the most common causes of iron deficiency in women of reproductive age. If you have heavy periods and symptoms of low iron, it's important to get tested and discuss options to reduce bleeding (such as hormonal treatments or the LNG-IUD)." },
  { id: 1976, category: 'nutrition', keywords: ['how to take iron supplements'], question: "How should I take iron supplements?", response: "Take iron once a day or every other day (or Monday/Wednesday/Friday) on an empty stomach for best absorption. Avoid taking it with coffee, tea, dairy, eggs, or whole grains at the same time. Vitamin C (from orange juice or supplements) can help absorption. Don't take more than prescribed — too much iron can be harmful." },
  { id: 1977, category: 'nutrition', keywords: ['side effects of iron pills'], question: "What side effects do iron pills cause?", response: "Common side effects include nausea, constipation, stomach upset, and dark or black stools. These are normal but can be bothersome. Taking iron every other day, with food (if needed), or switching to a different formulation or IV iron can help reduce side effects." },
  { id: 1978, category: 'nutrition', keywords: ['IV iron vs oral iron'], question: "When is IV iron better than pills?", response: "IV iron is often better if you can't tolerate oral iron, have absorption problems (after weight loss surgery or with inflammatory bowel disease), have very low iron levels, or are in late pregnancy. IV iron delivers a full dose quickly, often in one or two visits." },
  { id: 1979, category: 'nutrition', keywords: ['iron deficiency and restless legs'], question: "Can iron deficiency cause restless legs syndrome?", response: "Yes. Low iron stores (even without anemia) are a common cause of restless legs syndrome. Treating iron deficiency often improves or resolves restless legs symptoms." },
  { id: 1980, category: 'nutrition', keywords: ['why find cause of iron deficiency'], question: "Why is it important to find why I have low iron?", response: "Iron deficiency is usually a symptom of something else — most often bleeding. It's important to identify and treat the cause (heavy periods, GI bleeding, etc.) in addition to replacing iron. Simply taking iron without addressing the root cause often leads to iron levels dropping again." },
  { id: 1981, category: 'nutrition', keywords: ['iron pills safety children'], question: "Are iron supplements dangerous for children?", response: "Yes. Iron pills can cause serious poisoning in children if swallowed accidentally. Always store iron supplements safely out of reach of children. If a child swallows iron pills, call poison control immediately." },

  // === NEW UpToDate Menopause RAG Entries (IDs 1986–1996) ===
  { id: 1986, category: 'menopause', keywords: ['what is menopause'], question: "What is menopause?", response: "Menopause is the point when menstrual periods naturally stop permanently. It is diagnosed after you have gone 12 consecutive months without a period. At this time, the ovaries stop releasing eggs and produce much lower levels of estrogen and progesterone. The average age is 51, but it normally occurs between 45 and 55." },
  { id: 1987, category: 'menopause', keywords: ['perimenopause vs menopause'], question: "What is the difference between perimenopause and menopause?", response: "Perimenopause is the transition period leading up to menopause, when hormone levels fluctuate and periods become irregular. Menopause is the specific point when you have gone 12 months without a period. Symptoms often start during perimenopause and can continue for years after menopause." },
  { id: 1988, category: 'menopause', keywords: ['common menopause symptoms'], question: "What are the most common symptoms of menopause?", response: "Common symptoms include hot flashes, night sweats, sleep disturbances, mood changes (including depression and anxiety), trouble concentrating, vaginal dryness, and joint pain. Hot flashes often begin during perimenopause and can continue for years after periods stop." },
  { id: 1989, category: 'menopause', keywords: ['when to see doctor for bleeding in menopause'], question: "When should I see a doctor about bleeding during or after menopause?", response: "See a doctor if you have bleeding more often than every 3 weeks, very heavy periods, bleeding between periods, or any bleeding after you have gone 12 months without a period (postmenopausal bleeding). Postmenopausal bleeding should always be evaluated." },
  { id: 1990, category: 'menopause', keywords: ['hormone therapy for menopause'], question: "Is hormone therapy effective for menopause symptoms?", response: "Yes. Estrogen (combined with progesterone if you still have a uterus) is the most effective treatment for hot flashes and night sweats. It can also help with sleep, mood, and vaginal symptoms. It is generally considered safe and effective for most healthy people under age 60 or within 10 years of menopause." },
  { id: 1991, category: 'menopause', keywords: ['who should not take hormone therapy'], question: "Who should not take hormone therapy for menopause?", response: "Hormone therapy is usually not recommended if you have a history of breast cancer, heart attack, stroke, or blood clots. Your doctor will review your personal medical history and risk factors to help decide if it is safe for you." },
  { id: 1992, category: 'menopause', keywords: ['non-hormonal treatments for hot flashes'], question: "What non-hormonal treatments help with hot flashes?", response: "Options include certain antidepressants (such as paroxetine or venlafaxine), the medication fezolinetant (Veozah), and some anti-seizure medicines. These can be good choices for people who cannot or prefer not to use hormone therapy, including many breast cancer survivors." },
  { id: 1993, category: 'menopause', keywords: ['vaginal estrogen for dryness'], question: "How is vaginal dryness treated after menopause?", response: "Low-dose vaginal estrogen (creams, tablets, or a ring) is highly effective for vaginal dryness and painful sex. It has very low absorption into the rest of the body. Non-hormonal vaginal moisturizers used several times a week and lubricants during sex can also help." },
  { id: 1994, category: 'menopause', keywords: ['can I still get pregnant during menopause transition'], question: "Can I still get pregnant while going through menopause?", response: "Yes. As long as you are still having periods (even if irregular), pregnancy is possible. You should continue using contraception until you have gone a full 12 months without a period. After that, pregnancy is very unlikely." },
  { id: 1995, category: 'menopause', keywords: ['bone health after menopause'], question: "How can I protect my bones after menopause?", response: "Estrogen helps protect bones. After menopause, focus on getting enough calcium and vitamin D, staying physically active (especially weight-bearing and resistance exercise), and asking your doctor about bone density testing. Some people may need prescription medications to prevent bone loss." },
  { id: 1996, category: 'menopause', keywords: ['when to see a menopause specialist'], question: "When should I see a menopause specialist?", response: "Consider seeing a clinician with expertise in menopause if your symptoms are severe, you're not getting good relief, you have complex medical issues (such as breast cancer history or blood clot risk), or you want a full discussion of all hormonal and non-hormonal treatment options." },

  // === NEW UpToDate Painful Urination RAG Entries (IDs 2001–2009) ===
  { id: 2001, category: 'urinary', keywords: ['what is painful urination'], question: "What is painful urination?", response: "Painful urination (dysuria) is discomfort, burning, stinging, or itching while peeing or right after. It is a common symptom with many possible causes, most of which are treatable." },
  { id: 2002, category: 'urinary', keywords: ['most common cause of painful urination'], question: "What is the most common cause of painful urination?", response: "The most common cause is a urinary tract infection (UTI), especially a bladder infection. UTIs often also cause urgency, frequency, and cloudy or strong-smelling urine." },
  { id: 2003, category: 'urinary', keywords: ['painful urination and STIs'], question: "Can STIs cause painful urination?", response: "Yes. Sexually transmitted infections like chlamydia and gonorrhea commonly cause painful urination. They may also cause discharge, pelvic pain, or pain with sex. Testing is important if you're sexually active and have new symptoms." },
  { id: 2004, category: 'urinary', keywords: ['kidney stones and painful urination'], question: "Can kidney stones cause painful urination?", response: "Yes. Kidney stones can cause burning or pain with urination, often along with blood in the urine, side or back pain, nausea, or vomiting. Stones usually require different treatment than infections." },
  { id: 2005, category: 'urinary', keywords: ['painful urination after menopause'], question: "Why can painful urination happen after menopause?", response: "Low estrogen levels after menopause can cause genitourinary syndrome of menopause (GSM). This leads to thinning and dryness of the vaginal and urethral tissues, which can make urination painful or cause burning. Low-dose vaginal estrogen is often very effective for this." },
  { id: 2006, category: 'urinary', keywords: ['when to get tested for painful urination'], question: "When should I get tested for painful urination?", response: "See a doctor for testing if you have painful urination along with urgency, frequency, blood in urine, fever, back pain, discharge, or if symptoms don't improve quickly. Urine tests are usually the first step; STI testing or imaging may be added depending on your situation." },
  { id: 2007, category: 'urinary', keywords: ['treatment for painful urination'], question: "How is painful urination treated?", response: "Treatment depends on the cause. UTIs are treated with antibiotics. STIs require specific antibiotics. Kidney stones may need pain control, fluids, or procedures. GSM (low estrogen) is often treated with vaginal estrogen or non-hormonal moisturizers. Your doctor will choose the right approach based on testing." },
  { id: 2008, category: 'urinary', keywords: ['when to worry about painful urination'], question: "When is painful urination an emergency?", response: "Seek care promptly if you cannot urinate, have severe lower abdominal pain, fever with back pain, visible blood in urine, or swelling around the genitals. These can signal a more serious infection or blockage that needs urgent treatment." },
  { id: 2009, category: 'urinary', keywords: ['painful urination and vaginal dryness'], question: "Can vaginal dryness cause painful urination?", response: "Yes. When estrogen is low (especially after menopause), the tissues around the urethra can become thin and irritated, leading to burning with urination even without an infection. This is part of genitourinary syndrome of menopause and often improves with vaginal estrogen or moisturizers." },

  // === NEW UpToDate Menopause Patient Education RAG Entries (IDs 2016–2025) ===
  { id: 2016, category: 'menopause', keywords: ['when does menopause start and end'], question: "When does perimenopause end and menopause begin?", response: "Perimenopause (the menopausal transition) ends when you have your final menstrual period. Menopause is officially reached after you have gone 12 consecutive months without a period. After that point, you are considered postmenopausal." },
  { id: 2017, category: 'menopause', keywords: ['abnormal bleeding during perimenopause'], question: "When is bleeding abnormal during perimenopause or after menopause?", response: "See your doctor if you have bleeding more often than every 3 weeks, very heavy periods, bleeding between periods, or any bleeding after you have gone 12 months without a period. Postmenopausal bleeding should always be evaluated, even if it's just spotting." },
  { id: 2018, category: 'menopause', keywords: ['birth control during perimenopause'], question: "Do I still need birth control during perimenopause?", response: "Yes. You can still get pregnant during perimenopause as long as you are having periods, even if they are irregular. Continue using contraception until you have gone a full 12 months without a period. Hormonal birth control can also help with hot flashes and irregular bleeding." },
  { id: 2019, category: 'menopause', keywords: ['when to stop birth control menopause'], question: "When can I stop using birth control?", response: "You can stop contraception once you have gone 12 months without a period. If you are using hormonal birth control, your doctor may suggest stopping around age 50-51 (the average age of menopause) to see if your periods have truly stopped and whether you are having menopausal symptoms." },
  { id: 2020, category: 'menopause', keywords: ['how long do hot flashes last'], question: "How long do hot flashes usually last?", response: "Hot flashes often begin during perimenopause and typically last for about 7 to 10 years on average, though they can continue for much longer in some women. They are the most common symptom of menopause and can happen during the day or as night sweats." },
  { id: 2021, category: 'menopause', keywords: ['vaginal dryness after menopause'], question: "Why does vaginal dryness happen after menopause and how is it treated?", response: "Lower estrogen levels cause the vaginal and urethral tissues to become thinner and drier (called genitourinary syndrome of menopause). This can cause burning with urination, dryness, and painful sex. Low-dose vaginal estrogen (cream, tablet, or ring) is very effective and has minimal absorption into the rest of the body." },
  { id: 2022, category: 'menopause', keywords: ['non-hormonal options for hot flashes'], question: "What non-hormonal treatments help with hot flashes?", response: "Options include certain antidepressants (such as paroxetine or venlafaxine), fezolinetant (Veozah), and some other medications. These can be good choices if you cannot or prefer not to use hormone therapy. Lifestyle changes (cooling strategies, layered clothing, avoiding triggers) can also help." },
  { id: 2023, category: 'menopause', keywords: ['is hormone therapy safe'], question: "Is menopausal hormone therapy safe?", response: "For most healthy women under age 60 (or within 10 years of menopause), hormone therapy is considered safe and effective for treating hot flashes and other symptoms. It is not recommended if you have a history of breast cancer, heart disease, stroke, or blood clots. Your doctor can help weigh the benefits and risks for your situation." },
  { id: 2024, category: 'menopause', keywords: ['mood changes during menopause'], question: "Can menopause cause depression or mood changes?", response: "Yes. The hormonal shifts during perimenopause and menopause can trigger new or worsened mood symptoms, including depression and anxiety. Women with a prior history of depression are at higher risk. Effective treatments are available, and many women feel better after the transition stabilizes." },
  { id: 2025, category: 'menopause', keywords: ['sleep problems in menopause'], question: "Why do sleep problems happen during menopause?", response: "Sleep issues are common due to night sweats, hormonal changes, and the transition itself. Many women develop trouble falling or staying asleep. Treating hot flashes, practicing good sleep hygiene, and addressing any underlying sleep disorders can help significantly." },

  // === NEW UpToDate Abnormal Uterine Bleeding RAG Entries (IDs 2031–2040) ===
  { id: 2031, category: 'bleeding', keywords: ['what is abnormal uterine bleeding'], question: "What counts as abnormal uterine bleeding?", response: "Abnormal uterine bleeding includes bleeding that is too heavy, too long, occurs too frequently, happens between periods, or occurs after menopause. Any bleeding after menopause (once you've gone 12 months without a period) is considered abnormal and should be evaluated." },
  { id: 2032, category: 'bleeding', keywords: ['causes of abnormal bleeding by age'], question: "What causes abnormal uterine bleeding at different ages?", response: "In young girls, it can be caused by trauma, infection, or foreign objects. In teens, irregular ovulation is common at first. In premenopausal women, common causes include fibroids, polyps, adenomyosis, hormonal imbalances, pregnancy, and clotting disorders. After menopause, causes include thinning of the lining (atrophy), polyps, fibroids, or cancer." },
  { id: 2033, category: 'bleeding', keywords: ['fibroids polyps adenomyosis bleeding'], question: "Can fibroids, polyps, or adenomyosis cause heavy bleeding?", response: "Yes. Uterine fibroids, endometrial polyps, and adenomyosis are among the most common structural causes of heavy or irregular bleeding in premenopausal women. These conditions can often be seen on ultrasound and may require specific treatment." },
  { id: 2034, category: 'bleeding', keywords: ['when to worry about bleeding in perimenopause'], question: "When should I worry about bleeding during perimenopause?", response: "See your doctor for bleeding more often than every 3 weeks, very heavy periods, bleeding between periods, or any bleeding after you've gone 12 months without a period. While irregular bleeding is common in perimenopause, these patterns need evaluation." },
  { id: 2035, category: 'bleeding', keywords: ['postmenopausal bleeding causes'], question: "What causes bleeding after menopause?", response: "Common causes include thinning of the uterine lining (atrophy), polyps, fibroids, infection, or (less commonly) endometrial cancer or precancer. Any bleeding after menopause should be evaluated promptly, usually with an ultrasound and endometrial biopsy." },
  { id: 2036, category: 'bleeding', keywords: ['endometrial biopsy for bleeding'], question: "Why is an endometrial biopsy done for abnormal bleeding?", response: "An endometrial biopsy checks for cancer, precancer (hyperplasia), or infection of the uterine lining. It is often recommended for women 45 and older with abnormal bleeding, or younger women with risk factors such as obesity or long-term irregular cycles." },
  { id: 2037, category: 'bleeding', keywords: ['ultrasound for abnormal uterine bleeding'], question: "How does ultrasound help evaluate abnormal bleeding?", response: "Transvaginal ultrasound measures the thickness of the uterine lining and can detect fibroids, polyps, or other structural problems. Saline infusion sonography (sonohysterography) gives a clearer view inside the uterus and is often used when polyps or focal lesions are suspected." },
  { id: 2038, category: 'bleeding', keywords: ['progestin IUD for heavy bleeding'], question: "Can a hormonal IUD help with heavy or irregular bleeding?", response: "Yes. Progestin-releasing IUDs (such as Mirena or Liletta) significantly reduce menstrual bleeding and can make periods much lighter or stop them altogether. They are often a good long-term option for managing abnormal uterine bleeding without surgery." },
  { id: 2039, category: 'bleeding', keywords: ['treatment options for abnormal uterine bleeding'], question: "What are the main treatments for abnormal uterine bleeding?", response: "Treatment depends on the cause and may include hormonal birth control pills, progestin therapy, a progestin IUD, or procedures such as endometrial ablation, hysteroscopy to remove polyps, or surgery (myomectomy or hysterectomy) for fibroids or persistent bleeding." },
  { id: 2040, category: 'bleeding', keywords: ['red flags for abnormal uterine bleeding'], question: "What bleeding symptoms need prompt medical attention?", response: "Seek care for very heavy bleeding, bleeding that soaks through protection hourly, bleeding with dizziness or fainting, bleeding after menopause, or bleeding accompanied by severe pain or fever. These can signal significant blood loss or other serious issues." },

  // === NEW UpToDate Menopausal Transition & Menopause Clinical RAG Entries (IDs 2049–2057) ===
  { id: 2049, category: 'menopause', keywords: ['STRAW staging system menopause'], question: "What is the STRAW staging system for menopause?", response: "The Stages of Reproductive Aging Workshop (STRAW) system is the gold standard for describing reproductive aging. It divides the menopausal transition into early and late stages based on menstrual cycle changes, with supportive endocrine findings. It helps clinicians and patients understand what to expect and guides counseling about fertility, contraception, and symptoms." },
  { id: 2050, category: 'menopause', keywords: ['early vs late menopausal transition'], question: "What is the difference between early and late menopausal transition?", response: "In the early transition, menstrual cycles vary by 7 or more days. In the late transition, cycles become more irregular with skipped periods and longer stretches of amenorrhea. Hot flashes become more common in the late transition. The late stage typically lasts 1-3 years before the final menstrual period." },
  { id: 2051, category: 'menopause', keywords: ['when to measure FSH for menopause'], question: "When should FSH be measured to diagnose menopause or perimenopause?", response: "FSH is often not necessary in women over 45 with typical symptoms and irregular cycles. A single FSH level can be misleading because levels fluctuate widely during the transition. FSH is more useful in women under 45 with irregular cycles or when the diagnosis is unclear. A level >25 IU/L in the right clinical context supports the late transition." },
  { id: 2052, category: 'menopause', keywords: ['diagnosis of menopause by age'], question: "How is menopause diagnosed in women over 45 vs under 45?", response: "In women over 45, menopause is diagnosed clinically after 12 months of amenorrhea with no other cause. In women 40-45, other causes of amenorrhea should be ruled out (pregnancy, hyperprolactinemia, thyroid disease). In women under 40, primary ovarian insufficiency should be considered and fully evaluated." },
  { id: 2053, category: 'menopause', keywords: ['hot flashes timing in menopause transition'], question: "When do hot flashes typically start and how long do they last?", response: "Hot flashes often begin in the early menopausal transition and peak in frequency during the late transition and early postmenopause. On average they last 7-10 years, but can persist for 15-20 years in some women. They are more common at night (night sweats) and significantly impact sleep and quality of life." },
  { id: 2054, category: 'menopause', keywords: ['abnormal bleeding in perimenopause evaluation'], question: "When should abnormal bleeding in perimenopause be evaluated?", response: "Evaluate bleeding that occurs more often than every 3 weeks, is very heavy or prolonged, occurs between periods, or happens after 12 months of amenorrhea. While irregular bleeding is common, these patterns warrant investigation for structural causes, hyperplasia, or (less commonly) malignancy." },
  { id: 2055, category: 'menopause', keywords: ['genitourinary syndrome of menopause'], question: "What is genitourinary syndrome of menopause (GSM)?", response: "GSM refers to symptoms caused by low estrogen and androgen levels affecting the vulva, vagina, urethra, and bladder. It includes vaginal dryness, burning, painful sex, and urinary symptoms. Symptoms often appear later than hot flashes and respond well to low-dose vaginal estrogen or non-hormonal moisturizers." },
  { id: 2056, category: 'menopause', keywords: ['mood changes in perimenopause'], question: "Are mood changes common during the menopausal transition?", response: "Yes. There is an increased risk of new or recurrent depression and anxiety during perimenopause, especially in women with a prior history. Symptoms often improve after the final menstrual period. Both hormonal changes and sleep disruption contribute. Effective treatments are available." },
  { id: 2057, category: 'menopause', keywords: ['primary ovarian insufficiency vs early menopause'], question: "What is the difference between primary ovarian insufficiency and early menopause?", response: "Primary ovarian insufficiency (premature ovarian failure) occurs before age 40. Early menopause occurs between ages 40 and 45. Both are associated with higher risks of cardiovascular disease, bone loss, and cognitive concerns compared with menopause at the average age." },

  // === NEW UpToDate Menopausal Hormone Therapy RAG Entries (IDs 2066–2075) ===
  { id: 2066, category: 'menopause', keywords: ['what is menopausal hormone therapy'], question: "What is menopausal hormone therapy?", response: "Menopausal hormone therapy uses estrogen (and progestin if you have a uterus) to relieve bothersome menopause symptoms like hot flashes and vaginal dryness. Estrogen is the hormone that treats the symptoms. Progestin is added to protect the uterine lining from overgrowth when you still have a uterus." },
  { id: 2067, category: 'menopause', keywords: ['estrogen patch vs pill menopause'], question: "Is the estrogen patch better than pills for menopause?", response: "Many experts prefer the estradiol patch over pills because it has a lower risk of blood clots. Both are effective for hot flashes and bone health. The patch is changed once or twice a week depending on the brand." },
  { id: 2068, category: 'menopause', keywords: ['why take progestin with estrogen'], question: "Why do I need to take progestin if I take estrogen after menopause?", response: "If you still have a uterus, estrogen alone can cause the uterine lining to thicken and increase the risk of uterine cancer or precancer. Taking progestin (or using a levonorgestrel IUD) protects the lining. If you've had a hysterectomy, you can take estrogen alone." },
  { id: 2069, category: 'menopause', keywords: ['is hormone therapy safe after menopause'], question: "Is menopausal hormone therapy safe?", response: "For most healthy people under age 60 or within 10 years of menopause onset, hormone therapy is considered safe and effective for treating hot flashes and other symptoms. Risks are higher if started many years after menopause or in people with certain medical conditions." },
  { id: 2070, category: 'menopause', keywords: ['breast cancer risk hormone therapy menopause'], question: "Does hormone therapy increase breast cancer risk?", response: "The increase in breast cancer risk with combined estrogen-progestin therapy is small, especially in the first 5 years and in younger users. Estrogen alone (for those without a uterus) does not appear to increase breast cancer risk and may even slightly lower it. Individual risk depends on personal and family history." },
  { id: 2071, category: 'menopause', keywords: ['who should not take hormone therapy'], question: "Who should avoid menopausal hormone therapy?", response: "Hormone therapy is generally not recommended if you have a current or past history of breast cancer, coronary heart disease, a previous blood clot, heart attack, or stroke, active liver disease, or unexplained abnormal bleeding. Your doctor will review your personal risks." },
  { id: 2072, category: 'menopause', keywords: ['how long can I stay on hormone therapy'], question: "How long can I stay on menopausal hormone therapy?", response: "This is individualized. Some experts suggest trying to taper after about 5 years, while others support longer use if symptoms persist and benefits outweigh risks. Many women need therapy for 7-10+ years because hot flashes can last a long time. Discuss your personal situation with your clinician." },
  { id: 2073, category: 'menopause', keywords: ['vaginal estrogen after menopause'], question: "What is low-dose vaginal estrogen used for?", response: "Low-dose vaginal estrogen (cream, tablet, or ring) treats genitourinary syndrome of menopause — vaginal dryness, burning, painful sex, and some urinary symptoms. It has very low absorption into the bloodstream and does not usually require progestin. It does not treat hot flashes." },
  { id: 2074, category: 'menopause', keywords: ['compounded bioidentical hormones'], question: "Are compounded bioidentical hormones recommended?", response: "No. Expert groups do not recommend compounded bioidentical hormone products. They are not FDA-regulated like standard hormone therapy, and there is no good evidence they are safer or more effective. Approved estradiol and micronized progesterone are already bioidentical." },
  { id: 2075, category: 'menopause', keywords: ['low dose birth control pill perimenopause'], question: "Can I use a low-dose birth control pill in perimenopause?", response: "Very low-dose birth control pills can be a good option in your 40s if you have hot flashes, irregular bleeding, and still need reliable contraception. They are generally not recommended after menopause because the estrogen dose is higher than needed for symptom relief." },

  // === NEW UpToDate Menopausal Hormone Therapy Clinical RAG Entries (IDs 2081–2090) ===
  { id: 2081, category: 'menopause', keywords: ['first line estrogen for menopause'], question: "What is the preferred estrogen for menopausal hormone therapy?", response: "17-beta estradiol is preferred because it is structurally identical to the main estrogen produced by the ovaries. Transdermal estradiol is often favored over oral due to a lower risk of blood clots and stroke, though oral estradiol remains a reasonable option for many women without specific risk factors." },
  { id: 2082, category: 'menopause', keywords: ['transdermal vs oral estrogen menopause'], question: "When should transdermal estrogen be preferred over oral estrogen?", response: "Transdermal estradiol is generally preferred in women with hypertriglyceridemia, active gallbladder disease, known thrombophilias (such as factor V Leiden), or migraine with aura. It has a lower risk of venous thromboembolism and stroke compared with oral estrogen." },
  { id: 2083, category: 'menopause', keywords: ['progestogen choice with estrogen'], question: "What is the preferred progestogen to use with estrogen after menopause?", response: "Micronized progesterone (natural progesterone) is often preferred. It is metabolically neutral, has a good safety profile for the breast and cardiovascular system, and is effective for endometrial protection. It is usually given as 200 mg for 12 days per month (cyclic) or 100 mg daily (continuous)." },
  { id: 2084, category: 'menopause', keywords: ['who is a candidate for menopausal hormone therapy'], question: "Who is a good candidate for menopausal hormone therapy?", response: "Healthy women with bothersome vasomotor symptoms who are within 10 years of menopause onset or under age 60, and who have no contraindications (such as breast cancer, coronary heart disease, prior stroke, or VTE), are generally good candidates. Benefits usually outweigh risks in this group." },
  { id: 2085, category: 'menopause', keywords: ['who should avoid menopausal hormone therapy'], question: "Who should avoid menopausal hormone therapy?", response: "MHT is generally avoided in women with a history of breast cancer, coronary heart disease, prior VTE or stroke, active liver disease, or unexplained vaginal bleeding. Individual risk assessment (cardiovascular and breast cancer risk) should guide decisions." },
  { id: 2086, category: 'menopause', keywords: ['starting dose of estradiol menopause'], question: "What starting dose of estradiol is recommended for menopausal symptoms?", response: "Many clinicians now start with lower doses (e.g., transdermal estradiol 0.025 mg or oral estradiol 0.5 mg daily) and titrate upward based on symptom relief. Higher starting doses (transdermal 0.05 mg or oral 1 mg) may be used for more severe symptoms." },
  { id: 2087, category: 'menopause', keywords: ['cyclic vs continuous hormone therapy'], question: "When is cyclic versus continuous combined hormone therapy preferred?", response: "Cyclic regimens (estrogen daily + progestogen for 12 days per month) are often used in perimenopausal or recently postmenopausal women and usually cause monthly withdrawal bleeding. Continuous regimens (both hormones daily) are preferred once women are further from menopause and want to avoid bleeding." },
  { id: 2088, category: 'menopause', keywords: ['duration of menopausal hormone therapy'], question: "How long should menopausal hormone therapy be used?", response: "Use is individualized. Many women benefit from 3-5 years, but hot flashes often last 7-10+ years. Extended use beyond age 60 or 65 can be reasonable in selected women with persistent severe symptoms when benefits outweigh risks and after shared decision-making." },
  { id: 2089, category: 'menopause', keywords: ['tapering menopausal hormone therapy'], question: "How should menopausal hormone therapy be stopped or tapered?", response: "Abrupt cessation can cause return of hot flashes. Gradual tapering (e.g., reducing by one pill per week every few weeks, or stepping down patch strength over months) is often better tolerated. Nonhormonal therapies can be started during the taper to help manage recurrent symptoms." },
  { id: 2090, category: 'menopause', keywords: ['compounded bioidentical hormones'], question: "Are compounded bioidentical hormones recommended for menopause?", response: "No. Major expert societies advise against routine use of compounded bioidentical hormone therapy. They lack rigorous safety and efficacy data, are not FDA-regulated like approved products, and potency can be inconsistent. Approved estradiol and micronized progesterone are already bioidentical." },

  // === NEW UpToDate Biology & Epidemiology of Menopause RAG Entries (IDs 2099–2108) ===
  { id: 2099, category: 'menopause', keywords: ['ovarian follicular atresia'], question: "What causes the decline in ovarian follicles over a woman's lifetime?", response: "From fetal life onward, there is continuous follicular growth and atresia. Most follicles undergo atresia (degeneration) rather than ovulation. This leads to a steady exponential decline in oocyte number, which accelerates in the years before menopause." },
  { id: 2100, category: 'menopause', keywords: ['oocyte number at birth and menopause'], question: "How many oocytes does a woman have at birth and at menopause?", response: "A female fetus reaches a peak of approximately 7 million germ cells around 5 months of gestation. By birth, this has declined to about 1-2 million. By menopause, very few (or no) viable oocytes remain due to ongoing atresia throughout life." },
  { id: 2101, category: 'menopause', keywords: ['inhibin B and menopause transition'], question: "What role does inhibin B play in the menopausal transition?", response: "Inhibin B, produced by small growing follicles, declines as follicle numbers decrease. This is one of the earliest hormonal changes in the menopausal transition and contributes to the rise in FSH before estradiol levels fall significantly." },
  { id: 2102, category: 'menopause', keywords: ['AMH as marker of ovarian reserve'], question: "How useful is anti-Müllerian hormone (AMH) as a marker of reproductive aging?", response: "AMH, produced by small growing follicles, declines steadily with age and is a good marker of remaining ovarian reserve. Low AMH levels correlate with a shorter time to menopause and poorer response to ovarian stimulation, though it is not routinely used to diagnose menopause itself." },
  { id: 2103, category: 'menopause', keywords: ['early vs late menopausal transition endocrine changes'], question: "What are the key endocrine changes in the early and late menopausal transition?", response: "In the early transition, inhibin B falls and FSH begins to rise while estradiol is often preserved. In the late transition, cycle irregularity increases, FSH rises further, and estradiol levels begin to fluctuate more dramatically and eventually decline." },
  { id: 2104, category: 'menopause', keywords: ['factors affecting age at menopause'], question: "What factors influence the age at which a woman reaches menopause?", response: "Genetics play a major role. Other factors include smoking (advances menopause by 1-2 years), ethnicity, night shift work, and hysterectomy (even with ovarian conservation). Family history of early menopause increases risk." },
  { id: 2105, category: 'menopause', keywords: ['STRAW staging system menopause'], question: "What is the STRAW staging system used for?", response: "The Stages of Reproductive Aging Workshop (STRAW) system is the standard framework for describing reproductive aging. It defines stages from the late reproductive years through the menopausal transition, final menstrual period, and postmenopause based on bleeding patterns, symptoms, and endocrine changes." },
  { id: 2106, category: 'menopause', keywords: ['does night shift work affect menopause age'], question: "Does night shift work affect the age of menopause?", response: "Yes. Women who work rotating night shifts for more than 20 months in a two-year period have a modestly increased risk of earlier menopause, particularly menopause before age 45. This may be related to circadian disruption or associated stress and fatigue." },
  { id: 2107, category: 'menopause', keywords: ['oocyte viability decline with age'], question: "Why does fertility decline before menopause?", response: "Oocyte quality (viability) declines with age even before there is a measurable drop in hormone levels. This contributes to reduced fertility, higher miscarriage rates, and chromosomal abnormalities in pregnancies of women in their late 30s and 40s." },
  { id: 2108, category: 'menopause', keywords: ['neuroendocrine changes with menopause'], question: "Are there neuroendocrine changes that contribute to menopause?", response: "Yes. Aging affects the hypothalamus and pituitary as well as the ovaries. Postmenopausal women secrete FSH and LH with altered carbohydrate content and longer half-lives. There may also be reduced hypothalamic-pituitary sensitivity to estrogen feedback during the transition." },

  // === NEW UpToDate Hot Flashes RAG Entries (IDs 2113–2122) ===
  { id: 2113, category: 'hot flashes', keywords: ['how common are hot flashes'], question: "How common are hot flashes during menopause?", response: "Hot flashes occur in up to 80% of women during the menopausal transition. They are most frequent in the late transition and early postmenopause. Only about 20-30% of women seek medical treatment for them." },
  { id: 2114, category: 'hot flashes', keywords: ['how long do hot flashes last'], question: "How long do hot flashes typically last?", response: "Hot flashes often persist for many years. The median total duration is about 7.4 years, with symptoms continuing for a median of 4.5 years after the final menstrual period. Some women experience them for 10-20 years or longer." },
  { id: 2115, category: 'hot flashes', keywords: ['pathophysiology of hot flashes'], question: "What causes hot flashes?", response: "Hot flashes result from thermoregulatory dysfunction in the hypothalamus triggered by estrogen withdrawal. KNDy (kisspeptin/neurokinin B/dynorphin) neurons in the hypothalamus are thought to play a central role in mediating both the hormonal pulses and the temperature changes." },
  { id: 2116, category: 'hot flashes', keywords: ['impact of hot flashes on sleep'], question: "How do hot flashes affect sleep?", response: "Hot flashes (especially night sweats) are a major cause of sleep disruption in perimenopausal and postmenopausal women. They often cause awakenings, and women with frequent hot flashes report more insomnia, fatigue, and mood symptoms." },
  { id: 2117, category: 'hot flashes', keywords: ['hormone therapy for hot flashes'], question: "How effective is hormone therapy for hot flashes?", response: "Menopausal hormone therapy (estrogen +/- progestin) is the most effective treatment for hot flashes. It typically reduces frequency and severity by 75% or more. It is the preferred option for most healthy women with moderate to severe symptoms who have no contraindications." },
  { id: 2118, category: 'hot flashes', keywords: ['nonhormonal treatments for hot flashes'], question: "What nonhormonal treatments work for hot flashes?", response: "Effective nonhormonal options include certain SSRIs/SNRIs (e.g., escitalopram, venlafaxine, desvenlafaxine), gabapentin, and neurokinin 3 receptor antagonists (fezolinetant and elinzanetant). These are good choices for women who cannot or prefer not to use hormone therapy." },
  { id: 2119, category: 'hot flashes', keywords: ['fezolinetant for hot flashes'], question: "How effective is fezolinetant for hot flashes?", response: "Fezolinetant, a neurokinin 3 receptor antagonist, significantly reduces both the frequency and severity of hot flashes. It is a nonhormonal option approved for moderate to severe vasomotor symptoms. Liver function monitoring is now recommended due to rare cases of hepatotoxicity." },
  { id: 2120, category: 'hot flashes', keywords: ['hot flashes in breast cancer survivors'], question: "How are hot flashes managed in women with breast cancer?", response: "Hormone therapy is generally avoided. Nonhormonal options such as SSRIs/SNRIs (avoiding strong CYP2D6 inhibitors like paroxetine in women on tamoxifen), gabapentin, or fezolinetant/elinzanetant are preferred. Neurokinin antagonists are particularly useful in this population." },
  { id: 2121, category: 'hot flashes', keywords: ['when to use gabapentin for hot flashes'], question: "When is gabapentin useful for hot flashes?", response: "Gabapentin (especially at bedtime) can be effective for hot flashes, particularly when they disrupt sleep. It is a good nonhormonal option for women who cannot take hormone therapy or certain antidepressants. Dosing is often started low and titrated to effect (commonly 300-900 mg at night)." },
  { id: 2122, category: 'hot flashes', keywords: ['therapies not recommended for hot flashes'], question: "Which therapies are not recommended for hot flashes?", response: "The Menopause Society does not recommend paced respiration, most herbal supplements, soy, acupuncture, exercise, yoga, or clonidine as primary treatments for hot flashes due to limited or inconsistent evidence of benefit beyond placebo." },

  // === NEW UpToDate Combined Oral Contraceptives (COCs) RAG Entries (IDs 2129–2138) ===
  { id: 2129, category: 'contraception', keywords: ['how to choose a birth control pill'], question: "How do I choose the right birth control pill?", response: "Most women do well on a generic, monophasic, low-dose pill (20-35 mcg ethinyl estradiol). We usually start with a 24/4 regimen. The specific progestin matters less than consistent daily use. If you have a preference or specific symptoms (acne, heavy bleeding, mood changes), tell your clinician so they can tailor the choice." },
  { id: 2130, category: 'contraception', keywords: ['how do birth control pills work'], question: "How do combined birth control pills prevent pregnancy?", response: "They mainly work by stopping ovulation through suppression of FSH and the LH surge. They also thicken cervical mucus (making it harder for sperm to enter) and thin the uterine lining so a fertilized egg is less likely to implant." },
  { id: 2131, category: 'contraception', keywords: ['who should not take birth control pills'], question: "Who should not take combined birth control pills?", response: "Women over 35 who smoke heavily, those with a history of blood clots, stroke, heart attack, breast cancer, migraine with aura, uncontrolled high blood pressure, or certain liver diseases should generally avoid combined pills. Your clinician will review your full medical history before prescribing." },
  { id: 2132, category: 'contraception', keywords: ['monophasic vs triphasic birth control pills'], question: "What is the difference between monophasic and triphasic birth control pills?", response: "Monophasic pills have the same hormone dose every day. Triphasic (or multiphasic) pills change the hormone levels during the cycle. Monophasic pills are usually preferred because they are simpler to use, especially if you want to skip periods or use them continuously." },
  { id: 2133, category: 'contraception', keywords: ['continuous or extended cycle birth control pills'], question: "Can I take birth control pills continuously to skip my period?", response: "Yes. You can take active pills continuously (no placebo week) or use extended-cycle packs (e.g., 84 active days). This safely reduces or eliminates periods. You may have more unpredictable spotting in the first few months, but it usually improves over time." },
  { id: 2134, category: 'contraception', keywords: ['what if I miss a birth control pill'], question: "What should I do if I miss a birth control pill?", response: "If you miss one pill, take it as soon as you remember and continue the pack as usual (you may take two pills in one day). If you miss two or more pills, use backup contraception (like condoms) for seven days and consider emergency contraception if you had unprotected sex, especially in the first week of the pack." },
  { id: 2135, category: 'contraception', keywords: ['quick start birth control pills'], question: "What is the quick-start method for birth control pills?", response: "Quick start means beginning the pill on the same day you get the prescription (as long as pregnancy is reasonably ruled out). It is convenient and effective. Use backup contraception for the first seven days." },
  { id: 2136, category: 'contraception', keywords: ['birth control pills and blood clot risk'], question: "Do birth control pills increase the risk of blood clots?", response: "Yes, combined pills slightly increase the risk of blood clots (deep vein thrombosis and pulmonary embolism). The absolute risk is still low for most healthy women, but it is higher if you smoke, are over 35, are obese, or have other risk factors. Pills with certain progestins may carry a slightly higher risk than others." },
  { id: 2137, category: 'contraception', keywords: ['birth control pills for perimenopause'], question: "Can I use birth control pills in perimenopause?", response: "Yes. Low-dose combined pills can help with hot flashes, irregular or heavy bleeding, and provide contraception. They are generally safe for healthy nonsmoking women until menopause. Discuss your individual risks with your clinician." },
  { id: 2138, category: 'contraception', keywords: ['birth control pills and antibiotics or seizure medications'], question: "Do antibiotics or seizure medications affect birth control pills?", response: "Most antibiotics do not reduce pill effectiveness. Rifampin is an exception. Some seizure medications (phenytoin, carbamazepine, etc.) can lower pill effectiveness. Always tell your clinician about all medications you take so they can advise you on backup contraception if needed." },

  // === NEW UpToDate DMPA (Depo-Provera) RAG Entries (IDs 2144–2152) ===
  { id: 2144, category: 'contraception', keywords: ['what is Depo Provera'], question: "What is Depo-Provera (DMPA)?", response: "Depo-Provera is a progestin-only birth control shot given every 3 months (13 weeks). It is highly effective, private, and does not require daily pills or action at the time of sex. It comes in two forms: an intramuscular shot (150 mg) and a subcutaneous shot (104 mg) that some people can self-administer." },
  { id: 2145, category: 'contraception', keywords: ['how does the Depo shot work'], question: "How does the Depo-Provera shot prevent pregnancy?", response: "It mainly works by stopping ovulation. It also thickens cervical mucus (making it harder for sperm to reach the egg) and thins the uterine lining. These effects last for about 3 months after each injection." },
  { id: 2146, category: 'contraception', keywords: ['who is a good candidate for Depo shot'], question: "Who is a good candidate for the Depo-Provera shot?", response: "It is a good option for people who want highly effective contraception without daily pills, those who cannot use estrogen, people who want to reduce or stop periods, and those who may have trouble remembering daily methods. It is especially useful for adolescents and people who want privacy." },
  { id: 2147, category: 'contraception', keywords: ['Depo shot timing and quick start'], question: "When can I start the Depo-Provera shot?", response: "You can start it any time as long as pregnancy is reasonably ruled out. The ideal time is within the first 7 days of your period. It can also be started the same day (quick start) with backup contraception for the first 7 days." },
  { id: 2148, category: 'contraception', keywords: ['how late can I get my Depo shot'], question: "How late can I get my next Depo shot?", response: "You should get it every 13 weeks. You can receive it up to 15 weeks (2 weeks late) without needing backup contraception. If you are more than 15 weeks late, pregnancy should be ruled out and backup contraception used for 7 days after the injection." },
  { id: 2149, category: 'contraception', keywords: ['Depo shot and return to fertility'], question: "How long does it take to get pregnant after stopping Depo?", response: "Fertility can return, but it is often delayed. About 50% of people conceive within 10 months of their last shot. For some, it can take up to 18 months. If you want to get pregnant soon, another method may be better." },
  { id: 2150, category: 'contraception', keywords: ['Depo shot self administration'], question: "Can I give myself the Depo shot at home?", response: "Yes. The subcutaneous version (Depo-SubQ) can be self-administered at home after proper training. This option improves access and continuation rates for many people." },
  { id: 2151, category: 'contraception', keywords: ['Depo shot for perimenopause'], question: "Can I use the Depo shot in perimenopause?", response: "Yes. There is no upper age limit. It can suppress irregular bleeding and hot flashes. You can usually continue using it until your mid-50s. Menopause testing is less reliable while on Depo because it suppresses FSH." },
  { id: 2152, category: 'contraception', keywords: ['Depo shot and weight'], question: "Does weight affect how well the Depo shot works?", response: "No. Unlike some other hormonal methods, DMPA effectiveness is not reduced by higher body weight. It remains highly effective regardless of BMI." },

  // === NEW UpToDate Genitourinary Syndrome of Menopause (GSM) RAG Entries (IDs 2153–2161) ===
  { id: 2153, category: 'menopause', keywords: ['what is GSM genitourinary syndrome of menopause'], question: "What is genitourinary syndrome of menopause (GSM)?", response: "GSM is a collection of symptoms caused by low estrogen levels affecting the vulva, vagina, urethra, and bladder. It includes vaginal dryness, burning, irritation, painful sex, urinary urgency, and recurrent UTIs. It used to be called vaginal atrophy or atrophic vaginitis." },
  { id: 2154, category: 'menopause', keywords: ['common symptoms of GSM'], question: "What are the most common symptoms of GSM?", response: "Common symptoms include vaginal dryness, decreased lubrication during sex, pain with intercourse, vulvar burning or irritation, urinary urgency or burning, and more frequent urinary tract infections. Some people also notice vaginal itching or light bleeding after sex." },
  { id: 2155, category: 'menopause', keywords: ['why does GSM happen'], question: "Why does genitourinary syndrome of menopause happen?", response: "After menopause, estrogen levels drop dramatically. Estrogen helps keep the vaginal and urethral tissues thick, elastic, and well-lubricated. When estrogen is low, these tissues become thin, dry, and more fragile, leading to the symptoms of GSM." },
  { id: 2156, category: 'menopause', keywords: ['does GSM only happen after menopause'], question: "Can GSM happen before menopause?", response: "Yes. GSM can occur any time estrogen levels are low, including during breastfeeding, with certain medications (like aromatase inhibitors), after chemotherapy or radiation to the pelvis, or in people with primary ovarian insufficiency." },
  { id: 2157, category: 'menopause', keywords: ['how is GSM diagnosed'], question: "How is genitourinary syndrome of menopause diagnosed?", response: "GSM is diagnosed based on your symptoms and findings on pelvic exam. Classic signs include thinning and pallor of the vaginal tissues, loss of vaginal rugae (folds), dryness, and sometimes petechiae or easy bleeding. Lab tests are usually not needed." },
  { id: 2158, category: 'menopause', keywords: ['pelvic exam findings in GSM'], question: "What does a pelvic exam show in GSM?", response: "Exam findings may include pale or thin vaginal walls, loss of normal folds (rugae), dryness, introital narrowing, urethral prominence or eversion, and fragile tissue that bleeds easily. In more advanced cases, there may be labial resorption or fusion." },
  { id: 2159, category: 'menopause', keywords: ['GSM vs vaginal infection'], question: "How is GSM different from a vaginal infection?", response: "GSM causes dryness, burning, and painful sex without the thick discharge, strong odor, or itching typical of yeast or bacterial vaginosis. However, the changes from GSM can increase the risk of actual infections, so both can occur together." },
  { id: 2160, category: 'menopause', keywords: ['when to see a doctor for vaginal dryness'], question: "When should I see a doctor about vaginal dryness or painful sex after menopause?", response: "See your clinician if you have persistent dryness, pain with sex, urinary symptoms, or any bleeding after sex. These symptoms are common but very treatable, and it's important to rule out other causes like infection or skin conditions." },
  { id: 2161, category: 'menopause', keywords: ['GSM and urinary symptoms'], question: "Can GSM cause urinary problems?", response: "Yes. Low estrogen can affect the urethra and bladder, leading to urinary urgency, burning with urination, and more frequent urinary tract infections. This is why GSM is called \"genitourinary\" syndrome — it affects both genital and urinary tissues." },

  // === NEW UpToDate Abnormal Uterine Bleeding (AUB) Evaluation RAG Entries (IDs 2162–2170) ===
  { id: 2162, category: 'abnormal uterine bleeding', keywords: ['definition of abnormal uterine bleeding', 'AUB patterns'], question: "What are the main patterns of abnormal uterine bleeding?", response: "AUB includes bleeding that is too frequent (<24 days), infrequent (>38 days), irregular (cycle variance >7-9 days depending on age), prolonged (>8 days), heavy (interferes with quality of life), or occurs between periods (intermenstrual). Heavy menstrual bleeding is defined by its impact on the patient's life, not just volume." },
  { id: 2163, category: 'abnormal uterine bleeding', keywords: ['when to evaluate abnormal uterine bleeding'], question: "When should abnormal uterine bleeding be evaluated?", response: "Any single episode of postmenopausal bleeding needs evaluation. In reproductive-age patients, evaluate persistent or bothersome bleeding, heavy bleeding causing anemia or quality-of-life issues, intermenstrual bleeding, or bleeding with risk factors for endometrial cancer. A single isolated event in otherwise normal cycles may only need a menstrual diary." },
  { id: 2164, category: 'abnormal uterine bleeding', keywords: ['pregnancy test in abnormal bleeding'], question: "Should I always do a pregnancy test in patients with abnormal uterine bleeding?", response: "Yes. Pregnancy should be excluded in all reproductive-age patients with AUB, even if they report recent bleeding, no sexual activity, or contraceptive use. A urine hCG is a good start; use serum hCG if early pregnancy is still suspected despite a negative urine test." },
  { id: 2165, category: 'abnormal uterine bleeding', keywords: ['heavy menstrual bleeding workup'], question: "What is the initial workup for heavy menstrual bleeding?", response: "Start with history, physical exam, pregnancy test, and CBC (to check for anemia). Consider ferritin, TSH, and bleeding disorder evaluation if indicated. Pelvic ultrasound is usually the first imaging test to look for fibroids, adenomyosis, or polyps. Endometrial sampling is added for patients with risk factors for hyperplasia or cancer." },
  { id: 2166, category: 'abnormal uterine bleeding', keywords: ['intermenstrual bleeding causes and evaluation'], question: "How should intermenstrual bleeding be evaluated?", response: "Intermenstrual bleeding often comes from polyps, cervicitis, endometritis, or cesarean scar defects. Perform pelvic ultrasound (consider saline infusion sonography) and endometrial sampling if risk factors for malignancy exist. Postcoital bleeding should prompt cervical evaluation." },
  { id: 2167, category: 'abnormal uterine bleeding', keywords: ['irregular bleeding ovulatory dysfunction'], question: "What causes irregular uterine bleeding and how is it evaluated?", response: "Irregular bleeding is most often due to ovulatory dysfunction (AUB-O), especially at the extremes of reproductive age. Check TSH, prolactin, and androgens if indicated. Endometrial sampling is recommended if irregular bleeding persists for 6 months or more due to unopposed estrogen risk." },
  { id: 2168, category: 'abnormal uterine bleeding', keywords: ['endometrial sampling indications age'], question: "When should I do endometrial sampling for abnormal uterine bleeding?", response: "For patients age 45 to menopause: sample for frequent, heavy, prolonged, or intermenstrual bleeding. For patients under 45: sample if bleeding persists 6 months or more plus obesity, chronic anovulation, failed medical therapy, or high-risk features (tamoxifen, Lynch syndrome). Obesity significantly raises risk at any age." },
  { id: 2169, category: 'abnormal uterine bleeding', keywords: ['imaging for abnormal uterine bleeding'], question: "What imaging is best for abnormal uterine bleeding?", response: "Pelvic ultrasound (transvaginal + transabdominal) is first-line. If intracavitary pathology is suspected, add saline infusion sonography (SIS) or hysteroscopy. SIS is often preferred for assessing fibroid depth and endometrial contour; hysteroscopy allows direct visualization and biopsy." },
  { id: 2170, category: 'abnormal uterine bleeding', keywords: ['iatrogenic abnormal bleeding contraceptives'], question: "Can birth control cause abnormal uterine bleeding?", response: "Yes. Combined pills, progestin-only methods, and IUDs (especially copper IUD) commonly cause unscheduled bleeding, lighter periods, or amenorrhea. This is expected and often does not require extensive workup unless bleeding is new, heavy, or accompanied by pain or other red flags." },

  // === NEW UpToDate Premenopausal Osteoporosis RAG Entries (IDs 2175–2183) ===
  { id: 2175, category: 'bone health', keywords: ['premenopausal osteoporosis definition'], question: "How is osteoporosis defined in premenopausal women?", response: "In premenopausal women, osteoporosis is diagnosed by a history of fragility (low-trauma) fracture(s), especially at major sites like the spine or hip, or by low BMD (Z-score ≤-2.0 or T-score ≤-2.5) plus a known secondary cause of bone loss. Low BMD alone is not sufficient to diagnose osteoporosis in this population." },
  { id: 2176, category: 'bone health', keywords: ['ILBMD vs IOP premenopausal'], question: "What is the difference between idiopathic low BMD and idiopathic osteoporosis?", response: "Idiopathic low BMD (ILBMD) refers to low BMD (Z-score ≤-2.0) with no fragility fracture and no identifiable primary or secondary cause after thorough evaluation. Idiopathic osteoporosis (IOP) refers to fragility fracture(s) with no identifiable cause. Pharmacologic treatment is generally not indicated for ILBMD but may be considered in IOP with major or multiple fractures." },
  { id: 2177, category: 'bone health', keywords: ['when to screen BMD premenopausal'], question: "When should bone density be measured in premenopausal women?", response: "Routine screening is not recommended. Measure BMD in premenopausal women who have had a fragility fracture or who have known secondary causes of bone loss (e.g., anorexia nervosa, celiac disease, glucocorticoid use, primary ovarian insufficiency, hyperparathyroidism)." },
  { id: 2178, category: 'bone health', keywords: ['initial evaluation low BMD premenopausal'], question: "What is the initial evaluation for a premenopausal woman with low BMD or fragility fracture?", response: "Perform a detailed history (menstrual, dietary, exercise, medications, fractures) and physical exam, plus basic labs: CBC, calcium, phosphate, creatinine, LFTs, 25-hydroxyvitamin D, TSH, and 24-hour urine calcium and creatinine. Further testing is guided by these results." },
  { id: 2179, category: 'bone health', keywords: ['treat underlying cause premenopausal osteoporosis'], question: "What is the first step in managing premenopausal osteoporosis?", response: "Identify and treat any underlying secondary cause (e.g., celiac disease, hyperparathyroidism, glucocorticoid use, eating disorder, hypogonadism). Addressing the root cause is the most important intervention and often leads to stabilization or improvement in BMD." },
  { id: 2180, category: 'bone health', keywords: ['when to use medication premenopausal osteoporosis'], question: "When should pharmacologic therapy be considered in premenopausal women with low BMD or fracture?", response: "Consider medication for women with fragility fracture at a major site (spine, hip), multiple fragility fractures, or very low BMD (Z-score ≤-3.0) plus fracture. Also consider it in high-risk secondary causes that cannot be quickly corrected (e.g., ongoing high-dose glucocorticoids). Low BMD alone without fracture or high-risk features usually does not require medication." },
  { id: 2181, category: 'bone health', keywords: ['teriparatide vs bisphosphonate premenopausal'], question: "When is teriparatide preferred over bisphosphonates in premenopausal women?", response: "Teriparatide (anabolic therapy) is often preferred first-line in women at highest fracture risk — those with vertebral or hip fracture, very low BMD plus fracture, or those planning pregnancy in the near term. Bisphosphonates are reasonable alternatives but carry concerns about long skeletal retention in reproductive-age women." },
  { id: 2182, category: 'bone health', keywords: ['bisphosphonates pregnancy premenopausal osteoporosis'], question: "Can bisphosphonates be used in women who may become pregnant?", response: "Bisphosphonates have a long half-life in bone and should be used with caution in reproductive-age women. Oral agents are generally preferred over IV zoledronic acid if treatment is needed. Discuss risks and consider teriparatide first if pregnancy is planned soon." },
  { id: 2183, category: 'bone health', keywords: ['monitoring BMD premenopausal osteoporosis'], question: "How should premenopausal women with low BMD or osteoporosis be monitored?", response: "Remeasure BMD annually after starting pharmacologic or intensive nonpharmacologic treatment. A loss of 3-5% or more per year is concerning and may prompt treatment change or further evaluation for ongoing secondary causes." },

  // === NEW UpToDate Female Sexual Dysfunction Evaluation RAG Entries (IDs 2184–2193) ===
  { id: 2184, category: 'sexual health', keywords: ['how common is female sexual dysfunction'], question: "How common is female sexual dysfunction?", response: "Approximately 40% of females worldwide report sexual problems, but only about 12% have a sexual problem associated with personal or interpersonal distress (meeting criteria for sexual dysfunction). Low desire is the most common concern, followed by arousal and orgasm difficulties." },
  { id: 2185, category: 'sexual health', keywords: ['female sexual response cycle'], question: "How does the female sexual response cycle differ from the traditional model?", response: "The traditional four-phase model (desire → arousal → orgasm → resolution) does not fit many females well. Desire often emerges in response to arousal rather than preceding it, especially in long-term relationships. Phases can overlap, repeat, or be absent, and satisfaction does not always require orgasm." },
  { id: 2186, category: 'sexual health', keywords: ['GSM and sexual dysfunction'], question: "How does genitourinary syndrome of menopause affect sexual function?", response: "GSM causes vaginal dryness, reduced lubrication, tissue fragility, and dyspareunia due to estrogen deficiency. These physical changes often lead to decreased desire and arousal. Treating GSM (with vaginal estrogen or non-hormonal options) frequently improves overall sexual function." },
  { id: 2187, category: 'sexual health', keywords: ['role of testosterone in female sexuality'], question: "Does low testosterone cause low libido in females?", response: "The relationship is unclear. Most studies show little or no correlation between normal-range androgen levels and sexual desire or function. Supraphysiologic doses of testosterone can increase desire, but routine testing of testosterone levels is not recommended for evaluating sexual dysfunction in females." },
  { id: 2188, category: 'sexual health', keywords: ['how to screen for sexual dysfunction'], question: "How should clinicians screen for sexual concerns in females?", response: "Ask a simple, nonjudgmental question such as \"Do you have any sexual concerns?\" as part of routine gynecologic care. If concerns are raised, schedule a dedicated follow-up visit for a full sexual history. Many patients appreciate being asked and will not bring it up unless prompted." },
  { id: 2189, category: 'sexual health', keywords: ['key risk factors for female sexual dysfunction'], question: "What are the major risk factors for female sexual dysfunction?", response: "Key risk factors include relationship difficulties, history of sexual or physical abuse, depression/anxiety, fatigue and stress, genitourinary syndrome of menopause, pelvic floor disorders, certain medications (especially SSRIs), and medical conditions that affect energy, body image, or pelvic health." },
  { id: 2190, category: 'sexual health', keywords: ['sexual history questions female dysfunction'], question: "What key questions should be asked when taking a sexual history?", response: "Ask about onset (lifelong vs acquired), context (generalized vs situational), associated distress, relationship quality, partner sexual function, history of trauma or abuse, and any physical symptoms (dryness, pain, incontinence). Also explore medications, mood, and life stressors." },
  { id: 2191, category: 'sexual health', keywords: ['when to do pelvic exam for sexual dysfunction'], question: "When is a pelvic exam needed in the evaluation of female sexual dysfunction?", response: "A pelvic exam is required to diagnose sexual pain disorders (dyspareunia, vaginismus, GSM). It is also recommended for any sexual concern to assess for atrophy, prolapse, pelvic floor hypertonus, tenderness, or other gynecologic contributors." },
  { id: 2192, category: 'sexual health', keywords: ['should I check hormone levels for low libido'], question: "Should I check testosterone or estrogen levels in a woman with low libido?", response: "No. Serum androgen levels do not reliably predict sexual function in females, and available assays for low female-range levels are often unreliable. Estrogen testing is also not useful. Focus on history, relationship factors, and treatable conditions like GSM instead." },
  { id: 2193, category: 'sexual health', keywords: ['SSRIs and female sexual dysfunction'], question: "How do SSRIs affect female sexual function?", response: "SSRIs commonly cause decreased libido and difficulty with orgasm. Management options include switching to bupropion, dose reduction, drug holidays, or adding agents that may counteract sexual side effects. Discuss this proactively when starting SSRIs." },

  // === NEW UpToDate PMS & PMDD Diagnosis RAG Entries (IDs 2194–2202) ===
  { id: 2194, category: 'PMDD', keywords: ['difference between PMS and PMDD'], question: "What is the difference between PMS and PMDD?", response: "PMS involves one or more physical or behavioral symptoms that cause some impairment and occur in the luteal phase. PMDD is more severe and requires at least 5 symptoms (one of which must be affective, such as irritability, mood swings, anxiety, or hopelessness) that cause significant distress or functional impairment. PMDD is diagnosed using DSM-5 criteria." },
  { id: 2195, category: 'PMDD', keywords: ['most common symptoms of PMDD'], question: "What are the most common symptoms of PMDD?", response: "The hallmark symptoms of PMDD are affective: irritability/anger, mood swings, anxiety/tension, and depressed mood or hopelessness. Common physical symptoms include bloating, breast tenderness, fatigue, and headaches. Irritability is often the most prominent and distressing symptom." },
  { id: 2196, category: 'PMDD', keywords: ['timing of PMS PMDD symptoms'], question: "When do PMS and PMDD symptoms typically occur?", response: "Symptoms begin in the late luteal phase (usually the 4–5 days before menses) and resolve within a few days after menses starts. There should be a clear symptom-free interval in the follicular phase. Symptoms lasting throughout the entire cycle suggest another diagnosis." },
  { id: 2197, category: 'PMDD', keywords: ['how to diagnose PMDD'], question: "How is PMDD diagnosed?", response: "Diagnosis requires prospective daily symptom tracking for at least two cycles using a validated tool (such as the Daily Record of Severity of Problems – DRSP). At least 5 symptoms must be present in the late luteal phase (one affective), cause significant distress or impairment, and resolve after menses. Other medical and psychiatric conditions must be ruled out." },
  { id: 2198, category: 'PMDD', keywords: ['prospective symptom tracking DRSP'], question: "Why is prospective symptom tracking important for diagnosing PMDD?", response: "Retrospective recall is often inaccurate. Prospective daily charting (ideally for 2 cycles) confirms that symptoms are truly cyclical, limited to the luteal phase, and associated with impairment. This helps differentiate PMDD from ongoing mood disorders, which may worsen premenstrually but persist throughout the cycle." },
  { id: 2199, category: 'PMDD', keywords: ['PMDD vs premenstrual exacerbation of depression'], question: "How do you distinguish PMDD from premenstrual exacerbation of a mood disorder?", response: "In PMDD, symptoms are absent or minimal during the follicular phase. In premenstrual exacerbation of depression or anxiety, symptoms are present throughout the cycle but worsen before menses. Prospective charting is essential to make this distinction." },
  { id: 2200, category: 'PMDD', keywords: ['when to check TSH in PMDD evaluation'], question: "Should thyroid function be checked when evaluating PMDD?", response: "Yes. A TSH should be checked to rule out hyperthyroidism or hypothyroidism, both of which can cause mood and physical symptoms that overlap with PMS/PMDD. Other routine hormone testing (estradiol, progesterone, FSH) is not helpful for diagnosis." },
  { id: 2201, category: 'PMDD', keywords: ['PMDD in women without periods'], question: "Can PMDD be diagnosed in women without periods (e.g., after hysterectomy or with LNG-IUD)?", response: "Yes, but it is more challenging. Diagnosis relies on prospective symptom charting showing a clear ~28-35 day cyclical pattern of symptoms with a symptom-free interval, even without visible menses. Ovulation must still be occurring for true PMDD to be present." },
  { id: 2202, category: 'PMDD', keywords: ['suicidality in PMDD'], question: "Is there increased suicide risk in PMDD?", response: "Yes. Individuals with PMDD, especially those with more severe symptoms, have an elevated risk of suicidal ideation and attempts. Clinicians should screen for suicidal thoughts and refer promptly to mental health support when indicated." },

  // === NEW UpToDate Osteoporosis Treatment RAG Entries (IDs 2203–2211) ===
  { id: 2203, category: 'bone health', keywords: ['when to treat osteoporosis postmenopausal'], question: "Who should receive pharmacologic treatment for osteoporosis?", response: "Postmenopausal women with a fragility fracture, T-score ≤-2.5, or high 10-year fracture risk by FRAX (≥20% major osteoporotic fracture or ≥3% hip fracture in the US) should receive pharmacologic therapy. Treatment is especially important after a recent hip or vertebral fracture." },
  { id: 2204, category: 'bone health', keywords: ['first line treatment postmenopausal osteoporosis'], question: "What is first-line pharmacologic therapy for most postmenopausal women with osteoporosis?", response: "Oral bisphosphonates (alendronate or risedronate) are first-line for most women due to proven fracture reduction, cost, and long-term safety data. They are contraindicated in women with esophageal disorders, inability to remain upright, or eGFR <30-35 mL/min." },
  { id: 2205, category: 'bone health', keywords: ['anabolic therapy very high fracture risk'], question: "When should anabolic therapy be used first for osteoporosis?", response: "Anabolic agents (teriparatide, abaloparatide, or romosozumab) are preferred as initial therapy in women with very high fracture risk, such as T-score ≤-3.0, T-score ≤-2.5 plus fragility fracture, or multiple/severe fractures. These agents build bone more effectively than antiresorptives in the highest-risk patients." },
  { id: 2206, category: 'bone health', keywords: ['bisphosphonate vs denosumab postmenopausal'], question: "When is denosumab preferred over bisphosphonates?", response: "Denosumab is a good option when oral or IV bisphosphonates are contraindicated or not tolerated, in patients with eGFR <30 mL/min, or when greater BMD gains are needed. Note that vertebral fracture risk rises after stopping denosumab, so long-term planning is required." },
  { id: 2207, category: 'bone health', keywords: ['lifestyle measures osteoporosis postmenopausal'], question: "What lifestyle measures are recommended for all postmenopausal women?", response: "All women should ensure adequate calcium (approximately 1200 mg/day total) and vitamin D (800 IU/day), engage in regular weight-bearing and muscle-strengthening exercise, stop smoking, limit alcohol, and take fall-prevention measures. These are foundational for everyone, regardless of pharmacotherapy." },
  { id: 2208, category: 'bone health', keywords: ['monitoring osteoporosis treatment DXA'], question: "How should response to osteoporosis treatment be monitored?", response: "Repeat DXA of the hip and spine after 1-2 years on therapy (same machine when possible). A significant change usually exceeds the least significant change (LSC) or approximately 5%. Also consider bone turnover markers (CTX, P1NP) if there is concern about adherence or effectiveness." },
  { id: 2209, category: 'bone health', keywords: ['low bone mass osteopenia treatment'], question: "When should women with low bone mass (osteopenia) receive medication?", response: "Most women with T-scores between -1.0 and -2.5 do not need pharmacotherapy unless they have high fracture risk by FRAX, a prior fragility fracture, or strong patient preference to prevent further loss. Decisions should be individualized through shared decision-making." },
  { id: 2210, category: 'bone health', keywords: ['calcium vitamin D postmenopausal osteoporosis'], question: "How much calcium and vitamin D do postmenopausal women need?", response: "Aim for total daily calcium intake of approximately 1200 mg (diet + supplements) and vitamin D 800 IU. Most women need supplementation to reach these targets. Higher doses may be needed in malabsorption or with certain medications." },
  { id: 2211, category: 'bone health', keywords: ['duration of bisphosphonate therapy'], question: "How long should bisphosphonates be continued?", response: "Duration is individualized. After 3-5 years of oral bisphosphonates (or 3 years of IV zoledronic acid), reassess fracture risk. A drug holiday may be appropriate in lower-risk patients, but high-risk women often continue or switch therapy. Re-evaluate with DXA and clinical risk factors." },

  // === NEW UpToDate Vaginal Hysterectomy RAG Entries (IDs 2212–2220) ===
  { id: 2212, category: 'surgery', keywords: ['what is vaginal hysterectomy'], question: "What is a vaginal hysterectomy?", response: "A vaginal hysterectomy is surgery to remove the uterus through the vagina (without an abdominal incision). The cervix is always removed with the uterus. One or both ovaries and fallopian tubes may also be removed. It generally has fewer complications, shorter hospital stay, and faster recovery than abdominal hysterectomy." },
  { id: 2213, category: 'surgery', keywords: ['reasons for vaginal hysterectomy'], question: "Why might someone need a vaginal hysterectomy?", response: "Common reasons include heavy or irregular bleeding that doesn't respond to other treatments, symptomatic fibroids, pelvic organ prolapse, cervical precancer that hasn't resolved with less invasive procedures, endometrial hyperplasia, or chronic pelvic pain. The decision depends on symptoms, age, desire for future pregnancy, and other health factors." },
  { id: 2214, category: 'surgery', keywords: ['should I keep my ovaries during hysterectomy'], question: "Should the ovaries be removed during hysterectomy?", response: "This is an individual decision. Premenopausal women often keep their ovaries to maintain natural hormone production and avoid early menopause symptoms. Postmenopausal women are often advised to have them removed due to the small lifetime risk of ovarian cancer. Women in the menopausal transition should discuss their personal risks and benefits with their surgeon." },
  { id: 2215, category: 'surgery', keywords: ['removing fallopian tubes but keeping ovaries'], question: "Can the fallopian tubes be removed while keeping the ovaries?", response: "Yes. Removing the fallopian tubes (salpingectomy) while preserving the ovaries may lower the small risk of one type of ovarian cancer. This is often recommended when ovaries are being kept, especially in perimenopausal or postmenopausal women." },
  { id: 2216, category: 'surgery', keywords: ['LAVH vs vaginal hysterectomy'], question: "What is laparoscopically-assisted vaginal hysterectomy (LAVH)?", response: "LAVH uses a laparoscope (and sometimes instruments) inserted through small abdominal incisions or the vagina to help remove the uterus through the vaginal opening. It may be used when the uterus is enlarged, there is scar tissue, endometriosis, or other factors that make a standard vaginal hysterectomy more difficult. Recovery is similar to vaginal hysterectomy." },
  { id: 2217, category: 'surgery', keywords: ['complications of vaginal hysterectomy'], question: "What are the possible complications of vaginal hysterectomy?", response: "Possible complications include bleeding, infection, blood clots, injury to the bladder, ureters, or bowel, urinary retention, and constipation. Serious complications are uncommon. Women who keep their ovaries may still experience earlier menopause due to changes in blood flow to the ovaries." },
  { id: 2218, category: 'surgery', keywords: ['recovery after vaginal hysterectomy'], question: "What is recovery like after vaginal hysterectomy?", response: "Most women go home the same day or the next morning. Full recovery usually takes 4-6 weeks. Patients should avoid heavy lifting, intercourse, and tampons during this time. Walking is encouraged to prevent blood clots. Many women notice improvement in bleeding, pain, and prolapse symptoms after recovery." },
  { id: 2219, category: 'surgery', keywords: ['alternatives to hysterectomy for heavy bleeding or fibroids'], question: "What are alternatives to hysterectomy for heavy bleeding or fibroids?", response: "Alternatives depend on the cause and may include hormonal medications (pills, IUD, injections), endometrial ablation, uterine artery embolization, myomectomy (removal of fibroids only), or focused ultrasound. These options allow preservation of the uterus and future fertility in some cases." },
  { id: 2220, category: 'surgery', keywords: ['life after hysterectomy sexual function'], question: "How does vaginal hysterectomy affect sexual function?", response: "Most women report improvement in sexual function, enjoyment, and reduction in pain after hysterectomy, especially when surgery was done for heavy bleeding or prolapse. Some younger women experience grief related to loss of fertility. New or persistent sexual difficulties, mood changes, or pelvic pain should be discussed with a clinician." },

  // === NEW UpToDate Female Sexual Dysfunction Management RAG Entries (IDs 2221–2229) ===
  { id: 2221, category: 'sexual health', keywords: ['how to improve low libido in menopause'], question: "What helps improve low libido and sexual satisfaction during menopause?", response: "Many women notice changes in desire and arousal around menopause due to lower estrogen, vaginal dryness, sleep disruption, and hot flashes. Treating vaginal dryness with moisturizers and low-dose vaginal estrogen often helps. Reducing stress, improving sleep, trying new activities or toys, and addressing relationship issues are also very effective. Testosterone is sometimes considered but has limited benefit and potential side effects." },
  { id: 2222, category: 'sexual health', keywords: ['vaginal dilators for painful sex after menopause'], question: "How do vaginal dilators help with painful sex after menopause?", response: "After menopause the vagina can become shorter and narrower. Using a set of graduated vaginal dilators with lubricant for a few minutes most days gently stretches the tissues and reduces pain with penetration. This works best when guided by a gynecologist or pelvic floor physical therapist and combined with regular sexual activity or moisturizer use." },
  { id: 2223, category: 'sexual health', keywords: ['SSRIs and sexual side effects in women'], question: "Do SSRIs cause sexual problems and what can be done?", response: "SSRIs (and some other antidepressants) commonly reduce desire, arousal, and ability to orgasm. Options include lowering the dose, switching to bupropion or another medication with fewer sexual side effects, or adding a medication to counteract the problem. Never stop or change antidepressants without talking to your prescriber." },
  { id: 2224, category: 'sexual health', keywords: ['flibanserin and bremelanotide for low desire'], question: "What are flibanserin and bremelanotide and do they work?", response: "Flibanserin (daily pill) and bremelanotide (on-demand injection) are FDA-approved for premenopausal women with distressing low desire. They provide modest benefit for some women but can cause side effects (fatigue, nausea, dizziness, or blood pressure changes). They are not first-line treatments; counseling, lifestyle changes, and treating vaginal dryness are usually tried first." },
  { id: 2225, category: 'sexual health', keywords: ['pelvic floor physical therapy for sexual pain'], question: "How does pelvic floor physical therapy help with sexual pain?", response: "Many women with painful sex have tight or tender pelvic floor muscles. A specially trained pelvic floor physical therapist can use manual techniques, exercises, and biofeedback to relax these muscles and reduce pain. This is often combined with dilator therapy and is very effective for provoked pelvic floor hypertonus and postpartum or menopausal pain." },
  { id: 2226, category: 'sexual health', keywords: ['does hysterectomy affect sexual function'], question: "Does hysterectomy affect sexual desire or orgasm?", response: "Most women report the same or improved sexual function after hysterectomy, especially when it resolves heavy bleeding or pain. Removing the cervix does not usually affect orgasm. Removing both ovaries can lower hormone levels and sometimes reduce desire, but many women still have satisfying sex. Vaginal estrogen can help if dryness is an issue." },
  { id: 2227, category: 'sexual health', keywords: ['testosterone for low libido in women'], question: "Is testosterone helpful for low libido in women?", response: "Testosterone can provide a small improvement in desire for some postmenopausal women with distressing low libido and no other clear cause. However, no testosterone product is FDA-approved for this use in women, benefits are modest, and side effects (acne, hair growth, voice changes) can occur. Long-term safety is not well established. It should only be considered after other approaches have been tried." },
  { id: 2228, category: 'sexual health', keywords: ['vibrators for orgasm difficulties'], question: "Are vibrators helpful for women who have trouble reaching orgasm?", response: "Vibrators are one of the most effective tools for women who have difficulty with orgasm. They can be used alone or with a partner and often help women learn what kind of stimulation works best for them. They are safe, widely available, and recommended by many sex therapists." },
  { id: 2229, category: 'sexual health', keywords: ['when to see a sex therapist'], question: "When should someone see a sex therapist?", response: "A sex therapist can help when sexual problems persist despite treating physical issues (like vaginal dryness or medication side effects), when there are relationship conflicts affecting intimacy, or when past trauma or negative beliefs about sex are interfering. They provide education, communication tools, and specific exercises. Many people benefit from seeing one even for a short time." },

  // === NEW UpToDate Heavy Periods (Menorrhagia) RAG Entries (IDs 2231–2238) ===
  { id: 2231, category: 'heavy bleeding', keywords: ['what counts as a heavy period'], question: "How much bleeding is considered a heavy period?", response: "Heavy periods (menorrhagia) are defined as bleeding that affects your physical health, emotional health, or quality of life. Common signs include soaking through a pad or tampon every 1–3 hours on your heaviest days, bleeding for more than 7 days, passing large clots, or needing to change protection at night. Heavy bleeding can lead to iron deficiency and anemia." },
  { id: 2232, category: 'heavy bleeding', keywords: ['causes of heavy periods'], question: "What are the most common causes of heavy periods?", response: "The most common causes include not ovulating regularly (anovulation), uterine growths such as polyps, fibroids, or adenomyosis, bleeding disorders (like von Willebrand disease), and certain medications or the copper IUD. Anovulation is especially common in teenagers and in perimenopause." },
  { id: 2233, category: 'heavy bleeding', keywords: ['when to seek help for heavy bleeding'], question: "When should I get help for very heavy bleeding?", response: "Go to the emergency department or call your provider if you soak through two pads or tampons in one hour for two hours in a row. This level of bleeding can be serious. You should also seek care if you feel very weak, dizzy, or short of breath, as these can be signs of significant blood loss or anemia." },
  { id: 2234, category: 'heavy bleeding', keywords: ['hormonal IUD for heavy periods'], question: "How well does the hormonal IUD work for heavy periods?", response: "The levonorgestrel IUD (Mirena or Liletta) is one of the most effective medical treatments for heavy bleeding. It can significantly reduce or even stop periods for many users. It also provides contraception for up to 8 years. Irregular spotting is common in the first few months but usually improves over time." },
  { id: 2235, category: 'heavy bleeding', keywords: ['tranexamic acid for heavy periods'], question: "What is tranexamic acid and how does it help heavy periods?", response: "Tranexamic acid (Lysteda) is a non-hormonal medication that helps blood clot and can quickly reduce heavy menstrual bleeding (often within 2–3 hours). You only take it for a few days each month during your period. It does not affect your ability to get pregnant and can be combined with other treatments." },
  { id: 2236, category: 'heavy bleeding', keywords: ['continuous birth control pills for heavy bleeding'], question: "Can I take birth control pills continuously to reduce heavy periods?", response: "Yes. Taking combined estrogen-progestin pills continuously (skipping the placebo week) can reduce or eliminate monthly bleeding. This approach is often helpful for people with heavy or painful periods. It may take a few months to see the full benefit." },
  { id: 2237, category: 'heavy bleeding', keywords: ['endometrial ablation for heavy periods'], question: "What is endometrial ablation and is it a good option for heavy periods?", response: "Endometrial ablation destroys or removes most of the uterine lining to reduce or stop heavy bleeding. It is done as an outpatient procedure and has a relatively quick recovery. It is not recommended if you might want to become pregnant in the future, and it works best when heavy bleeding is not caused by anovulation or large fibroids." },
  { id: 2238, category: 'heavy bleeding', keywords: ['choosing treatment for heavy periods'], question: "How do I decide which treatment is best for my heavy periods?", response: "Start with medication unless you have large fibroids or other structural problems that need surgery. If you might want to get pregnant soon, consider NSAIDs or tranexamic acid. If you want reliable contraception and lighter periods, a hormonal IUD is often an excellent choice. Discuss your future pregnancy plans, symptom severity, and preferences with your clinician." },

  // === NEW UpToDate PMS & PMDD Overview & Treatment RAG Entries (IDs 2239–2247) ===
  { id: 2239, category: 'PMDD', keywords: ['PMS vs PMDD difference'], question: "What is the difference between PMS and PMDD?", response: "PMS involves mild to moderate physical and emotional symptoms in the second half of the menstrual cycle that interfere with daily life. PMDD is the severe form, where symptoms (especially irritability, anger, tension, and mood changes) are intense enough to significantly impair work, school, or relationships. PMDD affects only 3–8% of women, while mild PMS is very common." },
  { id: 2240, category: 'PMDD', keywords: ['causes of PMDD'], question: "What causes PMS and PMDD?", response: "The exact cause is unknown, but women with PMDD appear to be highly sensitive to normal cyclical changes in estrogen and progesterone. These hormone fluctuations may affect brain chemicals like serotonin. Hormone levels themselves are usually normal in women with PMDD." },
  { id: 2241, category: 'PMDD', keywords: ['common symptoms of PMDD'], question: "What are the most common symptoms of PMDD?", response: "Common symptoms include irritability, anger, tension, depression, anxiety, mood swings, fatigue, bloating, breast tenderness, food cravings, difficulty concentrating, and feeling overwhelmed. At least one symptom must be a significant mood change (irritability, depression, anxiety, or tension)." },
  { id: 2242, category: 'PMDD', keywords: ['how is PMDD diagnosed'], question: "How is PMDD diagnosed?", response: "There is no blood test for PMDD. Diagnosis requires that symptoms occur only in the second half of the menstrual cycle (luteal phase), resolve shortly after menses begins, and cause significant distress or impairment. Clinicians often ask patients to track symptoms daily for at least two full cycles to confirm the pattern and rule out other conditions like depression or anxiety disorders." },
  { id: 2243, category: 'PMDD', keywords: ['first line treatment for PMDD'], question: "What is the best first-line treatment for PMDD?", response: "Selective serotonin reuptake inhibitors (SSRIs) such as fluoxetine, sertraline, or escitalopram are the most effective treatments. They work for 60–75% of women with PMDD. They can be taken daily or only during the luteal phase (second half of the cycle). It usually takes 1–2 cycles to see full benefit." },
  { id: 2244, category: 'PMDD', keywords: ['birth control pills for PMDD'], question: "Do birth control pills help PMDD?", response: "Some women improve with continuous or extended-cycle combined birth control pills, which stabilize hormone levels. However, other women find that pills worsen their symptoms. A specific pill containing drospirenone (Yaz) is approved for PMDD, but results vary between individuals." },
  { id: 2245, category: 'PMDD', keywords: ['conservative treatments for PMS PMDD'], question: "What non-medication treatments help with PMS or PMDD?", response: "Regular exercise, stress reduction techniques (meditation, yoga, relaxation), good sleep, and healthy eating can help mild PMS. These are also recommended alongside medication for PMDD. Vitamin B6 and many herbal supplements have not been shown to be clearly better than placebo." },
  { id: 2246, category: 'PMDD', keywords: ['when to use GnRH agonists for PMDD'], question: "When are GnRH agonists used for PMDD?", response: "GnRH agonists (with estrogen + progestin add-back) are reserved for severe PMDD that does not respond to SSRIs or birth control pills. They temporarily shut down ovarian hormone production and can be very effective, but they cause menopausal symptoms and require add-back hormones to protect bone health. They are usually given as injections every 1–3 months." },
  { id: 2247, category: 'PMDD', keywords: ['PMDD vs depression'], question: "How do you tell PMDD apart from depression?", response: "In true PMDD, symptoms are absent or minimal in the first half of the cycle (roughly days 4–12) and appear only in the luteal phase. In depression or anxiety disorders, symptoms are usually present throughout the month, though they may worsen before menses. Prospective daily tracking helps make this distinction." },

  // === NEW UpToDate Estrogen-Associated Migraine RAG Entries (IDs 2248–2255) ===
  { id: 2248, category: 'migraine', keywords: ['menstrual migraine vs menstrually related migraine'], question: "What is the difference between menstrual migraine and menstrually related migraine?", response: "Menstrual migraine (MM) attacks occur only in close relation to menses (from 2 days before to 3 days after the first day of bleeding). Menstrually related migraine (MRM) also occurs during this window but can happen at other times in the cycle as well. Both are triggered by falling estrogen levels. Pure MM is less common than MRM." },
  { id: 2249, category: 'migraine', keywords: ['estrogen withdrawal migraine mechanism'], question: "How does estrogen withdrawal trigger migraine?", response: "Falling estrogen levels (especially a drop >10 mcg ethinyl estradiol equivalent) can lower the threshold for cortical spreading depression and increase sensitivity of the trigeminovascular system. This leads to release of inflammatory substances (including CGRP) that trigger migraine attacks in susceptible individuals." },
  { id: 2250, category: 'migraine', keywords: ['can women with migraine use estrogen contraceptives'], question: "Can patients with migraine safely use estrogen-containing contraceptives?", response: "Patients with migraine without aura can generally use estrogen-containing contraceptives. Those with migraine with aura should usually avoid them due to increased stroke risk. Physiologic doses of estrogen (e.g., for menopause) are generally safer than the higher doses in contraceptives." },
  { id: 2251, category: 'migraine', keywords: ['mini prophylaxis for menstrual migraine'], question: "What is mini prophylaxis for menstrual migraine?", response: "Mini (short-term) prophylaxis involves starting a preventive medication a few days before expected migraine onset and continuing through the high-risk window (usually 5–7 days total). Options include naproxen 500 mg twice daily or a triptan (e.g., frovatriptan or zolmitriptan). This approach reduces total medication exposure compared with daily preventive therapy." },
  { id: 2252, category: 'migraine', keywords: ['continuous hormonal contraception for menstrual migraine'], question: "Can hormonal contraception help prevent menstrual migraine?", response: "Yes. Continuous or extended-cycle combined estrogen-progestin pills or vaginal rings can suppress estrogen fluctuations and reduce estrogen-withdrawal migraine in patients without aura. This approach is especially useful for patients who also want contraception or treatment for heavy bleeding or dysmenorrhea." },
  { id: 2253, category: 'migraine', keywords: ['migraine in pregnancy and postpartum'], question: "How does pregnancy affect estrogen-related migraine?", response: "Migraine often worsens in the first trimester but improves in the second and third trimesters for most patients. Postpartum migraine frequently flares due to the sharp drop in estrogen. Breastfeeding can have a protective effect by keeping estrogen levels more stable." },
  { id: 2254, category: 'migraine', keywords: ['perimenopause and migraine worsening'], question: "Why does migraine often worsen during perimenopause?", response: "Fluctuating and eventually declining estrogen levels during the menopausal transition can increase migraine frequency and severity, especially in those with a hormonal trigger. Many patients improve once they reach stable postmenopausal estrogen levels." },
  { id: 2255, category: 'migraine', keywords: ['NSAIDs for menstrual migraine prevention'], question: "Are NSAIDs effective for preventing menstrual migraine?", response: "Yes. Short-term (mini) prophylaxis with naproxen sodium 500 mg twice daily, started 1–2 days before expected migraine onset, is a reasonable, low-cost, low-risk first option for many patients with predictable menstrual migraine." },

  // === NEW UpToDate Premenopausal Osteoporosis RAG Entries (IDs 2256–2263) ===
  { id: 2256, category: 'bone health', keywords: ['osteoporosis definition premenopausal women'], question: "How is osteoporosis defined in premenopausal women?", response: "In premenopausal women, osteoporosis is not defined by T-score alone. It is diagnosed in the presence of a low-trauma (fragility) fracture after other causes are excluded, or in women with low BMD (Z-score ≤-2.0) plus a known secondary cause of bone loss or fracture. Isolated low BMD without fracture or secondary cause is described as 'below the expected range for age' rather than osteoporosis." },
  { id: 2257, category: 'bone health', keywords: ['Z-score vs T-score premenopausal'], question: "Why use Z-scores instead of T-scores in premenopausal women?", response: "T-scores compare bone density to young adult peak bone mass and are validated for fracture risk in postmenopausal women. In premenopausal women, Z-scores (age-matched comparison) are preferred to avoid mislabeling normal variation or peak bone mass issues as osteoporosis. The term 'osteopenia' is also avoided in this age group." },
  { id: 2258, category: 'bone health', keywords: ['secondary causes premenopausal osteoporosis'], question: "What are common secondary causes of low bone mass or fracture in premenopausal women?", response: "Common causes include estrogen deficiency (from eating disorders, RED-S, hyperprolactinemia, premature ovarian insufficiency), glucocorticoid use, inflammatory bowel disease, celiac disease, hyperparathyroidism, hypercalciuria, smoking, and certain medications. A thorough evaluation for secondary causes is essential in all premenopausal women with low BMD or fractures." },
  { id: 2259, category: 'bone health', keywords: ['pregnancy lactation associated osteoporosis PLO'], question: "What is pregnancy and lactation-associated osteoporosis (PLO)?", response: "PLO is a rare presentation of early-onset osteoporosis in which women develop painful fractures (often vertebral) in the third trimester or early postpartum period. Many cases are considered idiopathic, though some women have identifiable risk factors or genetic variants. Bone loss during lactation is physiologic but can unmask underlying fragility in susceptible women." },
  { id: 2260, category: 'bone health', keywords: ['idiopathic osteoporosis premenopausal IOP'], question: "What is idiopathic osteoporosis (IOP) in premenopausal women?", response: "IOP refers to low-trauma fractures or very low BMD in premenopausal women after exclusion of known primary and secondary causes. Proposed mechanisms include osteoblast dysfunction, abnormalities in the GH/IGF-1 axis, subtle estrogen deficiency, high bone turnover, or hypercalciuria. Some cases may represent adult presentation of genetic bone fragility disorders." },
  { id: 2261, category: 'bone health', keywords: ['peak bone mass and premenopausal BMD'], question: "How does peak bone mass affect bone density in premenopausal women?", response: "Low BMD in a premenopausal woman may reflect failure to achieve optimal peak bone mass (usually reached by the late 20s to early 30s) due to genetics, illness, or lifestyle factors during adolescence and young adulthood, rather than active bone loss. Interpretation of BMD must consider whether peak bone mass has been attained." },
  { id: 2262, category: 'bone health', keywords: ['fracture risk premenopausal low BMD'], question: "What is the fracture risk in premenopausal women with low BMD?", response: "The relationship between BMD and fracture risk is less well defined in premenopausal women than in postmenopausal women. A history of premenopausal fragility fracture does increase the risk of future fractures. Women with low BMD plus a secondary cause or fragility fracture warrant further evaluation and possible treatment." },
  { id: 2263, category: 'bone health', keywords: ['genetic causes early onset osteoporosis'], question: "Can genetic conditions cause osteoporosis in premenopausal women?", response: "Yes. Some women with early-onset osteoporosis may have adult presentations of primary/genetic bone disorders such as osteogenesis imperfecta, hypophosphatasia, osteoporosis-pseudoglioma syndrome (LRP5 variants), or pathogenic variants in genes like COL1A1, COL1A2, WNT1, or PLS3. Genetic evaluation should be considered in selected cases with suggestive history or very severe presentation." },

  // === NEW UpToDate Progestin-Only Pills (POPs) RAG Entries (IDs 2264–2271) ===
  { id: 2264, category: 'contraception', keywords: ['progestin only pill types'], question: "What types of progestin-only pills are available?", response: "The main POPs are norethindrone (0.35 mg daily), drospirenone (4 mg daily for 24 days), norgestrel (0.075 mg daily), and desogestrel (75 mcg daily, available outside the US). Norethindrone and norgestrel primarily thicken cervical mucus, while drospirenone and desogestrel mainly suppress ovulation." },
  { id: 2265, category: 'contraception', keywords: ['effectiveness of progestin only pills'], question: "How effective are progestin-only pills?", response: "Typical-use effectiveness of POPs is estimated at over 93%. Drospirenone, norgestrel, and desogestrel appear more effective than norethindrone because they more consistently suppress ovulation. Efficacy is higher in less fertile users (e.g., breastfeeding or perimenopausal women)." },
  { id: 2266, category: 'contraception', keywords: ['unscheduled bleeding with POPs'], question: "Do progestin-only pills cause unscheduled bleeding?", response: "Yes. Irregular bleeding and spotting are the most common side effects of POPs and the main reason for discontinuation. Patterns vary: norethindrone users often have more frequent or prolonged bleeding, while drospirenone users may see improvement over time. Many users eventually have lighter or absent periods." },
  { id: 2267, category: 'contraception', keywords: ['POPs and mood changes'], question: "Do progestin-only pills affect mood?", response: "Data are mixed. Some studies show no clear worsening of mood or depression with POPs, while others report a small increased risk of first antidepressant use. Individual responses vary; women with PMDD or mood disorders should monitor symptoms closely when starting POPs." },
  { id: 2268, category: 'contraception', keywords: ['POPs in perimenopause'], question: "Can perimenopausal women use progestin-only pills?", response: "Yes. POPs are safe and effective for perimenopausal women who cannot or prefer not to use estrogen. They can help with heavy or irregular bleeding and provide contraception. Reduced fecundity in this age group also improves typical-use effectiveness." },
  { id: 2269, category: 'contraception', keywords: ['POPs and breastfeeding'], question: "Are progestin-only pills safe while breastfeeding?", response: "Yes. POPs are compatible with breastfeeding and do not affect milk supply. They can be started immediately postpartum. Norethindrone is commonly used in this setting and has minimal transfer into breast milk." },
  { id: 2270, category: 'contraception', keywords: ['missed progestin only pill'], question: "What should I do if I miss a progestin-only pill?", response: "Take the missed pill as soon as you remember, even if it means taking two pills in one day. For norethindrone or norgestrel, use back-up contraception for at least 48 hours if the pill is more than 3 hours late. For drospirenone, back-up is needed if ≥48 hours late. Consider emergency contraception if you had unprotected sex." },
  { id: 2271, category: 'contraception', keywords: ['POPs vs other progestin methods'], question: "How do progestin-only pills compare to the implant or IUD?", response: "POPs require daily timing and have lower typical-use effectiveness than the etonogestrel implant or levonorgestrel IUDs. They cause more unscheduled bleeding than IUDs but have a faster return to fertility and no procedure for insertion/removal. Long-acting methods are generally more effective and convenient." },

  // === NEW UpToDate Fertility Awareness-Based Methods RAG Entries (IDs 2272–2280) ===
  { id: 2272, category: 'contraception', keywords: ['fertility awareness based methods overview'], question: "What are fertility awareness-based (FAB) methods of contraception?", response: "FAB methods (also called natural family planning) involve tracking the menstrual cycle to identify the fertile window and then avoiding unprotected sex or using a barrier method during those days. They rely on cycle length, cervical secretions, and basal body temperature to estimate when ovulation is likely to occur." },
  { id: 2273, category: 'contraception', keywords: ['Standard Days Method'], question: "How does the Standard Days Method work?", response: "The Standard Days Method is a calendar-based approach for people with regular cycles (usually 26–32 days). Users avoid unprotected intercourse from day 8 through day 19 of the cycle (12 days total). It is one of the easiest FAB methods to learn and use, especially with tools like CycleBeads." },
  { id: 2274, category: 'contraception', keywords: ['TwoDay Method cervical secretions'], question: "How does the TwoDay Method work?", response: "The TwoDay Method is based on the presence or absence of cervical secretions. Users ask themselves two questions each day: 'Did I notice any secretions today?' and 'Did I notice any yesterday?' If the answer is yes to either question, they avoid unprotected sex that day. It is relatively simple and can be used even with somewhat irregular cycles." },
  { id: 2275, category: 'contraception', keywords: ['symptothermal method'], question: "What is the symptothermal method?", response: "The symptothermal method combines observation of cervical secretions with daily basal body temperature (BBT) tracking. The fertile window begins with the first signs of fertile-type cervical mucus and ends after a sustained rise in BBT confirms that ovulation has occurred. It is more complex but can be very effective when used correctly." },
  { id: 2276, category: 'contraception', keywords: ['effectiveness of fertility awareness methods'], question: "How effective are fertility awareness-based methods?", response: "Perfect-use failure rates for well-taught FAB methods range from about 0.4–5% in the first year, but typical-use failure rates are much higher (often 13–25%). Effectiveness depends heavily on correct and consistent use, cycle regularity, and user motivation. Apps with algorithms may improve usability but still have variable real-world effectiveness." },
  { id: 2277, category: 'contraception', keywords: ['who should not use FAB methods'], question: "Who should avoid fertility awareness-based methods?", response: "FAB methods are generally not ideal for people with irregular cycles, those who recently gave birth or had a pregnancy loss, adolescents with unpredictable cycles, people who cannot reliably track symptoms, or those whose partners will not cooperate with avoiding sex or using barriers during the fertile window. They also provide no protection against STIs." },
  { id: 2278, category: 'contraception', keywords: ['FAB methods and apps'], question: "Are smartphone apps reliable for fertility awareness contraception?", response: "Some apps are helpful digital tools for tracking established FAB methods (such as symptothermal or Standard Days). Others use proprietary algorithms. Only a few (such as Natural Cycles) have been formally evaluated and cleared by regulatory bodies. Many apps lack strong evidence for contraceptive effectiveness, so users should approach them with caution and combine them with proper instruction." },
  { id: 2279, category: 'contraception', keywords: ['FAB methods postpartum or breastfeeding'], question: "Can fertility awareness methods be used after giving birth or while breastfeeding?", response: "FAB methods can be challenging in the postpartum period because cycles are often irregular and cervical secretions can be confusing during lactation. The lactational amenorrhea method (exclusive breastfeeding with no periods) can be used for up to 6 months if specific criteria are met. Once cycles resume, users usually need additional instruction to use FAB methods reliably." },
  { id: 2280, category: 'contraception', keywords: ['counseling for fertility awareness methods'], question: "What should patients know before starting a fertility awareness-based method?", response: "Patients should understand that FAB methods require daily observation and charting, that they must avoid unprotected sex or use barriers during the fertile window (often 10–17 days per cycle), and that typical-use effectiveness is lower than many other methods. They work best for highly motivated users with regular cycles and cooperative partners. Emergency contraception should be discussed as a backup option." },

  // === NEW UpToDate AUB Management RAG Entries (IDs 2281–2288) ===
  { id: 2281, category: 'abnormal uterine bleeding', keywords: ['first line treatment abnormal uterine bleeding'], question: "What is first-line treatment for abnormal uterine bleeding (AUB) in reproductive-age women?", response: "For most patients with AUB and no structural, infectious, or endocrine cause, first-line options are estrogen-progestin contraceptives or the 52 mg levonorgestrel IUD (LNG 52 mg IUD). Both effectively reduce bleeding, provide contraception, and have a good safety profile. Choice depends on patient preference for daily pills/rings/patches versus a long-acting IUD." },
  { id: 2282, category: 'abnormal uterine bleeding', keywords: ['LNG IUD for heavy menstrual bleeding'], question: "How effective is the LNG 52 mg IUD for heavy menstrual bleeding?", response: "The LNG 52 mg IUD is highly effective for heavy menstrual bleeding. It typically reduces blood loss by 71–95% within 3–6 months, often leading to light bleeding or amenorrhea. It is one of the most effective non-surgical treatments and also provides contraception for up to 8 years (though replacement may be needed earlier for bleeding control)." },
  { id: 2283, category: 'abnormal uterine bleeding', keywords: ['AUB treatment when estrogen is contraindicated'], question: "What treatments are used for AUB when estrogen is contraindicated?", response: "When estrogen is contraindicated (e.g., history of thrombosis, migraine with aura, age ≥35 and smoking), the LNG 52 mg IUD is often first-line. Other options include oral progestins (norethindrone acetate or medroxyprogesterone acetate), depot medroxyprogesterone acetate (DMPA), or surgery. Medical consultation is recommended for patients with high thrombosis risk." },
  { id: 2284, category: 'abnormal uterine bleeding', keywords: ['tranexamic acid for heavy periods'], question: "When is tranexamic acid used for heavy menstrual bleeding?", response: "Tranexamic acid (TXA) is a non-hormonal option for heavy menstrual bleeding. It is taken only during menses (typically 1300 mg three times daily for up to 5 days) and can reduce blood loss by 26–54%. It is useful for patients who cannot or prefer not to use hormonal therapy, or those with suspected bleeding disorders. It is generally avoided with combined hormonal contraception due to thrombosis risk." },
  { id: 2285, category: 'abnormal uterine bleeding', keywords: ['NSAIDs for heavy menstrual bleeding'], question: "Do NSAIDs help with heavy menstrual bleeding?", response: "Yes. NSAIDs (ibuprofen, naproxen, mefenamic acid) can reduce menstrual blood loss by 10–52% when started on the first day of bleeding. They are a reasonable non-hormonal option for selected patients but are less effective than hormonal therapies or TXA. They should generally be avoided in patients on anticoagulants or with bleeding disorders." },
  { id: 2286, category: 'abnormal uterine bleeding', keywords: ['AUB treatment when trying to conceive'], question: "How do you treat abnormal uterine bleeding in women trying to conceive?", response: "Treatment is more limited. Options include estrogen-progestin contraceptives (stopped when trying to conceive), cyclic oral progestins, TXA, or NSAIDs. Long-acting methods like the LNG IUD or DMPA are usually avoided because they delay return to fertility. Treating the underlying cause (e.g., anovulation) is also important." },
  { id: 2287, category: 'abnormal uterine bleeding', keywords: ['endometrial ablation vs LNG IUD'], question: "When is endometrial ablation used for abnormal uterine bleeding?", response: "Endometrial ablation is a minimally invasive option for patients who have completed childbearing and have persistent heavy bleeding despite medical therapy. It is less effective than hysterectomy but has lower surgical risk. The LNG 52 mg IUD is often tried first because it is reversible and provides contraception; ablation is considered if the IUD is ineffective or not tolerated." },
  { id: 2288, category: 'abnormal uterine bleeding', keywords: ['AUB in patients on anticoagulants'], question: "How is abnormal uterine bleeding managed in patients on anticoagulants?", response: "Structural causes should be treated when possible. For medical management, the LNG 52 mg IUD is often preferred. Estrogen-containing methods require careful risk-benefit discussion. TXA use is controversial in anticoagulated patients. Close collaboration with hematology is recommended." },

  // === NEW UpToDate MHT and Bone Health RAG Entries (IDs 2292–2299) ===
  { id: 2292, category: 'menopause', keywords: ['MHT for osteoporosis prevention'], question: "Is menopausal hormone therapy still used to prevent osteoporosis?", response: "MHT is no longer considered first-line therapy for preventing osteoporosis in most women because of potential risks shown in the Women's Health Initiative (WHI). However, women who are already taking estrogen for menopausal symptoms (especially in their late 40s or early 50s) receive the additional benefit of reduced bone loss and lower fracture risk." },
  { id: 2293, category: 'menopause', keywords: ['estrogen dose for bone protection'], question: "What estrogen dose protects bone in menopausal women?", response: "Doses of estradiol equal to or higher than 25 mcg/day transdermal or 0.5 mg/day oral generally provide skeletal protection. Even ultra-low doses (such as 14 mcg transdermal estradiol) can help prevent bone loss, especially when combined with adequate calcium and vitamin D. Bone density should be monitored in high-risk women on very low doses." },
  { id: 2294, category: 'menopause', keywords: ['WHI study and fracture risk'], question: "Did the Women's Health Initiative show that estrogen reduces fractures?", response: "Yes. In the WHI, both estrogen-progestin and estrogen-only therapy reduced the risk of hip and vertebral fractures. However, the study population was older (average age 63–64), and the regimens used are no longer the preferred modern approach. Benefits appear greater and risks lower when MHT is started closer to menopause." },
  { id: 2295, category: 'menopause', keywords: ['bone loss after stopping estrogen'], question: "What happens to bone when you stop menopausal hormone therapy?", response: "Bone loss can accelerate after stopping estrogen, although studies are mixed on how much 'catch-up' loss occurs. Women who took estrogen in the past generally still have higher bone density than those who never took it, but the protective effect diminishes over time after discontinuation." },
  { id: 2296, category: 'menopause', keywords: ['MHT for established osteoporosis'], question: "Can menopausal hormone therapy treat established osteoporosis?", response: "Estrogen is FDA-approved for prevention but not treatment of osteoporosis. In women already taking MHT for menopausal symptoms who also have osteoporosis, it may be sufficient, but bone density should be monitored. More potent agents (such as bisphosphonates) are usually preferred for treating established osteoporosis." },
  { id: 2297, category: 'menopause', keywords: ['estrogen vs bisphosphonate for bone'], question: "How does estrogen compare with bisphosphonates for bone health?", response: "Estrogen and bisphosphonates are both effective at preventing bone loss. Some studies show similar effects on bone density, while others find bisphosphonates slightly superior, especially in older women. Combination therapy provides only modest additional benefit over either agent alone. We generally avoid routine combination therapy." },
  { id: 2298, category: 'menopause', keywords: ['progestin effect on bone'], question: "Does adding a progestin improve bone protection with estrogen?", response: "Adding a progestin (whether cyclic or continuous) does not significantly increase the bone-protective effect of estrogen. The main skeletal benefit comes from the estrogen component. Progestins have only minor independent effects on bone density." },
  { id: 2299, category: 'menopause', keywords: ['who should take MHT for bones'], question: "Who should consider MHT partly for bone protection?", response: "Women in their late 40s or early 50s who are starting MHT for bothersome menopausal symptoms (especially hot flashes) will also benefit from reduced bone loss. For women who only want bone protection and have no menopausal symptoms, other treatments such as bisphosphonates are usually preferred over MHT." },

  // === NEW UpToDate Causes of Female Genital Tract Bleeding RAG Entries (IDs 2302–2310) ===
  { id: 2302, category: 'abnormal bleeding', keywords: ['postcoital bleeding causes'], question: "What are common causes of postcoital bleeding?", response: "Postcoital bleeding is most often caused by cervical issues such as cervicitis (including Trichomonas), cervical polyps, ectropion, or cervical cancer. Vaginal causes include genitourinary syndrome of menopause (atrophy), vaginitis, or trauma. Any postcoital bleeding warrants a speculum exam and cervical cancer screening if due." },
  { id: 2303, category: 'abnormal bleeding', keywords: ['cervicitis and bleeding'], question: "How does cervicitis cause bleeding?", response: "Cervicitis (from infection or inflammation) makes the cervix friable and prone to bleeding, especially with intercourse. Trichomonas classically causes a 'strawberry cervix' with easy bleeding on contact. Other causes include chlamydia, gonorrhea, or nonspecific inflammation." },
  { id: 2304, category: 'abnormal bleeding', keywords: ['genitourinary syndrome of menopause bleeding'], question: "Can genitourinary syndrome of menopause cause bleeding?", response: "Yes. Genitourinary syndrome of menopause (GSM, formerly vaginal atrophy) causes thinning and fragility of vaginal and vulvar tissues due to low estrogen. This can lead to spotting or bleeding, especially with intercourse. It is very common in postmenopausal women and can also occur in lactating or premenarchal patients." },
  { id: 2305, category: 'abnormal bleeding', keywords: ['vaginal trauma bleeding'], question: "What causes vaginal bleeding from trauma?", response: "Vaginal bleeding from trauma can result from consensual intercourse (especially with inadequate lubrication or first-time intercourse), sexual assault, foreign bodies (retained tampon, pessary), straddle injuries, or pelvic trauma. Significant bleeding requires prompt evaluation." },
  { id: 2306, category: 'abnormal bleeding', keywords: ['vulvar lichen sclerosus bleeding'], question: "Does vulvar lichen sclerosus cause bleeding?", response: "Vulvar lichen sclerosus can cause bleeding, especially if there are fissures, erosions, or trauma from scratching. It typically presents with itching, pain, and white plaques, but bleeding or hemorrhage can occur in more severe or active cases." },
  { id: 2307, category: 'abnormal bleeding', keywords: ['PALM-COEIN causes of AUB'], question: "What does the PALM-COEIN system classify for abnormal uterine bleeding?", response: "PALM-COEIN is the FIGO classification for causes of abnormal uterine bleeding: Polyp, Adenomyosis, Leiomyoma, Malignancy/hyperplasia, Coagulopathy, Ovulatory dysfunction, Endometrial, Iatrogenic, and Not otherwise classified. It helps clinicians systematically evaluate uterine sources of bleeding." },
  { id: 2308, category: 'abnormal bleeding', keywords: ['coagulopathy and heavy menstrual bleeding'], question: "How common is a bleeding disorder in women with heavy periods?", response: "Bleeding disorders (especially von Willebrand disease) are found in 5–29% of reproductive-age women presenting with heavy menstrual bleeding. A structured bleeding history is essential. Heavy periods since menarche, easy bruising, or prolonged bleeding after procedures raise suspicion for AUB-C (coagulopathy)." },
  { id: 2309, category: 'abnormal bleeding', keywords: ['cesarean scar defect bleeding'], question: "What is a cesarean scar defect and how does it cause bleeding?", response: "A cesarean scar defect (isthmocele or niche) is a pouch at the site of a prior cesarean incision. It can trap menstrual blood and cause prolonged postmenstrual spotting. It is an increasingly recognized cause of abnormal uterine bleeding (classified under AUB-N)." },
  { id: 2310, category: 'abnormal bleeding', keywords: ['when bleeding is not from the uterus'], question: "What should I consider if bleeding is not from the uterus?", response: "Consider cervical (cervicitis, polyps, cancer), vaginal (atrophy, trauma, infection), or vulvar sources. Rarely, bleeding can come from the fallopian tube or ovary. Nongenital sources (urethra, bladder, anus, bowel) should also be ruled out, especially if the history or exam does not clearly point to a gynecologic source." },

  // === NEW UpToDate Breast Cysts RAG Entries (IDs 2311–2319) ===
  { id: 2311, category: 'breast health', keywords: ['breast cyst definition'], question: "What is a breast cyst?", response: "A breast cyst is a fluid-filled round or oval mass that develops from the terminal duct lobular unit (TDLU). Cysts form when fluid accumulates due to obstruction or distension of the efferent ductule. They are the most common nonproliferative breast disorder and are strongly influenced by hormonal fluctuations." },
  { id: 2312, category: 'breast health', keywords: ['breast cyst symptoms'], question: "What are the symptoms of a breast cyst?", response: "Breast cysts often present as a smooth, firm, discrete, and sometimes tender or painful mass. They may feel like a grape, water balloon, or even hard. Acute enlargement can cause sudden localized pain. Microcysts frequently cause cyclical breast pain or tenderness, especially in the days before menses." },
  { id: 2313, category: 'breast health', keywords: ['simple vs complicated vs complex breast cyst ultrasound'], question: "How are breast cysts classified on ultrasound?", response: "Breast cysts are classified on ultrasound as: Simple (anechoic, well-circumscribed, posterior enhancement, no internal echoes or solid components — always benign), Complicated (homogeneous low-level internal echoes from debris, no solid components or thick septa), or Complex (thick walls/septa >0.5 mm, solid components, or mixed cystic-solid features — requires biopsy)." },
  { id: 2314, category: 'breast health', keywords: ['simple breast cyst management'], question: "How are simple breast cysts managed?", response: "Simple cysts and clustered microcysts are benign (BI-RADS 2). No treatment or routine follow-up is needed. Fine-needle aspiration is only performed if the cyst is inflamed or infected (red skin). Complete collapse after aspiration confirms the diagnosis and requires no further action." },
  { id: 2315, category: 'breast health', keywords: ['complicated breast cyst management'], question: "How are complicated breast cysts managed?", response: "Most complicated cysts are BI-RADS 2 and require no intervention. Those classified as BI-RADS 3 should have repeat clinical exam and imaging (ultrasound ± mammography) in 6 months. If stable or downgraded, routine screening can resume. If the cyst grows or develops solid components, core needle biopsy is indicated. Ultrasound-guided aspiration with complete collapse is also acceptable for confirmation." },
  { id: 2316, category: 'breast health', keywords: ['complex breast cyst management'], question: "How are complex breast cysts managed?", response: "Complex cysts are BI-RADS 4 or 5 and require ultrasound-guided core needle biopsy targeting the solid component. If pathology is benign and concordant with imaging, follow with clinical exam and imaging every 6–12 months for 1–2 years. Surgical excision is needed if biopsy is not feasible, results are discordant, atypical, or malignant." },
  { id: 2317, category: 'breast health', keywords: ['breast cyst and breast cancer risk'], question: "Do breast cysts increase the risk of breast cancer?", response: "Simple cysts do not increase the risk of breast cancer. Complicated cysts have a very low risk of malignancy (<1%). Complex cysts carry a higher risk (generally <1–23%, depending on features). Women with a history of simple cysts do not have an elevated lifetime risk of developing breast cancer." },
  { id: 2318, category: 'breast health', keywords: ['breast cysts perimenopause hormones'], question: "How do hormones affect breast cysts?", response: "Breast cysts are strongly influenced by hormonal fluctuations. They are most common in women aged 35–50, peak in the premenopausal and perimenopausal years, and often fluctuate in size with the menstrual cycle. They can also appear or worsen with hormone replacement therapy in postmenopausal women." },
  { id: 2319, category: 'breast health', keywords: ['when to biopsy a breast cyst'], question: "When should a breast cyst be biopsied?", response: "Biopsy (core needle) is indicated for complex cysts, complicated cysts that are BI-RADS 3 and show growth or new solid components on follow-up, cysts that do not fully collapse after aspiration, or when imaging and clinical findings are discordant. Simple cysts almost never require biopsy unless inflamed or infected." },

  // === NEW UpToDate Insomnia Management RAG Entries (IDs 2320–2328) ===
  { id: 2320, category: 'sleep', keywords: ['CBT-I first line chronic insomnia'], question: "What is the first-line treatment for chronic insomnia?", response: "Cognitive behavioral therapy for insomnia (CBT-I) is first-line treatment for chronic insomnia (insomnia disorder). It is as effective as medication in the short term and superior for long-term outcomes. CBT-I addresses maladaptive thoughts and behaviors and gives patients lifelong skills. Medication is an acceptable initial alternative when CBT-I is not accessible or when rapid relief is clinically needed." },
  { id: 2321, category: 'sleep', keywords: ['acute vs chronic insomnia management'], question: "How should acute (short-term) insomnia be managed?", response: "Acute insomnia (<3 months) is usually triggered by stress. For mild cases, provide education, sleep hygiene guidance, and reassurance. For severe distress or functional impairment, short-term use of an insomnia medication is reasonable while addressing the precipitant. Reassess in 2–4 weeks. If symptoms persist, evaluate for chronic insomnia and offer CBT-I." },
  { id: 2322, category: 'sleep', keywords: ['when to combine CBT-I and medication'], question: "When should medication be combined with CBT-I?", response: "Combination therapy (CBT-I + medication) can be used initially when patients have severe distress, marked daytime impairment, or high anxiety about sleep that may interfere with their ability to follow CBT-I instructions (especially time-in-bed restriction). The medication can be tapered after 6–8 weeks once CBT-I skills are established." },
  { id: 2323, category: 'sleep', keywords: ['insomnia in menopause'], question: "How should insomnia be managed during the menopausal transition?", response: "Insomnia is common in perimenopause and menopause due to vasomotor symptoms, hormonal fluctuations, increased OSA risk, and mood changes. CBT-I is effective whether or not hot flashes are present. When hot flashes are prominent, menopausal hormone therapy, venlafaxine, gabapentin, or suvorexant may improve both sleep and vasomotor symptoms." },
  { id: 2324, category: 'sleep', keywords: ['insomnia in pregnancy'], question: "How should insomnia be managed during pregnancy?", response: "Nonpharmacologic approaches, especially CBT-I (in-person or digital), are preferred. Sleep disturbance increases across trimesters. Screen for restless legs syndrome and address it with iron if indicated. Over-the-counter antihistamines (doxylamine, diphenhydramine) can be considered when medication is needed. Most prescription insomnia medications are generally avoided due to limited safety data." },
  { id: 2325, category: 'sleep', keywords: ['insomnia and obstructive sleep apnea'], question: "How should insomnia be managed when obstructive sleep apnea is also present?", response: "Insomnia and OSA frequently coexist. CBT-I is effective and may improve CPAP adherence. Short-term use of certain sedating medications (e.g., eszopiclone) appears safe in mild-moderate untreated OSA and may help with CPAP initiation. Screen all patients with insomnia for OSA symptoms, especially if they have risk factors (obesity, snoring, daytime sleepiness)." },
  { id: 2326, category: 'sleep', keywords: ['tapering insomnia medications'], question: "How should long-term insomnia medications be tapered?", response: "Taper slowly, especially after chronic use (often over many months). Use CBT-I concurrently to reinforce good sleep habits and manage anxiety about returning insomnia. Allow as-needed use initially when stopping nightly dosing. The longer the patient has had insomnia before starting medication, the higher the likelihood they may need ongoing support." },
  { id: 2327, category: 'sleep', keywords: ['insomnia with psychiatric comorbidity'], question: "How should insomnia be managed when psychiatric disorders are present?", response: "Treat both the psychiatric disorder and insomnia. CBT-I remains first-line. In mood and anxiety disorders, concurrent insomnia treatment (e.g., eszopiclone) can speed psychiatric recovery. In PTSD, CBT-I is preferred; trazodone and prazosin are commonly used. In schizophrenia, CBT-I and eszopiclone have supportive data. Avoid BZRAs in active substance use disorders when possible." },
  { id: 2328, category: 'sleep', keywords: ['key perpetuating factors in insomnia'], question: "What are common perpetuating factors in chronic insomnia?", response: "Common perpetuating factors include irregular sleep schedules, excessive time in bed, napping, clock-watching, high anxiety about sleep ('insomnia phobia'), unrealistic sleep expectations, and poor sleep hygiene. These are the primary targets of CBT-I. Addressing them is essential even when medications are used." },

  // === NEW UpToDate Menopause & Menopausal Transition RAG Entries (IDs 2329–2337) ===
  { id: 2329, category: 'menopause', keywords: ['definition of natural menopause'], question: "How is natural menopause defined?", response: "Natural menopause is defined as the permanent cessation of menstrual periods, diagnosed retrospectively after 12 consecutive months of amenorrhea without any other obvious cause. It occurs at a median age of 51.4 years and reflects near-complete ovarian follicular depletion with resulting hypoestrogenemia and elevated FSH." },
  { id: 2330, category: 'menopause', keywords: ['STRAW staging system menopause'], question: "What is the STRAW staging system for reproductive aging?", response: "The Stages of Reproductive Aging Workshop (STRAW) system is the gold standard for classifying reproductive aging. It divides the process into late reproductive years, early and late menopausal transition, final menstrual period (FMP), and early/late postmenopause based on bleeding patterns, endocrine changes, and symptoms. It helps clinicians counsel patients about expected changes in cycles, symptoms, and fertility." },
  { id: 2331, category: 'menopause', keywords: ['early vs late menopausal transition'], question: "What is the difference between early and late menopausal transition?", response: "The early menopausal transition is marked by a change of ≥7 days in menstrual cycle length with variable but often elevated FSH. The late transition involves more dramatic irregularity (skipped cycles, amenorrhea), greater hormonal fluctuations, and higher likelihood of anovulatory cycles. Hot flashes become much more common in the late transition." },
  { id: 2332, category: 'menopause', keywords: ['hot flashes prevalence and duration'], question: "How common are hot flashes and how long do they last?", response: "Hot flashes occur in up to 80% of women during the menopausal transition and early postmenopause. They are most frequent in the late transition and early postmenopausal years. While many women experience them for a few years, symptoms can persist for 10–20 years or longer in some women, with significant variability by race/ethnicity." },
  { id: 2333, category: 'menopause', keywords: ['depression risk during menopausal transition'], question: "Is there an increased risk of depression during perimenopause?", response: "Yes. Women have a significantly higher risk of new-onset depression during the menopausal transition compared with their premenopausal years (approximately 2.5 times higher). The risk is greatest in women with a prior history of depression or mood problems and decreases again in early postmenopause." },
  { id: 2334, category: 'menopause', keywords: ['genitourinary syndrome of menopause GSM'], question: "What is genitourinary syndrome of menopause (GSM)?", response: "Genitourinary syndrome of menopause (formerly vulvovaginal atrophy) affects about 50% of menopausal women. It results from estrogen (and androgen) deficiency causing thinning, dryness, and reduced elasticity of the vulva, vagina, urethra, and bladder. Symptoms include vaginal dryness, dyspareunia, urinary urgency, and sexual dysfunction. It is highly responsive to vaginal estrogen therapy." },
  { id: 2335, category: 'menopause', keywords: ['diagnosis of menopause by age'], question: "How is menopause diagnosed in women over 45?", response: "In women over 45, menopause is diagnosed clinically as 12 months of amenorrhea without other obvious causes. The menopausal transition is diagnosed by a change in menstrual cycle length (≥7 days) with or without typical symptoms (hot flashes, sleep disturbance, mood changes). Routine FSH testing is not required and can be misleading due to wide fluctuations." },
  { id: 2336, category: 'menopause', keywords: ['early menopause evaluation ages 40-45'], question: "How should women ages 40–45 with irregular cycles be evaluated?", response: "Women ages 40–45 with irregular cycles (with or without hot flashes) should undergo evaluation for causes of oligo/amenorrhea, including pregnancy (hCG), hyperprolactinemia (prolactin), and thyroid dysfunction (TSH). FSH can be measured but is variable. If confirmed as menopause before age 45, it is termed early menopause and carries increased long-term risks for cardiovascular disease and bone loss." },
  { id: 2337, category: 'menopause', keywords: ['FSH testing for menopause'], question: "Is FSH testing useful for diagnosing menopause or perimenopause?", response: "FSH levels fluctuate widely during the menopausal transition and are often not helpful for diagnosis. A single normal FSH does not rule out perimenopause, and a high value does not confirm menopause. Menstrual cycle history and symptoms are more reliable. FSH may be useful in women under 45 or after hysterectomy/endometrial ablation." },

  // === NEW UpToDate MHT RAG Entries (IDs 2340–2349) ===
  { id: 2340, category: 'menopause', keywords: ['MHT first line for hot flashes'], question: "When is menopausal hormone therapy indicated?", response: "MHT is the most effective treatment for moderate-to-severe vasomotor symptoms (hot flashes) that impair sleep, quality of life, or daily function. It is also helpful for perimenopausal mood lability, sleep disturbance related to hot flashes, and some cases of joint pain. For genitourinary syndrome of menopause (GSM) alone, low-dose vaginal estrogen is preferred over systemic MHT." },
  { id: 2341, category: 'menopause', keywords: ['preferred estrogen for MHT'], question: "What is the preferred estrogen for menopausal hormone therapy?", response: "17-β-estradiol (bioidentical) is preferred over conjugated equine estrogens. Transdermal 17-β-estradiol is often favored over oral because it has a lower risk of VTE and stroke, avoids first-pass hepatic effects, and has less impact on triglycerides and SHBG. Oral estradiol remains a reasonable option for many healthy women who prefer pills." },
  { id: 2342, category: 'menopause', keywords: ['progestogen choice with MHT'], question: "What progestogen is preferred with estrogen therapy?", response: "Micronized progesterone (oral) is preferred over synthetic progestins such as medroxyprogesterone acetate. It is effective for endometrial protection, metabolically neutral, and appears to have a more favorable safety profile regarding breast cancer and cardiovascular risk. It is usually given cyclically (200 mg for 12 days/month) in perimenopause/early postmenopause or continuously (100 mg daily) later." },
  { id: 2343, category: 'menopause', keywords: ['starting dose MHT hot flashes'], question: "What starting dose of estrogen is recommended for hot flashes?", response: "Start with lower doses and titrate up: transdermal estradiol 0.025 mg or oral estradiol 0.5 mg daily. For more severe symptoms, begin with transdermal 0.05 mg or oral 1 mg. Younger women after bilateral oophorectomy often need higher initial doses (e.g., 0.1 mg transdermal or 2 mg oral) for the first 2–3 years." },
  { id: 2344, category: 'menopause', keywords: ['cyclic vs continuous MHT regimens'], question: "When to use cyclic versus continuous combined MHT?", response: "Use cyclic regimens (continuous estrogen + progesterone 12 days/month) in perimenopause and early postmenopause because they are easier to tolerate and produce predictable withdrawal bleeding. Switch to continuous combined regimens (estrogen + daily progesterone) after 2–3 years post-FMP when most women prefer to avoid monthly bleeding. Continuous regimens eventually induce amenorrhea in most women." },
  { id: 2345, category: 'menopause', keywords: ['duration of MHT use'], question: "How long should menopausal hormone therapy be used?", response: "Standard duration is 3–5 years, but this should be individualized. Many women have hot flashes for 10+ years. Extended use beyond age 60 (or >5 years) can be reasonable in symptomatic women with low breast cancer and cardiovascular risk when benefits outweigh risks. Reassess regularly and attempt to taper when appropriate." },
  { id: 2346, category: 'menopause', keywords: ['tapering MHT'], question: "How should menopausal hormone therapy be tapered?", response: "Taper gradually over 3–12 months (e.g., reduce by one pill/patch strength every 1–2 months). Abrupt cessation often causes return of severe hot flashes. Consider starting a nonhormonal agent (SSRI or gabapentin) during the taper. Many women need to resume a lower dose if symptoms recur significantly." },
  { id: 2347, category: 'menopause', keywords: ['MHT in perimenopausal depression'], question: "How should mood symptoms be managed during perimenopause?", response: "Perimenopause carries a high risk of new or recurrent depression. Estrogen therapy improves mood in perimenopausal (but not postmenopausal) women. Many women benefit from combined MHT + SSRI when both vasomotor symptoms and depression are prominent. Screen routinely for depression during the menopausal transition." },
  { id: 2348, category: 'menopause', keywords: ['contraindications to MHT'], question: "What are the main contraindications to menopausal hormone therapy?", response: "Contraindications include personal history of breast cancer, CHD, prior VTE or stroke, active liver disease, unexplained vaginal bleeding, and high-risk endometrial cancer. For women at high cardiovascular or breast cancer risk, nonhormonal options are generally preferred." },
  { id: 2349, category: 'menopause', keywords: ['compounded bioidentical hormones'], question: "Should compounded bioidentical hormone therapy be used?", response: "No. Compounded bioidentical hormones lack robust safety and efficacy data compared with FDA-approved products. Quality, dosing, and sterility are not well regulated. Major societies advise against their routine use. Approved 17-β-estradiol and micronized progesterone preparations are preferred." },

  // === NEW UpToDate Hot Flashes RAG Entries (IDs 2351–2359) ===
  { id: 2351, category: 'menopause', keywords: ['hot flash prevalence and duration'], question: "How common are hot flashes and how long do they last?", response: "Hot flashes occur in up to 80% of women during the menopausal transition. Median total duration is about 7.4 years, with symptoms often persisting for a median of 4.5 years after the final menstrual period. Some women (especially those with early onset) have symptoms for more than 10 years. African American women tend to have longer duration than other groups." },
  { id: 2352, category: 'menopause', keywords: ['pathophysiology of hot flashes'], question: "What causes hot flashes physiologically?", response: "Hot flashes result from thermoregulatory dysfunction in the hypothalamus triggered by estrogen withdrawal. The thermoneutral zone narrows, so even small rises in core body temperature trigger inappropriate vasodilation and sweating. KNDy (kisspeptin/neurokinin B/dynorphin) neurons in the hypothalamus are thought to mediate both the LH pulses and the thermoregulatory changes." },
  { id: 2353, category: 'menopause', keywords: ['first line treatment hot flashes'], question: "What is the most effective treatment for moderate to severe hot flashes?", response: "Menopausal hormone therapy (MHT) is the most effective treatment for moderate-to-severe vasomotor symptoms. Low-dose transdermal or oral 17-β-estradiol (with a progestogen if the uterus is intact) provides the greatest reduction in frequency and severity. Nonhormonal options are used when MHT is contraindicated or declined." },
  { id: 2354, category: 'menopause', keywords: ['nonhormonal treatments hot flashes'], question: "What are the best nonhormonal treatments for hot flashes?", response: "Effective nonhormonal options include certain SSRIs (citalopram, escitalopram), SNRIs (venlafaxine, desvenlafaxine), gabapentin (especially at bedtime for night sweats), and NK3 receptor antagonists (fezolinetant, elinzanetant). Paroxetine should be avoided in women taking tamoxifen because it inhibits CYP2D6." },
  { id: 2355, category: 'menopause', keywords: ['fezolinetant hot flashes'], question: "What is fezolinetant and how effective is it for hot flashes?", response: "Fezolinetant is a neurokinin 3 receptor (NK3R) antagonist approved for moderate-to-severe hot flashes. It reduces hot flash frequency by ~60% and improves sleep. Liver function tests (AST, ALT, bilirubin) must be checked at baseline and periodically because of rare but serious hepatotoxicity risk. Elinzanetant is a dual NK3/NK1 antagonist with similar efficacy." },
  { id: 2356, category: 'menopause', keywords: ['gabapentin for night sweats'], question: "How is gabapentin used for hot flashes?", response: "Gabapentin (typically 300–900 mg at bedtime) is particularly useful when hot flashes/night sweats disrupt sleep. It can be started at 100 mg and titrated. It is a good option when SSRIs/SNRIs are ineffective or not tolerated. Daytime dosing may cause sedation and dizziness." },
  { id: 2357, category: 'menopause', keywords: ['hot flashes and breast cancer'], question: "How are hot flashes managed in women with breast cancer?", response: "Systemic estrogen is generally avoided. Preferred options include SSRIs/SNRIs (avoid paroxetine and fluoxetine with tamoxifen), gabapentin, or NK3R antagonists (fezolinetant/elinzanetant). These are effective whether or not the woman is taking tamoxifen or aromatase inhibitors." },
  { id: 2358, category: 'menopause', keywords: ['impact of hot flashes on sleep'], question: "How do hot flashes affect sleep?", response: "Nocturnal hot flashes frequently cause awakenings and sleep fragmentation, especially in the first half of the night. They account for a significant portion of wake time after sleep onset. Treating vasomotor symptoms often improves sleep, but some women also have primary sleep disorders (e.g., OSA, restless legs) that require separate evaluation." },
  { id: 2359, category: 'menopause', keywords: ['therapies not recommended for hot flashes'], question: "Which therapies are not recommended for hot flashes?", response: "The Menopause Society does not recommend paced respiration, most herbal supplements, soy isoflavones, black cohosh, acupuncture, exercise, yoga, mindfulness, or clonidine as primary treatments because evidence of benefit beyond placebo is weak or inconsistent. Compounded bioidentical hormones are also not recommended due to lack of safety/efficacy data and quality concerns." },

  // === NEW UpToDate MHT Benefits & Risks RAG Entries (IDs 2362–2370) ===
  { id: 2362, category: 'menopause', keywords: ['MHT risk benefit by age'], question: "How do the risks and benefits of MHT differ by age?", response: "For healthy women ages 50–59 (or <10 years since menopause), the absolute risks of MHT for 5 years are very low. In contrast, women ≥60–70 years have a less favorable risk-benefit profile, particularly for cardiovascular events. Individualized assessment is essential, and MHT is generally avoided in women ≥70 years." },
  { id: 2363, category: 'menopause', keywords: ['attributable risks MHT women 50-59'], question: "What are the attributable risks of MHT for women in their 50s?", response: "For women ages 50–59 using combined estrogen-progestin for 5 years: ~3 extra breast cancers, 2.5 extra strokes, 3 extra pulmonary emboli, and 2.5 extra CHD events per 1000 women. Benefits include ~5 fewer deaths and fewer hip fractures. Risks are considerably lower than in older women." },
  { id: 2364, category: 'menopause', keywords: ['transdermal vs oral estrogen VTE stroke risk'], question: "Does transdermal estrogen have a lower risk of VTE and stroke than oral?", response: "Yes. Low-dose transdermal estradiol (≤50 mcg) does not appear to increase VTE or stroke risk, while oral estrogen does. Transdermal estrogen is preferred in women with higher baseline cardiovascular or VTE risk, thrombophilias, or migraine with aura." },
  { id: 2365, category: 'menopause', keywords: ['breast cancer risk combined vs estrogen alone MHT'], question: "How does breast cancer risk differ between combined MHT and estrogen-alone?", response: "Combined estrogen-progestin therapy (especially with medroxyprogesterone acetate) increases breast cancer risk. Estrogen-alone therapy is associated with a small reduction in breast cancer risk in the WHI. Current regimens using transdermal estradiol and micronized progesterone may have a more favorable profile, though long-term data are still limited." },
  { id: 2366, category: 'menopause', keywords: ['VTE risk and progestogen type'], question: "Does the type of progestogen affect VTE risk with MHT?", response: "Yes. VTE risk appears higher with medroxyprogesterone acetate than with micronized progesterone. Transdermal estrogen combined with micronized progesterone is generally considered to have the lowest VTE risk among systemic regimens." },
  { id: 2367, category: 'menopause', keywords: ['MHT and mortality'], question: "Does MHT affect overall mortality?", response: "MHT does not increase all-cause mortality. In women ages 50–59, some analyses show a possible reduction in mortality with MHT. Cardiovascular and breast cancer mortality rates were similar to placebo in long-term WHI follow-up." },
  { id: 2368, category: 'menopause', keywords: ['endometrial protection with progestogen'], question: "Do all women on systemic estrogen need a progestogen?", response: "Yes. Women with an intact uterus require a progestogen (micronized progesterone preferred) to prevent endometrial hyperplasia and cancer. Women who have had a hysterectomy should not take a progestogen. Low-dose vaginal estrogen does not require a progestogen." },
  { id: 2369, category: 'menopause', keywords: ['individualized MHT decision making'], question: "How should clinicians approach MHT decision-making?", response: "Use individualized risk assessment based on age, years since menopause, cardiovascular risk, breast cancer risk, symptom severity, and patient values. Provide absolute (attributable) risks for 5 years of use. Transdermal estradiol + micronized progesterone is often preferred for its safety profile in many women." },
  { id: 2370, category: 'menopause', keywords: ['MHT in women over 60'], question: "Should MHT be started or continued in women over 60?", response: "Starting MHT after age 60 is generally not recommended due to a less favorable risk-benefit ratio (particularly for stroke and VTE). Continuation beyond age 60 can be considered in select symptomatic women with low cardiovascular and breast cancer risk after careful discussion and at the lowest effective dose." },

  // === NEW UpToDate MHT Preparations RAG Entries (IDs 2373–2381) ===
  { id: 2373, category: 'menopause', keywords: ['preferred estrogen preparation MHT'], question: "What is the preferred estrogen preparation for menopausal hormone therapy?", response: "Transdermal 17-β-estradiol is often preferred over oral estrogen because it has a lower risk of VTE and stroke and avoids first-pass hepatic effects. Oral micronized 17-β-estradiol is a reasonable alternative for many women. Conjugated equine estrogens are effective but less commonly used as first-line now." },
  { id: 2374, category: 'menopause', keywords: ['estrogen dose equivalents MHT'], question: "What are the dose equivalents for different estrogen preparations?", response: "Approximate equivalents for standard-dose therapy: conjugated estrogens 0.625 mg = oral micronized 17-β-estradiol 1 mg = transdermal 17-β-estradiol 0.05 mg = ethinyl estradiol 5 mcg. Lower doses (e.g., transdermal 0.025 mg or oral 0.5 mg) are often effective and better tolerated for many women." },
  { id: 2375, category: 'menopause', keywords: ['micronized progesterone vs MPA'], question: "Why is micronized progesterone preferred over medroxyprogesterone acetate?", response: "Micronized progesterone (bioidentical) is metabolically neutral, does not negate estrogen's beneficial lipid effects, and appears to have a more favorable profile regarding breast cancer and cardiovascular risk compared with medroxyprogesterone acetate. Both are effective for endometrial protection." },
  { id: 2376, category: 'menopause', keywords: ['levonorgestrel IUD for endometrial protection'], question: "Can a levonorgestrel IUD be used for endometrial protection with estrogen therapy?", response: "Yes. Levonorgestrel-releasing IUDs (LNG-14 or LNG-20) provide excellent endometrial protection and are often used off-label in the United States for women who cannot tolerate oral progestins. They are particularly useful in perimenopausal women who also need contraception or have heavy bleeding." },
  { id: 2377, category: 'menopause', keywords: ['low-dose vaginal estrogen'], question: "When is low-dose vaginal estrogen used?", response: "Low-dose vaginal estrogen (e.g., 4–10 mcg estradiol) is used for genitourinary syndrome of menopause (vaginal dryness, dyspareunia, urinary symptoms). It has minimal systemic absorption and does not require a progestogen. It can be used alone or added to systemic MHT if GSM symptoms persist." },
  { id: 2378, category: 'menopause', keywords: ['compounded bioidentical hormones not recommended'], question: "Why are compounded bioidentical hormones not recommended?", response: "Compounded bioidentical hormone regimens lack rigorous quality control for purity and dosing. There are no large randomized trials proving superior safety or efficacy compared with approved, regulated products. Major societies advise against their routine use." },
  { id: 2379, category: 'menopause', keywords: ['tibolone for hot flashes'], question: "What is tibolone and is it recommended?", response: "Tibolone is a synthetic steroid with estrogenic, androgenic, and progestogenic effects. It reduces hot flashes and improves bone density but is less effective than estrogen and increases stroke risk in women over 60. It is not available in the United States and is generally not first-line." },
  { id: 2380, category: 'menopause', keywords: ['starting low-dose estrogen MHT'], question: "Should MHT be started at a low dose?", response: "Yes. Most experts recommend starting with low-dose estrogen (e.g., transdermal 0.025 mg or oral 0.5 mg) and titrating upward if needed. Low doses relieve hot flashes in many women and have fewer side effects (breast tenderness, bleeding). Ultra-low doses (e.g., transdermal 0.014 mg) may help some women with hot flashes and protect bone." },
  { id: 2381, category: 'menopause', keywords: ['TSEC conjugated estrogen bazedoxifene'], question: "What is a TSEC and when is it used?", response: "A tissue-selective estrogen complex (TSEC) combines conjugated estrogen with bazedoxifene (a SERM). The SERM protects the endometrium, so no progestin is needed. It may be useful for women with moderate-severe hot flashes who cannot tolerate progestins or who have breast tenderness on standard regimens." },

  // === NEW UpToDate Sexual Dysfunction in Female Cancer Survivors RAG Entries (IDs 2384–2392) ===
  { id: 2384, category: 'sexual health', keywords: ['sexual dysfunction female cancer survivors prevalence'], question: "How common is sexual dysfunction in female cancer survivors?", response: "A majority of female cancer survivors experience distressing sexual dysfunction. Rates are especially high after breast, gynecologic, and colorectal cancer treatment (often >50%). Dyspareunia is the most common complaint. Survivors of hematologic malignancies (post-transplant), head and neck cancers, and those with genetic cancer predispositions also have high rates but are frequently under-recognized." },
  { id: 2385, category: 'sexual health', keywords: ['biopsychosocial model sexual dysfunction cancer'], question: "What is the biopsychosocial model for sexual dysfunction in cancer survivors?", response: "The biopsychosocial model frames sexual dysfunction as resulting from biological (hormonal changes, anatomic effects of treatment), psychological (mood, body image, anxiety), interpersonal (relationship satisfaction, partner function), and sociocultural factors. This framework helps clinicians provide holistic assessment and care rather than focusing only on physical symptoms." },
  { id: 2386, category: 'sexual health', keywords: ['causes of dyspareunia in cancer survivors'], question: "What causes dyspareunia in female cancer survivors?", response: "Common causes include genitourinary syndrome of menopause (from chemotherapy, oophorectomy, or aromatase inhibitors), vaginal stenosis (from pelvic radiation or surgery), pelvic floor muscle dysfunction, vulvovaginal graft-versus-host disease, and surgical changes (e.g., after hysterectomy or vulvectomy). Treatment often starts with nonhormonal moisturizers/lubricants and may include low-dose vaginal estrogen in appropriately selected patients." },
  { id: 2387, category: 'sexual health', keywords: ['vaginal stenosis management cancer survivors'], question: "How is vaginal stenosis managed in cancer survivors?", response: "Vaginal stenosis (narrowing/shortening from pelvic radiation, surgery, or GVHD) is treated primarily with regular use of vaginal dilators (starting ~2–4 weeks after radiation) plus pelvic floor physical therapy. Consistent use of graduated dilators for at least 1 year, combined with lubricants and moisturizers, helps maintain vaginal capacity and reduces pain with penetration." },
  { id: 2388, category: 'sexual health', keywords: ['endocrine therapy sexual side effects'], question: "How does endocrine therapy affect sexual function in breast cancer survivors?", response: "Aromatase inhibitors commonly cause severe vaginal dryness, dyspareunia, and decreased libido due to profound estrogen suppression. Tamoxifen is more likely to cause vaginal discharge than dryness. These side effects are a major reason for early discontinuation of therapy. Low-dose vaginal estrogen can be considered in carefully selected patients after discussion of risks and benefits." },
  { id: 2389, category: 'sexual health', keywords: ['screening sexual dysfunction cancer survivors'], question: "How should clinicians screen for sexual dysfunction in female cancer survivors?", response: "Use ubiquity-style inquiry (e.g., 'Many patients notice changes in sexual function after treatment — have you experienced any that are bothersome?') combined with brief validated tools such as the Sexual Symptom Checklist for Female Patients After Cancer. Routine screening should occur before, during, and after treatment. Longer questionnaires (e.g., FSFI) are useful for research but less practical in busy clinics." },
  { id: 2390, category: 'sexual health', keywords: ['pelvic floor physical therapy cancer survivors'], question: "What is the role of pelvic floor physical therapy in cancer survivors with sexual dysfunction?", response: "Pelvic floor PT is highly valuable for dyspareunia, vaginal stenosis, pelvic pain, and incontinence after cancer treatment. Therapists teach dilator use, pelvic floor relaxation, and muscle coordination. It is especially helpful for secondary vaginismus and overactive pelvic floor muscles triggered by pain or anxiety." },
  { id: 2391, category: 'sexual health', keywords: ['multidisciplinary approach sexual dysfunction cancer'], question: "What is the recommended approach to managing sexual dysfunction in female cancer survivors?", response: "Use a multidisciplinary biopsychosocial approach. This may include gynecologic care (for GSM, vaginal health), pelvic floor PT, sex therapy or couples counseling, and mental health support. Address both physical (hormonal, anatomic) and psychosocial (body image, relationship, mood) contributors for best outcomes." },
  { id: 2392, category: 'sexual health', keywords: ['when to refer sexual dysfunction cancer survivor'], question: "When should clinicians refer female cancer survivors with sexual dysfunction?", response: "Refer when symptoms are complex, persist despite initial treatment, or involve significant psychological distress, relationship issues, or pelvic floor dysfunction. Ideal referrals include specialized gynecologists, pelvic floor physical therapists, and certified sex therapists with experience in cancer survivorship." },

  // === NEW UpToDate Secondary Amenorrhea Evaluation RAG Entries (IDs 2395–2403) ===
  { id: 2395, category: 'amenorrhea', keywords: ['secondary amenorrhea definition'], question: "How is secondary amenorrhea defined?", response: "Secondary amenorrhea is the absence of menses for more than 3 months in women who previously had regular cycles, or 6 months in those with irregular cycles. Oligomenorrhea (cycles >35 days or <9 menses/year) is evaluated similarly. Pregnancy must always be ruled out first." },
  { id: 2396, category: 'amenorrhea', keywords: ['initial lab workup secondary amenorrhea'], question: "What is the initial laboratory evaluation for secondary amenorrhea?", response: "After ruling out pregnancy, initial labs include serum FSH, prolactin, TSH, and estradiol. These help evaluate for primary ovarian insufficiency, hyperprolactinemia, thyroid disease, and estrogen status. If hyperandrogenism is present, add total testosterone ± 17-hydroxyprogesterone." },
  { id: 2397, category: 'amenorrhea', keywords: ['high FSH secondary amenorrhea'], question: "What does a high FSH mean in secondary amenorrhea?", response: "A high FSH indicates primary ovarian insufficiency (POI). In women without an obvious cause (e.g., chemotherapy), further testing should include karyotype (for Turner syndrome/mosaicism), fragile X premutation, and anti-adrenal antibodies. Note that FSH can fluctuate in early POI." },
  { id: 2398, category: 'amenorrhea', keywords: ['low or normal FSH secondary amenorrhea'], question: "What does low or normal FSH suggest in secondary amenorrhea?", response: "Low or inappropriately normal FSH with low estradiol suggests hypogonadotropic hypogonadism (hypothalamic or pituitary cause). Common etiologies include functional hypothalamic amenorrhea (stress, weight loss, excessive exercise), structural lesions, or infiltrative diseases. MRI of the sella is indicated if no clear functional cause is identified." },
  { id: 2399, category: 'amenorrhea', keywords: ['hyperprolactinemia evaluation amenorrhea'], question: "How should hyperprolactinemia be evaluated in amenorrhea?", response: "Mildly elevated prolactin (<50 ng/mL) should be repeated fasting in the morning. Confirm with TSH (hypothyroidism can raise prolactin). If confirmed or initially >50 ng/mL, perform pituitary MRI to evaluate for lactotroph adenoma or other sellar masses." },
  { id: 2400, category: 'amenorrhea', keywords: ['Asherman syndrome evaluation'], question: "How is Asherman syndrome (intrauterine adhesions) diagnosed?", response: "Suspect in women with normal labs and a history of uterine instrumentation (D&C, infection, etc.). A progestin challenge can be done first. If no withdrawal bleed, perform hysteroscopy or hysterosalpingogram to confirm intrauterine adhesions." },
  { id: 2401, category: 'amenorrhea', keywords: ['PCOS evaluation amenorrhea'], question: "How is PCOS evaluated in women with amenorrhea?", response: "PCOS is a common cause of secondary amenorrhea with hyperandrogenism. Diagnosis requires clinical/biochemical hyperandrogenism plus ovulatory dysfunction (after ruling out other causes). Measure testosterone; consider 17-hydroxyprogesterone to exclude nonclassic CAH. Ultrasound may show polycystic ovarian morphology but is not required for diagnosis in most cases." },
  { id: 2402, category: 'amenorrhea', keywords: ['when to do pituitary MRI amenorrhea'], question: "When should pituitary MRI be performed in secondary amenorrhea?", response: "MRI is indicated for confirmed hyperprolactinemia, hypogonadotropic hypogonadism without a clear functional cause (e.g., weight loss, stress, exercise), or any neurologic symptoms (headaches, visual changes). It is not needed if there is an obvious explanation for hypothalamic amenorrhea." },
  { id: 2403, category: 'amenorrhea', keywords: ['estrogen status assessment amenorrhea'], question: "How is estrogen status assessed in secondary amenorrhea?", response: "Estrogen status can be assessed by serum estradiol level or endometrial thickness on ultrasound (<4–5 mm suggests hypoestrogenism). This helps interpret FSH results and guides therapy (e.g., need for estrogen replacement vs. progestin for endometrial protection)." },

  // === NEW UpToDate Ovarian Development & Menopause Pathophysiology RAG Entries (IDs 2405–2412) ===
  { id: 2405, category: 'menopause', keywords: ['ovarian development and oocyte depletion'], question: "How does ovarian follicle number change across a woman's life?", response: "A female fetus has a maximum of approximately 7 million germ cells. Follicular atresia begins before birth and continues throughout life, leading to an exponential decline in oocyte number. By menopause, very few oocytes remain. This continuous process of follicular growth and atresia is the primary driver of reproductive aging." },
  { id: 2406, category: 'menopause', keywords: ['age at natural menopause'], question: "What is the average age of natural menopause and what factors influence it?", response: "The average age of natural menopause in the United States is 51 years, with most women experiencing it between ages 45–55. Factors associated with earlier menopause include smoking, certain genetic variants (including FMR1 premutation), night shift work, and hysterectomy (even with ovarian conservation). Ethnicity may also play a role." },
  { id: 2407, category: 'menopause', keywords: ['STRAW staging system'], question: "What is the STRAW staging system for reproductive aging?", response: "The Stages of Reproductive Aging Workshop (STRAW) system is the standard framework for describing reproductive aging. It divides the process into late reproductive stage, early and late menopausal transition, final menstrual period (FMP), and early/late postmenopause, based on menstrual cycle changes, endocrine markers, and symptoms." },
  { id: 2408, category: 'menopause', keywords: ['inhibin B and FSH changes in perimenopause'], question: "What hormonal changes occur during the menopausal transition?", response: "Inhibin B and anti-Müllerian hormone (AMH) levels decline early due to falling follicle numbers, leading to a rise in FSH. Estradiol levels are often preserved or even elevated in the early transition but become more variable later. These changes drive menstrual irregularity and eventual menopause." },
  { id: 2409, category: 'menopause', keywords: ['AMH as marker of ovarian reserve'], question: "What is the role of anti-Müllerian hormone (AMH) in assessing reproductive aging?", response: "Serum AMH is a useful marker of ovarian reserve. Levels decline steadily with age and falling follicle numbers. Low AMH can help predict poor ovarian response to stimulation and may mark the timing of the menopausal transition earlier than FSH changes." },
  { id: 2410, category: 'menopause', keywords: ['neuroendocrine changes with aging'], question: "How does hypothalamic-pituitary function change with reproductive aging?", response: "Aging is associated with changes in gonadotropin secretion. Postmenopausal FSH and LH have higher carbohydrate content and longer serum half-lives. There may also be reduced hypothalamic-pituitary sensitivity to estrogen feedback during the menopausal transition." },
  { id: 2411, category: 'menopause', keywords: ['oocyte viability decline with age'], question: "When does oocyte quality begin to decline?", response: "Oocyte viability begins to decline in the 30s, even before measurable changes in hormone levels. This contributes to the gradual decrease in fertility that starts around age 30–35, well before the menopausal transition." },
  { id: 2412, category: 'menopause', keywords: ['hysterectomy effect on menopause timing'], question: "Does hysterectomy affect the timing of menopause even if ovaries are conserved?", response: "Yes. Women who undergo hysterectomy (even with ovarian conservation) tend to experience menopause earlier than women who have not had this surgery. This may be related to disruption of ovarian blood supply or other mechanisms." },

  // === NEW UpToDate GSM RAG Entries (IDs 2415–2422) ===
  { id: 2415, category: 'menopause', keywords: ['genitourinary syndrome of menopause definition'], question: "What is genitourinary syndrome of menopause (GSM)?", response: "GSM is a collection of symptoms and signs caused by hypoestrogenic (and possibly hypoandrogenic) changes to the labia, clitoris, vestibule, vagina, urethra, and bladder. It includes genital symptoms (dryness, burning, irritation), sexual symptoms (lack of lubrication, pain, impaired function), and urinary symptoms (urgency, dysuria, recurrent UTIs). Symptoms must be bothersome and not better explained by another diagnosis." },
  { id: 2416, category: 'menopause', keywords: ['pathophysiology of GSM'], question: "What causes genitourinary syndrome of menopause?", response: "GSM results primarily from a marked decline in estrogen (and possibly androgens) affecting the labia, vagina, urethra, and bladder. Estrogen loss leads to thinning of the vaginal epithelium, loss of rugae and elasticity, reduced lubrication, increased vaginal pH, and changes in the vaginal microbiome. Androgen receptors are also present in these tissues and may play a supporting role." },
  { id: 2417, category: 'menopause', keywords: ['symptoms of GSM'], question: "What are the common symptoms of genitourinary syndrome of menopause?", response: "Common symptoms include vulvovaginal dryness, decreased lubrication during sex, dyspareunia, vulvar burning or irritation, vaginal itching, postcoital bleeding or spotting, urinary urgency, dysuria, and recurrent urinary tract infections. Symptoms often progress and worsen with longer duration of hypoestrogenism." },
  { id: 2418, category: 'menopause', keywords: ['physical exam findings in GSM'], question: "What are the typical pelvic exam findings in GSM?", response: "Exam findings may include pale or erythematous vaginal mucosa, loss of rugae, decreased elasticity, introital narrowing, labia minora resorption or fusion, prominent urethral meatus, petechiae, tissue fragility, and reduced vaginal secretions. In severe cases, vaginal shortening or stenosis may occur. A single-finger exam is often better tolerated than a bidigital exam." },
  { id: 2419, category: 'menopause', keywords: ['diagnosis of GSM'], question: "How is genitourinary syndrome of menopause diagnosed?", response: "GSM is a clinical diagnosis based on characteristic symptoms and physical findings in a patient with hypoestrogenism (most commonly perimenopause or postmenopause). Laboratory testing is usually not required. Vaginal pH ≥5 (in the absence of infection or recent intercourse) can support the diagnosis but is not mandatory." },
  { id: 2420, category: 'menopause', keywords: ['who gets GSM'], question: "Who is at risk for genitourinary syndrome of menopause?", response: "GSM primarily affects perimenopausal and postmenopausal women. It can also occur in premenopausal women with hypoestrogenism due to bilateral oophorectomy, primary ovarian insufficiency, chemotherapy/radiation, aromatase inhibitors, postpartum lactation, or hypothalamic amenorrhea. Longer duration of low estrogen increases risk and severity." },
  { id: 2421, category: 'menopause', keywords: ['vaginal pH in GSM'], question: "What is the role of vaginal pH in evaluating GSM?", response: "An estrogenized vagina typically has a pH of 4–4.5. In GSM, vaginal pH often rises to ≥5 due to loss of lactobacilli and glycogen. A pH ≥5 (without infection or recent intercourse) supports the diagnosis of GSM and can help patients visually understand the effects of estrogen deficiency." },
  { id: 2422, category: 'menopause', keywords: ['differential diagnosis of GSM'], question: "What is the differential diagnosis for GSM symptoms?", response: "Consider vaginitis (yeast, BV, trichomonas), vulvar lichen sclerosus or lichen planus, contact/irritant dermatitis, vulvodynia, urethral caruncle or prolapse, and other causes of urinary symptoms or postcoital bleeding. Always evaluate for infection or malignancy when symptoms are atypical or new." },

  // === NEW UpToDate Female Sexual Dysfunction Epidemiology & Evaluation RAG Entries (IDs 2425–2433) ===
  { id: 2425, category: 'sexual health', keywords: ['prevalence of female sexual dysfunction'], question: "How common is sexual dysfunction in women?", response: "Approximately 40% of women worldwide report sexual problems, and about 12% experience a sexual problem associated with personal or relationship distress. Low sexual desire is the most common concern, followed by difficulties with arousal and orgasm. Many women do not discuss these issues with their clinicians." },
  { id: 2426, category: 'sexual health', keywords: ['impact of GSM on sexual function'], question: "How does genitourinary syndrome of menopause affect sexual function?", response: "Genitourinary syndrome of menopause (GSM) is a major contributor to sexual dysfunction in perimenopausal and postmenopausal women. Vaginal dryness, reduced lubrication, and dyspareunia are very common and often lead to decreased desire and avoidance of intimacy. Treating GSM frequently improves overall sexual satisfaction." },
  { id: 2427, category: 'sexual health', keywords: ['relationship factors and sexual dysfunction'], question: "How do relationship factors affect female sexual function?", response: "Relationship quality is one of the strongest predictors of sexual satisfaction. Emotional connection, communication, partner sexual function (e.g., erectile dysfunction), and life stressors often have a bigger impact on desire and arousal than hormone levels alone. Addressing relationship issues is frequently a key part of treatment." },
  { id: 2428, category: 'sexual health', keywords: ['menopause and sexual dysfunction'], question: "How does menopause affect sexual function?", response: "Menopause commonly affects sexual function through genitourinary syndrome of menopause (dryness and pain), vasomotor symptoms, sleep disruption, and mood changes. Surgical menopause (bilateral oophorectomy) tends to have a greater impact than natural menopause. Many changes are treatable with local estrogen, moisturizers, and addressing other menopausal symptoms." },
  { id: 2429, category: 'sexual health', keywords: ['SSRIs and sexual dysfunction in women'], question: "How do antidepressants affect sexual function?", response: "Selective serotonin reuptake inhibitors (SSRIs) are a common cause of decreased libido, arousal difficulties, and delayed or absent orgasm. Bupropion and some other antidepressants are less likely to cause these side effects. Sexual side effects should be discussed when starting or changing psychiatric medications." },
  { id: 2430, category: 'sexual health', keywords: ['postpartum sexual dysfunction'], question: "Why is sexual function often affected after childbirth?", response: "Postpartum sexual concerns are very common due to hormonal changes, vaginal dryness (especially while breastfeeding), perineal trauma, fatigue, body image changes, and the demands of caring for a newborn. Most women resume sexual activity within a few months, but many experience ongoing issues with desire, arousal, or pain that benefit from support and treatment." },
  { id: 2431, category: 'sexual health', keywords: ['pelvic organ prolapse and sexual function'], question: "How do pelvic floor disorders affect sexual function?", response: "Pelvic organ prolapse and urinary incontinence are associated with sexual dysfunction, including pain, embarrassment, and reduced desire. Urinary leakage during sex is not uncommon. Pelvic floor physical therapy and addressing incontinence can significantly improve sexual comfort and confidence." },
  { id: 2432, category: 'sexual health', keywords: ['screening for sexual concerns in women'], question: "How should clinicians screen for sexual dysfunction?", response: "Sexual health should be routinely addressed during gynecologic and primary care visits. A simple open-ended question such as \"Do you have any sexual concerns?\" is effective. For menopausal patients, specifically ask about vaginal dryness and painful sex. Many women appreciate being asked and will share concerns when invited." },
  { id: 2433, category: 'sexual health', keywords: ['when to evaluate hormones in sexual dysfunction'], question: "Should hormone levels be checked when evaluating sexual dysfunction?", response: "Routine testing of testosterone, estradiol, or other hormones is not recommended for evaluating sexual dysfunction in most women. Serum androgen levels do not reliably predict sexual function. Evaluation should focus on history, relationship factors, medications, and physical findings (especially signs of GSM) rather than hormone panels." },

  // === NEW UpToDate Female Sexual Dysfunction Management RAG Entries (IDs 2434–2442) ===
  { id: 2434, category: 'sexual health', keywords: ['first-line treatment female sexual dysfunction'], question: "What is the initial approach to managing female sexual dysfunction?", response: "Start with nonpharmacologic interventions. Address relationship issues, treat underlying conditions (e.g., GSM, depression, incontinence), optimize lifestyle (sleep, stress, exercise), and refer to sex therapy or couples counseling. Pharmacologic therapy should be reserved for patients who meet diagnostic criteria for a sexual disorder and have not responded to nonpharmacologic approaches." },
  { id: 2435, category: 'sexual health', keywords: ['sex therapy for female sexual dysfunction'], question: "When should patients with sexual dysfunction be referred to sex therapy?", response: "Sex therapy is highly effective and should be considered early for most patients. It is especially helpful for low desire, arousal difficulties, orgasm concerns, and pain-related avoidance. Certified sex therapists provide education, communication strategies, sensate focus exercises, and guidance on sexual aids. Referral is often a prerequisite before starting pharmacologic therapy." },
  { id: 2436, category: 'sexual health', keywords: ['testosterone therapy postmenopausal women'], question: "When is testosterone therapy appropriate for postmenopausal women with low libido?", response: "Testosterone (typically compounded 1% topical cream 0.5 g daily) may be considered in carefully selected postmenopausal women with distressing low desire after nonpharmacologic interventions have been tried. It should not be used in premenopausal women. Discuss limited efficacy data, lack of FDA approval for this indication, and potential androgenic side effects. Monitor for hirsutism, acne, lipids, and liver function." },
  { id: 2437, category: 'sexual health', keywords: ['flibanserin for HSDD'], question: "What is the role of flibanserin in treating low sexual desire?", response: "Flibanserin is FDA-approved for premenopausal and postmenopausal women <65 years with low sexual desire and distress. It produces a small increase in satisfying sexual events (~0.5 per month) but requires daily dosing and has significant side effects (somnolence, dizziness, nausea). It is contraindicated with alcohol and strong CYP3A4 inhibitors. Many clinicians prefer other options due to modest benefit and safety concerns." },
  { id: 2438, category: 'sexual health', keywords: ['bremelanotide for HSDD'], question: "How is bremelanotide used for female sexual dysfunction?", response: "Bremelanotide is an on-demand subcutaneous injection (1.75 mg) given at least 45 minutes before anticipated sexual activity. It is approved for premenopausal women with HSDD. It can improve desire and satisfaction but causes nausea in ~40% of users (often with first dose). It should not be used in women with uncontrolled hypertension or cardiovascular disease." },
  { id: 2439, category: 'sexual health', keywords: ['bupropion for sexual dysfunction'], question: "When is bupropion useful for female sexual dysfunction?", response: "Bupropion (off-label for sexual dysfunction) is often a first-choice pharmacologic option due to its favorable long-term safety profile and low cost. It can help with low desire and SSRI-induced sexual side effects. It is typically dosed in the morning; monitor for anxiety, insomnia, and hypertension. It is a reasonable alternative to flibanserin for many patients." },
  { id: 2440, category: 'sexual health', keywords: ['GSM treatment improves sexual function'], question: "How does treating GSM affect overall sexual function?", response: "Treating genitourinary syndrome of menopause (with vaginal estrogen, moisturizers, or DHEA) often improves not only dyspareunia but also sexual desire and arousal by reducing pain and fear of discomfort. Many women experience secondary gains in libido once pain is addressed. Always evaluate and treat GSM before or alongside other interventions for low desire." },
  { id: 2441, category: 'sexual health', keywords: ['multidisciplinary approach sexual dysfunction'], question: "What is the recommended multidisciplinary approach to female sexual dysfunction?", response: "Optimal care often involves coordination between gynecology, primary care, mental health/sex therapy, and pelvic floor physical therapy. Address medical contributors (GSM, incontinence, medications), psychological factors (depression, body image, trauma), and relationship dynamics. Shared decision-making and realistic goal-setting are essential." },
  { id: 2442, category: 'sexual health', keywords: ['PDE5 inhibitors in women'], question: "Do PDE-5 inhibitors help women with sexual dysfunction?", response: "PDE-5 inhibitors (e.g., sildenafil) are generally not effective for most women with sexual dysfunction. They may have a limited role in women with SSRI-induced orgasm difficulties or arousal problems related to diabetes or neurologic conditions. They are not FDA-approved for use in women." },

  // === NEW UpToDate POI Pathogenesis & Causes RAG Entries (IDs 2443–2451) ===
  { id: 2443, category: 'POI', keywords: ['primary ovarian insufficiency definition'], question: "How is primary ovarian insufficiency (POI) defined?", response: "POI (formerly premature ovarian failure) is primary hypogonadism in a woman under age 40, characterized by loss of oocytes, lack of folliculogenesis, ovarian estrogen production, and infertility. It is diagnosed by elevated FSH with low or undetectable estradiol. More than 50% of women show some evidence of intermittent or partial ovarian activity over time." },
  { id: 2444, category: 'POI', keywords: ['genetic causes of POI'], question: "What proportion of POI cases have an identifiable genetic cause?", response: "Whole exome or whole genome sequencing identifies a genetic cause in approximately 30–35% of POI cases. The etiology remains unknown in most women. Commercially available gene panels are incomplete because new genes are still being discovered rapidly." },
  { id: 2445, category: 'POI', keywords: ['Turner syndrome and POI'], question: "How does Turner syndrome cause POI?", response: "Turner syndrome (45,X or mosaicism) is one of the most common causes of POI. Ovaries initially have a normal complement of primordial germ cells, but accelerated follicular atresia leads to streak gonads. Clinical presentation ranges from primary amenorrhea with absent puberty to secondary amenorrhea with preserved stature and minimal dysmorphic features." },
  { id: 2446, category: 'POI', keywords: ['FMR1 premutation and POI'], question: "What is the relationship between FMR1 premutation and POI?", response: "Women who carry an FMR1 premutation (55–200 CGG repeats) have a 12–28% risk of POI. The prevalence of FMR1 premutations is 2–5% in sporadic POI and 12–16% in familial POI. ACOG recommends screening all women with POI or elevated FSH before age 40 for FMR1 premutations. Premutation carriers also have increased risk of fragile X-associated tremor/ataxia syndrome (FXTAS)." },
  { id: 2447, category: 'POI', keywords: ['autoimmune oophoritis POI'], question: "What is the role of autoimmunity in POI?", response: "Autoimmune oophoritis accounts for approximately 4% of 46,XX POI cases, especially when associated with adrenal autoimmunity (polyglandular autoimmune syndromes). It features lymphocytic infiltration of theca cells with sparing of primordial follicles early on. Anti-adrenal antibodies are a useful marker. Immunosuppressive therapy is not currently recommended outside research settings." },
  { id: 2448, category: 'POI', keywords: ['genes associated with POI'], question: "Which genes are commonly implicated in POI?", response: "Genes associated with POI include those involved in ovarian development (NR5A1, WT1, ESR2), oocyte/follicle maintenance (FIGLA, NOBOX, BMP15, FOXL2), meiosis and DNA repair (STAG3, SYCE1, MCM8, MCM9, BRCA2), and mitochondrial function. Many are rare; commercial panels do not yet include all clinically relevant genes." },
  { id: 2449, category: 'POI', keywords: ['chemotherapy radiation and POI'], question: "How do chemotherapy and radiation cause POI?", response: "Chemotherapeutic agents (especially alkylators) and pelvic/abdominal radiation are the most common iatrogenic causes of POI. Risk depends on age, dose, and specific agents. Even sub-sterilizing doses can accelerate ovarian aging and increase risk of early menopause. Fertility preservation should be discussed before gonadotoxic therapy." },
  { id: 2450, category: 'POI', keywords: ['galactosemia and POI'], question: "What is the relationship between galactosemia and POI?", response: "Women with classic galactosemia have a very high rate of POI due to toxic effects of galactose metabolites on the ovary. Even heterozygous carriers of galactosemia mutations may have a modestly earlier age at menopause. Newborn screening and early dietary treatment do not fully prevent ovarian failure." },
  { id: 2451, category: 'POI', keywords: ['steroidogenic defects and POI'], question: "Can steroidogenic enzyme defects cause POI?", response: "Yes. Mutations in genes such as StAR (lipoid congenital adrenal hyperplasia), CYP17, and aromatase can present with primary hypogonadism and high FSH despite the presence of follicles. These are rare but important to recognize because they represent primary hypogonadism without complete follicle depletion." },

  // === NEW UpToDate GSM Management RAG Entries (IDs 2452–2460) ===
  { id: 2452, category: 'menopause', keywords: ['first-line treatment GSM'], question: "What is first-line treatment for genitourinary syndrome of menopause?", response: "Nonhormonal vaginal moisturizers (used 2–3 times per week) and lubricants (used during sexual activity) are first-line therapy for most patients with GSM. Pelvic floor muscle exercises can also be helpful. These options are safe for all patients, including those with estrogen-sensitive cancers, but many women with moderate-to-severe symptoms will eventually need hormonal therapy for adequate relief." },
  { id: 2453, category: 'menopause', keywords: ['vaginal estrogen for GSM'], question: "When and how should vaginal estrogen be used for GSM?", response: "Low-dose vaginal estrogen is the most effective treatment for moderate-to-severe GSM symptoms that do not respond to moisturizers and lubricants. Available options include estradiol vaginal tablets/capsules (4 or 10 mcg), the 7.5 mcg/day estradiol ring, and low-dose estradiol or conjugated estrogen creams. Typical regimen: daily for 2 weeks, then twice weekly. Improvement is usually seen within 2–4 weeks." },
  { id: 2454, category: 'menopause', keywords: ['systemic absorption low-dose vaginal estrogen'], question: "How much systemic absorption occurs with low-dose vaginal estrogen?", response: "Low-dose vaginal estrogen (≤10 mcg estradiol or ≤0.3 mg conjugated estrogens) produces only minimal systemic absorption, with serum estradiol levels remaining near or slightly above typical postmenopausal levels (~5–10 pg/mL). Absorption is highest initially and decreases as the vaginal epithelium thickens. Long-term observational data have not shown increased risk of breast cancer, endometrial cancer, VTE, or cardiovascular events." },
  { id: 2455, category: 'menopause', keywords: ['progestogen with vaginal estrogen'], question: "Is a progestogen needed with low-dose vaginal estrogen for GSM?", response: "For standard low-dose vaginal estrogen regimens (4–10 mcg estradiol tablet/ring or low-dose cream), a progestogen is generally not required for endometrial protection. However, any postmenopausal bleeding should still prompt evaluation. Data supporting endometrial safety beyond 1 year are limited." },
  { id: 2456, category: 'menopause', keywords: ['vaginal DHEA prasterone for GSM'], question: "What is the role of vaginal DHEA (prasterone) in GSM?", response: "Vaginal DHEA (6.5 mg daily suppository) is FDA-approved for dyspareunia due to GSM. It improves vaginal maturation, dryness, and pain. It causes small increases in serum DHEA, testosterone, and estrone but not usually estradiol. It is a reasonable option for patients who prefer to avoid estrogen or cannot use vaginal estrogen, though daily dosing is less convenient than twice-weekly estrogen." },
  { id: 2457, category: 'menopause', keywords: ['ospemifene for GSM'], question: "When should ospemifene be used for GSM?", response: "Ospemifene (60 mg oral daily) is a SERM approved for moderate-to-severe dyspareunia and vaginal dryness due to GSM. It is a good option for patients who cannot or prefer not to use vaginal products. Main side effects are hot flashes and a potential (though low) risk of VTE. It has not been adequately studied in women with breast cancer." },
  { id: 2458, category: 'menopause', keywords: ['GSM treatment breast cancer aromatase inhibitors'], question: "How should GSM be managed in women on aromatase inhibitors?", response: "Nonhormonal moisturizers and lubricants are first-line. For women with persistent, bothersome symptoms, low-dose vaginal estrogen or prasterone can be considered after shared decision-making with the oncologist. Short-term use appears unlikely to meaningfully affect long-term cancer outcomes, but data are limited. Some oncologists switch patients from AI to tamoxifen to reduce GSM severity." },
  { id: 2459, category: 'menopause', keywords: ['pelvic floor therapy and dilators for GSM'], question: "When are pelvic floor physical therapy and vaginal dilators used in GSM?", response: "Pelvic floor PT and graduated vaginal dilators are helpful for refractory GSM symptoms, introital or vaginal stenosis, levator spasm, or when hormone therapy is contraindicated. Dilators are most effective after atrophy has been improved with hormonal therapy. They are also useful for maintaining vaginal capacity after radiation or surgery." },
  { id: 2460, category: 'menopause', keywords: ['laser therapy for GSM evidence'], question: "What is the current evidence for vaginal laser therapy in GSM?", response: "Fractional CO2 and Er:YAG lasers have been marketed for GSM, but high-quality randomized sham-controlled trials show no clear benefit over sham treatment for vaginal symptoms or sexual function. The FDA has issued safety communications regarding risks (pain, burns, scarring). We do not recommend laser therapy outside of clinical trials until better data are available." },

  // === NEW UpToDate MHT & Osteoporosis RAG Entries (IDs 2461–2468) ===
  { id: 2461, category: 'menopause', keywords: ['MHT for osteoporosis prevention'], question: "Is menopausal hormone therapy recommended as first-line therapy for osteoporosis prevention?", response: "No. MHT is no longer considered first-line for osteoporosis prevention due to the risks demonstrated in the Women's Health Initiative (increased breast cancer, stroke, VTE, and CHD with combined therapy in older women). However, women who take MHT for menopausal symptoms (hot flashes) in their late 40s or early 50s receive meaningful skeletal protection as an added benefit." },
  { id: 2462, category: 'menopause', keywords: ['estrogen prevents bone loss and fractures'], question: "Does estrogen prevent bone loss and fractures?", response: "Yes. Estrogen therapy attenuates postmenopausal bone loss and reduces fracture risk. In the WHI, both estrogen-alone and estrogen-progestin therapy reduced hip, vertebral, and other osteoporotic fractures. The protective effect is seen across different estrogen and progestin types and routes of administration." },
  { id: 2463, category: 'menopause', keywords: ['low dose estrogen bone protection'], question: "Do lower doses of estrogen protect bone?", response: "Yes. Standard low doses (transdermal estradiol ≥25 mcg/day or oral estradiol ≥0.5 mg/day) provide good skeletal protection. Even ultra-low-dose transdermal estradiol (14 mcg/day) and oral estradiol 0.25 mg/day appear to prevent bone loss when calcium and vitamin D intake are adequate. Bone density monitoring is recommended in high-risk women on ultra-low doses." },
  { id: 2464, category: 'menopause', keywords: ['timing of MHT for bone benefit'], question: "When should MHT be started for bone protection?", response: "The greatest skeletal benefit occurs when MHT is started soon after menopause (within ~10 years) and continued. Starting estrogen later in life (e.g., after age 60–65) still provides some benefit but carries higher risks. Women who stop estrogen experience variable rates of bone loss; some show catch-up loss while others do not." },
  { id: 2465, category: 'menopause', keywords: ['estrogen for established osteoporosis'], question: "Is estrogen first-line treatment for established osteoporosis?", response: "No. Estrogen is FDA-approved for prevention but not treatment of osteoporosis. More potent agents (bisphosphonates, denosumab, etc.) are preferred for women with established osteoporosis or high fracture risk. However, in women already taking MHT for symptoms who have osteoporosis, estrogen may be sufficient if bone density is monitored." },
  { id: 2466, category: 'menopause', keywords: ['progestin effect on bone'], question: "Does adding a progestin improve bone protection with estrogen?", response: "Adding a progestin (cyclic or continuous) does not meaningfully increase the bone-protective effect of estrogen. Progesterone itself has only a modest antiresorptive effect compared with estrogen. The main reason to add a progestin is endometrial protection in women with a uterus." },
  { id: 2467, category: 'menopause', keywords: ['estrogen vs bisphosphonate bone'], question: "How does estrogen compare with bisphosphonates for bone?", response: "In younger postmenopausal women, estrogen is roughly comparable to alendronate for preventing bone loss. In older women, alendronate may be superior. Bone loss after stopping estrogen can be greater than after stopping alendronate. Combination therapy provides only modest additional BMD gains and is not routinely recommended." },
  { id: 2468, category: 'menopause', keywords: ['MHT and bone density monitoring'], question: "When should bone density be monitored in women on MHT?", response: "Women on standard or higher doses of estrogen for menopausal symptoms usually do not need a separate osteoporosis drug. However, women on ultra-low-dose estrogen (e.g., 14 mcg transdermal) who are at high fracture risk should have bone density monitoring, as an additional agent may be needed." },

  // === NEW UpToDate Oophorectomy & Surgical Menopause RAG Entries (IDs 2471–2478) ===
  { id: 2471, category: 'surgical menopause', keywords: ['oophorectomy definition'], question: "What is an oophorectomy?", response: "Oophorectomy is surgery to remove one or both ovaries. Removing part of an ovary is called cystectomy. It is often performed for ovarian cancer risk reduction, endometriosis, tubo-ovarian abscess, benign cysts/tumors, or metastatic cancer. It may be done alone or with hysterectomy and/or salpingectomy (salpingo-oophorectomy)." },
  { id: 2472, category: 'surgical menopause', keywords: ['bilateral oophorectomy surgical menopause'], question: "What happens after bilateral oophorectomy?", response: "Bilateral oophorectomy in a premenopausal woman causes surgical menopause. Estrogen and progesterone production drops abruptly, leading to hot flashes, night sweats, mood changes, vaginal dryness, and accelerated bone loss. Symptoms can be more sudden and intense than natural menopause. Hormone therapy may be appropriate depending on age, symptoms, and cancer risk." },
  { id: 2473, category: 'surgical menopause', keywords: ['unilateral oophorectomy effects'], question: "What are the effects of unilateral oophorectomy?", response: "Removing only one ovary usually does not cause surgical menopause. Fertility is typically preserved (similar pregnancy rates to women with two ovaries). However, menopause may occur earlier than average due to reduced ovarian reserve." },
  { id: 2474, category: 'surgical menopause', keywords: ['fertility after oophorectomy'], question: "How does oophorectomy affect fertility?", response: "Bilateral oophorectomy causes infertility without assisted reproduction. Options include egg freezing before surgery (with later IVF) or using donor eggs. These are expensive and not always covered by insurance. Women with one remaining ovary usually retain good fertility potential. Pre-surgical fertility counseling and referral to a reproductive endocrinologist are essential if future childbearing is desired." },
  { id: 2475, category: 'surgical menopause', keywords: ['surgical menopause symptoms and management'], question: "How should surgical menopause be managed?", response: "Surgical menopause causes abrupt estrogen deficiency. Management may include menopausal hormone therapy (if not contraindicated), nonhormonal options for hot flashes, vaginal estrogen or moisturizers for GSM, and attention to bone health (calcium, vitamin D, weight-bearing exercise, and possible bone density testing). Psychological support is often needed due to the sudden transition." },
  { id: 2476, category: 'surgical menopause', keywords: ['oophorectomy and bone health'], question: "How does oophorectomy affect bone health?", response: "Bilateral oophorectomy causes rapid bone loss due to sudden estrogen withdrawal. This increases lifetime fracture risk. Women should discuss bone density monitoring, calcium/vitamin D intake, exercise, and whether hormone therapy or other osteoporosis prevention strategies are appropriate, especially if oophorectomy occurs before natural menopause age." },
  { id: 2477, category: 'surgical menopause', keywords: ['questions to ask before oophorectomy'], question: "What key questions should patients ask before oophorectomy?", response: "Important questions include: How will this help me? Will it help me live longer? Are there alternatives? What are the risks? What will my life be like afterward (symptoms, hormones, sexual function, bone health)? What if I want to get pregnant in the future? Patients should receive clear answers and fertility counseling before proceeding." },
  { id: 2478, category: 'surgical menopause', keywords: ['CycleMind tracking after oophorectomy'], question: "How should CycleMind support users after oophorectomy?", response: "CycleMind should offer a distinct 'Surgical Menopause' mode with tracking for abrupt onset of vasomotor symptoms, mood changes, vaginal dryness, and sexual function. It should include prompts for bone health reminders, GSM symptom logging, hormone therapy decision support (when appropriate), and notes on fertility status or preservation history." },

  // === NEW UpToDate Absent/Irregular Periods RAG Entries (IDs 2481–2489) ===
  { id: 2481, category: 'menstrual disorders', keywords: ['absent or irregular periods definition'], question: "What are absent or irregular periods?", response: "Absent periods (amenorrhea) means no periods at all. Irregular periods (oligomenorrhea) typically means fewer than 6–8 periods per year or cycles longer than 45 days. A single missed period is common, but persistent absence or irregularity warrants evaluation after ruling out pregnancy." },
  { id: 2482, category: 'menstrual disorders', keywords: ['PCOS irregular periods'], question: "How does PCOS cause irregular periods?", response: "PCOS is the most common cause of irregular or absent periods. Excess androgens from the ovaries disrupt normal ovulation, leading to infrequent or absent menses. It is often accompanied by acne, hirsutism, weight gain, and insulin resistance. Diagnosis requires clinical or biochemical hyperandrogenism plus ovulatory dysfunction after excluding other causes." },
  { id: 2483, category: 'menstrual disorders', keywords: ['functional hypothalamic amenorrhea causes'], question: "What causes functional hypothalamic amenorrhea?", response: "Functional hypothalamic amenorrhea occurs when the body's energy supply is insufficient (from excessive exercise, stress, eating disorders, or low calorie intake). This suppresses GnRH pulsatility, lowering FSH, LH, and estradiol. It is a diagnosis of exclusion after ruling out pregnancy, PCOS, hyperprolactinemia, and thyroid disease." },
  { id: 2484, category: 'menstrual disorders', keywords: ['primary ovarian insufficiency irregular periods'], question: "When should primary ovarian insufficiency be considered with irregular periods?", response: "Primary ovarian insufficiency (POI) should be considered in women under 40 with irregular or absent periods, especially with hot flashes or night sweats. It is diagnosed by elevated FSH on two occasions. Early menopause (ages 40–45) is also possible. Both require evaluation for underlying causes and hormone replacement considerations." },
  { id: 2485, category: 'menstrual disorders', keywords: ['hyperprolactinemia amenorrhea'], question: "How does high prolactin cause absent periods?", response: "Elevated prolactin (from a pituitary adenoma, medications, hypothyroidism, or other causes) suppresses GnRH, leading to low FSH/LH and absent or irregular periods. Milky breast discharge (galactorrhea) may be present. Prolactin should be measured in the workup of secondary amenorrhea, ideally fasting and without recent nipple stimulation." },
  { id: 2486, category: 'menstrual disorders', keywords: ['evaluation of absent irregular periods'], question: "What is the initial evaluation for absent or irregular periods?", response: "Start with a pregnancy test. Then obtain FSH, prolactin, TSH, and estradiol. Add total testosterone ± 17-hydroxyprogesterone if hyperandrogenism is present. Pelvic ultrasound can assess for PCOS morphology or other uterine/ovarian pathology. MRI of the pituitary is indicated if prolactin is significantly elevated or if there are neurologic symptoms." },
  { id: 2487, category: 'menstrual disorders', keywords: ['when to evaluate absent periods'], question: "When should absent or irregular periods be evaluated?", response: "Evaluate if: no periods by age 15–16, previously regular periods now absent for >3 months, or cycles >45 days apart. Also evaluate with red flags such as hot flashes, galactorrhea, new headaches/visual changes, signs of hyperandrogenism, rapid weight changes, or high stress/exercise." },
  { id: 2488, category: 'menstrual disorders', keywords: ['treatment of irregular periods'], question: "How are absent or irregular periods treated?", response: "Treatment depends on the cause and fertility goals. Options include: combined hormonal contraceptives for regulation (if not trying to conceive), lifestyle changes (weight restoration, reduced exercise, stress management) for functional hypothalamic amenorrhea, metformin or other agents for PCOS, dopamine agonists for hyperprolactinemia, and hormone therapy for POI/early menopause. Fertility treatment may be needed if pregnancy is desired." },
  { id: 2489, category: 'menstrual disorders', keywords: ['CycleMind tracking irregular periods'], question: "How should CycleMind help users with irregular or absent periods?", response: "CycleMind should allow flexible cycle length tracking, symptom logging (hot flashes, acne, hirsutism, galactorrhea, mood, energy), and prompts for red-flag symptoms. It can guide users on when to seek care and support lifestyle tracking (exercise, nutrition, stress) relevant to functional hypothalamic amenorrhea while reminding that medical evaluation is needed for persistent irregularity." },

  // === NEW UpToDate Oophorectomy Surgical Details RAG Entries (IDs 2491–2498) ===
  { id: 2491, category: 'surgical menopause', keywords: ['oophorectomy open vs minimally invasive'], question: "What are the surgical approaches for oophorectomy?", response: "Oophorectomy can be performed via open surgery (larger incision) or minimally invasive surgery (laparoscopic or robotic-assisted with smaller incisions and a camera). Minimally invasive approaches generally allow faster recovery and return to normal activities. The choice depends on the reason for surgery, patient factors, and surgeon expertise." },
  { id: 2492, category: 'surgical menopause', keywords: ['preparing for oophorectomy'], question: "How should patients prepare for oophorectomy?", response: "Preparation includes a physical exam, imaging and lab tests as needed, review of medical history, current medications, allergies, and bleeding risk. Patients may need to fast before surgery, trim (not shave) body hair, and wash with special soap. They should also arrange for help at home after surgery and discuss family history of ovarian or breast cancer." },
  { id: 2493, category: 'surgical menopause', keywords: ['anesthesia for oophorectomy'], question: "What type of anesthesia is used for oophorectomy?", response: "Oophorectomy is usually performed under general anesthesia (patient is unconscious). Regional anesthesia (spinal or epidural) may be used in some cases, sometimes combined with sedation. A breathing tube may be placed during general anesthesia. Pain control medications are given before and after surgery." },
  { id: 2494, category: 'surgical menopause', keywords: ['ovarian remnant syndrome'], question: "What is ovarian remnant syndrome?", response: "Ovarian remnant syndrome occurs when small pieces of ovarian tissue are left behind after oophorectomy. This tissue can continue to produce hormones and cause pain, cysts, or other symptoms, sometimes requiring additional surgery. It is an uncommon but recognized complication." },
  { id: 2495, category: 'surgical menopause', keywords: ['risks of oophorectomy'], question: "What are the main risks of oophorectomy?", response: "Risks include bleeding, infection, injury to nearby organs (bowel, bladder, ureters), and (rarely) spillage of cancer cells if a malignant tumor is present. Other risks include anesthesia complications and ovarian remnant syndrome. The specific risks depend on whether surgery is open or minimally invasive and the underlying reason for the procedure." },
  { id: 2496, category: 'surgical menopause', keywords: ['recovery after oophorectomy'], question: "What is recovery like after oophorectomy?", response: "After surgery, patients are monitored in the recovery room as anesthesia wears off. Common temporary effects include grogginess, nausea, and sore throat (if a breathing tube was used). Most patients start with clear liquids and advance to regular food as tolerated. Light vaginal bleeding or spotting is normal. Pain is managed with medication, and early mobilization is encouraged." },
  { id: 2497, category: 'surgical menopause', keywords: ['fertility planning before oophorectomy'], question: "How can fertility be preserved before oophorectomy?", response: "If future pregnancy is desired and both ovaries will be removed, patients should discuss fertility preservation before surgery. Options include egg freezing (oocyte cryopreservation) with later IVF, or using donor eggs. These discussions should occur with a reproductive endocrinologist as early as possible, as they require time and planning." },
  { id: 2498, category: 'surgical menopause', keywords: ['surgical menopause symptoms'], question: "What symptoms occur with surgical menopause after oophorectomy?", response: "Bilateral oophorectomy before natural menopause causes abrupt surgical menopause. Symptoms can include hot flashes, night sweats, vaginal dryness, low mood, sleep disturbance, difficulty concentrating, and accelerated bone loss. These symptoms are often more sudden and intense than in natural menopause. Treatment options (hormonal and non-hormonal) should be discussed preoperatively." },

  // === NEW UpToDate Sexual Function & Aging RAG Entries (IDs 2501–2509) ===
  { id: 2501, category: 'sexual health', keywords: ['sex changes with aging in women'], question: "How does sexual function typically change as women get older?", response: "Many women experience decreased sexual interest, difficulty with arousal or lubrication, less intense orgasms, and pain during sex as they age. These changes are often linked to menopause (especially the drop in estrogen), but medical conditions, medications, mood, past surgery, and relationship factors also play major roles. Sex can remain satisfying with appropriate support and treatment." },
  { id: 2502, category: 'sexual health', keywords: ['GSM and sexual pain in older women'], question: "How does genitourinary syndrome of menopause affect sex?", response: "After menopause, declining estrogen causes vaginal dryness, thinning of tissues, and reduced elasticity, leading to pain, discomfort, or bleeding with penetration. This is a major cause of sexual dysfunction in older women. Low-dose vaginal estrogen, moisturizers, and lubricants are effective treatments. Pain should not be accepted as inevitable." },
  { id: 2503, category: 'sexual health', keywords: ['medical conditions affecting sex in older adults'], question: "Which medical conditions commonly affect sexual function in older women?", response: "Diabetes (especially erectile issues in partners or neuropathy), heart disease, obesity, high blood pressure, chronic pain, and depression/anxiety can reduce desire, arousal, and comfort with sex. Past cancer treatments, pelvic surgery, or radiation can also cause lasting changes. Treating the underlying condition often improves sexual function." },
  { id: 2504, category: 'sexual health', keywords: ['medications and sexual side effects older women'], question: "How do medications affect sexual function in older adults?", response: "Many common medications for blood pressure, depression, anxiety, diabetes, and heart disease can cause low desire, arousal difficulties, or orgasm problems. A medication review is often one of the most helpful first steps when sexual concerns arise in older patients." },
  { id: 2505, category: 'sexual health', keywords: ['when to seek help for sexual changes with age'], question: "When should older women seek help for sexual concerns?", response: "Women should talk to their clinician if they are unhappy with their sex life, have pain during sex, or notice new difficulties with desire, arousal, or orgasm. Many effective treatments exist (vaginal estrogen, medication adjustments, counseling, lubricants). Clinicians are accustomed to these discussions and can help." },
  { id: 2506, category: 'sexual health', keywords: ['vaginal estrogen for older women'], question: "Is vaginal estrogen safe and effective for sexual symptoms in older women?", response: "Yes. Low-dose vaginal estrogen is highly effective for GSM-related dryness, pain, and discomfort during sex. It has minimal systemic absorption and a strong safety record for most women, including many breast cancer survivors (after discussion with oncology). It is often more effective than moisturizers alone for moderate-to-severe symptoms." },
  { id: 2507, category: 'sexual health', keywords: ['communication and sex in older couples'], question: "How can older couples improve their sex life?", response: "Open communication about desires, concerns, and physical changes is essential. Sex does not have to mean intercourse — exploring other forms of intimacy and pleasure can be very satisfying. Planning sex when pain or stiffness is lowest (e.g., after pain medication) and trying different positions can help. Partners should also seek treatment for their own sexual difficulties." },
  { id: 2508, category: 'sexual health', keywords: ['sex after heart attack or major illness'], question: "Is it safe to have sex after a heart attack or major health event?", response: "Most people can safely resume sexual activity after a heart attack or similar event, but timing and modifications may be needed. Patients should check with their doctor. Fear and anxiety are common and can be addressed with reassurance and guidance on safe activity levels." },
  { id: 2509, category: 'sexual health', keywords: ['CycleMind sexual health tracking older users'], question: "How can CycleMind support sexual health tracking in perimenopausal and older users?", response: "CycleMind should include optional tracking for sexual desire, arousal, lubrication, pain/discomfort, orgasm satisfaction, and relationship factors. It can prompt users about GSM symptoms after menopause or oophorectomy and suggest evidence-based options (vaginal estrogen, moisturizers, communication tips) while encouraging professional evaluation when concerns persist." },

  // === NEW UpToDate Painful Sex (Dyspareunia) RAG Entries (IDs 2511–2519) ===
  { id: 2511, category: 'sexual health', keywords: ['painful sex definition dyspareunia'], question: "What is painful sex (dyspareunia)?", response: "Painful sex (dyspareunia) is pain or discomfort that occurs just before, during, or after sexual activity. In females, pain can be at the vulva (superficial), inside the vagina, or deep in the pelvis/lower abdomen. It is more common in females than males and has many treatable causes." },
  { id: 2512, category: 'sexual health', keywords: ['causes of painful sex in women'], question: "What are common causes of painful sex in women?", response: "Common causes include genitourinary syndrome of menopause (vaginal dryness and thinning), endometriosis, postpartum changes, vulvodynia, bladder pain syndrome, chronic pelvic pain, vaginal or bladder infections, skin conditions, insufficient arousal/lubrication, past trauma or painful experiences, relationship issues, and sometimes hormonal birth control." },
  { id: 2513, category: 'sexual health', keywords: ['GSM and dyspareunia'], question: "How does genitourinary syndrome of menopause cause painful sex?", response: "After menopause, low estrogen causes vaginal dryness, thinning of tissues, and loss of elasticity, leading to pain, burning, or bleeding with penetration. This is one of the most common and treatable causes of dyspareunia in older women. Low-dose vaginal estrogen, moisturizers, and lubricants are effective treatments." },
  { id: 2514, category: 'sexual health', keywords: ['postpartum painful sex'], question: "Why is sex often painful after childbirth?", response: "Pain after childbirth is common due to perineal trauma, episiotomy, vaginal dryness (especially while breastfeeding), hormonal changes, and pelvic floor muscle tension. Most women resume intercourse within a few months, but pain can persist and often improves with time, lubricants, moisturizers, or pelvic floor physical therapy." },
  { id: 2515, category: 'sexual health', keywords: ['vulvodynia and painful sex'], question: "What is vulvodynia and how does it cause painful sex?", response: "Vulvodynia is chronic pain in the vulva without an identifiable cause. It can cause burning, stinging, or sharp pain with touch or penetration. It is distinct from GSM or infection. Treatment often includes pelvic floor physical therapy, topical medications, counseling, and avoiding irritants." },
  { id: 2516, category: 'sexual health', keywords: ['when to seek care for painful sex'], question: "When should someone see a doctor for painful sex?", response: "Anyone experiencing pain with sex should see a clinician. Evaluation includes a history, pelvic exam, and possible urine or vaginal testing for infection. Red flags include new or worsening pain, bleeding, discharge, or pain associated with other symptoms (e.g., pelvic pain, bladder symptoms)." },
  { id: 2517, category: 'sexual health', keywords: ['treatment of painful sex in women'], question: "How is painful sex treated in women?", response: "Treatment is cause-specific and may include: treating infections, vaginal moisturizers/lubricants or low-dose vaginal estrogen for GSM, pelvic floor physical therapy for muscle tension or vulvodynia, counseling for relationship or trauma-related issues, numbing agents, or (rarely) surgery. A multimodal approach is often most effective." },
  { id: 2518, category: 'sexual health', keywords: ['pelvic floor physical therapy for dyspareunia'], question: "How does pelvic floor physical therapy help painful sex?", response: "Pelvic floor PT is very effective for dyspareunia caused by muscle tension, levator spasm, or vaginismus. Therapists use manual techniques, biofeedback, dilators, and exercises to reduce pain, improve muscle relaxation, and restore comfortable penetration. It is often combined with other treatments." },
  { id: 2519, category: 'sexual health', keywords: ['CycleMind painful sex tracking'], question: "How should CycleMind support users with painful sex?", response: "CycleMind should allow users to log pain location (superficial vs. deep), timing (before/during/after sex), severity, and associated symptoms (dryness, burning, bladder symptoms). It can prompt consideration of GSM, postpartum status, or endometriosis and suggest evidence-based next steps while encouraging professional evaluation." },

  // === NEW UpToDate Psychotherapy Overview RAG Entries (IDs 2521–2529) ===
  { id: 2521, category: 'psychotherapy', keywords: ['cognitive behavioral therapy CBT overview'], question: "What is cognitive-behavioral therapy (CBT) and for which conditions is it effective?", response: "CBT helps patients identify and change maladaptive thoughts and behaviors. It is one of the most evidence-based psychotherapies and is effective for depression, anxiety disorders (including generalized anxiety, panic, and social anxiety), PTSD, OCD, eating disorders, substance use disorders, and some medical conditions (e.g., insomnia, chronic pain). It is structured, skill-based, and works best for motivated patients who value a problem-solving approach." },
  { id: 2522, category: 'psychotherapy', keywords: ['interpersonal psychotherapy IPT'], question: "What is interpersonal psychotherapy (IPT) and when is it used?", response: "IPT is a time-limited, evidence-based therapy that focuses on improving interpersonal relationships and social functioning. It targets four main areas: grief, interpersonal disputes, role transitions, and interpersonal deficits. It is particularly effective for depression and eating disorders, and is well-suited for patients whose symptoms are linked to relationship or life transition issues." },
  { id: 2523, category: 'psychotherapy', keywords: ['dialectical behavior therapy DBT'], question: "What is dialectical behavior therapy (DBT) and who is it best for?", response: "DBT is a structured therapy originally developed for borderline personality disorder. It combines cognitive-behavioral techniques with mindfulness, distress tolerance, emotion regulation, and interpersonal effectiveness skills. It is especially helpful for patients with severe emotion dysregulation, self-harm, or chronic suicidal thoughts, and is often delivered with both individual and group components plus between-session coaching." },
  { id: 2524, category: 'psychotherapy', keywords: ['motivational interviewing'], question: "What is motivational interviewing and when is it useful?", response: "Motivational interviewing is a collaborative, patient-centered counseling style that helps people resolve ambivalence and increase motivation for behavior change. It is effective for substance use disorders, smoking cessation, weight management, medication adherence, and other health behavior changes. It is often used as an adjunct when patients show low motivation to change." },
  { id: 2525, category: 'psychotherapy', keywords: ['supportive psychotherapy'], question: "What is supportive psychotherapy and when is it appropriate?", response: "Supportive psychotherapy (or counseling) emphasizes empathy, encouragement, and practical guidance. It helps patients cope with crises, illness, stress, or transient problems and maintain hope. It is widely used in medical settings and is a reasonable option when more structured therapies are not available or when the goal is primarily emotional support and coping." },
  { id: 2526, category: 'psychotherapy', keywords: ['remote vs in-person psychotherapy'], question: "Is remote (telehealth) psychotherapy as effective as in-person therapy?", response: "For CBT, remote delivery appears to be as effective as in-person therapy for anxiety disorders, depression, insomnia, chronic pain, and several other conditions. Evidence for other evidence-based therapies is more limited but also suggests comparable outcomes. Remote options significantly improve access, especially for patients with scheduling, transportation, or geographic barriers." },
  { id: 2527, category: 'psychotherapy', keywords: ['when to refer for psychotherapy'], question: "When should clinicians refer patients for psychotherapy?", response: "Consider referral for psychotherapy when the patient has a psychiatric disorder, maladaptive thoughts/behaviors/relationships, difficulty coping with a crisis or chronic problem, low motivation for health behavior change, or significant relationship/family issues impacting functioning. Patients with moderate-to-severe or complex symptoms often benefit from evidence-based therapies delivered by trained mental health clinicians." },
  { id: 2528, category: 'psychotherapy', keywords: ['formats of psychotherapy'], question: "What are the main formats of psychotherapy?", response: "Psychotherapy can be delivered in individual, couple, family, or group formats. Individual therapy allows maximum privacy and is the most studied. Couple therapy is useful for relationship distress. Family therapy and psychoeducation are particularly helpful for schizophrenia and bipolar disorder. Group therapy can provide peer support for grief, substance use, or chronic illness." },
  { id: 2529, category: 'psychotherapy', keywords: ['psychodynamic psychotherapy'], question: "What is psychodynamic psychotherapy and when is it used?", response: "Psychodynamic psychotherapy focuses on uncovering unconscious patterns from childhood and past relationships that influence current functioning. It aims to increase insight and resolve internal conflicts. It is used for depression, personality disorders, and some eating disorders, and may be particularly helpful for patients interested in understanding the roots of their difficulties." },

  // === NEW UpToDate MDD Initial Management RAG Entries (IDs 2531–2539) ===
  { id: 2531, category: 'depression', keywords: ['major depression severity assessment'], question: "How is the severity of major depression determined for treatment planning?", response: "Severity is based on the number, frequency, and intensity of symptoms plus the degree of functional impairment. Use the PHQ-9 (mild 5–9, moderate 10–14, moderately severe 15–19, severe ≥20). Also consider symptom duration, trajectory, suicidal ideation, psychosis, and catatonia. Treatment selection (active surveillance, psychotherapy, antidepressants, or combination) is guided by overall severity." },
  { id: 2532, category: 'depression', keywords: ['urgent management major depression'], question: "When does major depression require urgent or emergency management?", response: "Refer to the emergency department for imminent suicide risk (plan + intent + means), active suicidal behavior, intent to harm others, inability to care for self (e.g., dehydration, malnutrition), psychotic features, mania, catatonia, or need for safe detoxification. These patients generally require inpatient evaluation and stabilization." },
  { id: 2533, category: 'depression', keywords: ['treatment selection by depression severity'], question: "How should initial treatment for major depression be selected based on severity?", response: "Mild (short duration, minimal impairment): Consider active surveillance + exercise or psychotherapy. Mild (prior episodes or longer duration): Antidepressant or psychotherapy. Moderate: Antidepressant or psychotherapy (combination if marked impairment). Severe: Combination of antidepressant + psychotherapy (or ECT if rapid response needed). Patient preference, access to quality psychotherapy, and prior treatment response guide the final choice." },
  { id: 2534, category: 'depression', keywords: ['antidepressant vs psychotherapy major depression'], question: "How do antidepressants and psychotherapy compare for initial treatment of major depression?", response: "Both are more effective than placebo and have roughly comparable efficacy for response and remission in moderate-to-severe depression. Psychotherapy may have more lasting benefits after treatment ends. Combination therapy is often preferred for severe depression. Choice depends mainly on patient preference, availability of high-quality psychotherapy, cost, and prior treatment response." },
  { id: 2535, category: 'depression', keywords: ['PHQ-9 monitoring depression treatment'], question: "How should the PHQ-9 be used to monitor depression treatment?", response: "Use the PHQ-9 at every visit to quantify symptoms and track response. A clinically meaningful change is typically ≥5 points. It helps identify early response, partial response, non-response, and residual symptoms. Regular monitoring improves engagement, guides dose adjustments, and supports measurement-based care." },
  { id: 2536, category: 'depression', keywords: ['collaborative care depression'], question: "What is collaborative care for depression and why is it effective?", response: "Collaborative care is a team-based model (primary care clinician + care manager + psychiatric consultant) that includes systematic follow-up, measurement-based care (e.g., PHQ-9), and stepped treatment. It significantly improves response, remission, adherence, and outcomes compared with usual care, especially in primary care settings and for patients with comorbid medical illness." },
  { id: 2537, category: 'depression', keywords: ['persistent depressive disorder treatment'], question: "How should persistent depressive disorder (dysthymia) be treated initially?", response: "For persistent depressive disorder, combination treatment with an antidepressant plus psychotherapy is generally preferred over either alone. Antidepressant monotherapy is a reasonable alternative. Psychotherapy alone is less effective than pharmacotherapy in this population. SSRIs and other second-generation antidepressants are commonly used." },
  { id: 2538, category: 'depression', keywords: ['depression with mixed features treatment'], question: "How should depression with mixed features be treated?", response: "Treat depression with mixed features (subthreshold hypomanic symptoms) similarly to bipolar depression. Prefer medications such as quetiapine, lurasidone, or other mood stabilizers/antipsychotics over SSRIs/SNRIs, which may increase risk of switching to mania/hypomania. Combine with psychotherapy when possible. Referral to psychiatry is often warranted." },
  { id: 2539, category: 'depression', keywords: ['engaging patients in depression treatment'], question: "How can clinicians improve engagement in depression treatment?", response: "Elicit the patient's beliefs about depression and address stigma or misconceptions. Frame treatment as a trial. Use regular PHQ-9 monitoring to show objective improvement. Provide tailored education. For reluctant patients with mild symptoms, active surveillance with close follow-up can build trust and facilitate later acceptance of active treatment." },

  // === NEW UpToDate Antidepressant Management of MDD RAG Entries (IDs 2541–2549) ===
  { id: 2541, category: 'depression', keywords: ['antidepressant selection mild moderate depression'], question: "How should clinicians select an initial antidepressant for mild to moderate major depression?", response: "Start by asking about the patient's priorities for avoiding specific side effects (e.g., weight gain, sexual dysfunction, sedation, insomnia) and which symptoms they want to target. Then choose an agent whose side-effect profile best matches those priorities. SSRIs (especially escitalopram or sertraline) are reasonable defaults when no strong patient preference exists. Efficacy is generally similar across and within classes of second-generation antidepressants." },
  { id: 2542, category: 'depression', keywords: ['SSRIs first-line mild moderate depression'], question: "Why are SSRIs often preferred for initial treatment of mild to moderate MDD?", response: "SSRIs (e.g., escitalopram, sertraline) offer a favorable balance of efficacy, tolerability, safety in overdose, and low cost. They are effective across a range of depressive symptoms and have a well-established safety profile. Other second-generation agents (SNRIs, bupropion, mirtazapine, vortioxetine) are good alternatives when side-effect profile or specific symptoms (e.g., fatigue, sexual dysfunction, weight concerns) make them more suitable." },
  { id: 2543, category: 'depression', keywords: ['antidepressant selection severe depression'], question: "How should antidepressants be selected for severe major depression?", response: "For severe MDD, SNRIs (venlafaxine or duloxetine) are often preferred over SSRIs because some data suggest modestly higher remission rates. SSRIs remain reasonable alternatives. Mirtazapine and tricyclic antidepressants are also options but have more side effects. Combination treatment with psychotherapy is generally recommended for severe depression, and referral to psychiatry is advised." },
  { id: 2544, category: 'depression', keywords: ['tailoring antidepressants side effects symptoms'], question: "How can antidepressants be tailored to specific patient priorities or symptoms?", response: "Match the medication to patient goals: Bupropion or fluoxetine for weight concerns; bupropion or mirtazapine to minimize sexual dysfunction; mirtazapine for prominent insomnia; SNRIs for comorbid chronic pain; bupropion for patients who also want to quit smoking. Avoid venlafaxine in uncontrolled hypertension and bupropion in seizure disorders. Always incorporate patient preferences about side effects." },
  { id: 2545, category: 'depression', keywords: ['starting dose and titration antidepressants'], question: "How should antidepressants be initiated and titrated?", response: "Start at a low dose (often half the usual starting dose in sensitive patients) to minimize side effects, then titrate upward to the minimum therapeutic dose over 1–3 weeks. Reassess at 2–4 weeks. If there is no meaningful improvement, increase the dose toward the upper end of the usual range as tolerated. Slow titration is appropriate if side effects occur." },
  { id: 2546, category: 'depression', keywords: ['monitoring initial antidepressant treatment'], question: "How should clinicians monitor patients starting antidepressants?", response: "Follow up within 1–2 weeks, then every 2–4 weeks during the initial phase. Use a validated scale such as the PHQ-9 at every visit to track symptoms. Ask specifically about common early side effects (nausea, insomnia, activation, sexual dysfunction) and monitor for rare but serious effects (e.g., mania, hyponatremia, blood pressure changes). Early improvement at 2 weeks predicts higher likelihood of eventual response/remission." },
  { id: 2547, category: 'depression', keywords: ['adequate trial antidepressant nonresponse'], question: "What constitutes an adequate antidepressant trial before considering next-step treatment?", response: "For patients with partial response, continue the current agent for a total of 6–12 weeks. For those with minimal or no response, an adequate trial is typically 4–6 weeks at a therapeutic dose. Before declaring nonresponse, confirm adherence, optimize the dose, address comorbidities, and rule out misdiagnosis (e.g., bipolar disorder). Many patients need 8–12 weeks to achieve full benefit." },
  { id: 2548, category: 'depression', keywords: ['next steps partial or nonresponse antidepressant'], question: "What are reasonable next steps when a patient has partial or no response to the first antidepressant?", response: "For minimal/no response: Switch to an antidepressant from a different class. For partial response: Either switch to a different-class agent or augment with a second medication (e.g., bupropion or mirtazapine). Psychotherapy can be added at any point. Reserve more complex augmentation strategies (e.g., atypical antipsychotics) for patients who have not responded to two adequate antidepressant trials." },
  { id: 2549, category: 'depression', keywords: ['avoiding antidepressant discontinuation syndrome'], question: "How should antidepressants be discontinued to minimize withdrawal symptoms?", response: "Taper antidepressants gradually rather than stopping abruptly, especially those with short half-lives (paroxetine, venlafaxine, desvenlafaxine). Fluoxetine has a long half-life and is less likely to cause discontinuation symptoms. Educate patients about possible withdrawal symptoms (dizziness, flu-like symptoms, sensory disturbances, mood changes) and taper over weeks to months depending on dose and duration of use." },

  // === NEW UpToDate Supplemental Interventions for MDD RAG Entries (IDs 2551–2558) ===
  { id: 2551, category: 'depression', keywords: ['supplemental interventions major depression role'], question: "What is the role of supplemental interventions in treating major depression?", response: "Supplemental interventions (exercise, bright light therapy, mind-body practices, internet-based psychotherapy, and self-help) are primarily used as adjuncts to standard treatment (antidepressants and/or in-person psychotherapy). For selected patients with mild MDD (short duration, no prior episodes, minimal impairment), they can serve as stand-alone alternatives when patients prefer to avoid or cannot access standard care. Close monitoring is required if used as monotherapy." },
  { id: 2552, category: 'depression', keywords: ['exercise for depression efficacy'], question: "How effective is exercise for treating major depression?", response: "Exercise has moderate evidence for reducing depressive symptoms. It is a first-line supplemental intervention for all patients willing and able to participate. It can be used as monotherapy for mild MDD or as an adjunct for moderate-to-severe MDD. Supervised exercise (group or trainer) improves adherence. Aim for 30–60 minutes of moderate-to-vigorous aerobic or resistance exercise at least 3 times weekly. Benefits may extend to mortality reduction in depressed adults." },
  { id: 2553, category: 'depression', keywords: ['bright light therapy nonseasonal depression'], question: "How is bright light therapy used for nonseasonal major depression?", response: "Bright light therapy (5000–10,000 lux for 30–60 minutes in the morning) is a reasonable adjunct for MDD, especially when there is partial response to standard treatment or prominent hypersomnia. Minimum duration is typically 2 weeks. It can be combined with pharmacotherapy or psychotherapy. Evidence supports modest benefit as an adjunct, with stronger data in seasonal affective disorder." },
  { id: 2554, category: 'depression', keywords: ['yoga tai chi for depression'], question: "What is the role of yoga and tai chi in treating depression?", response: "Yoga and tai chi are reasonable mind-body adjuncts for MDD, particularly for patients interested in these practices or who cannot do conventional exercise. They combine movement, breath control, and mindfulness. Evidence suggests small-to-moderate benefits for depressive symptoms, though study quality is variable. They are low-risk options that may also help comorbid anxiety." },
  { id: 2555, category: 'depression', keywords: ['internet-based psychotherapy IBP depression'], question: "When and how should internet-based psychotherapy be used for depression?", response: "Clinician-guided IBP (especially iCBT) is a useful adjunct for any severity of MDD and can serve as a stand-alone option or bridge to in-person therapy for selected patients with mild symptoms. Guided programs are generally more effective than unguided ones. Typical programs last 8–18 sessions. They are particularly helpful when access to traditional psychotherapy is limited. Monitor closely for lack of improvement or worsening symptoms." },
  { id: 2556, category: 'depression', keywords: ['selecting supplemental interventions depression'], question: "How should clinicians choose among supplemental interventions for depression?", response: "Prioritize patient preference and feasibility. Exercise is first-line for most patients. For those who cannot or will not exercise, consider mind-body options (yoga, tai chi) or bright light therapy. Use IBP when patients want psychotherapy but have access barriers. Combine modalities when appropriate. Always integrate with standard care for moderate-to-severe MDD and monitor response." },
  { id: 2557, category: 'depression', keywords: ['self-help interventions depression'], question: "What other self-help interventions are available for depression?", response: "Other options include community support groups (e.g., NAMI, DBSA), smartphone apps (some with modest evidence), and bibliotherapy (structured workbooks). These have weaker evidence than exercise or IBP but are low-risk and can be used as adjuncts. Smartphone apps and guided self-help programs may provide small benefits, especially when access to care is limited." },
  { id: 2558, category: 'depression', keywords: ['CycleMind supplemental interventions tracking'], question: "How can CycleMind support users with supplemental interventions for mood symptoms?", response: "CycleMind can include optional modules for tracking exercise, sleep, light exposure, yoga/tai chi practice, and use of apps or self-help resources. It can prompt users about evidence-based options (especially exercise) and encourage integration with standard care while reminding that these are adjuncts, not replacements, for professional treatment when symptoms are moderate to severe." },

  // === NEW UpToDate Suicidality Management RAG Entries (IDs 2561–2568) ===
  { id: 2561, category: 'suicide prevention', keywords: ['indications for psychiatric hospitalization suicidality'], question: "When should patients with suicidal ideation or behavior be hospitalized?", response: "Hospitalization is typically indicated for imminent/high risk of suicide, a recent life-threatening suicide attempt, persistent suicidal intent after an attempt, inability to ensure safety in a less restrictive setting, or lack of social support. Involuntary hospitalization may be necessary if the patient poses imminent danger to self and refuses voluntary admission." },
  { id: 2562, category: 'suicide prevention', keywords: ['safety plan for suicidality'], question: "What is a safety plan and how is it used in managing suicidality?", response: "A safety plan is a collaboratively written document that helps patients recognize warning signs of a suicidal crisis, identify coping strategies, restrict access to lethal means, and know who to contact for support. It is used in conjunction with other treatments (not as a stand-alone intervention) and should be reviewed and updated regularly. Safety plans have largely replaced 'contracts for safety'." },
  { id: 2563, category: 'suicide prevention', keywords: ['psychotherapy for suicidal ideation and behavior'], question: "Which psychotherapies are effective for reducing suicidal behavior?", response: "Cognitive-behavioral therapy (CBT), psychodynamic psychotherapy, and dialectical behavior therapy (DBT) have the strongest evidence for reducing future suicide attempts. Other structured therapies (behavioral activation, interpersonal psychotherapy, problem-solving therapy) can also be helpful. Psychotherapy should address both the underlying psychiatric disorder and factors contributing to suicidality." },
  { id: 2564, category: 'suicide prevention', keywords: ['lithium for suicide prevention'], question: "When is lithium recommended for suicide prevention?", response: "Lithium is recommended for maintenance treatment in patients with bipolar disorder or major depressive disorder who remain at elevated suicide risk after acute treatment (e.g., history of multiple attempts). It has demonstrated efficacy in reducing suicide mortality in both disorders. Monitor renal and thyroid function regularly." },
  { id: 2565, category: 'suicide prevention', keywords: ['firearm safety counseling suicidality'], question: "How should clinicians counsel patients about firearm access when there is suicide risk?", response: "For patients at increased suicide risk who have access to firearms, clinicians should recommend either temporary removal of firearms or secure storage (unloaded, locked, ammunition stored separately). This is a critical, evidence-based intervention. Involve family members when appropriate and be aware of local extreme risk protection order laws." },
  { id: 2566, category: 'suicide prevention', keywords: ['follow-up after hospitalization for suicidality'], question: "What is recommended follow-up after hospitalization for suicidality?", response: "Schedule the first outpatient follow-up appointment within 1–2 weeks of discharge. Continue regular monitoring thereafter based on ongoing risk. Assess for changes in underlying psychiatric disorders, psychosocial stressors, medication adherence, and re-emergence of precipitants. Timely follow-up is associated with reduced suicide risk after discharge." },
  { id: 2567, category: 'suicide prevention', keywords: ['ketamine esketamine for acute suicidal ideation'], question: "What is the role of ketamine or esketamine in managing acute suicidal ideation?", response: "Ketamine can rapidly reduce suicidal ideation (within hours), with effects lasting up to one week. Esketamine has FDA approval for this indication but randomized trials have not consistently shown superiority over placebo when added to standard antidepressants. These are options for severe, acute suicidal ideation but are not first-line for most patients." },
  { id: 2568, category: 'suicide prevention', keywords: ['CycleMind safety planning and monitoring'], question: "How can CycleMind support users and clinicians managing suicide risk?", response: "CycleMind should include prompts for safety planning, means restriction (especially firearms), warning sign recognition, and coping strategies. It can track mood, sleep, and stressors while reminding users to seek professional help. Integration with crisis resources (e.g., 988) and clear guidance on when to escalate care are essential." },

  // === NEW UpToDate Course of Illness in Depression RAG Entries (IDs 2571–2579) ===
  { id: 2571, category: 'depression', keywords: ['recovery time major depressive episode'], question: "What is the typical time to recovery from a major depressive episode?", response: "The median time to recovery from a major depressive episode is approximately 20 weeks. Many episodes remit relatively quickly (within 8 weeks), but the probability of recovery progressively decreases as episode duration increases. Risk factors for longer time to recovery include greater baseline severity, psychotic features, comorbid anxiety or personality disorders, high neuroticism, poor psychosocial functioning, and history of childhood maltreatment." },
  { id: 2572, category: 'depression', keywords: ['recurrence risk major depressive disorder'], question: "What is the risk of recurrence after a major depressive episode?", response: "Major depressive disorder is highly recurrent. Approximately 50% of patients experience recurrence. The risk is highest in the first few months after recovery and then gradually declines. Each prior episode increases the risk of future recurrence by about 16%. Residual depressive symptoms after recovery are one of the strongest predictors of early recurrence." },
  { id: 2573, category: 'depression', keywords: ['risk factors for recurrence depression'], question: "What are key risk factors for recurrence of major depression?", response: "Strongest risk factors include: prior history of recurrence, residual depressive symptoms after recovery, childhood maltreatment, greater severity of the index episode, younger age at onset or assessment, comorbid personality or anxiety disorders, and poorer psychosocial functioning. Patients with residual symptoms have a much shorter median time to recurrence (e.g., 32 vs 135 weeks)." },
  { id: 2574, category: 'depression', keywords: ['long-term course of major depression'], question: "Does the long-term course of major depression worsen over time?", response: "For groups of patients, the long-term course (mean time to recovery, probability of recurrence, and proportion of time ill) tends to remain relatively stable over decades. However, for any individual patient, the duration of episodes and time to recurrence can vary. Patients with more symptoms are more likely to remain in treatment, which can create the impression of progressive worsening." },
  { id: 2575, category: 'depression', keywords: ['residual symptoms and recurrence'], question: "How do residual symptoms affect the course of depression?", response: "Residual symptoms after recovery from a major depressive episode are one of the strongest predictors of early recurrence. Even mild residual symptoms significantly shorten the time to the next episode. This supports the importance of treating to full remission rather than just response, and continuing maintenance treatment when residual symptoms persist." },
  { id: 2576, category: 'depression', keywords: ['persistent depressive disorder course'], question: "What is the typical course of persistent depressive disorder?", response: "Most episodes of persistent depressive disorder eventually resolve, but recurrence is common. Many patients experience 'double depression' (exacerbations meeting full criteria for major depressive episodes). Recovery from persistent depressive episodes tends to be slower than from non-chronic major depression. Childhood maltreatment and comorbid anxiety increase risk of poor outcomes." },
  { id: 2577, category: 'depression', keywords: ['depression functional impairment quality of life'], question: "How does depression affect long-term functioning and quality of life?", response: "Functional recovery often lags behind syndromal recovery by about one year, largely due to residual symptoms. Quality of life frequently remains impaired even after full remission of depressive symptoms. Depression is a leading cause of disability worldwide and worsens outcomes of comorbid medical conditions." },
  { id: 2578, category: 'depression', keywords: ['mortality in major depression'], question: "What is the impact of major depression on mortality?", response: "All-cause mortality is 50–100% higher in individuals with depression. Life expectancy is shortened by approximately 5–11 years. Excess mortality is only partly explained by comorbid medical illness. Depression also increases risk of suicide, homicidal death, and accidental death. Risk is higher in men than women." },
  { id: 2579, category: 'depression', keywords: ['treatment-resistant depression outcomes'], question: "How does treatment-resistant depression affect long-term outcomes?", response: "Patients who require multiple treatment steps to achieve remission have higher relapse rates (up to 50%) compared with those who remit after the first treatment (~34%). Treatment-resistant depression is associated with greater chronicity, functional impairment, and healthcare utilization, though it is not entirely clear whether it independently increases mortality beyond that of depression in general." },

  // === NEW UpToDate SAD Treatment RAG Entries (IDs 2581–2589) ===
  { id: 2581, category: 'seasonal affective disorder', keywords: ['winter depression first-line treatment'], question: "What is first-line treatment for winter depression (SAD)?", response: "For winter depression, first-line treatment is typically an antidepressant (usually an SSRI) plus artificial light therapy (bright light therapy and/or dawn simulation). Antidepressants alone are a reasonable alternative. For mild to moderate winter depression, light therapy alone can also be used as first-line treatment. Severe episodes generally require pharmacotherapy, often combined with light therapy." },
  { id: 2582, category: 'seasonal affective disorder', keywords: ['bright light therapy SAD administration'], question: "How is bright light therapy administered for winter depression?", response: "Use a 10,000 lux light box with white fluorescent light. Position it ~40–80 cm away so light enters the eyes at a downward angle. Administer for 30 minutes in the early morning soon after waking. Start with 30 minutes; increase to 45–60 minutes if no response after 1–2 weeks. Treatment is typically continued daily until at least 2 weeks past the usual spring/summer offset of symptoms." },
  { id: 2583, category: 'seasonal affective disorder', keywords: ['efficacy bright light therapy SAD'], question: "How effective is bright light therapy for winter depression?", response: "Bright light therapy produces response or remission in approximately 60% of patients with winter depression. Morning administration is generally more effective than evening administration, especially in patients with hypersomnia. It is a well-established, first-line option for mild to moderate winter depression and can be combined with antidepressants for more severe cases." },
  { id: 2584, category: 'seasonal affective disorder', keywords: ['maintenance treatment winter depression'], question: "How should maintenance treatment be managed after winter depression remits?", response: "Continue the acute treatment (antidepressant ± light therapy) for at least 2 weeks beyond the usual spontaneous spring/summer offset. Light therapy is typically stopped in late spring/summer and restarted in the fall (2–4 weeks before expected symptom onset). Antidepressants may be used seasonally or year-round, depending on history and severity. Adjunctive interventions (sleep hygiene, outdoor walks, exercise) should continue year-round." },
  { id: 2585, category: 'seasonal affective disorder', keywords: ['adjunctive interventions SAD'], question: "What adjunctive interventions are recommended for winter depression?", response: "Encourage all patients to use these throughout acute and maintenance treatment: good sleep hygiene (including minimizing evening blue light), daily walks outside (even on cloudy days), regular aerobic exercise, enhanced indoor lighting, and dawn simulation. These interventions support circadian rhythm regulation and overall mood stability." },
  { id: 2586, category: 'seasonal affective disorder', keywords: ['dawn simulation SAD'], question: "What is dawn simulation and when is it used in SAD?", response: "Dawn simulation gradually increases light intensity (up to ~250 lux) over 30–90 minutes while the patient is still asleep, ending at their usual wake time. It is a reasonable alternative or addition to standard bright light therapy, especially for patients who prefer not to sit in front of a light box. It may be particularly helpful for hypersomnia and difficulty awakening." },
  { id: 2587, category: 'seasonal affective disorder', keywords: ['summer depression treatment'], question: "How is summer depression managed?", response: "Summer depression is treated with standard interventions used for nonseasonal major depression (antidepressants and/or psychotherapy). Adjunctive strategies may include limiting daily light exposure and using air conditioning to stay cool, especially at night. It is much less common and less studied than winter depression." },
  { id: 2588, category: 'seasonal affective disorder', keywords: ['bipolar disorder seasonal pattern treatment'], question: "How is bipolar disorder with seasonal pattern treated?", response: "Treat bipolar episodes with seasonal pattern using standard bipolar pharmacotherapy (mood stabilizers ± antipsychotics) and psychotherapy. Bright light therapy can be added cautiously for bipolar depression with seasonal features, but patients should be monitored closely for switching into hypomania or mania. Start at low intensity/duration and titrate slowly if there is a history of mood switching." },
  { id: 2589, category: 'seasonal affective disorder', keywords: ['when to refer SAD treatment resistance'], question: "When should patients with winter depression be referred to psychiatry?", response: "Refer to psychiatry for severe episodes (e.g., suicidal ideation/behavior, psychosis, marked functional impairment), treatment resistance after first- and second-line therapies, or diagnostic uncertainty (e.g., possible bipolar disorder). Primary care clinicians can manage many cases of mild to moderate winter depression with antidepressants and/or light therapy." },

  // === NEW UpToDate Postpartum Depression RAG Entries (IDs 2591–2598) ===
  { id: 2591, category: 'postpartum depression', keywords: ['prevalence postpartum depression'], question: "What is the prevalence of postpartum unipolar major depression?", response: "The prevalence of postpartum major depression is approximately 10–15% across studies in different countries and settings. Rates appear higher in low- and middle-income countries. Onset occurs before or during pregnancy in roughly 50% of cases. Most episodes that begin after delivery start within the first few months postpartum." },
  { id: 2592, category: 'postpartum depression', keywords: ['risk factors postpartum depression'], question: "What are the strongest risk factors for postpartum depression?", response: "The two strongest and most consistent risk factors are: (1) depression during pregnancy, and (2) a prior history of depression (perinatal or non-perinatal). Other important risk factors include stressful life events, poor social support, perinatal anxiety, intimate partner violence, young maternal age, unintended pregnancy, and personality traits such as high neuroticism." },
  { id: 2593, category: 'postpartum depression', keywords: ['screening postpartum depression Edinburgh scale'], question: "How should postpartum women be screened for depression?", response: "We recommend screening all postpartum women for depression when follow-up systems are in place. The most widely used and validated tool is the 10-item Edinburgh Postnatal Depression Scale (EPDS). A cutoff score of ≥11 maximizes sensitivity plus specificity. A reasonable alternative is the 9-item Patient Health Questionnaire (PHQ-9). Screening is typically done once between 4–8 weeks postpartum, though some clinicians screen multiple times in the first year." },
  { id: 2594, category: 'postpartum depression', keywords: ['clinical features postpartum depression'], question: "What are the clinical features of postpartum major depression?", response: "The symptoms of postpartum unipolar major depression are generally similar to non-perinatal major depression (dysphoria, anhedonia, worthlessness/guilt, impaired concentration, suicidal ideation). Somatic symptoms (sleep changes, fatigue, appetite changes) overlap with normal puerperal experiences, so clinicians should focus on the five mood/cognitive symptoms. Comorbid anxiety disorders are very common." },
  { id: 2595, category: 'postpartum depression', keywords: ['postpartum blues vs postpartum depression'], question: "How do you differentiate postpartum blues from postpartum depression?", response: "Postpartum blues are mild, self-limited depressive symptoms that begin within 2–3 days of delivery, peak soon after, and resolve within 2 weeks. They do not meet full criteria for major depression. Symptoms that persist beyond 2 weeks, are more severe, or include suicidal ideation should be considered postpartum depression rather than blues." },
  { id: 2596, category: 'postpartum depression', keywords: ['adverse effects postpartum depression infant'], question: "What are the adverse consequences of untreated postpartum depression?", response: "Untreated postpartum depression can impair maternal-infant bonding, breastfeeding, and maternal functioning. It is associated with poorer health care practices for the infant and increased risk of cognitive, emotional, and behavioral problems in the child. It also increases risk of maternal suicide (though absolute rates remain low) and, rarely, infanticide (especially if psychosis is present)." },
  { id: 2597, category: 'postpartum depression', keywords: ['bipolar vs unipolar postpartum depression'], question: "How do you distinguish bipolar from unipolar postpartum depression?", response: "Bipolar depression should be considered in women with postpartum depression who have a history of hypomania or mania. Agitation may be more prominent in bipolar depression. A careful history for prior manic or hypomanic symptoms is essential, as misdiagnosing bipolar depression as unipolar depression can lead to inappropriate antidepressant monotherapy and risk of mood switching." },
  { id: 2598, category: 'postpartum depression', keywords: ['CycleMind postpartum depression support'], question: "How can CycleMind help users with postpartum mood concerns?", response: "CycleMind should include prompts for EPDS or PHQ-9 screening, tracking of mood, sleep, bonding, and infant care concerns. It can provide education about normal postpartum blues vs. depression, red-flag symptoms (suicidal thoughts, intrusive thoughts of harm), and encourage timely professional evaluation. Integration with safety planning and crisis resources is important." },

  // === NEW UpToDate Severe Antenatal Depression Treatment RAG Entries (IDs 2601–2608) ===
  { id: 2601, category: 'antenatal depression', keywords: ['severe antenatal depression initial treatment'], question: "What is the recommended initial treatment for severe antenatal major depression?", response: "For pregnant women with severe unipolar major depression, initial treatment should include an antidepressant plus adjunctive psychotherapy. This combined approach is preferred over monotherapy. The specific antidepressant is chosen based on prior treatment response, safety data, and patient preferences. SSRIs are generally first-line for patients with no prior antidepressant exposure." },
  { id: 2602, category: 'antenatal depression', keywords: ['SSRI choice pregnancy sertraline'], question: "Which antidepressant is preferred for severe antenatal depression in patients with no prior treatment history?", response: "For pregnant patients with severe depression who have not previously taken antidepressants, SSRIs are preferred. Sertraline is typically the first choice among SSRIs due to its favorable safety profile in observational studies and reasonable compatibility with breastfeeding. Citalopram and escitalopram are reasonable alternatives. Paroxetine is generally avoided as initial treatment due to concerns about possible cardiac anomalies." },
  { id: 2603, category: 'antenatal depression', keywords: ['antidepressant dosing pregnancy third trimester'], question: "How should antidepressant dosing be managed during pregnancy?", response: "Start at low doses and titrate to the lowest effective therapeutic dose, especially in the first trimester. Doses may need to be increased in the third trimester due to increased hepatic enzyme activity and volume of distribution. Antidepressants prescribed during the third trimester are generally continued through delivery at the same dose, as tapering increases risk of postpartum relapse without clear benefit for neonatal outcomes." },
  { id: 2604, category: 'antenatal depression', keywords: ['treatment resistant antenatal depression'], question: "How should treatment-resistant antenatal depression be managed?", response: "For patients who do not respond to an initial SSRI, first optimize the dose, then switch to a different SSRI. If there is still inadequate response after two SSRI trials, switch to an SNRI (venlafaxine is often preferred due to more pregnancy safety data). Monotherapy is preferred when possible to minimize fetal exposure. Adding multiple medications is generally avoided during pregnancy." },
  { id: 2605, category: 'antenatal depression', keywords: ['ECT in pregnancy severe depression'], question: "When is electroconvulsive therapy (ECT) used for antenatal depression?", response: "ECT is a reasonable option for severe antenatal depression when patients do not respond to multiple medication trials, decline pharmacotherapy, have high suicide risk, psychotic features, catatonia, or are deteriorating medically. ECT is generally considered safe in pregnancy when technique is modified appropriately, though it carries risks of uterine contractions, preterm labor, and transient fetal arrhythmias. It often provides rapid improvement." },
  { id: 2606, category: 'antenatal depression', keywords: ['TMS antenatal depression'], question: "What is the role of transcranial magnetic stimulation (TMS) in antenatal depression?", response: "Repetitive TMS (left high-frequency or right low-frequency targeting dorsolateral prefrontal cortex) is a reasonable option for severe antenatal depression that has not responded to initial treatments. Small studies suggest it can be beneficial with relatively low risk to mother and fetus, though data are limited. It is often used while continuing any pre-existing antidepressant." },
  { id: 2607, category: 'antenatal depression', keywords: ['shared decision making antidepressants pregnancy'], question: "What should be discussed in shared decision making for antidepressants in pregnancy?", response: "Clinicians must discuss the risks of untreated severe depression (poor nutrition, poor prenatal care adherence, suicidal behavior, adverse pregnancy outcomes, impaired bonding, and increased risk of postpartum depression) versus the potential risks of antidepressants (possible small increases in certain pregnancy complications or neonatal effects). Document the discussion thoroughly. Most guidelines state that the benefits of treating severe depression outweigh the risks of medication for many patients." },
  { id: 2608, category: 'antenatal depression', keywords: ['CycleMind severe antenatal depression support'], question: "How can CycleMind support users and clinicians managing severe antenatal depression?", response: "CycleMind should include clear prompts for PHQ-9 monitoring, safety assessment (suicidal ideation, psychotic symptoms), and education about the importance of treating severe depression. It can track symptoms, sleep, appetite, and functioning while providing balanced information on treatment options. Strong integration with crisis resources and encouragement of multidisciplinary care (obstetrics + psychiatry) is essential." },

  // === NEW UpToDate Antenatal Depression – Child Outcomes RAG Entries (IDs 2611–2618) ===
  { id: 2611, category: 'antenatal depression', keywords: ['antenatal depression child language delay'], question: "Is antenatal depression associated with language delays in children?", response: "Yes. Multiple prospective studies show that untreated antenatal maternal depression is associated with delays in language acquisition in infants and toddlers. One large study found an 80% increased risk of language delay at age 3. The effect appears independent of postnatal depression and SSRI exposure in some analyses." },
  { id: 2612, category: 'antenatal depression', keywords: ['antenatal depression child cognitive outcomes'], question: "What is the impact of antenatal depression on general cognitive functioning in children?", response: "Antenatal depression is associated with modestly poorer general cognitive performance in children (small to moderate effect size). This includes a composite of verbal and performance IQ. However, several studies have not found a significant association with full-scale intelligence quotient when measured later in childhood." },
  { id: 2613, category: 'antenatal depression', keywords: ['antenatal depression child aggression conduct problems'], question: "Is antenatal depression linked to aggressive or antisocial behavior in children?", response: "Yes. Prospective studies show that antenatal depression is associated with increased aggressive behavior in infancy and conduct problems/oppositional defiant disorder in later childhood and adolescence. The association persists after controlling for postnatal depression and other confounders in several studies." },
  { id: 2614, category: 'antenatal depression', keywords: ['antenatal depression child anxiety depression'], question: "Does antenatal depression increase risk of anxiety or depression in offspring?", response: "Yes. Antenatal depression is associated with increased risk of anxiety disorders and depressive disorders in children and adolescents. The elevated risk for depression appears to extend into late adolescence. Some studies suggest the effect may be partly mediated by postnatal maternal depression." },
  { id: 2615, category: 'antenatal depression', keywords: ['antenatal depression child hyperactivity ADHD'], question: "Is antenatal depression associated with hyperactivity or ADHD symptoms in children?", response: "Yes. Prospective studies consistently link antenatal maternal depression with increased hyperactivity and ADHD symptoms in children, even after controlling for maternal ADHD, postnatal depression, and other confounders." },
  { id: 2616, category: 'antenatal depression', keywords: ['antenatal depression autism risk'], question: "Is antenatal depression associated with autism spectrum disorder in children?", response: "Evidence is mixed and inconclusive. Some large registry studies suggest a modest increased risk, while others find no association after adjusting for confounders. It remains unclear whether any observed association is due to depression itself or confounding factors. This uncertainty is relevant when interpreting studies of SSRI exposure and autism." },
  { id: 2617, category: 'antenatal depression', keywords: ['treating antenatal depression child outcomes'], question: "Does treating antenatal depression improve child cognitive or behavioral outcomes?", response: "Treating antenatal depression is recommended to reduce maternal suffering and improve functioning. While direct evidence that treatment improves long-term child cognitive or behavioral outcomes is limited, reducing the duration and severity of antenatal depression is biologically and psychologically plausible to be beneficial for the child. Untreated severe depression clearly carries risks for both mother and child." },
  { id: 2618, category: 'antenatal depression', keywords: ['CycleMind antenatal depression child outcomes education'], question: "How can CycleMind help pregnant users understand risks to the child from antenatal depression?", response: "CycleMind should provide balanced, evidence-based information that antenatal depression is associated with modestly increased risks of language delays, behavioral problems, anxiety, and depression in children. It should emphasize that these risks are not deterministic, that many children are unaffected, and that treating maternal depression is one of the most important things a mother can do for both herself and her child. Avoid alarmist language while encouraging evidence-based care." },

  // === NEW UpToDate Neurobiology of Depression RAG Entries (IDs 2621–2628) ===
  { id: 2621, category: 'depression neurobiology', keywords: ['HPA axis cortisol depression'], question: "What is the role of the HPA axis in unipolar depression?", response: "Patients with acute and remitted unipolar major depression show elevated cortisol responses to stress. Overproduction of corticotropin-releasing hormone is thought to drive excess HPA axis activity. Prolonged hypercortisolemia may suppress neurogenesis and contribute to hippocampal atrophy. The dexamethasone suppression test has poor sensitivity and is not used clinically for diagnosis or prognosis." },
  { id: 2622, category: 'depression neurobiology', keywords: ['neural networks connectivity depression'], question: "How is brain connectivity altered in major depression?", response: "Major depression is associated with hyperconnectivity in the default mode network (linked to self-referential rumination) and hypoconnectivity in the frontoparietal network (linked to cognitive control). Abnormal connectivity between networks is also observed. Some connectivity patterns may predict differential response to pharmacotherapy versus psychotherapy." },
  { id: 2623, category: 'depression neurobiology', keywords: ['hippocampal volume depression'], question: "What structural brain changes are seen in unipolar depression?", response: "Unipolar depression is associated with reduced gray matter volume in several regions, most consistently the hippocampus, anterior cingulate cortex, orbitofrontal cortex, and putamen. Reduced hippocampal volume can precede the onset of depression in high-risk individuals (e.g., offspring of depressed parents). White matter integrity is also disrupted, particularly in the corpus callosum and superior longitudinal fasciculus." },
  { id: 2624, category: 'depression neurobiology', keywords: ['inflammation depression CRP IL-6'], question: "What is the relationship between inflammation and depression?", response: "Unipolar major depression is associated with elevated peripheral inflammatory markers, including CRP, IL-6, and TNF. Higher levels of these markers correlate with greater symptom severity, anhedonia, psychomotor slowing, and poorer treatment response. Inflammation may define a biologically distinct subtype of depression more likely to benefit from anti-inflammatory approaches." },
  { id: 2625, category: 'depression neurobiology', keywords: ['reward network depression anhedonia'], question: "How is the brain's reward circuitry affected in depression?", response: "Major depression is associated with blunted activity in reward-processing regions, including the ventral striatum (nucleus accumbens) and caudate during reward tasks. Reduced striatal activation in healthy individuals predicts future development of depressive symptoms, supporting a role in vulnerability and anhedonia." },
  { id: 2626, category: 'depression neurobiology', keywords: ['neurotransmitters glutamate GABA depression'], question: "What neurotransmitter abnormalities are found in depression?", response: "Depression involves dysregulation of multiple systems: reduced serotonergic and noradrenergic transmission, decreased dopamine signaling (especially in anhedonic subtypes), elevated glutamate, and reduced GABA in several cortical regions. These changes support the rationale for treatments targeting glutamate (e.g., ketamine/esketamine) and inform why some patients respond better to specific medication classes." },
  { id: 2627, category: 'depression neurobiology', keywords: ['telomere length depression aging'], question: "What is the relationship between depression and telomere length?", response: "Depression is associated with shorter telomeres, a marker of accelerated cellular aging. The association is stronger in cross-sectional studies and may be more pronounced in White populations. Short telomeres appear to be a consequence of depression rather than a predictor of future depression onset." },
  { id: 2628, category: 'depression neurobiology', keywords: ['CycleMind neurobiology education users'], question: "How should CycleMind explain neurobiology findings to users with PMDD or perinatal mood symptoms?", response: "CycleMind should present neurobiological findings in accessible, non-alarmist language: e.g., 'Depression and PMDD involve measurable changes in brain networks, stress hormones, and inflammation — these are not character flaws or 'all in your head.' Tracking symptoms alongside hormonal phases helps identify patterns and guide effective treatment.' Emphasize that these changes are often reversible with treatment and that CycleMind data can help personalize care." },

  // === NEW UpToDate Epidemiology of Major Depression RAG Entries (IDs 2631–2637) ===
  { id: 2631, category: 'depression epidemiology', keywords: ['prevalence major depression United States'], question: "What is the prevalence of major depressive disorder in the United States?", response: "In the US general adult population, the 12-month prevalence of major depressive disorder is approximately 10%, and the lifetime prevalence is approximately 21%. Clinically significant depressive symptoms (PHQ-9 ≥10) have a point prevalence of about 12%. Persistent depressive disorder (dysthymia) has a lower lifetime prevalence of around 3%." },
  { id: 2632, category: 'depression epidemiology', keywords: ['global prevalence major depression'], question: "What is the global prevalence of major depression?", response: "Nationally representative surveys across 21 countries estimate the 12-month prevalence of major depression at approximately 5%. The lifetime prevalence of major depressive disorder plus persistent depressive disorder is about 12% globally. Prevalence is roughly twice as high in resource-abundant countries (US/Europe ~18%) compared with resource-limited countries (~9%)." },
  { id: 2633, category: 'depression epidemiology', keywords: ['prevalence depression medical illness'], question: "How common is depression in patients with general medical disorders?", response: "Depressive syndromes are significantly more common in outpatients with general medical disorders than in the general population. A meta-analysis found a pooled point prevalence of 27% in medical outpatients worldwide. In direct comparisons, depression was approximately three times more prevalent in medical outpatients than in controls without medical illness." },
  { id: 2634, category: 'depression epidemiology', keywords: ['age of onset major depression'], question: "What is the typical age of onset for major depressive disorder?", response: "In the US general population, the average age of onset for both major depressive disorder and persistent depressive disorder is approximately 30 years. Onset of the first lifetime episode of major depression occurs at a mean age of 29 years." },
  { id: 2635, category: 'depression epidemiology', keywords: ['sex differences depression prevalence'], question: "How does the prevalence of depression differ by sex?", response: "Worldwide, the prevalence of major depression and persistent depressive disorder is approximately 1.9 to 2 times higher in females than in males. In the US, the 12-month prevalence is about 13% in females vs 7% in males, and lifetime prevalence is 26% vs 15%." },
  { id: 2636, category: 'depression epidemiology', keywords: ['demographic risk factors depression'], question: "What demographic factors are associated with higher risk of major depression?", response: "Higher risk is associated with: younger age, lower income, being divorced/separated/widowed, and female sex. In the US, prevalence is highest among Native Americans and lowest among Asian/Pacific Islanders. These factors interact with biological vulnerability and psychosocial stressors." },
  { id: 2637, category: 'depression epidemiology', keywords: ['CycleMind epidemiology context'], question: "Why is understanding depression epidemiology important for CycleMind?", response: "CycleMind users experience mood symptoms in the context of hormonal transitions (menstrual cycle, pregnancy, postpartum, perimenopause). Knowing that major depression has a ~10% 12-month and ~21% lifetime prevalence in the US, is twice as common in women, and is even more prevalent in medical populations helps set realistic expectations, reduce stigma, and guide when symptoms warrant clinical evaluation versus self-management." },

  // === NEW UpToDate Minor Depression RAG Entries (IDs 2641–2647) ===
  { id: 2641, category: 'minor depression', keywords: ['definition minor depression criteria'], question: "What are the diagnostic criteria for minor depression?", response: "Minor depression is diagnosed when a patient has 2 to 4 depressive symptoms (including dysphoria or anhedonia) lasting at least 2 weeks that cause clinically significant distress or functional impairment. Symptoms must not meet criteria for major depression, persistent depressive disorder, or be better explained by another condition (e.g., substance use, medical illness, or adjustment disorder). This corresponds to DSM-5-TR 'Other specified depressive disorder, depressive episode with insufficient symptoms'." },
  { id: 2642, category: 'minor depression', keywords: ['prevalence minor depression primary care'], question: "How common is minor depression in primary care and the general population?", response: "In the US general population, lifetime prevalence of minor depression is approximately 9%. One-year prevalence globally is about 2.8%. In primary care settings, point prevalence ranges from 6–16%. It is more common in women and previously married individuals and is frequently under-recognized by clinicians." },
  { id: 2643, category: 'minor depression', keywords: ['minor depression vs major depression'], question: "How does minor depression differ from major depression?", response: "Minor depression involves 2–4 depressive symptoms causing distress or impairment, while major depression requires 5 or more symptoms. Minor depression can be a prodromal, residual, or standalone syndrome. Patients with minor depression that includes suicidal ideation have the highest risk of progressing to major depression." },
  { id: 2644, category: 'minor depression', keywords: ['course prognosis minor depression'], question: "What is the typical course of minor depression?", response: "Many episodes remit (37–76% within 1–3 years in community studies), but 12–19% persist at 3 years and ~19% at 5 years in primary care. Minor depression frequently recurs and carries a significantly increased risk of progressing to major depression. It is also associated with higher all-cause mortality and increased risk of other psychiatric disorders (e.g., anxiety)." },
  { id: 2645, category: 'minor depression', keywords: ['comorbidity minor depression'], question: "What comorbidities are common with minor depression?", response: "Psychiatric comorbidity occurs in 30–54% of cases, especially anxiety disorders, alcohol/substance use disorders, and personality disorders. General medical comorbidity is also elevated (e.g., diabetes, cardiovascular disease). The relationship is often bidirectional — poor health behaviors and inflammation may worsen both depression and medical illness." },
  { id: 2646, category: 'minor depression', keywords: ['screening minor depression PHQ-9'], question: "How should minor depression be screened for in clinical practice?", response: "Use the PHQ-9. A score of 5–9 indicates a high probability of minor depression (or subsyndromal symptoms). However, the PHQ-9 does not confirm the diagnosis — a clinical interview is required to verify symptom count (2–4 symptoms), duration, and impairment, and to rule out major depression or other causes." },
  { id: 2647, category: 'minor depression', keywords: ['CycleMind minor depression tracking'], question: "How should CycleMind handle users with minor or subsyndromal depressive symptoms?", response: "CycleMind should track symptoms continuously across the hormonal lifecycle and flag when users have 2–4 depressive symptoms with distress/impairment (especially if suicidal ideation is present). It should educate users that minor depression is clinically significant, carries risk of progression to major depression, and warrants professional evaluation. Clear escalation pathways and integration with PHQ-9/EPDS screening are essential." },

  // === NEW UpToDate Antenatal Depression Epidemiology & Diagnosis RAG Entries (IDs 2651–2658) ===
  { id: 2651, category: 'antenatal depression', keywords: ['prevalence antenatal depression'], question: "What is the prevalence of antenatal major depression?", response: "In high-income countries, the prevalence of unipolar major depression during pregnancy is approximately 7–9%. In low- and middle-income countries, it is roughly twice as high (16–19%). In clinical settings, the diagnosed prevalence is lower (3–6%). Minor depression is also common, with an estimated prevalence of ~17% in one US survey of pregnant women." },
  { id: 2652, category: 'antenatal depression', keywords: ['risk factors antenatal depression'], question: "What are the strongest risk factors for antenatal major depression?", response: "The strongest and most consistent risk factor is a prior history of perinatal or non-perinatal depression. Other major risk factors include current anxiety, unintended/unwanted pregnancy, life stress, intimate partner violence or history of abuse, poor social support, and chronic medical conditions. Many risk factors overlap with those for depression in the general population." },
  { id: 2653, category: 'antenatal depression', keywords: ['screening antenatal depression EPDS'], question: "How should pregnant women be screened for depression?", response: "We recommend screening all pregnant women for depression when follow-up systems are in place. The Edinburgh Postnatal Depression Scale (EPDS) is the most widely used and validated tool. A reasonable alternative is the PHQ-9. Screening is typically recommended at least once (e.g., second trimester), with more frequent screening for women with multiple risk factors. A positive screen requires a clinical interview to confirm the diagnosis." },
  { id: 2654, category: 'antenatal depression', keywords: ['clinical features antenatal depression'], question: "How do the symptoms of antenatal depression compare to non-perinatal depression?", response: "The core symptoms of antenatal major depression are generally similar to non-perinatal depression. However, somatic symptoms (changes in sleep, energy, appetite, and libido) overlap significantly with normal pregnancy changes, which can lead to missed diagnoses. Clinicians should focus on the five mood and cognitive symptoms: dysphoria, anhedonia, worthlessness/guilt, impaired concentration, and suicidal ideation." },
  { id: 2655, category: 'antenatal depression', keywords: ['missing diagnosis antenatal depression'], question: "Why is antenatal depression often missed?", response: "Approximately 50–66% of women with antenatal major depression go undiagnosed. Reasons include overlap of somatic symptoms with normal pregnancy, stigma, fear of custody loss, and clinician hesitation to diagnose or treat during pregnancy. Screening with validated tools followed by clinical interview helps reduce under-recognition." },
  { id: 2656, category: 'antenatal depression', keywords: ['suicide risk antenatal depression'], question: "What is the suicide risk in pregnant women with depression?", response: "Although suicide is a leading cause of death in pregnant women, the absolute rate of antenatal suicide is very low (~1 per 100,000 live births). However, antenatal depression significantly increases the risk of suicidal ideation and attempts. Suicidal ideation occurs in 4–8% of pregnant women; most who endorse it on screening are not at imminent high risk, but all require careful assessment." },
  { id: 2657, category: 'antenatal depression', keywords: ['paternal antenatal depression'], question: "How common is depression in expectant fathers?", response: "Antenatal depression in expectant fathers has an estimated point prevalence of 2–12%. The strongest identified risk factor is antenatal depression in their pregnant partner. Assessment and management are similar to depression in the general male population." },
  { id: 2658, category: 'antenatal depression', keywords: ['CycleMind antenatal depression screening'], question: "How can CycleMind support screening and recognition of antenatal depression?", response: "CycleMind should include built-in EPDS or PHQ-9 screening prompts during pregnancy mode, with clear guidance on interpreting scores and when to seek professional evaluation. It should educate users about the overlap between depressive and normal pregnancy symptoms and emphasize that mood symptoms causing distress or impairment warrant assessment. Integration with safety planning and crisis resources (e.g., 988) is essential." },

  // === NEW UpToDate Mild-Moderate Antenatal Depression Treatment RAG Entries (IDs 2661–2667) ===
  { id: 2661, category: 'antenatal depression', keywords: ['prevention antenatal depression psychotherapy'], question: "How can antenatal depression be prevented in at-risk patients?", response: "For pregnant patients at increased risk of depression (e.g., prior history of depression, young age, low income, intimate partner violence, poor social support, or stressful life events), we suggest structured psychotherapy such as CBT or interpersonal psychotherapy as selective prevention. A meta-analysis showed this approach reduced the incidence of perinatal depression (13% vs 17%). Universal prevention for all pregnant patients is not supported by current evidence." },
  { id: 2662, category: 'antenatal depression', keywords: ['initial treatment mild moderate antenatal depression'], question: "What is first-line treatment for mild to moderate antenatal major depression?", response: "For mild to moderate antenatal unipolar major depression, we suggest structured psychotherapy (CBT or interpersonal psychotherapy) as initial treatment, especially for patients with no prior antidepressant exposure or those who prefer to avoid medication. These therapies should ideally be tailored to pregnancy-specific issues (e.g., role transitions, attachment, stigma). Antidepressants are a reasonable alternative for patients with a strong prior response to medication or when psychotherapy is unavailable." },
  { id: 2663, category: 'antenatal depression', keywords: ['CBT vs interpersonal therapy antenatal depression'], question: "How do you choose between CBT and interpersonal psychotherapy for antenatal depression?", response: "Choose CBT when prominent dysfunctional thoughts, anxiety, or marked inactivity are present. Choose interpersonal psychotherapy when the depression is linked to role disputes, role transitions (e.g., becoming a mother), or grief. Both have good evidence in perinatal populations. The choice is also guided by availability and patient preference. Both should be adapted for pregnancy-specific concerns." },
  { id: 2664, category: 'antenatal depression', keywords: ['exercise antenatal depression'], question: "Is exercise recommended for antenatal depression?", response: "Yes. We suggest regular exercise (aerobic activity or yoga, 30–60 minutes, 3–5 times per week) as an adjunct for mild to moderate antenatal depression. Meta-analyses show moderate to large benefits on depressive symptoms. Exercise is safe for most physically healthy pregnant patients and aligns with general pregnancy recommendations." },
  { id: 2665, category: 'antenatal depression', keywords: ['treatment resistant mild moderate antenatal depression'], question: "How should non-response to initial psychotherapy be managed in antenatal depression?", response: "First, verify the diagnosis, check adherence, address comorbidities, and evaluate ongoing stressors. For partial responders, increase the number or frequency of sessions. For minimal responders, switch to a different psychotherapy (e.g., from CBT to IPT) or consider adding/switching to an antidepressant. Antidepressant use in mild-moderate cases follows the same principles as in severe antenatal depression." },
  { id: 2666, category: 'antenatal depression', keywords: ['monitoring antenatal depression EPDS'], question: "How should response to treatment be monitored in antenatal depression?", response: "Routinely monitor symptoms using the Edinburgh Postnatal Depression Scale (EPDS). It is quick to administer, does not include somatic items that overlap with normal pregnancy, and is available in many languages. A reasonable alternative is the PHQ-9. Monitor regularly during acute treatment and continuation phases to guide adjustments and detect early signs of relapse." },
  { id: 2667, category: 'antenatal depression', keywords: ['CycleMind mild moderate antenatal depression support'], question: "How can CycleMind support users with mild to moderate antenatal depressive symptoms?", response: "CycleMind should include prompts for EPDS monitoring, education about the continuum of depressive symptoms in pregnancy, and clear guidance on when symptoms warrant professional evaluation. It can track mood alongside pregnancy stage, encourage evidence-based adjuncts like exercise, and provide balanced information about psychotherapy options. Strong safety netting and pathways to care are essential." },

  // === NEW UpToDate Antenatal Depression – Infant/Child Development RAG Entries (IDs 2681–2686) ===
  { id: 2681, category: 'antenatal depression', keywords: ['antenatal depression neonatal neurobehavior'], question: "How does antenatal depression affect neonatal neurobehavioral functioning?", response: "Antenatal depression is associated with impaired neonatal neurobehavioral functioning in the first weeks of life, including poorer habituation, reduced attention/orientation, increased excitability and stress signs, hypotonia, poorer motor performance, and more disturbed/disorganized sleep. These effects are observed even in neonates whose mothers were not treated with antidepressants." },
  { id: 2682, category: 'antenatal depression', keywords: ['antenatal depression infant sleep temperament'], question: "Does antenatal depression affect infant sleep and temperament?", response: "Yes. Neonates of mothers with antenatal depression show more disturbed/disorganized sleep, fussing, and crying, and are described as having more difficult temperament. Antenatal depression may also be linked to excessive crying in early infancy and modestly increased sleep problems in early childhood, though effect sizes are generally small to moderate." },
  { id: 2683, category: 'antenatal depression', keywords: ['antenatal depression brain development child'], question: "Is antenatal depression associated with changes in brain structure or function in children?", response: "Evidence is mixed. Some studies show associations with altered amygdala volume or connectivity, reduced cortical thickness, and changes in white matter integrity in offspring, with some findings appearing sex-specific. Other studies find no clear differences after controlling for confounders. Postnatal maternal depression and other factors may also contribute." },
  { id: 2684, category: 'antenatal depression', keywords: ['antenatal depression physical health growth child'], question: "Does antenatal depression affect physical health or growth in children?", response: "Findings are inconsistent. Some studies link antenatal depression to increased risk of diarrhea, stunting, or underweight in infants (especially in low-resource settings), while others find no clear effect on growth parameters in high-income settings. Antenatal depression may also be associated with sudden infant death syndrome and certain allergic or respiratory issues, but results vary across studies." },
  { id: 2685, category: 'antenatal depression', keywords: ['treating antenatal depression child outcomes'], question: "Does treating antenatal depression improve child developmental outcomes?", response: "Treating antenatal depression is strongly recommended to reduce maternal suffering and improve functioning. While direct high-quality evidence that treatment improves specific child developmental outcomes is limited, reducing the duration and severity of maternal depression is biologically and psychologically plausible to benefit the child. Untreated antenatal depression carries measurable risks for both mother and baby." },
  { id: 2686, category: 'antenatal depression', keywords: ['CycleMind antenatal depression child development education'], question: "How should CycleMind discuss the effects of antenatal depression on the baby?", response: "CycleMind should provide balanced, evidence-based information: antenatal depression is associated with small-to-moderate effects on neonatal neurobehavior, sleep, and temperament, with some longer-term developmental associations. Emphasize that these risks are not deterministic, many children are unaffected, and that getting effective treatment for maternal depression is one of the most important protective steps a mother can take for both herself and her baby. Avoid causing unnecessary alarm while encouraging care." },

  // === NEW UpToDate Prevention of Postpartum Depression RAG Entries (IDs 2691–2696) ===
  { id: 2691, category: 'postpartum depression prevention', keywords: ['indications prevention postpartum depression'], question: "Who should receive interventions to prevent postpartum depression?", response: "Prevention is indicated for euthymic women at increased risk of postpartum major depression, especially those with a prior history of perinatal or non-perinatal depression and/or depressive symptoms during the current pregnancy. These women are at highest risk and should be offered proactive preventive interventions." },
  { id: 2692, category: 'postpartum depression prevention', keywords: ['antidepressant prophylaxis postpartum depression'], question: "When should antidepressants be used to prevent postpartum depression?", response: "For women with a prior history of successful antidepressant treatment who are at high risk, we recommend resuming (or continuing) the previously effective antidepressant, ideally starting in the third trimester. This is often the preferred approach when there is a strong history of response to medication. Most antidepressants are compatible with breastfeeding with appropriate infant monitoring." },
  { id: 2693, category: 'postpartum depression prevention', keywords: ['psychotherapy prevention postpartum depression'], question: "What psychotherapies are effective for preventing postpartum depression?", response: "Cognitive-behavioral therapy (CBT) and interpersonal psychotherapy have the strongest evidence for preventing postpartum depression in high-risk women. Mindfulness-based cognitive therapy is also a reasonable option. These are particularly useful for women without a prior strong response to antidepressants or those who prefer non-medication approaches. Individual therapy tends to be more effective than group formats." },
  { id: 2694, category: 'postpartum depression prevention', keywords: ['psychosocial interventions postpartum depression'], question: "Are psychosocial interventions effective for preventing postpartum depression?", response: "Yes, but the benefit is often modest. Home visits by nurses or midwives and certain structured behavioral interventions show the strongest evidence. Simple education alone is generally not effective. Interventions that address both maternal and infant factors (e.g., infant sleep/crying) and are initiated postnatally may be more helpful than antenatal-only approaches." },
  { id: 2695, category: 'postpartum depression prevention', keywords: ['choosing prevention strategy postpartum depression'], question: "How should clinicians choose a prevention strategy for postpartum depression?", response: "Base the choice on prior treatment history: Resume a previously effective antidepressant for women with a strong medication response history. For women without prior successful antidepressant treatment, prefer CBT, interpersonal psychotherapy, or structured psychosocial interventions. Watchful waiting with close monitoring is reasonable for lower-risk or mildly symptomatic women. Patient preference and availability of services should guide decisions." },
  { id: 2696, category: 'postpartum depression prevention', keywords: ['CycleMind postpartum depression prevention'], question: "How can CycleMind support prevention of postpartum depression?", response: "CycleMind should proactively identify high-risk users (prior depression history, antenatal symptoms) during pregnancy and early postpartum. It can offer education about prevention options, prompt screening (e.g., EPDS), encourage evidence-based strategies (psychotherapy referral, medication discussion with clinician), and support close monitoring in the early postpartum weeks when risk is highest. Integration with safety planning remains essential." },

  // === NEW UpToDate Minor Depression Management RAG Entries (IDs 2701–2707) ===
  { id: 2701, category: 'minor depression', keywords: ['initial treatment minor depression'], question: "What is recommended as initial treatment for minor depression?", response: "For most patients with minor depression, we suggest structured, time-limited psychotherapy (especially CBT) as initial treatment. Watchful waiting is a reasonable alternative for recent-onset cases without suicidal ideation or severe impairment. Antidepressants are generally reserved for patients with a strong prior response to medication, strong preference for pharmacotherapy, or lack of access to psychotherapy." },
  { id: 2702, category: 'minor depression', keywords: ['psychotherapy options minor depression'], question: "Which psychotherapies are effective for minor depression?", response: "Cognitive-behavioral therapy (CBT) has the strongest evidence and is often preferred due to availability. Reasonable alternatives include behavioral activation, cognitive therapy, interpersonal psychotherapy, and problem-solving therapy. These therapies are typically administered over 2–4 months and can also help prevent progression to major depression." },
  { id: 2703, category: 'minor depression', keywords: ['watchful waiting minor depression'], question: "When is watchful waiting appropriate for minor depression?", response: "Watchful waiting (close monitoring every 2–6 weeks plus patient education) is reasonable for recent-onset minor depression, especially when patients prefer to avoid active treatment and have no suicidal ideation or severe functional impairment. If symptoms worsen or do not improve after 6–12 weeks, active treatment should be initiated." },
  { id: 2704, category: 'minor depression', keywords: ['antidepressants minor depression'], question: "When should antidepressants be used for minor depression?", response: "Antidepressants are not first-line for most cases of minor depression. They are reasonable when psychotherapy is unavailable, the patient has a strong prior response to medication, or symptoms are more persistent/severe. SSRIs (e.g., fluoxetine) are commonly used. Treatment duration generally follows guidelines for major depression once a response is achieved." },
  { id: 2705, category: 'minor depression', keywords: ['treatment resistant minor depression'], question: "How should persistent or treatment-resistant minor depression be managed?", response: "First, verify the diagnosis, assess adherence, address comorbidities, and evaluate life stressors. For non-response to initial psychotherapy, switch to a different structured psychotherapy. For patients who fail multiple courses of psychotherapy, add or switch to an antidepressant. Close monitoring and measurement-based care help guide decisions." },
  { id: 2706, category: 'minor depression', keywords: ['preventing progression minor to major depression'], question: "Can treatment of minor depression prevent progression to major depression?", response: "Yes. Structured psychotherapy (especially CBT and interpersonal psychotherapy) can reduce the risk of progression from minor to major depression. The number needed to treat in studies typically ranges from 6 to 13. Early intervention in high-risk individuals is particularly valuable." },
  { id: 2707, category: 'minor depression', keywords: ['CycleMind minor depression management'], question: "How can CycleMind support users with minor depressive symptoms?", response: "CycleMind should track symptoms over time, distinguish minor depression from normal mood variation or major depression, and offer education about evidence-based options (psychotherapy first-line, watchful waiting for mild/recent cases). It can prompt monitoring, encourage engagement in structured therapies or behavioral activation, and flag when escalation to professional care or antidepressants may be warranted." },

  // === NEW UpToDate Severe Postpartum Depression Treatment RAG Entries (IDs 2711–2718) ===
  { id: 2711, category: 'postpartum depression', keywords: ['initial treatment severe postpartum depression zuranolone'], question: "What is recommended as initial treatment for severe postpartum major depression?", response: "For patients with severe postpartum unipolar major depression and no prior history of depression, zuranolone is often preferred as initial treatment due to ease of administration, relatively rapid onset, and good tolerability. For patients with a prior history of successful response to a standard antidepressant, resuming that same medication is recommended. Standard antidepressants remain a reasonable alternative in both scenarios. Most options are compatible with breastfeeding." },
  { id: 2712, category: 'postpartum depression', keywords: ['zuranolone postpartum depression dosing efficacy side effects'], question: "How is zuranolone used for postpartum depression?", response: "Zuranolone is given orally at 50 mg each evening for 14 days (with fat-containing food). The dose can be reduced to 40 mg if sedation occurs. It has demonstrated efficacy in randomized trials, with higher remission rates than placebo at day 45. The most common side effect is sedation/somnolence. It is compatible with breastfeeding and has a low relative infant dose." },
  { id: 2713, category: 'postpartum depression', keywords: ['standard antidepressants postpartum depression breastfeeding'], question: "How are standard antidepressants used in severe postpartum depression?", response: "For patients with a prior successful response to a specific antidepressant (including during pregnancy), resume that same medication. SSRIs (especially sertraline), SNRIs, bupropion, mirtazapine, and nortriptyline are commonly used. Dosing is similar to non-postpartum patients. Most are considered compatible with breastfeeding, though infant monitoring for sedation and feeding difficulties is advised." },
  { id: 2714, category: 'postpartum depression', keywords: ['next step treatment nonresponse severe postpartum depression'], question: "What is next-step treatment if initial therapy for severe postpartum depression is insufficient?", response: "First, assess adherence, confirm the diagnosis, evaluate life stressors, and check for comorbidities. For insufficient response to a standard antidepressant, switch to zuranolone or add a second agent (e.g., zuranolone or a second-generation antipsychotic). For insufficient response to zuranolone, switch to a standard antidepressant such as an SSRI." },
  { id: 2715, category: 'postpartum depression', keywords: ['ECT severe postpartum depression'], question: "When is electroconvulsive therapy used for postpartum depression?", response: "ECT is a reasonable third-line option for severe postpartum depression when pharmacotherapy (standard antidepressants and zuranolone) has failed or is declined, or in life-threatening situations such as active suicidal intent, psychotic features, catatonia, or severe malnutrition/dehydration. It is generally considered safe in breastfeeding mothers." },
  { id: 2716, category: 'postpartum depression', keywords: ['psychotic depression postpartum treatment'], question: "How is psychotic postpartum depression treated?", response: "Psychotic postpartum depression is typically treated with an antidepressant plus an antipsychotic, or with ECT (often preferred for faster onset). Second-generation antipsychotics such as aripiprazole, risperidone, or olanzapine appear relatively safe in breastfeeding when clinically indicated." },
  { id: 2717, category: 'postpartum depression', keywords: ['maintenance treatment severe postpartum depression'], question: "When is maintenance treatment indicated after severe postpartum depression?", response: "Maintenance treatment with a standard antidepressant is generally indicated if the patient has had prior non-perinatal depressive episodes. For a first lifetime episode, maintenance is often not required unless the episode was particularly severe or life-threatening. Decisions should be individualized based on history, severity, and patient preference." },
  { id: 2718, category: 'postpartum depression', keywords: ['CycleMind severe postpartum depression support'], question: "How can CycleMind support users and clinicians managing severe postpartum depression?", response: "CycleMind should include clear pathways for identifying severe symptoms (high PHQ-9/EPDS scores, suicidal ideation, psychosis, severe functional impairment), prompt urgent professional evaluation, and provide balanced education on evidence-based options including zuranolone and standard antidepressants. Strong integration with crisis resources, safety planning, and breastfeeding-compatible treatment information is essential." },

  // === NEW UpToDate Comorbid Anxiety & Depression RAG Entries (IDs 2719–2725) ===
  { id: 2719, category: 'comorbid anxiety depression', keywords: ['epidemiology comorbid anxiety depression'], question: "How common is comorbidity between anxiety disorders and depression?", response: "Comorbidity is very high. In large international studies, nearly half of individuals with lifetime major depressive disorder also had one or more lifetime anxiety disorders. In clinical samples, 30–60%+ of patients with anxiety disorders have comorbid depression, and rates of anxiety in depressed patients are similarly high. GAD shows the strongest association with depression." },
  { id: 2720, category: 'comorbid anxiety depression', keywords: ['risk factors comorbid anxiety depression'], question: "What are key risk factors for comorbid anxiety and depression?", response: "Risk factors include female sex, younger age, lower education, unemployment, parental psychiatric history, childhood trauma, higher neuroticism, greater symptom severity, and the presence of multiple anxiety disorders. Many risk factors overlap with those for either disorder alone; few are unique to the comorbid state." },
  { id: 2721, category: 'comorbid anxiety depression', keywords: ['symptom overlap anxiety depression'], question: "What symptoms overlap between anxiety (especially GAD) and depression?", response: "Shared symptoms include dysphoric mood, irritability, agitation/restlessness, concentration difficulties, insomnia, and fatigue. Symptoms more specific to depression include anhedonia, weight/appetite change, psychomotor slowing, guilt/worthlessness, and thoughts of death. Symptoms more specific to GAD include excessive worry, autonomic hyperactivity, exaggerated startle, and muscle tension." },
  { id: 2722, category: 'comorbid anxiety depression', keywords: ['course comorbid anxiety depression'], question: "How does the course of comorbid anxiety and depression differ from either disorder alone?", response: "Comorbid anxiety and depression is generally associated with earlier onset (especially when anxiety presents first), greater chronicity, higher symptom severity, more functional impairment, lower rates of recovery, longer time to treatment response, and poorer long-term outcomes compared with either disorder in isolation." },
  { id: 2723, category: 'comorbid anxiety depression', keywords: ['anxious distress specifier major depression'], question: "What is the 'anxious distress' specifier in major depression?", response: "Anxious distress is a DSM-5-TR specifier for major depressive episodes. It requires ≥2 of: feeling keyed-up/tense, unusually restless, concentration difficulties due to worry, fear that something awful will happen, or fear of losing control. It is associated with greater severity, suicidality, and poorer treatment response. Clinicians should still screen for discrete comorbid anxiety disorders." },
  { id: 2724, category: 'comorbid anxiety depression', keywords: ['diagnosis comorbid anxiety depression'], question: "How should clinicians diagnose comorbid anxiety and depression?", response: "Use full DSM-5-TR criteria for each disorder. Carefully assess for overlapping symptoms while identifying disorder-specific features. Screen for medical causes, substances, and other psychiatric conditions. Structured interviews and validated scales (e.g., DASS, HAMA, PDSS, Y-BOCS) can help. Distinguish 'anxious distress' within depression from a discrete comorbid anxiety disorder, as the latter may warrant targeted treatment." },
  { id: 2725, category: 'comorbid anxiety depression', keywords: ['CycleMind comorbid anxiety depression support'], question: "How can CycleMind support users with co-occurring anxiety and depressive symptoms?", response: "CycleMind should track both anxiety and mood symptoms over time (especially in relation to hormonal phases), help users recognize overlapping vs. distinct features, and flag when symptoms meet criteria for major depression with anxious distress or comorbid anxiety disorders. It can prompt appropriate screening, encourage professional evaluation, and support integrated treatment planning that addresses both domains." },

  // === NEW UpToDate Bipolar Major Depression Treatment RAG Entries (IDs 2727–2734) ===
  { id: 2727, category: 'bipolar depression', keywords: ['first-line treatment bipolar I major depression'], question: "What is first-line pharmacotherapy for acute bipolar I major depression in patients not on antimanic drugs?", response: "For patients presenting with bipolar I major depression without current antimanic coverage, first-line options are quetiapine or lurasidone monotherapy. Quetiapine is often started first due to more extensive data and established maintenance efficacy. If one is ineffective or poorly tolerated, switch to the other. Electroconvulsive therapy is considered for life-threatening presentations (e.g., active suicidal intent, severe psychosis, catatonia, or profound functional impairment)." },
  { id: 2728, category: 'bipolar depression', keywords: ['second-line treatment bipolar depression'], question: "What are second-line options for bipolar I major depression?", response: "Second-line options include olanzapine plus fluoxetine, valproate monotherapy, combination therapy with quetiapine/lurasidone/lumateperone plus lithium or valproate, and lithium plus valproate or lamotrigine. These are used when first-line agents (quetiapine or lurasidone) are ineffective or intolerable. Olanzapine + fluoxetine is effective but often reserved due to metabolic side effects." },
  { id: 2729, category: 'bipolar depression', keywords: ['third-line and refractory bipolar depression'], question: "What are third-line and refractory options for bipolar major depression?", response: "Third-line options include monotherapy with lamotrigine, lithium, olanzapine, carbamazepine, cariprazine, or lumateperone; olanzapine plus lithium/valproate; other antimanic combinations; and antimanic drug plus antidepressant (with caution). For severe/refractory cases (especially with suicidal intent, psychosis, or catatonia), electroconvulsive therapy is recommended. Antidepressants should generally be avoided or used cautiously due to risk of mood switching." },
  { id: 2730, category: 'bipolar depression', keywords: ['breakthrough bipolar depression management'], question: "How should breakthrough bipolar major depression be managed during ongoing antimanic therapy?", response: "First evaluate and address adherence, subtherapeutic dosing, substance use, psychosocial stressors, and drug interactions. Optimize the current antimanic drug dose. For insufficient antidepressant effect, add lamotrigine, lithium, or valproate (if on a second-generation antipsychotic) or add a second-generation antipsychotic (if on lithium/valproate/lamotrigine). Antidepressants can be considered cautiously in select cases but carry switching risk." },
  { id: 2731, category: 'bipolar depression', keywords: ['bipolar II depression treatment'], question: "How is bipolar II major depression treated compared with bipolar I?", response: "Bipolar II major depression is generally managed similarly to bipolar I depression using the same stepped-care approach (quetiapine or lurasidone first-line, etc.). However, fewer high-quality trials exist specifically for bipolar II. Some data suggest adjunctive antidepressants may carry lower switching risk in bipolar II than bipolar I, but caution is still required." },
  { id: 2732, category: 'bipolar depression', keywords: ['bipolar depression with psychotic features'], question: "How is bipolar major depression with psychotic features treated?", response: "Treatment includes an antipsychotic as part of the regimen. Standard first- and second-line options (quetiapine, lurasidone, olanzapine + fluoxetine, etc.) are used. For treatment-resistant cases or life-threatening presentations, electroconvulsive therapy is indicated. Antipsychotics help address both depressive and psychotic symptoms." },
  { id: 2733, category: 'bipolar depression', keywords: ['pregnancy postpartum bipolar depression'], question: "What special considerations apply to bipolar depression in pregnancy and postpartum?", response: "Treatment must balance maternal benefit against fetal/neonatal risks. Many standard options (e.g., lithium, valproate, certain antipsychotics) have teratogenic or breastfeeding concerns. Quetiapine and some antipsychotics have relatively more safety data. ECT is often considered for severe cases. Close collaboration with obstetrics and perinatal psychiatry is essential. (See related perinatal safety topics for details.)" },
  { id: 2734, category: 'bipolar depression', keywords: ['CycleMind bipolar depression support'], question: "How can CycleMind support users with possible bipolar depression or complex mood patterns?", response: "CycleMind should include prompts to screen for history of mania/hypomania (elevated mood, decreased need for sleep, increased energy/goal-directed activity) when users report depressive symptoms, especially if severe, recurrent, or treatment-resistant. It can educate on the distinction between unipolar and bipolar depression, flag the need for professional evaluation, and support tracking of mood episodes, sleep, and energy in relation to hormonal phases. Strong safety netting and referral pathways are critical." },

  // === NEW UpToDate Antenatal Depression Pregnancy/Neonatal Outcomes RAG Entries (IDs 2735–2742) ===
  { id: 2735, category: 'antenatal depression', keywords: ['antenatal depression adverse pregnancy outcomes overview'], question: "What is the overall association between antenatal depression and adverse pregnancy/neonatal outcomes?", response: "Antenatal depression is associated with small but consistent increased risks of pregnancy loss (spontaneous abortion), operative delivery, preterm birth, and reduced likelihood of breastfeeding. Effects on teratogenicity, late fetal death, bleeding, and low birth weight are uncertain. Most evidence suggests no clear association with preeclampsia, gestational diabetes, placental abruption, gestational age, fetal growth restriction, or NICU admission. Evidence quality is generally low to moderate, with potential confounding by antidepressant use and depression severity." },
  { id: 2736, category: 'antenatal depression', keywords: ['antenatal depression preterm birth'], question: "Is antenatal depression associated with preterm birth?", response: "Yes. Multiple meta-analyses and prospective studies show antenatal depression is associated with an increased risk of preterm birth (<37 weeks), with relative risks/odds ratios typically in the 1.1–1.6 range. The association appears stronger in more recent studies and holds in analyses that control for or exclude antidepressant use. Both very preterm and moderately preterm birth may be affected." },
  { id: 2737, category: 'antenatal depression', keywords: ['antenatal depression pregnancy loss miscarriage'], question: "Is antenatal depression associated with pregnancy loss or miscarriage?", response: "Yes, but the effect is small. Registry studies controlling for confounders (including no antidepressant use) show a modestly increased risk of spontaneous abortion (relative risk ~1.1–1.3). The association is consistent but clinically modest." },
  { id: 2738, category: 'antenatal depression', keywords: ['antenatal depression operative delivery cesarean'], question: "Is antenatal depression associated with operative delivery or cesarean birth?", response: "Yes, modestly. Meta-analyses and large registry/administrative studies show increased risk of operative deliveries (including cesarean) with relative risks/odds ratios around 1.25–1.3. The clinical effect size is small." },
  { id: 2739, category: 'antenatal depression', keywords: ['antenatal depression uncertain outcomes teratogenicity low birth weight'], question: "What pregnancy/neonatal outcomes have uncertain associations with antenatal depression?", response: "Associations are uncertain for: teratogenicity/major congenital anomalies (some registry studies show increased risk; others controlling for no antidepressant exposure do not); late fetal death/stillbirth (inconsistent findings); antenatal/postpartum hemorrhage (small effects in some studies, none in others); and low birth weight (mixed meta-analysis results, some showing modest increase, others none)." },
  { id: 2740, category: 'antenatal depression', keywords: ['antenatal depression no association preeclampsia gestational diabetes'], question: "Which pregnancy outcomes are NOT clearly associated with antenatal depression?", response: "Most evidence shows no clear association with preeclampsia, gestational diabetes, placental abruption, gestational age at delivery, fetal growth restriction/intrauterine growth restriction, or neonatal intensive care unit (NICU) admission." },
  { id: 2741, category: 'antenatal depression', keywords: ['antenatal depression breastfeeding'], question: "Does antenatal depression affect breastfeeding?", response: "Yes, modestly. Meta-analyses show antenatal depression is associated with lower likelihood of initiating breastfeeding or breastfeeding exclusively for at least 3 months. The effect is generally small. Confounding by antidepressant use is possible but the association persists in several studies." },
  { id: 2742, category: 'antenatal depression', keywords: ['CycleMind antenatal depression pregnancy outcomes'], question: "How can CycleMind support users experiencing antenatal depression regarding pregnancy outcomes?", response: "CycleMind's pregnancy mode should include balanced, evidence-based education on the modest risks associated with untreated antenatal depression (especially preterm birth and pregnancy loss) while emphasizing that most outcomes are not strongly affected and that effective treatment may mitigate risks. It should prompt appropriate screening (e.g., EPDS), encourage prompt professional evaluation and treatment discussion, track symptoms alongside gestational age, and provide clear safety netting without causing undue alarm. Integration with clinician resources and perinatal mental health pathways is essential." },

  // === NEW UpToDate Treatment-Resistant Depression (Mild–Moderate) RAG Entries (IDs 2743–2752) ===
  { id: 2743, category: 'treatment resistant depression', keywords: ['definition treatment resistant depression'], question: "How is treatment-resistant depression defined?", response: "Treatment-resistant depression typically refers to major depressive episodes that do not respond satisfactorily after two adequate trials of antidepressant monotherapy (sufficient dose and duration). We also use the term more broadly for depression that has not responded to initial standard treatments, including antidepressants, psychotherapy, or neuromodulation. Remission is usually defined as a depression rating scale score in the normal range (e.g., HAM-D ≤7 or equivalent)." },
  { id: 2744, category: 'treatment resistant depression', keywords: ['prevalence risk factors treatment resistant depression'], question: "How common is treatment-resistant depression and what are key risk factors?", response: "Approximately 50% of patients do not remit after two treatment trials. Risk factors include male sex, early age of onset, high neuroticism, childhood trauma, severe or recurrent depression, suicidal ideation, comorbid anxiety/personality/substance use disorders, chronic pain, and certain medical conditions or medications (e.g., glucocorticoids, interferons)." },
  { id: 2745, category: 'treatment resistant depression', keywords: ['pretreatment assessment treatment resistant depression'], question: "What should be assessed before managing treatment-resistant depression?", response: "Confirm the diagnosis of unipolar major depression and rule out bipolar depression, psychotic features, or secondary causes. Thoroughly review prior treatment history (type, dose, duration, adherence, and response). Assess comorbidities (psychiatric and medical), severity, suicidal risk, and functional impairment. Use structured tools if helpful but rely primarily on clinical interview and record review." },
  { id: 2746, category: 'treatment resistant depression', keywords: ['augmentation vs switching treatment resistant depression'], question: "Should clinicians augment or switch treatment in treatment-resistant depression?", response: "Augmentation is generally preferred as the initial next-step strategy, especially when there has been partial benefit and good tolerability. It may act faster and avoids withdrawal symptoms. Switching is reasonable when there has been little benefit or significant side effects. Both strategies have supporting evidence; patient preference, prior response, and tolerability should guide the choice." },
  { id: 2747, category: 'treatment resistant depression', keywords: ['second generation antipsychotic augmentation treatment resistant depression'], question: "What is the role of second-generation antipsychotics in treatment-resistant depression?", response: "Adding a second-generation antipsychotic (aripiprazole, brexpiprazole, quetiapine, risperidone, lumateperone, etc.) is a first-line augmentation strategy with the strongest evidence base. Aripiprazole is often preferred initially due to a relatively favorable side-effect profile. These agents are particularly helpful for anxious depression. Monitor for metabolic effects, akathisia, and sedation." },
  { id: 2748, category: 'treatment resistant depression', keywords: ['other augmentation options lithium thyroid ketamine'], question: "What other augmentation options exist for treatment-resistant depression?", response: "Reasonable alternatives include lithium or thyroid hormone (T3). For patients who do not respond to or cannot tolerate these, intravenous ketamine or intranasal esketamine, a second antidepressant (with distinct mechanism), or stimulant/stimulant-like agents (modafinil, pramipexole, lisdexamfetamine) can be considered. Choice depends on patient factors, comorbidities, and prior history." },
  { id: 2749, category: 'treatment resistant depression', keywords: ['switching antidepressants treatment resistant depression'], question: "How should clinicians approach switching antidepressants in treatment-resistant depression?", response: "Switch to an agent from a different class (different mechanism of action) when augmentation is not preferred or has failed. Common options include SNRIs (especially venlafaxine XR), atypical antidepressants (bupropion, mirtazapine), vortioxetine, or tricyclics/MAOIs in later lines. Cross-taper carefully, watching for overlapping side effects and drug interactions." },
  { id: 2750, category: 'treatment resistant depression', keywords: ['psychotherapy TMS treatment resistant depression'], question: "What is the role of psychotherapy and TMS in treatment-resistant depression?", response: "Both structured psychotherapy (especially CBT or interpersonal psychotherapy) and transcranial magnetic stimulation (TMS) are evidence-based options. They can be added to current pharmacotherapy (preferred) or used when switching from medication. Psychotherapy may have advantages for long-term relapse prevention. TMS is generally well tolerated and effective as augmentation or switching strategy." },
  { id: 2751, category: 'treatment resistant depression', keywords: ['prognosis treatment resistant depression'], question: "What is the prognosis for treatment-resistant depression?", response: "Approximately two-thirds of patients eventually achieve remission with sequential next-step treatments. Remission rates decline with each unsuccessful trial (roughly 37% after step 1, 31% after step 2, 14% after step 3). Persistent nonresponse increases risk of chronicity, functional impairment, and suicide. Maintenance treatment is usually required after remission." },
  { id: 2752, category: 'treatment resistant depression', keywords: ['CycleMind treatment resistant depression support'], question: "How can CycleMind support users with treatment-resistant depression?", response: "CycleMind should help users track prior treatment trials (medications, doses, durations, side effects, and response), prompt adherence, and flag when criteria for treatment resistance are met. It can provide balanced education on augmentation vs switching strategies, encourage engagement with evidence-based options (including psychotherapy and TMS), and prompt timely professional evaluation or specialist referral when multiple trials have failed. Integration with crisis resources and longitudinal symptom tracking is essential." },

  // === NEW UpToDate GAD Treatment RAG Entries (IDs 2753–2761) ===
  { id: 2753, category: 'generalized anxiety disorder', keywords: ['initial treatment GAD SRI'], question: "What is recommended as initial pharmacotherapy for generalized anxiety disorder?", response: "For patients who choose pharmacotherapy for GAD, initial treatment with a serotonin reuptake inhibitor (SRI) — either an SSRI or SNRI — is preferred. All SRIs have roughly comparable efficacy. Selection among specific agents is guided by side-effect profile, drug-drug interactions, prior treatment history, and patient preference. Response rates are typically 60–70% versus ~40% for placebo." },
  { id: 2754, category: 'generalized anxiety disorder', keywords: ['CBT versus medication GAD'], question: "How should clinicians choose between CBT and medication for GAD?", response: "Both CBT and SRIs are effective first-line options with roughly equivalent benefits based on indirect comparisons. Choice is individualized: prefer CBT for patients who want to avoid medications or side effects; prefer pharmacotherapy when CBT is unavailable, too burdensome, or the patient cannot participate due to symptom severity. Combination treatment may be superior but most patients start with one modality and add the second if needed." },
  { id: 2755, category: 'generalized anxiety disorder', keywords: ['managing early SRI side effects GAD'], question: "How should early side effects of SRIs (agitation, insomnia) be managed in GAD?", response: "Early agitation or insomnia with SRIs can lead to premature discontinuation. For patients without substance use disorder, use short-term low-dose benzodiazepine (e.g., lorazepam 1–2 mg/day) for 4–6 weeks while titrating the SRI, then taper by 25% per week. For patients with substance use disorder history, use hydroxyzine (or gabapentin as alternative) instead. Taper the adjunct once the SRI effect emerges." },
  { id: 2756, category: 'generalized anxiety disorder', keywords: ['suboptimal response GAD management'], question: "How should suboptimal response to initial SRI treatment in GAD be managed?", response: "Add CBT if not already done. For partial response, augment the SRI with buspirone (first choice); gabapentin or pregabalin are reasonable next options. For no response, switch to a second SRI. If still unresponsive, trial buspirone, gabapentin, or pregabalin. For prominent mood instability/irritability, consider adding a mood stabilizer such as lamotrigine or valproate." },
  { id: 2757, category: 'generalized anxiety disorder', keywords: ['refractory GAD treatment options'], question: "What options exist for GAD that remains unresponsive to multiple trials?", response: "Options include switching to or adding mirtazapine (especially with insomnia), imipramine, vilazodone, or vortioxetine. Second-generation antipsychotics (quetiapine, aripiprazole) can be used as augmentation or monotherapy but are generally reserved due to metabolic and other risks. Benzodiazepines are used only after other options are exhausted, avoiding them in patients with substance use or depression history. Hydroxyzine is another alternative." },
  { id: 2758, category: 'generalized anxiety disorder', keywords: ['benzodiazepines GAD role'], question: "What is the role of benzodiazepines in GAD treatment?", response: "Benzodiazepines are effective and fast-acting but carry risks of dependence, withdrawal, cognitive impairment, and rebound anxiety. They are reserved for refractory cases after multiple other trials have failed, or for short-term management of early SRI side effects. Prefer longer-acting agents (diazepam, clonazepam) when used. Avoid in patients with substance use disorder or depression history." },
  { id: 2759, category: 'generalized anxiety disorder', keywords: ['duration of treatment GAD'], question: "How long should pharmacotherapy for GAD be continued after response?", response: "Continue effective pharmacotherapy for at least 12 months to reduce risk of relapse. If relapse occurs after discontinuation, extend the treatment duration. After two relapses on taper, consider ongoing maintenance. CBT typically involves 10–15 sessions with encouragement to continue using skills; monthly booster sessions may help maintain gains." },
  { id: 2760, category: 'generalized anxiety disorder', keywords: ['buspirone gabapentin pregabalin GAD'], question: "How are buspirone, gabapentin, and pregabalin used in GAD?", response: "Buspirone is used for augmentation after partial SRI response or as monotherapy after SRI nonresponse (start 10 mg/day divided, titrate to max 60 mg/day; allow 6-week trial). Gabapentin is often next after buspirone nonresponse. Pregabalin is an alternative but has higher misuse/dependence potential. All require adequate dose and duration trials." },
  { id: 2761, category: 'generalized anxiety disorder', keywords: ['CycleMind GAD support'], question: "How can CycleMind support users with generalized anxiety symptoms?", response: "CycleMind should track anxiety symptoms over time (especially in relation to hormonal phases), distinguish GAD from normal worry or other anxiety disorders, and offer education on evidence-based options (SRI first-line, CBT as strong alternative/adjunct). It can prompt monitoring for early medication side effects, adherence, and when to escalate care. Include clear guidance on when benzodiazepines are and are not appropriate, plus safety netting and referral pathways. Integration with CBT skill reminders and complementary strategies (exercise, mindfulness) is valuable." },

  // === NEW UpToDate GAD Epidemiology, Features & Diagnosis RAG Entries (IDs 2762–2769) ===
  { id: 2762, category: 'generalized anxiety disorder', keywords: ['epidemiology prevalence comorbidity GAD'], question: "What is the prevalence and comorbidity pattern of generalized anxiety disorder?", response: "GAD is common, with lifetime prevalence estimates of 5–12% and past-year prevalence of ~2–3% in the US. It is approximately twice as common in females. Comorbidity is very high: ~66% of current cases and ~90% of lifetime cases have at least one other psychiatric disorder. Major depressive disorder is the most frequent comorbidity (39% current, 62% lifetime). Other common comorbidities include social phobia, specific phobia, and panic disorder. GAD is also frequent in chronic pain and chronic physical illness." },
  { id: 2763, category: 'generalized anxiety disorder', keywords: ['pathogenesis genetics cognitive factors GAD'], question: "What are the key pathogenic factors in generalized anxiety disorder?", response: "GAD has genetic contributions and shares heritability with major depression and the trait of neuroticism. Cognitive factors include biased attention to threat, negative interpretation of ambiguous information, intolerance of uncertainty, and use of worry as an avoidance strategy. Developmental factors include childhood trauma/maltreatment, behavioral inhibition, and high neuroticism. Neuroimaging suggests difficulties engaging prefrontal and anterior cingulate regions during emotion regulation. Neurotransmitter and inflammatory marker changes have been observed but are less consistently replicated." },
  { id: 2764, category: 'generalized anxiety disorder', keywords: ['clinical features symptoms GAD'], question: "What are the characteristic clinical features of generalized anxiety disorder?", response: "Core feature is excessive, persistent worry about multiple everyday domains (work, health, family, finances, minor matters) that is difficult to control and out of proportion to the actual threat. Associated symptoms include restlessness/feeling keyed up, easy fatigability, poor concentration, irritability, muscle tension, and sleep disturbance. Symptoms are chronic and often lead to repeated medical presentations without clear explanation." },
  { id: 2765, category: 'generalized anxiety disorder', keywords: ['course onset chronicity impairment GAD'], question: "What is the typical course and functional impact of generalized anxiety disorder?", response: "Average age of onset is ~30 years (range is broad); subsyndromal symptoms often begin earlier. Late-onset GAD (≥50 years) is common in older adults and linked to poorer health-related quality of life. GAD is chronic with fluctuating severity; roughly half of patients have intervening symptom-free periods. It causes substantial impairment in occupational, social, and household functioning — often greater than major depression alone when comorbid. GAD is associated with increased cardiovascular risk and mortality." },
  { id: 2766, category: 'generalized anxiety disorder', keywords: ['screening GAD-7 USPSTF'], question: "What are the recommendations for screening generalized anxiety disorder?", response: "The USPSTF recommends screening for anxiety disorders in adults aged 19–65 years (including pregnant and postpartum persons). The GAD-7 is a widely used, validated, brief self-report tool that is sensitive to change and suitable for both screening and monitoring treatment response. All positive screens should be followed by a full clinical evaluation by a clinician trained in anxiety disorders. Evidence for screening adults >65 years is currently insufficient." },
  { id: 2767, category: 'generalized anxiety disorder', keywords: ['DSM-5-TR diagnostic criteria GAD'], question: "What are the DSM-5-TR diagnostic criteria for generalized anxiety disorder?", response: "Diagnosis requires: (A) excessive anxiety/worry occurring more days than not for ≥6 months about multiple events/activities; (B) difficulty controlling the worry; (C) ≥3 of 6 associated symptoms (restlessness, fatigability, concentration problems, irritability, muscle tension, sleep disturbance) present more days than not; (D) clinically significant distress or impairment; (E) not due to substances or another medical condition; and (F) not better explained by another mental disorder. Only one associated symptom is required in children." },
  { id: 2768, category: 'generalized anxiety disorder', keywords: ['differential diagnosis GAD vs depression panic OCD'], question: "How is generalized anxiety disorder differentiated from other disorders with overlapping symptoms?", response: "Differentiate primarily by history and symptom pattern: vs. depression (future-oriented worry vs. past-oriented brooding/guilt; less early morning awakening/suicidal ideation in pure GAD); vs. panic disorder (persistent worry vs. discrete, unexpected panic attacks); vs. OCD (day-to-day worries vs. intrusive obsessions + ritualistic compulsions); vs. illness anxiety/somatic symptom disorder (multiple life domains vs. predominant health/illness focus); vs. adjustment disorder (chronic symptoms vs. identifiable recent stressor within 3 months). Rule out substance-induced anxiety and normal worry (minimal impairment)." },
  { id: 2769, category: 'generalized anxiety disorder', keywords: ['CycleMind GAD assessment support'], question: "How can CycleMind support users with possible generalized anxiety symptoms?", response: "CycleMind should include the GAD-7 (or similar) for periodic screening/monitoring, especially across hormonal phases, and help users distinguish pervasive, difficult-to-control worry across multiple domains from normal worry or phase-specific anxiety (e.g., PMDD). It can educate on core features, prompt tracking of associated symptoms (sleep, irritability, muscle tension, concentration), flag when symptoms meet duration/impairment thresholds, and encourage professional evaluation. Clear differentiation from depressive symptoms and safety netting for comorbid depression or suicidal ideation are important." },

  // === NEW UpToDate Acute Procedural Anxiety Treatment RAG Entries (IDs 2770–2778) ===
  { id: 2770, category: 'procedural anxiety', keywords: ['treatment planning acute procedural anxiety'], question: "How should treatment for acute procedural anxiety be planned?", response: "Use shared decision-making. Assess impact on quality of life and whether anxiety causes avoidance of needed procedures. Mild symptoms without avoidance may not require treatment. Establish a trusting relationship, educate the patient about the procedure and anxiety, address specific fears, maximize patient control where safe, and make the environment as comfortable as possible. Prioritize treatment of co-occurring anxiety disorders (e.g., GAD, panic disorder) if present." },
  { id: 2771, category: 'procedural anxiety', keywords: ['benzodiazepines first-line procedural anxiety'], question: "What is first-line pharmacologic treatment for acute procedural anxiety?", response: "Benzodiazepines are first-line for most patients needing medication. Choice depends on onset, duration, route availability, monitoring, comorbidities, and clinician comfort. Common options include midazolam (rapid onset, amnestic, IV preferred when monitoring available), diazepam, and lorazepam. Use the lowest effective dose; reduce by ~50% in older adults or those with respiratory/cardiac disease. Educate on sedation, driving restrictions, and need for accompaniment at discharge." },
  { id: 2772, category: 'procedural anxiety', keywords: ['benzodiazepine routes dosing procedural anxiety'], question: "How are benzodiazepines administered for procedural anxiety?", response: "Oral (diazepam or lorazepam) 30–60 min before procedure is common for outpatient settings. IV midazolam (slow push) for rapid effect when monitoring and airway support are available. Sublingual and intranasal routes offer faster onset than oral without IV access. Repeat doses at half the initial amount if needed, with close monitoring for sedation or respiratory depression. Tables for specific dosing and pharmacokinetics are available in clinical references." },
  { id: 2773, category: 'procedural anxiety', keywords: ['melatonin alternative procedural anxiety'], question: "When is melatonin used for procedural anxiety?", response: "Melatonin (3 mg sublingual or 3–10 mg oral, ~90 min before procedure) is a reasonable alternative when benzodiazepines are undesirable (e.g., active severe substance use disorder, cognitive impairment, contraindications, or prior ineffectiveness). It reduces preprocedural anxiety with less psychomotor impairment and shorter recovery time than midazolam. Quality and dosing consistency of melatonin supplements can vary." },
  { id: 2774, category: 'procedural anxiety', keywords: ['CBT psychosocial procedural anxiety'], question: "What psychosocial interventions are used for acute procedural anxiety?", response: "Brief CBT (psychoeducation, cognitive restructuring, muscle relaxation, exposure) or brief supportive therapy are first-line psychosocial options. CBT components can be delivered in a few short sessions and have longer-lasting effects than medication. Psychoeducation about the procedure and anxiety is foundational. In vivo or virtual reality exposure is particularly useful for specific phobias. Supportive therapy focuses on validation, emotional support, and coping." },
  { id: 2775, category: 'procedural anxiety', keywords: ['dental phobia treatment'], question: "How is dental phobia treated?", response: "Prefer psychotherapy (in vivo exposure with or without cognitive components) over medication for longer-lasting effects, as dental care is recurring. CBT with exposure is supported by small trials. Nitrous oxide is the sedation medication of choice in dental practice when pharmacotherapy is used. Benzodiazepines are effective but cause longer sedation. General anesthesia is reserved for major work or when other methods fail." },
  { id: 2776, category: 'procedural anxiety', keywords: ['blood injection injury phobia applied tension'], question: "How is blood-injection-injury phobia managed?", response: "First-line is applied tension: repeated muscle tensing to increase blood pressure and prevent fainting, combined with exposure. Once mastered, patients use the technique at the first sign of lightheadedness during exposure. If fainting history exists and technique is not yet learned, have the patient lie down during the procedure, look away, and sit up slowly after dizziness resolves." },
  { id: 2777, category: 'procedural anxiety', keywords: ['MRI claustrophobia management'], question: "How is MRI claustrophobia managed?", response: "First, adjust patient positioning in the scanner if possible. For persistent symptoms, benzodiazepines (same approach as general procedural anxiety) are generally used. For patients needing repeated MRIs or preferring to avoid medication, in vivo exposure therapy or cognitive therapy are effective alternatives and have shown sustained benefit at one-year follow-up in trials." },
  { id: 2778, category: 'procedural anxiety', keywords: ['CycleMind procedural anxiety support'], question: "How can CycleMind support users with procedural or medical anxiety?", response: "CycleMind can include brief validated screening for procedural anxiety, education on evidence-based options (benzodiazepines for one-time needs, CBT/exposure for recurring procedures or specific phobias), and prompts to discuss fears with clinicians. It can help users prepare questions, practice simple relaxation or applied tension techniques, and track anxiety related to upcoming procedures (e.g., mammograms, dental work, MRIs). Strong safety netting and encouragement of shared decision-making with providers are essential." },

  // === NEW UpToDate Social Anxiety Disorder RAG Entries (IDs 2779–2787) ===
  { id: 2779, category: 'social anxiety disorder', keywords: ['epidemiology prevalence comorbidity SAD'], question: "What is the prevalence and comorbidity pattern of social anxiety disorder?", response: "SAD is one of the most common psychiatric disorders, with lifetime prevalence in the US estimated at 5–12% and 12-month prevalence of 3–7%. It is more common in females. Comorbidity is very high: lifetime mood disorders (~56%), other anxiety disorders (~54%), and any personality disorder (~55%). Avoidant personality disorder frequently overlaps with severe/generalized SAD. SAD is also associated with increased rates of substance use disorders, which may develop as self-medication." },
  { id: 2780, category: 'social anxiety disorder', keywords: ['pathogenesis behavioral inhibition SAD'], question: "What role does behavioral inhibition play in social anxiety disorder?", response: "Behavioral inhibition (a childhood temperament involving fear and withdrawal in novel situations) is a strong risk factor for SAD. It is heritable and linked to amygdala hyperactivity. Prospective studies show it increases the risk of developing SAD by approximately sevenfold. Many adults with SAD describe lifelong shyness that intensified into impairing anxiety." },
  { id: 2781, category: 'social anxiety disorder', keywords: ['cognitive behavioral factors SAD'], question: "What cognitive and behavioral factors maintain social anxiety disorder?", response: "Individuals with SAD show biased attention to threat, negative interpretation of ambiguous social cues, and excessive self-focus. They often avoid social situations or engage in subtle safety behaviors. After social encounters, they ruminate on perceived failures, reinforcing fears. These patterns create a vicious cycle. Cognitive-behavioral therapy directly targets these biases and avoidance behaviors." },
  { id: 2782, category: 'social anxiety disorder', keywords: ['clinical manifestations SAD'], question: "What are the typical clinical manifestations of social anxiety disorder?", response: "Core features include marked fear of scrutiny, embarrassment, or humiliation in social or performance situations. Patients often appear shy or ill at ease in interviews, make poor eye contact, and give brief answers. They experience anticipatory anxiety, physical symptoms (blushing, sweating, trembling, palpitations), and post-event rumination. Fear may be generalized across most social situations or limited to performance situations (performance-only specifier)." },
  { id: 2783, category: 'social anxiety disorder', keywords: ['course prognosis SAD'], question: "What is the typical course and prognosis of social anxiety disorder?", response: "Mean age of onset is mid-teens (can begin as early as age 5). New onset after age 30 is uncommon. Untreated, it tends to be chronic with fluctuating severity. Avoidance is often the most impairing feature. With effective treatment, roughly half of responders achieve full remission. CBT shows durable benefits (up to 5 years in studies), while medication benefits are more likely to be maintained with continued treatment for 6–12 months." },
  { id: 2784, category: 'social anxiety disorder', keywords: ['screening Mini-SPIN LSAS SAD'], question: "What tools are used to screen and monitor social anxiety disorder?", response: "The 3-item Mini-Social Phobia Inventory (Mini-SPIN) is a brief, validated screening tool with good sensitivity and specificity. The Liebowitz Social Anxiety Scale (LSAS) is the gold-standard instrument for assessing fear and avoidance across common social and performance situations and is excellent for monitoring treatment response over time (can be clinician-rated or self-report)." },
  { id: 2785, category: 'social anxiety disorder', keywords: ['DSM-5-TR diagnostic criteria SAD'], question: "What are the DSM-5-TR diagnostic criteria for social anxiety disorder?", response: "Diagnosis requires marked fear/anxiety about one or more social situations involving possible scrutiny, fear of acting in a way that will be negatively evaluated, situations almost always provoking fear, avoidance or endurance with intense distress, recognition that fear is excessive or out of proportion, persistence (typically ≥6 months), and clinically significant distress or impairment. The 'performance only' specifier is used when fear is limited to speaking or performing in public." },
  { id: 2786, category: 'social anxiety disorder', keywords: ['differential diagnosis SAD vs shyness depression autism'], question: "How is social anxiety disorder differentiated from similar conditions?", response: "Differentiate from nonpathologic shyness (greater severity, pervasiveness, and impairment in SAD); depression (social withdrawal due to anhedonia vs. primary fear of negative evaluation); autism spectrum disorder (SAD has intact social knowledge but anxiety interferes with use; autism has broader social communication deficits); panic disorder/OCD (fear of scrutiny is primary in SAD); agoraphobia (fear of being trapped vs. fear of embarrassment); and body dysmorphic disorder (fixed belief about appearance defect)." },
  { id: 2787, category: 'social anxiety disorder', keywords: ['CycleMind social anxiety support'], question: "How can CycleMind support users with social anxiety symptoms?", response: "CycleMind should include brief screening (e.g., Mini-SPIN), help users distinguish impairing social anxiety from normal shyness or performance anxiety, and track avoidance behaviors and post-event rumination. It can offer education on evidence-based treatments (CBT with exposure is first-line for many; medication when preferred or symptoms are severe), encourage gradual exposure planning, and prompt professional evaluation when anxiety causes significant avoidance or impairment. Integration with mood/hormonal tracking is valuable given high comorbidity with depression." },

  // === NEW UpToDate Acute Procedural Anxiety RAG Entries (IDs 2788–2796) ===
  { id: 2788, category: 'procedural anxiety', keywords: ['definition acute procedural anxiety vs specific phobia'], question: "What is acute procedural anxiety and how does it differ from specific phobia of clinical procedures?", response: "Acute procedural anxiety is excessive fear of medical, dental, or surgical procedures causing acute distress or interference with completing the procedure. It is not a formal DSM-5-TR diagnosis. Specific phobias of clinical procedures (e.g., dental phobia, blood-injection-injury phobia, MRI claustrophobia) are diagnosed when fear is focused specifically on the procedure or its immediate effects (e.g., seeing blood, suffocating in the scanner) and causes significant distress or impairment." },
  { id: 2789, category: 'procedural anxiety', keywords: ['epidemiology risk factors procedural anxiety'], question: "What is known about the epidemiology and risk factors for acute procedural anxiety?", response: "Rates vary widely by procedure and study methods (up to 50% moderate-severe anxiety before colonoscopy; up to 80% before major cardiac surgery). Risk factors include female sex, high baseline anxiety, previous negative (or sometimes positive) anesthesia experiences, lower education level, and hospitalization before surgery. Anxiety is common even with minimally invasive or lower-risk procedures." },
  { id: 2790, category: 'procedural anxiety', keywords: ['clinical manifestations components of anxiety'], question: "What are the cognitive, physiological, and behavioral components of acute procedural anxiety?", response: "Cognitive: apprehension about future threat, pain, complications, outcomes, or embarrassment. Physiological: tachycardia, palpitations, sweating, shortness of breath, muscle tension. Behavioral: avoidance, delay of procedures, reassurance seeking, or subtle safety behaviors. Severe anxiety can lead to cancellation or early termination of necessary procedures." },
  { id: 2791, category: 'procedural anxiety', keywords: ['focus of fear procedural anxiety'], question: "What are common focuses of fear in acute procedural anxiety?", response: "Common fears include pain/discomfort, complications, anesthesia risks, poor outcomes, disability, wait time for results, embarrassment (e.g., bowel prep, exposure), and fear of death. The specific focus often depends on the procedure type and individual history." },
  { id: 2792, category: 'procedural anxiety', keywords: ['screening tools APAIS DAS-R Claustrophobia Miniscreen'], question: "What screening tools are recommended for acute procedural anxiety?", response: "APAIS (Amsterdam Preoperative Anxiety and Information Scale) for surgical/anesthesia anxiety (score ≥11 on anxiety subscale is positive). DAS-R (Dental Anxiety Scale-Revised) for dental anxiety (score ≥13 positive; ≥15 highly anxious). Claustrophobia Miniscreen (6 items) for MRI claustrophobia (score ≥9 highly predictive of panic during scan). Simple direct questioning about procedure-related anxiety is also useful." },
  { id: 2793, category: 'procedural anxiety', keywords: ['assessment procedural anxiety'], question: "What should be assessed in patients with acute procedural anxiety?", response: "Prior history of procedural anxiety and coping strategies; specific focus of fear; understanding of risks, pain, recovery, and implications; severity of avoidance behaviors (delaying scheduling, missing appointments, needing heavy premedication); and comorbid anxiety disorders (e.g., GAD), which increase vulnerability." },
  { id: 2794, category: 'procedural anxiety', keywords: ['course of illness procedural anxiety'], question: "What is the typical course of acute procedural anxiety?", response: "Anxiety usually peaks in anticipation of or immediately before the procedure and decreases afterward. In most cases it is time-limited to the periprocedural period, though some patients experience more persistent worry, especially if results have significant implications or prior experiences were negative." },
  { id: 2795, category: 'procedural anxiety', keywords: ['differential diagnosis procedural anxiety'], question: "How is acute procedural anxiety differentiated from other anxiety disorders?", response: "Differentiate from GAD (chronic, multiple life worries vs. focused on one procedure); panic disorder (spontaneous attacks focused on the attack itself vs. procedure-focused); agoraphobia (fear of being trapped/helpless vs. fear of the procedure); and adjustment disorder (anxiety tied to broader illness stressor). Rule out medical causes (e.g., arrhythmias, pulmonary embolism) that can mimic anxiety symptoms." },
  { id: 2796, category: 'procedural anxiety', keywords: ['CycleMind procedural anxiety support'], question: "How can CycleMind support users experiencing procedural or medical anxiety?", response: "CycleMind can include brief screening questions or validated tools (e.g., simplified APAIS or direct inquiry) before known procedures, education on the difference between normal anticipatory anxiety and impairing procedural anxiety, and strategies to reduce avoidance. It can help users prepare questions for clinicians, track anxiety patterns (including any hormonal influences), and encourage timely discussion of fears or need for support (e.g., premedication planning or referral for CBT/exposure). Strong safety netting for avoidance of necessary care is important." },

  // === NEW UpToDate Specific Phobia Treatment RAG Entries (IDs 2797–2804) ===
  { id: 2797, category: 'specific phobia', keywords: ['decision to treat specific phobia'], question: "How should clinicians decide whether to treat a specific phobia?", response: "Use shared decision-making. Assess the impact on quality of life, level of distress, avoidance behaviors, and interference with daily functioning (work, social, etc.). Encourage treatment when the phobia significantly affects daily life. For less pervasive phobias or those involving rarely encountered stimuli, respect patient preference, which may include no treatment or as-needed medication only." },
  { id: 2798, category: 'specific phobia', keywords: ['CBT exposure first-line specific phobia'], question: "What is first-line treatment for specific phobia in adults?", response: "For most patients, first-line treatment is cognitive-behavioral therapy (CBT) that includes exposure (in vivo, imaginal, virtual reality, or augmented reality). Exposure-based CBT has the strongest evidence and appears highly efficacious. While emotionally taxing, it produces robust and often durable gains. Patients reluctant to start exposure can be supported with psychoeducation about its effectiveness and strategies to increase tolerability." },
  { id: 2799, category: 'specific phobia', keywords: ['benzodiazepines specific phobia indications cautions'], question: "When are benzodiazepines used for specific phobia and what are the cautions?", response: "Benzodiazepines (e.g., clonazepam or lorazepam) are reasonable alternatives when CBT/exposure is unavailable, not tolerated, or refused, or when the phobic stimulus is infrequent and unavoidable (e.g., a necessary flight). They provide short-term relief but do not treat the underlying phobia. Key cautions: may interfere with engagement in exposure, can increase anxiety in future encounters (pharmaco-dependence effect), risk of sedation/impairment, and higher misuse liability in those with substance use history. Use the lowest effective dose, test dose first, and limit prescriptions." },
  { id: 2800, category: 'specific phobia', keywords: ['co-occurring disorders specific phobia'], question: "How should co-occurring disorders be handled in specific phobia?", response: "Thoroughly assess for comorbid anxiety disorders (e.g., GAD, panic), mood disorders, and substance use disorders. Treat the primary disorder causing the greatest distress/impairment first (as identified by the patient or clinician). Some specific phobias (e.g., choking, medical procedure fears) may be severe or life-threatening and warrant clinical priority even if other comorbidities are present." },
  { id: 2801, category: 'specific phobia', keywords: ['inadequate response exposure therapy specific phobia'], question: "How should inadequate response to exposure therapy for specific phobia be managed?", response: "First confirm the patient is not using benzodiazepines, alcohol, or safety behaviors that undermine exposure. Then add or intensify components such as cognitive therapy, psychoeducation, anxiety management skills, or applied tension (for blood-injection-injury type). There are no established medication augmentation strategies with strong evidence; options like D-cycloserine, hydrocortisone, or others have only minimal supporting data and are not routinely used." },
  { id: 2802, category: 'specific phobia', keywords: ['real-world treatment helpfulness specific phobia'], question: "How helpful do patients find treatment for specific phobia in real-world settings?", response: "In large international surveys, only about 23% found the first professional they saw helpful, but the cumulative probability of finding treatment helpful rose to ~86% after seeing up to nine professionals. Overall, only ~48% ever received helpful treatment. This underscores the importance of referring to clinicians skilled in evidence-based treatments (especially exposure-based CBT) and encouraging persistence in help-seeking if initial attempts are unsuccessful." },
  { id: 2803, category: 'specific phobia', keywords: ['maintenance of gains specific phobia'], question: "How are treatment gains maintained in specific phobia?", response: "Gains from exposure-based CBT are often maintained for at least one year and sometimes longer. Ongoing self-exposure on a regular basis helps sustain benefits. Gains from benzodiazepines last only while the medication is taken. Booster sessions may be helpful for some patients if symptoms recur." },
  { id: 2804, category: 'specific phobia', keywords: ['CycleMind specific phobia support'], question: "How can CycleMind support users with specific phobias?", response: "CycleMind can help users identify impairing phobias vs. mild fears, track avoidance behaviors and distress levels, and provide balanced education on evidence-based options (CBT with exposure is first-line and highly effective for most; short-term benzodiazepines only for infrequent/unavoidable situations with clear cautions). It can encourage referral to exposure-capable clinicians, support preparation for treatment, and prompt persistence if initial help-seeking is unhelpful. Integration with broader anxiety/mood tracking is valuable given frequent comorbidity." },

  // === NEW UpToDate Panic Disorder Management RAG Entries (IDs 2805–2813) ===
  { id: 2805, category: 'panic disorder', keywords: ['initial management decisions panic disorder'], question: "How should clinicians decide whether and how to treat panic disorder?", response: "Use shared decision-making based on symptom severity, distress, functional impairment, and patient preference. Mild cases with minimal avoidance and preserved functioning may reasonably start with education/reassurance and close follow-up (every 3–6 months). For most patients needing active treatment, choose between CBT and an SSRI based on preference and availability. Strongly consider combined CBT + SSRI for patients with suicidality, severe impairment, or significant comorbidity." },
  { id: 2806, category: 'panic disorder', keywords: ['CBT first-line panic disorder'], question: "What is the preferred psychotherapy for panic disorder?", response: "Cognitive-behavioral therapy (CBT), particularly with exposure, is the preferred first-line psychotherapy. It has the strongest evidence base among psychotherapies for panic disorder and is effective when delivered by trained clinicians (including in primary care). Remote CBT options (internet, videoconference, bibliotherapy) can also be useful when in-person treatment is unavailable." },
  { id: 2807, category: 'panic disorder', keywords: ['SSRI first-line pharmacotherapy panic disorder'], question: "What is recommended as initial pharmacotherapy for panic disorder?", response: "Selective serotonin reuptake inhibitors (SSRIs) are first-line pharmacotherapy. Start at lower doses than for depression (e.g., sertraline 25 mg, escitalopram 5 mg, fluoxetine 5 mg) because patients with panic disorder are sensitive to initial overstimulation. Titrate gradually to the usual therapeutic range. Allow at least 6 weeks at the maximally tolerated dose before judging full response. All SSRIs appear comparably effective; choose based on side-effect profile, interactions, and cost." },
  { id: 2808, category: 'panic disorder', keywords: ['adjunctive treatment early distress panic disorder'], question: "How should marked distress or early SSRI side effects be managed in panic disorder?", response: "For patients with high distress who cannot wait for the SSRI to work, or who experience initial worsening, add a short-term adjunct. For those without substance use disorder history, use a long-acting benzodiazepine (e.g., clonazepam) for 10–12 weeks while titrating the SSRI, then taper slowly. For those with active or past SUD, use gabapentin (or mirtazapine if insomnia is prominent) instead. Taper the adjunct once the SSRI effect is established." },
  { id: 2809, category: 'panic disorder', keywords: ['duration of treatment panic disorder'], question: "How long should pharmacotherapy for panic disorder be continued?", response: "Continue effective medication for at least 12 months after symptom control is achieved. Many patients benefit from 12–24 months, especially those with more severe initial illness, comorbidity (depression, agoraphobia), residual symptoms (especially avoidance), or ongoing stressors. Relapse risk after discontinuation is substantial (25–50%). CBT gains are often more durable; booster sessions can help maintain benefits." },
  { id: 2810, category: 'panic disorder', keywords: ['managing partial response panic disorder'], question: "How should partial response to initial treatment in panic disorder be managed?", response: "First confirm adequate exposure/engagement (if in CBT) or adherence (if on medication). For partial response to CBT, add an SSRI. For partial response to an SSRI/SNRI, add CBT. If medication-focused care continues, augment with a long-acting benzodiazepine (no SUD history) or gabapentin (SUD history). Combined CBT + medication often provides modest additive benefit over either alone." },
  { id: 2811, category: 'panic disorder', keywords: ['poor response switching panic disorder'], question: "How should poor (minimal) response to initial SSRI treatment be managed?", response: "After an adequate trial (≥6 weeks at maximally tolerated therapeutic dose), switch to a second SSRI. An inadequate response to one SSRI does not predict failure of another. If there is still poor response after two SSRIs, try an SNRI (e.g., venlafaxine ER). Monitor blood pressure with venlafaxine. Continue to assess for adherence, adequate exposure (if CBT is involved), and alternative or comorbid diagnoses." },
  { id: 2812, category: 'panic disorder', keywords: ['treatment resistant panic disorder'], question: "What options exist for treatment-resistant panic disorder?", response: "For patients who have not responded to multiple SSRIs, an SNRI, and appropriate augmentation or CBT, consider sequential trials of nortriptyline (preferred TCA), then a monoamine oxidase inhibitor (e.g., phenelzine) if needed. Other agents (gabapentin, pregabalin, mirtazapine) have limited supporting data. Review the history carefully for missed comorbidities or alternative diagnoses. True pharmacologic resistance is uncommon when CBT with adequate exposure has also been tried." },
  { id: 2813, category: 'panic disorder', keywords: ['CycleMind panic disorder support'], question: "How can CycleMind support users with panic symptoms?", response: "CycleMind should include brief screening for panic attacks and agoraphobic avoidance, help users distinguish panic from other anxiety or hormonal symptoms, and track attack frequency, anticipatory anxiety, and avoidance over time (especially in relation to cycle phases). It can educate on evidence-based options (CBT with exposure is highly effective; SSRIs are first-line medication), support gradual exposure planning, and prompt timely professional evaluation when symptoms cause significant distress or impairment. Strong safety netting for suicidality and comorbid depression is essential." },
];